window.HADITH_CACHE["darimi_2"] = {"1001":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ أَنَا سَأَلْتُهُ عَنْهُ قَالَ أَخْبَرَنِي عَمْرُو بْنُ يَحْيَى عَنْ أَبِيهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْأَرْضُ كُلُّهَا مَسْجِدٌ إِلَّا الْمَقْبَرَةَ وَالْحَمَّامَ قِيلَ لِأَبِي مُحَمَّدٍ تُجْزِئُ الصَّلَاةُ فِي الْمَقْبَرَةِ قَالَ إِذَا لَمْ تَكُنْ عَلَى الْقَبْرِ فَنَعَمْ وَقَالَ الْحَدِيثُ أَكْثَرُهُمْ أَرْسَلُوهُ","id":"Telah mengabarkan kepada kami [Sa'id? bin Manshur] telah menceritakan kepada kami [Abdul Aziz bin Muhammad] -aku bertanya kepadanya tentangnya- ia berkata; telah mengabarkan kepadaku ['Amru bin Yahya] dari [Ayahnya] dari [Abu Sa'id Al Khudri] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seluruh bumi adalah masjid, kecuali kuburan dan kamar mandi.\" Abu Muhammad ditanya, \"Apakah shalat di kuburan sah?\" Ia menjawab, \"Selama tidak di atas kuburan maka shalatnya sah.\" Dan ia berkata, \"Kebanyakan ahli hadits telah memursalkan hadits tersebut.\" "},"1002":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ مِنْهَالٍ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا هِشَامُ بْنُ حَسَّانَ عَنْ مُحَمَّدٍ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا حَضَرَتْ الصَّلَاةُ فَلَمْ تَجِدُوا إِلَّا مَرَابِضَ الْغَنَمِ وَأَعْطَانَ الْإِبِلِ فَصَلُّوا فِي مَرَابِضِ الْغَنَمِ وَلَا تُصَلُّوا فِي أَعْطَانِ الْإِبِلِ","id":"Telah mengabarkan kepada kami [Muhammad bin Minhal] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Hisyam bin Hassan] dari [Muhammad] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila telah masuk waktu shalat dan kalian tidak mendapatkan tempat kecuali kandang kambing dan kandang unta, maka shalatlah di kandang kambing dan jangan kalian melakukan shalat di kandang unta.\" "},"1003":{"ar":" حَدَّثَنَا أَبُو عَاصِمٍ عَنْ عَبْدِ الْحَمِيدِ بْنِ جَعْفَرٍ حَدَّثَنِي أَبِي عَنْ مَحْمُودِ بْنِ لَبِيدٍ أَنَّ عُثْمَانَ لَمَّا أَرَادَ أَنْ يَبْنِيَ الْمَسْجِدَ كَرِهَ النَّاسُ ذَلِكَ فَقَالَ عُثْمَانُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ بَنَى لِلَّهِ مَسْجِدًا بَنَى اللَّهُ لَهُ فِي الْجَنَّةِ مِثْلَهُ","id":"Telah menceritakan kepada kami [Abu 'Ashim] dari [Abdul Hamid bin Ja'far] telah menceritakan kepadaku [Ayahku] dari [Mahmud bin Labid], bahwa saat Utsman akan membangun masjid, maka orang-orang merasa tidak menyukai hal tersebut. Kemudian [Utsman] berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membangun masjid maka Allah akan membangunkan baginya seperti itu di Surga.\""},"1004":{"ar":" أَخْبَرَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ وَفُلَيْحُ بْنُ سُلَيْمَانَ عَنْ عَامِرِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ عَمْرِو بْنِ سُلَيْمٍ عَنْ أَبِي قَتَادَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا جَاءَ أَحَدُكُمْ الْمَسْجِدَ فَلْيَرْكَعْ رَكْعَتَيْنِ قَبْلَ أَنْ يَجْلِسَ","id":"Telah mengabarkan kepada kami [Yahya bin Hassan] telah menceritakan kepada kami [Malik bin Anas] dan [Fulaih bin Sulaiman] dari ['Amir bin Abdullah bin Az Zubair] dari ['Amru bin Sulaim] dari [Abu Qatadah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang di antara kalian datang ke masjid, maka hendaknya ia shalat dua rakaat sebelum duduk.\""},"1005":{"ar":" حَدَّثَنَا يَحْيَى بْنُ حَسَّانَ أَخْبَرَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ رَبِيعَةَ بْنِ أَبِي عَبْدِ الرَّحْمَنِ عَنْ عَبْدِ الْمَلِكِ بْنِ سَعِيدِ بْنِ سُوَيْدٍ قَالَ سَمِعْتُ أَبَا حُمَيْدٍ أَوْ أَبَا أُسَيْدٍ الْأَنْصَارِيَّ يَقُولُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا دَخَلَ أَحَدُكُمْ الْمَسْجِدَ فَلْيُسَلِّمْ عَلَى النَّبِيِّ ثُمَّ لِيَقُلْ اللَّهُمَّ افْتَحْ لِي أَبْوَابَ رَحْمَتِكَ وَإِذَا خَرَجَ فَلْيَقُلْ اللَّهُمَّ إِنِّي أَسْأَلُكَ مِنْ فَضْلِكَ","id":"Telah menceritakan kepada kami [Yahya bin Hassan] telah mengabarkan kepada kami [Abdul 'Aziz bin Muhammad] dari [Rabi'ah bin Abu Abdurrahman] dari [Abdul Malik bin Sa'id bin Suwaid] ia berkata, saya mendengar [Abu Humaid] atau [Abu Usaid Al Anshari] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang di antara kalian memasuki masjid maka hendaknya ia mengucapkan salam kepada Nabi kemudian mengucapkan: 'ALLAAHUMMAFTAH LII ABWAABA RAHMATIKA (Ya Allah, bukakanlah untukku pintu-pintu rahmat-Mu).' Dan jika akan keluar hendaknya mengucapkan: 'ALLAAHUMMA INNII AS-ALUKA MIN FADLLIK (Ya Allah, sesungguhnya aku memohon karunia-Mu).\" "},"1006":{"ar":" حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا شُعْبَةُ قَالَ قُلْتُ لِقَتَادَةَ أَسَمِعْتَ أَنَسًا يَقُولُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْبُزَاقُ فِي الْمَسْجِدِ خَطِيئَةٌ قَالَ نَعَمْ وَكَفَّارَتُهَا دَفْنُهَا","id":"Telah menceritakan kepada kami [Hasyim bin Al Qasim] telah menceritakan kepada kami [Syu'bah] ia berkata, \"Aku katakan kepada [Qatadah], \"Apakah engkau pernah mendengar [Anas] berkata dari Nabi shallallahu 'alaihi wasallam: \"Meludah di masjid adalah sebuah kesalahan?\" Ia menjawab, \"Ya. Dan kafarahnya adalah dengan memendamnya.\" "},"1007":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا حُمَيْدٌ عَنْ أَنَسٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الْعَبْدَ إِذَا صَلَّى فَإِنَّمَا يُنَاجِي رَبَّهُ أَوْ رَبُّهُ بَيْنَهُ وَبَيْنَ الْقِبْلَةِ فَإِذَا بَزَقَ أَحَدُكُمْ فَلْيَبْصُقْ عَنْ يَسَارِهِ أَوْ تَحْتَ قَدَمِهِ أَوْ يَقُولُ هَكَذَا وَبَزَقَ فِي ثَوْبِهِ وَدَلَكَ بَعْضَهُ بِبَعْضٍ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Humaid] dari [Anas], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika seorang hamba melaksanakan shalat maka sesungguhnya ia sedang berdialog dengan Tuhannya, atau Tuhannya berada di antara dirinya dan Kiblat. Kemudian apabila salah seorang di antara kalian meludah, maka hendaknya ia meludah ke samping kirinya atau di bawah kakinya.\" Atau beliau mengatakan: \"Meludah di pakaiannya dan menggosok sebagian kainnya dengan sebagian yang lain.\" "},"1008":{"ar":" أَخْبَرَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَ بَيْنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ إِذْ رَأَى نُخَامَةً فِي قِبْلَةِ الْمَسْجِدِ فَتَغَيَّظَ عَلَى أَهْلِ الْمَسْجِدِ وَقَالَ إِنَّ اللَّهَ قِبَلَ أَحَدِكُمْ إِذَا كَانَ فِي صَلَاتِهِ فَلَا يَبْزُقَنَّ أَوْ قَالَ لَا يَتَنَخَّعَنَّ ثُمَّ أَمَرَ بِهَا فَحُكَّ مَكَانُهَا وَأَمَرَ بِهَا فَلُطِخَتْ قَالَ حَمَّادٌ لَا أَعْلَمُهُ إِلَّا قَالَ بِزَعْفَرَانٍ","id":"Telah mengabarkan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Ketika Nabi shallallahu 'alaihi wasallam berkhutbah, tiba-tiba beliau melihat ludah di kiblat masjid. Maka beliau marah kepada penghuni masjid seraya bersabda: \"Sesungguhnya Allah berada di hadapan salah seorang dari kalian saat ia sedang shalat, maka janganlah ia meludah atau membuang ingus! \" Kemudian beliau memerintahkan agar dibersihkan, maka ludah itu pun dikerik dan beliau memerintahkan agar ludah tersebut dilumuri (timbun dengan debu).\" Hammad berkata, \"Aku tidak mengetahuinya kecuali ia berkata, \"Dengan Za'faran.\" "},"1009":{"ar":" حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ الزُّهْرِيِّ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ أَنَّ أَبَا سَعِيدٍ وَأَبَا هُرَيْرَةَ أَخْبَرَاهُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى نُخَامَةً فِي جِدَارِ الْمَسْجِدِ فَتَنَاوَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَصَاةً وَحَتَّهَا ثُمَّ قَالَ إِذَا تَنَخَّمَ أَحَدُكُمْ فَلَا يَتَنَخَّمَنَّ قِبَلَ وَجْهِهِ وَلَا عَنْ يَمِينِهِ وَلْيَبْصُقْ عَنْ يَسَارِهِ أَوْ تَحْتَ قَدَمِهِ","id":"Telah menceritakan kepada kami [Sulaiman bin Daud] telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Az Zuhri] dari [Humaid bin Abdurrahman] bahwa [Abu Sa'id] dan [Abu Hurairah] telah mengabarkan kepadanya, bahwa Rasulullah shallallahu 'alaihi wasallam melihat ingus di dinding masjid, kemudian Rasulullah shallallahu 'alaihi wasallam mengambil pasir dan menggosoknya. Setelah itu beliau bersabda: \"Apabila salah seorang di antara kalian membuang dahak, maka janganlah ia membuangnya ke arah depan atau samping kanannya. Hendaklah ia meludah ke samping kirinya atau ke bawah kakinya.\""},"1010":{"ar":" حَدَّثَنَا سَعِيدُ بْنُ الْمُغِيرَةِ حَدَّثَنَا مُعْتَمِرٌ عَنْ دَاوُدَ بْنِ أَبِي هِنْدٍ عَنْ أَبِي حَرْبِ بْنِ أَبِي الْأَسْوَدِ الدِّيلِيِّ عَنْ عَمِّهِ عَنْ أَبِي ذَرٍّ قَالَ أَتَانِي نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا نَائِمٌ فِي الْمَسْجِدِ فَضَرَبَنِي بِرِجْلِهِ قَالَ أَلَا أَرَاكَ نَائِمًا فِيهِ قُلْتُ يَا نَبِيَّ اللَّهِ غَلَبَتْنِي عَيْنِي","id":"Telah menceritakan kepada kami [Sa'id? bin Al Mughirah] telah menceritakan kepada kami [Mu'tamir] dari [Daud bin Abu Hindun] dari [Abu Harb bin Abu Asad Ad Dili] dari [Pamannya] dari [Abu Dzar] ia berkata, \"Nabi shallallahu 'alaihi wasallam datang kepadaku sementara saya sedang tidur di masjid, kemudian beliau mengoyang-goyangku menggunakan kakinya. Beliau berkata: \"Kenapa aku melihat kamu tidur dalam masjid?\" Aku lalu menjawab, \"Aku terkalahkan oleh rasa kantuk.\" "},"1011":{"ar":" حَدَّثَنَا مُوسَى بْنُ خَالِدٍ عَنْ أَبِي إِسْحَقَ الْفَزَارِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَ كُنْتُ أَبِيتُ فِي الْمَسْجِدِ وَلَمْ يَكُنْ لِي أَهْلٌ فَرَأَيْتُ فِي الْمَنَامِ كَأَنَّمَا انْطُلِقَ بِي إِلَى بِئْرٍ فِيهَا رِجَالٌ مُعَلَّقُونَ فَقِيلَ انْطَلِقُوا بِهِ إِلَى ذَاتِ الْيَمِينِ فَذَكَرْتُ الرُّؤْيَا لِحَفْصَةَ فَقُلْتُ قُصِّيهَا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَصَّتْهَا عَلَيْهِ فَقَالَ مَنْ رَأَى هَذِهِ قَالَتْ ابْنُ عُمَرَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نِعْمَ الْفَتَى أَوْ قَالَ نِعْمَ الرَّجُلُ لَوْ كَانَ يُصَلِّي مِنْ اللَّيْلِ قَالَ وَكُنْتُ إِذَا نِمْتُ لَمْ أَقُمْ حَتَّى أُصْبِحَ قَالَ فَكَانَ ابْنُ عُمَرَ يُصَلِّي اللَّيْلَ","id":"Telah menceritakan kepada kami [Musa bin Khalid] dari [Abu Ishaq Al Fazari] dari ['Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Aku pernah bermalam di masjid, dan aku tidak memiliki keluarga. Kemudian dalam tidur aku bermimpi seolah-olah aku dibawa ke sebuah sumur yang padanya terdapat beberapa orang laki-laki yang bergantungan. Kemudian dikatakan, 'Bawalah ia pergi ke Dzatul yamin.' Kemudian aku menceritakan mimpi tersebut kepada Hafshah, aku katakan, \"Ceritakan hal tersebut kepada Rasulullah shallallahu 'alaihi wasallam! \" Kemudian ia menceritakannya kepada Rasulullah shallallahu 'alaihi wasallam. Maka beliau pun bersabda: \"Siapa yang mimpi seperti ini?\" Hafshah menjawab, \"Ibnu Umar.\" Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ia adalah sebaik-baik pemuda.\" Atau beliau mengatakan: \"Ia adalah sebaik-baik laki-laki seandainya mau shalat malam.\" Ibnu Umar berkata, \"Jika aku tidur maka aku tidak akan bangun kecuali telah datang subuh.\" Nafi' berkata, \"Setelah itu Ibnu Umar selalu shalat malam.\" "},"1012":{"ar":" أَخْبَرَنَا الْحَسَنُ بْنُ أَبِي زَيْدٍ الْكُوفِيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ أَخْبَرَنِي يَزِيدُ بْنُ خُصَيْفَةَ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ ثَوْبَانَ عَنْ أَبِي هُرَيْرَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا رَأَيْتُمْ مَنْ يَبِيعُ أَوْ يَبْتَاعُ فِي الْمَسْجِدِ فَقُولُوا لَا أَرْبَحَ اللَّهُ تِجَارَتَكَ وَإِذَا رَأَيْتُمْ مَنْ يَنْشُدُ فِيهِ الضَّالَّةَ فَقُولُوا لَا أَدَّى اللَّهُ عَلَيْكَ","id":"Telah mengabarkan kepada kami [Al Hasan bin Abu Zaid Al Kufi] telah menceritakan kepada kami [Abdul Aziz bin Muhammad] telah mengabarkan kepadaku [Yazid bin Khushaifah] dari [Muhammad bin Abdurrahman bin Tsauban] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila kalian melihat orang yang berjualan atau membeli di masjid maka katakan, 'Semoga Allah tidak memberikan keuntungan kepada perniagaanmu.' Dan apabila kalian melihat orang yang mengumumkan di masjid barang hilang, maka katakan, 'Semoga Allah tidak mengembalikannya kepadamu'.\""},"1013":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُبَارَكِ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ قَالَ قُلْتُ لِعَمْرِو بْنِ دِينَارٍ أَسَمِعْتَ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُ مَرَّ رَجُلٌ فِي الْمَسْجِدِ يَحْمِلُ نَبْلًا فَقَالَ لَهُ ال��َّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمْسِكْ نُصُولَهَا قَالَ نَعَمْ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mubarak] telah menceritakan kepada kami [Sufyan bin 'Uyainah] ia berkata; aku katakan kepada ['Amru bin Dinar], \"Apakah engkau pernah mendengar [Jabir bin Abdullah] berkata, \"Ada seorang laki-laki lewat di masjid membawa anak panah, kemudian Nabi shallallahu 'alaihi wasallam berkata kepadanya: \"Peganglah mata panahnya?\" Jabir menjawab, \"Ya.\""},"1014":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ نَافِعٍ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ أَنَّ ابْنَ عَبَّاسٍ وَعَائِشَةَ قَالَا لَمَّا نُزِلَ بِالنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَفِقَ يَطْرَحُ خَمِيصَةً لَهُ عَلَى وَجْهِهِ فَإِذَا اغْتَمَّ كَشَفَهَا عَنْ وَجْهِهِ فَقَالَ وَهُوَ كَذَلِكَ لَعْنَةُ اللَّهِ عَلَى الْيَهُودِ وَالنَّصَارَى اتَّخَذُوا قُبُورَ أَنْبِيَائِهِمْ مَسَاجِدَ يُحَذِّرُ مِثْلَ مَا صَنَعُوا","id":"Telah mengabarkan kepada kami [Al Hakam bin Nafi'] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] telah mengabarkan kepadaku ['Ubaidullah bin Abdullah] bahwa [Ibnu Abbas] dan [Aisyah] berkata, \"Tatkala Nabi shallallahu 'alaihi wasallam mengalami sakaratul maut beliau menutupkan kainnya ke wajah, dan saat beliau terasa sesak nafasnya beliau membukanya kembali. Lalu beliau bersabda: \"Semoga Allah melaknat orang-orang Yahudi dan Nasrani, mereka telah menjadikan kuburan para nabi mereka sebagai masjid.\" Beliau memberikan peringatan terhadap perbuatan yang sama dengan apa yang mereka lakukan.\""},"1015":{"ar":" حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ أَخْبَرَنَا دَاوُدُ بْنُ قَيْسٍ الْفَرَّاءُ عَنْ سَعْدِ بْنِ إِسْحَقَ عَنْ أَبِي ثُمَامَةَ الْحَنَّاطِ قَالَ أَدْرَكَنِي كَعْبُ بْنُ عُجْرَةَ بِالْبَلَاطِ وَأَنَا مُشَبِّكٌ بَيْنَ أَصَابِعِي فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا تَوَضَّأَ أَحَدُكُمْ ثُمَّ خَرَجَ عَامِدًا إِلَى الصَّلَاةِ فَلَا يُشَبِّكُ بَيْنَ أَصَابِعِهِ","id":"Telah menceritakan kepada kami [Utsman bin Umar] telah mengabarkan kepada kami [Daud bin Qais Al Farra`] dari [Sa'd bin Ishaq] dari [Abu Tsumamah Al Hannath] ia berkata, \" [Ka'b bin 'Ujrah] mendapatiku di Balath (tempat yang padanya terhampar bebatuan di samping masjid Rasulullah shallallahu 'alaihi wasallam) sementara aku dalam keadaan menjalin jari-jariku. Maka ia pun berkata, \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam berkata: \"Apabila salah seorang di antara kalian berwudlu kemudian keluar untuk melaksanakan shalat, maka tidak boleh ia menjalin jari-jarinya.\""},"1016":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ مُحَمَّدِ بْنِ عَجْلَانَ عَنْ الْمَقْبُرِيِّ عَنْ كَعْبِ بْنِ عُجْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا تَوَضَّأْتَ فَعَمَدْتَ إِلَى الْمَسْجِدِ فَلَا تُشَبِّكَنَّ بَيْنَ أَصَابِعِكَ فَإِنَّكَ فِي صَلَاةٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Muhammad bin 'Ajlan] dari [Al Maqburi] dari [Ka'b bin 'Ujrah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila engkau berwudlu kemudian menuju masjid maka janganlah engkau menjalin jari-jarimu, karena sesungguhnya engkau ada dalam shalat.\""},"1017":{"ar":" أَخْبَرَنَا الْهَيْثَمُ بْنُ جَمِيلٍ عَنْ مُحَمَّدِ بْنِ مُسْلِمٍ عَنْ إِسْمَعِيلَ بْنِ أُمَيَّةَ عَنْ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَوَضَّأَ ثُمَّ خَرَجَ يُرِيدُ الصَّلَاةَ فَهُوَ فِي صَلَاةٍ حَتَّى يَرْجِعَ إِلَى بَيْتِهِ فَلَا تَقُولُوا هَكَذَا يَعْنِي يُشَبِّكُ بَيْنَ أَصَابِعِهِ","id":"Telah mengabarkan kepada kami [Al Haitsam bin Jamil] dari [Muhammad bin Muslim] dari [Isma'il bin Umayyah] dari [Al Maqburi] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa berwudlu kemudian keluar untuk melaksanakan shalat, maka ia dalam hitungan shalat hingga ia kembali ke rumahnya. Maka janganlah kalian melakukan demikian, yaitu menjalin jari-jari.\""},"1018":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا مُحَمَّدُ بْنُ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَزَالُ الْمَلَائِكَةُ تُصَلِّي عَلَى الْعَبْدِ مَا دَامَ فِي مُصَلَّاهُ الَّذِي يُصَلِّي فِيهِ مَا لَمْ يَقُمْ أَوْ يُحْدِثْ تَقُولُ اللَّهُمَّ اغْفِرْ لَهُ اللَّهُمَّ ارْحَمْهُ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Muhammad bin 'Amru] dari [Abu Salamah] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Malaikat senantiasa mendoakan seorang hamba selama ia berada di tempat shalat yang ia gunakan untuk shalat, selama belum berdiri atau berhadats. Malaikat berdoa: 'ALLAAHUMMAGHFIR LAHU, ALLAAHUMMARHAMHU (Ya Allah ampunilah dia. Ya Allah rahmatilah dia).\" "},"1019":{"ar":" أَخْبَرَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ حَدَّثَنَا أَيُّوبُ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسِ بْنِ مَالِكٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَقُومُ السَّاعَةُ حَتَّى يَتَبَاهَى النَّاسُ فِي الْمَسَاجِدِ","id":"Telah mengabarkan kepada kami ['Affan] telah menceritakan kepada kami [Hammad bin Salamah] telah menceritakan kepada kami [Ayyub] dari [Abu Qilabah] dari [Anas bin Malik] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidaklah terjadi Hari Kiamat hingga orang-orang saling membangga-banggakan masjid.\""},"1020":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ بْنِ عُتَيْبَةَ قَالَ سَمِعْتُ أَبَا جُحَيْفَةَ يَقُولُ خَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْبَطْحَاءِ بِالْهَاجِرَةِ فَصَلَّى الظُّهْرَ رَكْعَتَيْنِ وَالْعَصْرَ رَكْعَتَيْنِ وَبَيْنَ يَدَيْهِ عَنَزَةٌ وَإِنَّ الظُّعُنَ لَتَمُرُّ بَيْنَ يَدَيْهِ","id":"Telah mengabarkan kepada kami [Abu Al Walid Ath Thayalisi] telah menceritakan kepada kami [Syu'bah] dari [Al Hakam bin 'Utaibah] ia berkata, saya mendengar [Abu Juhaifah] berkata, \"Rasulullah shallallahu 'alaihi wasallam keluar di Bathha` pada saat siang terik, kemudian beliau melakukan shalat zhuhur dua rakaat dan shalat asar dua rakaat sementara di depan beliau terdapat sebuah tombak. Dan sungguh seekor kambing lewat di hadapan beliau.\""},"1021":{"ar":" أَخْبَرَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَتْ تُرْكَزُ لَهُ الْعَنَزَةُ يُصَلِّي إِلَيْهَا","id":"Telah mengabarkan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya bin Sa'id] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar], bahwa pernah ditancapkan sebuah tombak di hadapan Rasulullah shallallahu 'alaihi wasallam, lalu beliau shalat menghadap ke arahnya.\" "},"1022":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ الْمَجِيدِ حَدَّثَنَا مَالِكٌ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي سَعِيدٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا كَانَ أَحَدُكُمْ يُصَلِّي فَلَا يَدَعْ أَحَدًا يَمُرُّ بَيْنَ يَدَيْهِ فَإِنْ أَبَى فَلْيُقَاتِلْهُ فَإِنَّمَا هُوَ شَيْطَانٌ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Abdul Majid] telah menceritakan kepada kami [Malik] dari [Zaid bin Aslam] dari [Abdurrahman bin Abu Sa'id] dari [Abu Sa'id Al Khudri], bahwa Rasulullah shallallahu 'alaihi wasallam berkata: \"Jika salah seorang di antara kalian shalat janganlah membiarkan seseorang lewat di hadapannya, jika menolak maka hendaklah ia memeranginya. Sebab itu adalah setan.\" "},"1023":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ الْمُبَارَكِ وَعَبْدُ اللَّهِ بْنُ سَعِيدٍ عَنْ أَبِي خَالِدٍ الْأَحْمَرِ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي إِلَى رَاحِلَتِهِ","id":"Telah mengabarkan kepada kami [Al Hakam bin Al Mubarak] dan [Abdullah bin Sa'id] dari [Abu Khalid Al Ahmar] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar], bahwa Nabi shallallahu 'alaihi wasallam pernah melakukan shalat menghadap ke kendaraannya.\""},"1024":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنِي اللَّيْثُ حَدَّثَنِي عُقَيْلٌ عَنْ ابْنِ شِهَابٍ حَدَّثَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ عَائِشَةَ أَخْبَرَتْهُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي وَهِيَ بَيْنَهُ وَبَيْنَ الْقِبْلَةِ عَلَى فِرَاشِ أَهْلِهِ اعْتِرَاضَ الْجَنَازَةِ","id":"Telah mengabarkan kepada kami [Abdullah bin Shalih] telah menceritakan kepada kami [Al Laits] telah menceritakan kepadaku ['Uqail] dari [Ibnu Syihab] telah menceritakan kepadaku ['Urwah bin Az Zubair] bahwa [Aisyah] telah mengabarkan kepadanya, bahwa Rasulullah shallallahu 'alaihi wasallam pernah shalat sementara dirinya ada di antara beliau dan arah kiblat, tidur di seperti melintangnya jenazah.\" "},"1025":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ وَحَجَّاجٌ قَالَا حَدَّثَنَا شُعْبَةُ أَخْبَرَنِي حُمَيْدُ بْنُ هِلَالٍ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ الصَّامِتِ عَنْ أَبِي ذَرٍّ أَنَّهُ قَالَ يَقْطَعُ صَلَاةَ الرَّجُلِ إِذَا لَمْ يَكُنْ بَيْنَ يَدَيْهِ كَآخِرَةِ الرَّحْلِ الْحِمَارُ وَالْكَلْبُ الْأَسْوَدُ وَالْمَرْأَةُ قَالَ قُلْتُ فَمَا بَالُ الْأَسْوَدِ مِنْ الْأَحْمَرِ مِنْ الْأَصْفَرِ قَالَ سَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَمَا سَأَلْتَنِي فَقَالَ الْأَسْوَدُ شَيْطَانٌ","id":"Telah mengabarkan kepada kami [Abu Al Walid] dan [Hajjaj] mereka berkata; telah menceritakan kepada kami [Syu'bah] telah mengabarkan kepadaku [Humaid bin Hilal] ia berkata, saya mendengar [Abdullah bin Ash Shamit] dari [Abu Dzar] bahwa ia berkata, \"Shalat seorang laki-laki bisa terputus (batal) oleh keledai, anjing hitam dan wanita jika antara dirinya dengan arah depannya tidak ada (pembatas) seperti bagian belakang pelana.\" Abdullah berkata, \"Aku bertanya, \"Apa bedanya antara hitam dan merah serta kuning?\" Abu Dzar menjawab, \"Aku pernah bertanya kepada Rasulullah shallallahu 'alaihi wasallam sebagaimana yang engkau tanyakan kepadaku, kemudian beliau menjawab: \"Anjing hitam adalah setan.\" "},"1026":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ قَالَ جِئْتُ أَنَا وَالْفَضْلُ يَعْنِي عَلَى أَتَانٍ وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي بِمِنًى أَوْ بِعَرَفَةَ فَمَرَرْتُ عَلَى بَعْضِ الصَّفِّ فَنَزَلْتُ عَنْهَا وَتَرَكْتُهَا تَرْعَى وَدَخَلْتُ فِي الصَّفِّ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Ibnu 'Uyainah] dari [Az Zuhri] dari ['Ubaidullah bin Abdullah] dari [Ibnu Abbas] ia berkata, \"Aku dan Al Fadll datang dengan mengendarai keledai, sementara Nabi shallallahu 'alaihi wasallam sedang melaksanakan shalat di Mina, atau Arafah. Aku lalu melintasi sebagian shaf, aku lalu turun dan membiarkan keledai itu merumput. Setelah itu aku masuk ke dalam shaf.\""},"1027":{"ar":" حَدَّثَنَا يَحْيَى بْنُ حَسَّانَ أَخْبَرَنَا ابْنُ عُيَيْنَةَ عَنْ سَالِمٍ أَبِي النَّضْرِ عَنْ بُسْرِ بْنِ سَعِيدٍ قَالَ أَرْسَلَنِي أَبُو جُهَيْمٍ الْأَنْصَارِيُّ إِلَى زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّ أَسْأَلُهُ مَا سَمِعَ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الَّذِي يَمُرُّ بَيْنَ يَدَيْ الْمُصَلِّي فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَأَنْ يَقُومَ أَحَدُكُمْ أَرْبَعِينَ خَيْرٌ لَهُ مِنْ أَنْ يَمُرَّ بَيْنَ يَدَيْ الْمُصَلِّي قَالَ فَلَا أَدْرِي سَنَةً أَوْ شَهْرًا أَوْ يَوْمًا","id":"Telah menceritakan kepada kami [Yahya bin Hassan] telah mengabarkan kepada kami [Ibnu 'Uyainah] dari [Salim Abu An Nadlr] dari [Busr bin Sa'id] ia berkata; Abu Juhaim Al Anshari mengutusku datang kepada [Zaid bin Khalid Al Juhani] untuk bertanya kepadanya apa yang pernah ia dengar dari Nabi shallallahu 'alaihi wasallam, tentang setatus orang yang lewat di hadapan orang yang melakukan shalat. Kemudian ia menjawab, \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh, salah seorang di antara kalian berdiri selama empat puluh, adalah lebih baik baginya daripada lewat di hadapan orang yang sedang melakukan shalat.\" Zaid bin Khalid Al Juhani berkata, \"Aku tidak tahu apakah tahun, atau bulan, atau hari.\""},"1028":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ الْمَجِيدِ حَدَّثَنَا مَالِكٌ عَنْ أَبِي النَّضْرِ مَوْلَى عُمَرَ بْنِ عُبَيْدِ اللَّهِ بْنِ مَعْمَرٍ أَنَّ بُسْرَ بْنَ سَعِيدٍ أَخْبَرَهُ أَنَّ زَيْدَ بْنَ خَالِدٍ الْجُهَنِيَّ أَرْسَلَهُ إِلَى أَبِي جُهَيْمٍ يَسْأَلُهُ مَاذَا سَمِعَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِي الْمَارِّ بَيْنَ يَدَيْ الْمُصَلِّي فَقَالَ أَبُو جُهَيْمٍ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ يَعْلَمُ الْمَارُّ بَيْنَ يَدَيْ الْمُصَلِّي مَاذَا عَلَيْهِ فِي ذَلِكَ لَكَانَ أَنْ يَقِفَ أَرْبَعِينَ خَيْرًا لَهُ مِنْ أَنْ يَمُرَّ بَيْنَ يَدَيْهِ قَالَ أَبُو النَّضْرِ لَا أَدْرِي أَرْبَعِينَ يَوْمًا أَوْ شَهْرًا أَوْ سَنَةً","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Abdul Majid] telah menceritakan kepada kami [Malik] dari [Abu An Nadlr] mantan budak Umar bin 'Ubaidullah bin Ma'mar, bahwa [Busr bin Sa'id] mengabarkan kepadanya, bahwa Zaid bin Khalid Al Juhani telah mengutusnya menemui Abu Juhaim untuk bertanya kepadanya apa yang ia dengar dari Rasulullah shallallahu 'alaihi wasallam mengenai orang yang lewat di hadapan orang yang sedang shalat? Kemudian [Abu Juhaim] menjawab, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila orang yang lewat (di hadapan orang yang sedang shalat) mengetahui dosa apa yang akan ditimpakan kepadanya karenanya, niscaya ia berdiri selama empat puluh adalah lebih baik baginya daripada lewat di hadapannya.\" Abu An Nadlr berkata, \"Aku tidak tahu apakah itu empat puluh hari, atau bulan, atau tahun.\" "},"1029":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ الْمَجِيدِ حَدَّثَنَا أَفْلَحُ هُوَ ابْنُ حُمَيْدٍ حَدَّثَنِي أَبُو بَكْرِ بْنُ مُحَمَّدٍ حَدَّثَنِي سَلْمَانُ الْأَغَرُّ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةٌ فِي مَسْجِدِي هَذَا كَأَلْفِ صَلَاةٍ فِيمَا سِوَاهُ مِنْ الْمَسَاجِدِ إِلَّا الْمَسْجِدَ الْحَرَامَ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Abdul Majid] telah menceritakan kepada kami [Aflah] -yaitu Ibnu Humaid- telah menceritakan kepadaku [Abu Bakr bin Muhammad] telah menceritakan kepadaku [Salman Al Aghar] ia berkata, saya mendengar [Abu Hurairah] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Shalat di masjidku ini seperti seribu shalat di masjid-masjid yang lain, kecuali Masjid Al Haram.\" "},"1030":{"ar":" أَخْبَرَنَا مُسَدَّدٌ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةٌ فِي مَسْجِدِي هَذَا أَفْضَلُ مِنْ أَلْفِ صَلَاةٍ فِيمَا سِوَاهُ إِلَّا الْمَسْجِدَ الْحَرَامَ","id":"Telah mengabarkan kepada kami [Musaddad] telah menceritakan kepada kami [Bisyr bin Al Mufadldlal] telah menceritakan kepada kami ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Shalat di masjidku ini lebih baik dari shalat seribu kali di tempat yang lain, kecuali Masjid Al Haram.\""},"1031":{"ar":" حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ صَلَاةٌ فِي مَسْجِدِي هَذَا أَفْضَلُ مِنْ أَلْفِ صَلَاةٍ فِيمَا سِوَاهُ إِلَّا الْمَسْجِدَ الْحَرَامَ","id":"Telah menceritakan kepada kami [Hajjaj bin Minhal] Telah menceritakan kepada kami [Ibnu 'Uyainah] dari [Az Zuhri] dari [Sa'id? bin Al Musayyab] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Shalat di masjidku ini lebih baik dari shalat seribu kali di tempat yang lain, kecuali Masjid Al Haram.\""},"1032":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُشَدُّ الرِّحَالُ إِلَّا إِلَى ثَلَاثَةِ مَسَاجِدَ الْكَعْبَةِ وَمَسْجِدِي هَذَا وَمَسْجِدِ الْأَقْصَى","id":"Telah mengabarkan kepada kami [Yazid bin Harun] Telah menceritakan kepada kami [Muhammad bin 'Amru] dari [Abu Salamah] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak boleh diniatkan bepergian untuk beribadah kecuali ke tiga masjid; Ka'bah, masjidku ini, dan Masjid Al Aqsha.\""},"1033":{"ar":" حَدَّثَنَا زَكَرِيَّا بْنُ عَدِيٍّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَمْرٍو عَنْ زَيْدِ بْنِ أَبِي أُنَيْسَةَ عَنْ جُنَادَةَ عَنْ مَكْحُولٍ عَنْ أَبِي إِدْرِيسَ عَنْ أَبِي الدَّرْدَاءِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ مَشَى فِي ظُلْمَةِ لَيْلٍ إِلَى صَلَاةٍ آتَاهُ اللَّهُ نُورًا يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Zakaria bin Adi] dari ['Ubaidullah bin 'Amru] dari [Zaid bin Abu Unaisah] dari [Junadah] dari [Makhul] dari [Abu Idris] dari [Abu Ad Darda`] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa berjalan dalam kegelapan malam untuk melaksanakan shalat, maka Allah akan memberikan kepadanya cahaya pada Hari Kiamat.\""},"1034":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنِي اللَّيْثُ حَدَّثَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ سَمِعْتُ أَبَا الْأَحْوَصِ يُحَدِّثُ عَنْ ابْنِ الْمُسَيَّبِ أَنَّ أَبَا ذَرٍّ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَزَالُ اللَّهُ مُقْبِلًا عَلَى الْعَبْدِ مَا لَمْ يَلْتَفِتْ فَإِذَا صَرَفَ وَجْهَهُ انْصَرَفَ عَنْهُ","id":"Telah menceritakan kepada kami [Abdullah bin Shalih] telah menceritakan kepadaku [Al Laits] telah menceritakan kepadaku [Yunus] dari [Ibnu Syihab] ia berkata, saya mendengar [Abu Al Ahwash] menceritakan dari [Ibnu Al Musayyab] bahwa [Abu Dzar] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah senantiasa menghadap ke arah seorang hamba selama ia tidak menoleh, apabila ia memalingkan wajahnya maka Allah berpaling darinya.\" "},"1035":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا حَجَّاجُ بْنُ مُحَمَّدٍ قَالَ قَالَ ابْنُ جُرَيْجٍ أَخْبَرَنِي عُثْمَانُ بْنُ أَبِي سُلَيْمَانَ عَنْ عَلِيٍّ الْأَزْدِيِّ عَنْ عُبَيْدِ بْنِ عُمَيْرٍ اللَّيْثِيِّ عَنْ عَبْدِ اللَّهِ بْنِ حُبْشِيٍّ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ أَيُّ الْأَعْمَالِ أَفْضَلُ قَالَ إِيمَانٌ لَا شَكَّ فِيهِ وَجِهَادٌ لَا غُلُولَ فِيهِ وَحَجَّةٌ مَبْرُورَةٌ قِيلَ فَأَيُّ الصَّلَاةِ أَفْضَلُ قَالَ طُولُ الْقِيَامِ قِيلَ فَأَيُّ الصَّدَقَةِ أَفْضَلُ قَالَ جُهْدُ مُقِلٍّ قِيلَ فَأَيُّ الْهِجْرَةِ أَفْضَلُ قَالَ أَنْ تَهْجُرَ مَا حَرَّمَ اللَّهُ عَلَيْكَ قِيلَ فَأَيُّ الْجِهَادِ أَفْضَلُ قَالَ مَنْ جَاهَدَ الْمُشْرِكِينَ بِمَالِهِ وَنَفْسِهِ قِيلَ فَأَيُّ الْقَتْلِ أَشْرَفُ قَالَ مَنْ عُقِرَ جَوَادُهُ وَأُهْرِيقَ دَمُهُ","id":"Telah mengabarkan kepada kami [Ahmad bin Abdullah] telah menceritakan kepada kami [Hajjaj bin Muhammad] ia berkata, [Ibnu Juraij] berkata, telah mengabarkan kepadaku [Utsman bin Abu Sulaiman] dari [Ali Al Azdi] dari ['Ubaid bin 'Umair Al Laitsi] dari [Abdullah bin Hubsyi], bahwa Nabi shallallahu 'alaihi wasallam ditanya, \"Amalan apakah yang paling utama?\" Beliau menjawab: \"Keimanan yang tidak ada keraguan padanya, jihad yang tidak ada kecurangan padanya, dan haji yang mabrur.\" Beliau ditanya lagi, \"Shalat apakah yang paling utama?\" Beliau menjawab: \"Shalat yang lama.\" Beliau ditanya lagi, \"Sedekah apakah yang paling utama?\" Beliau menjawab: \"Membantu orang miskin.\" Beliau ditanya lagi, \"Hijrah apakah yang paling utama?\" Beliau menjawab: \"Engkau meninggalkan apa yang Allah haramkan kepadamu.\" Beliau ditanya lagi, \"Jihad apakah yang paling utama?\" Beliau menjawab: \"Orang yang memerangi orang-orang musyrik dengan harta dan jiwanya.\" Beliau ditanya lagi, \"Kematian apakah yang paling mulia?\" Beliau menjawab: \"Orang yang kudanya disembelih dan darahnya ditumpahkan (mati syahiud).\""},"1036":{"ar":" حَدَّثَنَا عَفَّانُ أَخْبَرَنَا هَمَّامٌ عَنْ أَبِي جَمْرَةَ عَنْ أَبِي بَكْرِ بْنِ أَبِي مُوسَى عَنْ أَبِيهِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَلَّى الْبَرْدَيْنِ دَخَلَ الْجَنَّةَ قِيلَ لِأَبِي مُحَمَّدٍ مَا الْبَرْدَيْنِ قَالَ الْغَدَاةُ وَالْعَصْرُ","id":"Telah menceritakan kepada kami ['Affan] telah mengabarkan kepada kami [Hammam] dari [Abu Jamrah] dari [Abu Bakr bin Abu Musa] dari [Ayahnya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa melakukan shalat bardain maka ia masuk Surga.\" Abu Muhammad ditanya, \"Apakah shalat bardain itu? Ia menjawab, \"Subuh dan asar.\" "},"1037":{"ar":" أَخْبَرَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ عَنْ إِبْرَاهِيمَ بْنِ أَبِي أُسَيْدٍ عَنْ جَدِّهِ عَنْ أَبِي هُرَيْرَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ صَلَّى الصُّبْحَ فَهُوَ فِي جِوَارِ اللَّهِ فَلَا تُخْفِرُوا اللَّهَ فِي جَارِهِ وَمَنْ صَلَّى الْعَصْرَ فَهُوَ فِي جِوَارِ اللَّهِ فَلَا تُخْفِرُوا اللَّهَ فِي جَارِهِ قَالَ أَبُو مُحَمَّد إِذَا أُمِّنَ وَلَمْ يَفِ فَقَدْ غَدَرَ وَأَخْفَرَ","id":"Telah mengabarkan kepada kami [Yahya bin Hassan] telah menceritakan kepada kami [Sulaiman bin Bilal] dari [Ibrahim bin Abu Usaid] dari [Kakeknya] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam berkata: \"Barangsiapa melakukan shalat subuh maka ia berada di samping Allah, maka janganlah kalian mencabut janji Allah pada orang yang ada di samping-Nya. Dan barangsiapa melakukan shalat asar maka ia berada di samping Allah, maka janganlah kalian mencabut janji Allah pada orang yang ada di samping-Nya.\" Abu Muhammad berkata, \"Apabila diberi keamanan kemudian tidak menepati janji maka sungguh ia telah mengingkari dan menjabut janji.\""},"1038":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ كُنَاسَةَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ الْأَرْقَمِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا حَضَرَتْ الصَّلَاةُ وَأَرَادَ الرَّجُلُ الْخَلَاءَ فَابْدَأْ بِالْخَلَاءِ","id":"Telah menceritakan kepada kami [Muhammad bin Kunasah] dari [Hisyam bin 'Urwah] dari [Bapaknya] dari [Abdullah bin Al Arqam] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika waktu shalat telah tiba lalu ada yang ingin membuang hajat, maka hendaklah ia dahulukan untuk buang hajat.\" "},"1039":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو خَالِدٍ عَنْ هِشَامٍ عَنْ ابْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ قَالَ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُصَلِّيَ الرَّجُلُ مُخْتَصِرًا","id":"Telah menceritakan kepada kami [Abdullah bin Sa'id] telah menceritakan kepada kami [Abu Khalid] dari [Hisyam] dari [Ibnu Sirin] dan [Abu Hurairah] Ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang seorang laki-laki shalat sambil menahan keinginan untuk buang hajat.\""},"1040":{"ar":" أَخْبَرَنَا حَفْصُ بْنُ عُمَرَ الْحَوْضِيُّ حَدَّثَنَا شُعْبَةُ عَنْ سَيَّارٍ أَبِي الْمِنْهَالِ الرِّيَاحِيِّ عَنْ أَبِي بَرْزَةَ قَالَ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَكْرَهُ النَّوْمَ قَبْلَ الْعِشَاءِ وَالْحَدِيثَ بَعْدَهَا","id":"Telah mengabarkan kepada kami [Hafsh bin Umar Al Haudli] telah menceritakan kepada kami [Syu'bah] dari [Sayyar Abu Al Minhal Ar Riyahi] dari [Abu Barzah] ia berkata, \"Nabi shallallahu 'alaihi wasallam membenci tidur sebelum shalat isya dan berbicara setelahnya.\""},"1041":{"ar":" أَخْبَرَنَا بِشْرُ بْنُ ثَابِتٍ الْبَزَّارُ حَدَّثَنَا شُعْبَةُ عَنْ الْمُغِيرَةِ عَنْ الشَّعْبِيِّ عَنْ الْمُحَرَّرِ بْنِ أَبِي هُرَيْرَةَ عَنْ أَبِيهِ قَالَ كُنْتُ مَعَ عَلِيِّ بْنِ أَبِي طَالِبٍ لَمَّا بَعَثَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَادَى بِأَرْبَعٍ حَتَّى صَهَلَ صَوْتُهُ أَلَا إِنَّهُ لَا يَدْخُلُ الْجَنَّةَ إِلَّا نَفْسٌ مُؤْمِنَةٌ وَلَا يَحُجَّنَّ بَعْدَ الْعَامِ مُشْرِكٌ وَلَا يَطُوفُ بِالْبَيْتِ عُرْيَانٌ وَمَنْ كَانَ بَيْنَهُ وَبَيْنَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَهْدٌ فَإِنَّ أَجَلَهُ إِلَى أَرْبَعَةِ أَشْهُرٍ فَإِذَا مَضَتْ الْأَرْبَعَةُ فَإِنَّ اللَّهَ بَرِيءٌ مِنْ الْمُشْرِكِينَ وَرَسُولُهُ","id":"Telah mengabarkan kepada kami [Bisyr bin Tsabit Al Bazzar] telah menceritakan kepada kami [Syu'bah] dari [Al Mughirah] dari [Asy Sya'bi] dari [Al Muharrir bin Abu Hurairah] dari [Ayahnya] ia berkata, \"Aku bersama [Ali bin Abu Thalib] saat Rasulullah shallallahu 'alaihi wasallam mengutusnya untuk menyerukan empat hal sehingga suaranya serak, yaitu, \"Ketahuilah, tidak akan masuk surga kecuali jiwa mukmin, setelah tahun ini orang musyrik tidak boleh menunaikan ibadah haji, orang yang telanjang tidak boleh melakukan tawaf di Ka'bah, dan barangsiapa memiliki perjanjian antara dirinya dan Rasulullah shallallahu 'alaihi wasallam, maka temponya adalah empat bulan. Jika telah berlalu empat bulan, maka sesungguhnya Allah dan rasulNya berlepas diri dari orang-orang musyrik.\" "},"1042":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الزُّبَيْرِ الْحُمَيْدِيُّ حَدَّثَنَا حَرْمَلَةُ بْنُ عَبْدِ الْعَزِيزِ بْنِ الرَّبِيعِ بْنِ سَبْرَةَ بْنِ مَعْبَدٍ الْجُهَنِيُّ حَدَّثَنِي عَمِّي عَبْدُ الْمَلِكِ بْنُ الرَّبِيعِ بْنِ سَبْرَةَ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلِّمُوا الصَّبِيَّ الصَّلَاةَ ابْنَ سَبْعِ سِنِينَ وَاضْرِبُوهُ عَلَيْهَا ابْنَ عَشْرٍ","id":"Telah mengabarkan kepada kami [Abdullah bin Az Zubair Al Humaidi] telah menceritakan kepada kami [Harmalah bin Abdul Aziz bin Ar Rabi' bin Sabrah bin Ma'bad Al Juhani] telah menceritakan kepadaku pamanku [Abdul Malik bin Ar Rabi' bin Sabrah] dari [Ayahnya] dari [Kakeknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ajarkan anak kecil shalat saat berumur tujuh tahun, dan pukullah karena meninggalkannya saat berumur sepuluh tahun\""},"1043":{"ar":" أَخْبَرَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا مُوسَى بْنُ عَلِيٍّ قَالَ سَمِعْتُ أَبِي قَالَ سَمِعْتُ عُقْبَةَ بْنَ عَامِرٍ قَالَ ثَلَاثُ سَاعَاتٍ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْهَانَا أَنْ نُصَلِّيَ فِيهِنَّ أَوْ أَنْ نَقْبُرَ فِيهِنَّ مَوْتَانَا حِينَ تَطْلُعُ الشَّمْسُ بَازِغَةً حَتَّى تَرْتَفِعَ وَحِينَ يَقُومُ قَائِمُ الظَّهِيرَةِ حَتَّى تَمِيلَ الشَّمْسُ وَحِينَ تَضَيَّفُ الشَّمْسُ لِلْغُرُوبِ حَتَّى تَغْرُبَ","id":"Telah mengabarkan kepada kami [Wahb bin Jarir] telah menceritakan kepada kami [Musa bin Ali] ia berkata, saya mendengar [Ayahku] berkata, aku mendengar ['Uqbah bin 'Amir] berkata, \"Ada tiga waktu yang Rasulullah shallallahu 'alaihi wasallam melarang kami mengerjakan shalat, atau menguburkan jenazah di dalamnya; ketika matahari terbit hingga meninggi, saat seseorang berdiri dan matahari tepat di atas kepala hingga condong ke arah barat, dan ketika matahari cenderung untuk tenggelam hingga matahari tersebut tenggelam.\" "},"1044":{"ar":" أَخْبَرَنَا عَفَّانُ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ أَبِي الْعَالِيَةِ عَنْ ابْنِ عَبَّاسٍ قَالَ حَدَّثَنِي رِجَالٌ مَرْضِيُّونَ فِيهِمْ عُمَرُ بْنُ الْخَطَّابِ وَأَرْضَاهُمْ عِنْدِي عُمَرُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا صَلَاةَ بَعْدَ صَلَاةِ الصُّبْحِ حَتَّى تَطْلُعَ الشَّمْسُ وَلَا صَلَاةَ بَعْدَ صَلَاةِ الْعَصْرِ حَتَّى تَغْرُبَ الشَّمْسُ","id":"Telah mengabarkan kepada kami [Affan] telah menceritakan kepada kami [Hammam] dari [Qatadah] dari [Abu Al 'Aliyah] dari [Ibnu Abbas] berkata, telah menceritakan kepadaku orang-orang yang diridlai, yang di antarannya adalah [Umar bin Al Khathab] -dan di antara mereka yang paling diridlai menurutku adalah Umar-, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada shalat setelah shalat subuh hingga matahari terbit, dan tidak ada shalat setelah shalat asar hingga Telah memberitakan kepada kami Matahari tenggelam.\"."},"1045":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ الرَّبِيعِ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ قَالَ سَمِعْتُ الْأَسْوَدَ بْنَ يَزِيدَ وَمَسْرُوقًا يَشْهَدَانِ عَلَى عَائِشَةَ أَنَّهَا شَهِدَتْ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ لَمْ يَكُنْ عِنْدَهَا يَوْمًا إِلَّا صَلَّى هَاتَيْنِ الرَّكْعَتَيْنِ قَالَ أَبُو مُحَمَّد تَعْنِي بَعْدَ الْعَصْرِ","id":"Telah mengabarkan kepada kami [Sa'id? bin Ar Rabi'] telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] ia berkata, saya mendengar [Al Aswad bin Yazid] dan [Masruq] bersaksi atas [Aisyah], bahwa ia berkata; ersaksi atas Rasulullah shallallahu 'alaihi wasallam, bahwa tidak sehari pun Rasulullah berada di sisinya kecuali beliau selalu mengerjakan shalat dua rakaat ini.\" Abu Muhammad berkata, \"(Yaitu) dua rakaat setelah asar.\" "},"1046":{"ar":" أَخْبَرَنَا فَرْوَةُ بْنُ أَبِي الْمَغْرَاءِ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْ مَا تَرَكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَكْعَتَيْنِ بَعْدَ الْعَصْرِ قَطُّ","id":"Telah mengabarkan kepada kami [Farwah bin Abu Al Maghra`] telah menceritakan kepada kami [Ali bin Mushir] dari [Hisyam bin 'Urwah] dari [Ayahnya] dari [Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam tidak pernah meninggalkan dua rakaat setelah asar.\" "},"1047":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ عِيسَى حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ عَنْ بُكَيْرِ بْنِ الْأَشَجِّ عَنْ كُرَيْبٍ مَوْلَى ابْنِ عَبَّاسٍ أَنَّ عَبْدَ اللَّهِ بْنَ عَبَّاسٍ وَعَبْدَ الرَّحْمَنِ بْنَ أَزْهَرَ وَالْمِسْوَرَ بْنَ مَخْرَمَةَ أَرْسَلُوهُ إِلَى عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا اقْرَأْ عَلَيْهَا السَّلَامَ مِنَّا جَمِيعًا وَسَلْهَا عَنْ الرَّكْعَتَيْنِ بَعْدَ الْعَصْرِ وَقُلْ إِنَّا أُخْبِرْنَا أَنَّكِ تُصَلِّينَهُمَا وَقَدْ بَلَغَنَا أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْهُمَا قَالَ ابْنُ عَبَّاسٍ وَكُنْتُ أَضْرِبُ مَعَ عُمَرَ بْنِ الْخَطَّابِ النَّاسَ عَلَيْهِمَا قَالَ كُرَيْبٌ فَدَخَلْتُ عَلَيْهَا وَبَلَّغْتُهَا مَا أَرْسَلُونِي بِهِ فَقَالَتْ سَلْ أُمَّ سَلَمَةَ فَخَرَجْتُ إِلَيْهِمْ فَأَخْبَرْتُهُمْ بِقَوْلِهَا فَرَدُّونِي إِلَى أُمِّ سَلَمَةَ بِمِثْلِ مَا أَرْسَلُونِي إِلَى عَائِشَةَ فَقَالَتْ أُمُّ سَلَمَةَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْهَى عَنْهُمَا ثُمَّ رَأَيْتُهُ يُصَلِّيهِمَا أَمَّا حِينَ صَلَّاهُمَا فَإِنَّهُ صَلَّى الْعَصْرَ ثُمَّ دَخَلَ وَعِنْدِي نِسْوَةٌ مِنْ بَنِي حَرَامٍ مِنْ الْأَنْصَارِ فَصَلَّاهُمَا فَأَرْسَلْتُ إِلَيْهِ الْجَارِيَةَ فَقُلْتُ قُومِي بِجَنْبِهِ فَقُولِي أُمُّ سَلَمَةَ تَقُولُ يَا رَسُولَ اللَّهِ أَلَمْ أَسْمَعْكَ تَنْهَى عَنْ هَاتَيْنِ الرَّكْعَتَيْنِ وَأَرَاكَ تُصَلِّيهِمَا فَإِنْ أَشَارَ بِيَدِهِ فَاسْتَأْخِرِي عَنْهُ قَالَتْ فَفَعَلَتْ الْجَارِيَةُ فَأَشَارَ بِيَدِهِ فَاسْتَأْخَرَتْ عَنْهُ فَلَمَّا انْصَرَفَ قَالَ يَا ابْنَةَ أَبِي أُمَيَّةَ سَأَلْتِ عَنْ الرَّكْعَتَيْنِ بَعْدَ الْعَصْرِ إِنَّهُ أَتَانِي نَاسٌ مِنْ عَبْدِ الْقَيْسِ بِالْإِسْلَامِ مِنْ قَوْمِهِمْ فَشَغَلُونِي عَنْ الرَّكْعَتَيْنِ اللَّتَيْنِ بَعْدَ الظُّهْرِ فَهُمَا هَاتَانِ سُئِلَ أَبُو مُحَمَّد عَنْ هَذَا الْحَدِيثِ فَقَالَ أَنَا أَقُولُ بِحَدِيثِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا صَلَاةَ بَعْدَ الْعَصْرِ حَتَّى تَغْرُبَ الشَّمْسُ وَلَا بَعْدَ الْفَجْرِ حَتَّى تَطْلُعَ الشَّمْسُ","id":"Telah mengabarkan kepada kami [Ahmad bin Isa] telah menceritakan kepada kami [Abdullah bin Wahb] telah mengabarkan kepadaku ['Amru bin Al Harits] dari [Bukair bin Al Asyajj] dari [Kuraib] mantan budak Ibnu Abbas, bahwa Abdullah bin Abbas dan Abdurrahman bin Azhar dan Al Miswar bin Makhramah mengirimnya menemui Aisyah, isteri Nabi shallallahu 'alaihi wasallam. Mereka berkata, \"Sampaikan salam kami kepadanya dan tanyakan kepadanya mengenai dua rakaat setelah shalat asar, dan katakanlah, 'Sesungguhnya kami telah mendapatkan berita bahwa engkau melakukan kedua rakaat tersebut, sementara telah sampai kepada kami bahwa Nabi shallallahu 'alaihi wasallam melarang dari keduanya.' Ibnu Abbas berkata, \"Aku dan Umar bin Al Khathab pernah memukul orang-orang karena mengerjakan hal tersebut (shalat setelah asar).\" Kuraib berkata, \"Kemudian aku menemui Aisyah dan menyampaikan kepadanya apa yang dipesankan kepadaku. Kemudian Aisyah berkata, \"Tanyakanlah kepada Ummu Salamah! \" Kemudian aku keluar menemui orang-orang dan mengabarkan kepada mereka tentang jawaban Aisyah. Dan mereka pun menyuruhku untuk menemui Ummu Salamah sebagaimana mereka mengutusku menemui Aisyah. Kemudian [Ummu Salamah] berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam melarang dari keduanya, kemudian aku melihat beliau melakukan keduanya. Adapun ketika beliau melakukan keduanya, maka sesungguhnya beliau telah melakukan shalat asar, kemudian beliau masuk menemuiku sementara di sisiku ada beberapa orang wanita dari Bani Haram dari kaum Anshar, kemudian beliau melakukan shalat dua rakaat tersebut. Maka aku pun mengutus seorang budak wanita kepada beliau, dan aku katakan, \"Berdirilah di samping beliau dan katakan, 'Ummu Salamah bertanya, 'Wahai Rasulullah, bukankah saya telah mendengar anda melarang dari melakukan dua rakaat ini? Tetapi kenapa saya melihat melakukan keduanya? Kemudian apabila beliau memberikan isyarat dengan tangannya maka mundurlah darinya.\" Ummu Salamah berkata, \"Kemudian budak wanita itu pun melakukannya, beliau lalu berisyarat dengan tangannya, sehingga budak wanita itu pun mundur dari beliau. Ketika beliau selesai, beliau mengatakan: \"Wahai anak Abu Umayyah, engkau bertanya mengenai dua rakaat setelah asar, sesungguhnya beberapa orang dari Bani Abdul Qais datang kepadaku bersama kaumnya yang telah masuk Islam, sehingga mereka membuatku sibuk dari mengerjakan dua rakaat setelah zhuhur. Maka dua rakaat itu adalah apa yang aku kerjakan sekarang ini.\" Abu Muhammad ditanya mengenai hadits ini, kemudian ia menjawab, \"Aku berpendapat dengan hadits Umar, dari Nabi shallallahu 'alaihi wasallam: \"Tidak ada shalat setelah shalat asar hingga matahari tenggelam, dan tidak ada shalat setelah shalat subuh hingga matahari terbit.\""},"1048":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي قَبْلَ الظُّهْرِ رَكْعَتَيْنِ وَبَعْدَ الظُّهْرِ رَكْعَتَيْنِ وَبَعْدَ الْمَغْرِبِ رَكْعَتَيْنِ فِي بَيْتِهِ وَبَعْدَ الْعِشَاءِ رَكْعَتَيْنِ وَبَعْدَ الْجُمُعَةِ رَكْعَتَيْنِ فِي بَيْتِهِ","id":"Telah mengabarkan kepada kami [Abu 'Ashim] dari [Malik] dari [Nafi'] dari [Ibnu Umar], bahwa Nabi shallallahu 'alaihi wasallam melakukan shalat dua rakaat sebelum dan sesudah shalat zhuhur, setelah maghrib dua rakaat di rumahnya, setelah isya` dua rakaat dan setelah Jum'at dua rakaat di rumahnya.\""},"1049":{"ar":" حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا شُعْبَةُ عَنْ النُّعْمَانِ بْنِ سَالِمٍ قَالَ سَمِعْتُ عَمْرَو بْنَ أَوْسٍ الثَّقَفِيَّ يُحَدِّثُ عَنْ عَنْبَسَةَ بْنِ أَبِي سُفْيَانَ عَنْ أُمِّ حَبِيبَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهَا سَمِعَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا مِنْ عَبْدٍ مُسْلِمٍ يُصَلِّي كُلَّ يَوْمٍ ثِنْتَيْ عَشْرَةَ رَكْعَةً تَطَوُّعًا غَيْرَ الْفَرِيضَةِ إِلَّا لَهُ بَيْتٌ فِي الْجَنَّةِ أَوْ بُنِيَ لَهُ بَيْتٌ فِي الْجَنَّةِ قَالَتْ أُمُّ حَبِيبَةَ مَا بَرِحْتُ أُصَلِّيهِنَّ بَعْدُ وَقَالَ عَمْرٌو مِثْلَهُ وَقَالَ النُّعْمَانُ مِثْلَهُ","id":"Telah menceritakan kepada kami [Hasyim bin Al Qasim] telah menceritakan kepada kami [Syu'bah] dari [An Nu'man bin Salim] ia berkata, saya mendengar ['Amru bin Aus Ats Tsaqafi] menceritakan dari ['Anbasah bin Abu Sufyan] dari [Ummu Habibah] isteri Nabi shallallahu 'alaihi wasallam, bahwa ia mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang Muslim melakukan shalat setiap hari dua belas rakaat sunnah bukan wajib, kecuali baginya rumah di surga, atau dibangunkan baginya sebuah rumah di surga.\" Ummu Habibah berkata, \"Setelah itu aku tidak pernah meninggalkannya.\" 'Amru menyebutkan seperti itu, dan An Nu'man juga menyebutkan yang seperti itu.\" "},"1050":{"ar":" أَخْبَرَنَا عُثْمَانُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ إِبْرَاهِيمَ بْنِ مُحَمَّدِ بْنِ الْمُنْتَشِرِ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَدَعُ أَرْبَعًا قَبْلَ الظُّهْرِ وَرَكْعَتَيْنِ قَبْلَ الْفَجْرِ","id":"Telah mengabarkan kepada kami [Utsman bin Umar] telah menceritakan kepada kami [Syu'bah] dari [Ibrahim bin Muhammad bin Al Muntasyir] dari [Ayahnya] dari [Aisyah radliallahu 'anha] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam tidak meninggalkan shalat empat rakaat sebelum zhuhur dan dua rakaat sebelum Subuh.\""},"1051":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا الْجُرَيْرِيُّ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ كُلِّ أَذَانَيْنِ صَلَاةٌ بَيْنَ كُلِّ أَذَانَيْنِ صَلَاةٌ بَيْنَ كُلِّ أَذَانَيْنِ صَلَاةٌ لِمَنْ شَاءَ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Al Jurairi] dari [Abdullah bin Buraidah] dari [Abdullah bin Mughaffal] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Antara dua adzan terdapat shalat, antara dua adzan terdapat shalat, antara dua adzan terdapat shalat bagi orang yang menghendaki.\""},"1052":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ الرَّبِيعِ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ عَامِرٍ قَالَ سَمِعْتُ أَنَسًا قَالَ كَانَ الْمُؤَذِّنُ يُؤَذِّنُ لِصَلَاةِ الْمَغْرِبِ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَقُومُ لُبَابُ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَبْتَدِرُونَ السَّوَارِيَ حَتَّى يَخْرُجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُمْ كَذَلِكَ قَالَ وَقَلَّ مَا كَانَ يَلْبَثُ","id":"Telah mengabarkan kepada kami [Sa'id? bin Ar Rabi'] telah menceritakan kepada kami [Syu'bah] dari ['Amru bin 'Amir] ia berkata, saya mendengar [Anas] berkata, \"Pada masa Rasulullah shallallahu 'alaihi wasallam seorang muadzin mengumandangkan adzan, lalu para sahabat Rasulullah shallallahu 'alaihi wasallam bersegera menuju tiang-tiang masjid, hingga Rasulullah shallallahu 'alaihi wasallam keluar, sementara mereka dalam keadaan demikian.\" 'Amru berkata, \"Tidak lama kemudian beliau melakukan shalat Maghrib.\" "},"1053":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ هِشَامٍ عَنْ مُحَمَّدٍ عَنْ عَائِشَةَ قَالَتْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُخْفِي مَا يَقْرَأُ فِيهِمَا وَذَكَرَتْ قُلْ يَا أَيُّهَا الْكَافِرُونَ وَقُلْ هُوَ اللَّهُ أَحَدٌ قَالَ سَعِيدٌ فِي رَكْعَتَيْ الْفَجْرِ","id":"Telah mengabarkan kepada kami [Sa'id? bin 'Amir] dari [Hisyam] dari [Muhammad] dari [Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam tidak mengeraskan apa yang beliau baca pada keduanya. Dan Aisyah menyebutkan; QUL YAA AYYUHAL KAAFIRUUN dan QUL HUWALLAAHU AHAD.\" Sa'id berkata, \"Yakni dalam shalat dua rakaat fajar.\" "},"1054":{"ar":" حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ حَدَّثَنِي نَافِعٌ عَنْ ابْنِ عُمَرَ حَدَّثَتْنِي حَفْصَةُ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي سَجْدَتَيْنِ خَفِيفَتَيْنِ بَعْدَ مَا يَطْلُعُ الْفَجْرُ وَكَانَتْ سَاعَةً لَا أَدْخُلُ فِيهَا عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Ubaidullah] telah menceritakan kepadaku [Nafi'] dari [Ibnu Umar] telah menceritakan kepadaku [Hafshah], bahwa Nabi shallallahu 'alaihi wasallam melakukan shalat dua rakaat ringan setelah terbit fajar. Dan itu adalah waktu yang aku tidak menemui Nabi shallallahu 'alaihi wasallam.\" "},"1055":{"ar":" حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ حَفْصَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا سَكَتَ الْمُؤَذِّنُ مِنْ أَذَانِ الصُّبْحِ وَبَدَا الصُّبْحُ صَلَّى رَكْعَتَيْنِ خَفِيفَتَيْنِ قَبْلَ أَنْ تُقَامَ الصَّلَاةُ","id":"Telah menceritakan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Malik] dari [Nafi'] dari [Ibnu Umar] dari [Hafshah] isteri Nabi shallallahu 'alaihi wasallam, ia berkata, \"Apabila Muadzin selesai dari mengumandangkan adzan dan waktu subuh telah nampak, maka Rasulullah shallallahu 'alaihi wasallam shalat dua rakaat yang ringan sebelum melaksanakan shalat subuh.\" "},"1056":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ أَحْمَدَ بْنِ أَبِي خَلَفٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَمْرٍو عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي بَعْدَ الْجُمُعَةِ رَكْعَتَيْنِ وَأَخْبَرَتْهُ حَفْصَةُ أَنَّهُ كَانَ يُصَلِّي إِذَا أَضَاءَ الصُّبْحُ رَكْعَتَيْنِ","id":"Telah mengabarkan kepada kami [Muhammad bin Ahmad bin Abu Khalaf] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari ['Amr] dari [Az Zuhri] dari [Salim] dari [Ayahnya], bahwa Nabi shallallahu 'alaihi wasallam melakukan shalat setelah Jum'at dua rakaat, dan Hafshah memberitahukan kepadanya bahwa beliau juga melaksanakan shalat dua rakaat jika waktu subuh pagi telah nampak.\" "},"1057":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ مَالِكِ بْنِ أَنَسٍ عَنْ سَالِمٍ أَبِي النَّضْرِ عَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَ قَالَتْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا صَلَّى الرَّكْعَتَيْنِ قَبْلَ الْفَجْرِ فَإِنْ كَانَتْ لَهُ حَاجَةٌ كَلَّمَنِي بِهَا وَإِلَّا خَرَجَ إِلَى الصَّلَاةِ","id":"Telah menceritakan kepada kami [Abdullah bin Sa'id] telah menceritakan kepada kami [Abdullah bin Idris] dari [Malik bin Anas] dari [Salim Abu An Nadlr] dari [Abu Salamah] dari [Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam jika telah selesai mengerjakan shalat dua rakaat sebelum Fajar; bila beliau mempunyai hajat mengatakannya kepadaku, jika tidak maka beliau langsung keluar untuk shalat subuh.\" "},"1058":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي مَا بَيْنَ الْعِشَاءِ إِلَى الْفَجْرِ إِحْدَى عَشْرَةَ رَكْعَةً يُسَلِّمُ فِي كُلِّ رَكْعَتَيْنِ يُوتِرُ بِوَاحِدَةٍ فَإِذَا سَكَتَ الْمُؤَذِّنُ مِنْ الْأَذَانِ الْأَوَّلِ رَكَعَ رَكْعَتَيْنِ خَفِيفَتَيْنِ ثُمَّ اضْطَجَعَ حَتَّى يَأْتِيَهُ الْمُؤَذِّنُ فَيَخْرُجُ مَعَهُ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] dari [Ibnu Abu Dzi`b] dari [Az Zuhri] dari ['Urwah] dari [Aisyah] ia berkata, \"Nabi shallallahu 'alaihi wasallam melakukan shalat antara Isya` hingga fajar sebanyak sebelas rakaat, mengucapkan salam setiap dua rakaat dan witir dengan satu rakaat. Kemudian apabila muadzin telah selesai dari adzan pertama, maka beliau melakukan shalat dua rakaat ringan. Kemudian beliau berbaring hingga datang muadzin dan keluar bersamanya.\" "},"1059":{"ar":" حَدَّثَنَا أَبُو عَاصِمٍ عَنْ زَكَرِيَّا بْنِ إِسْحَقَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أُقِيمَتْ الصَّلَاةُ فَلَا صَلَاةَ إِلَّا الْمَكْتُوبَةُ أَخْبَرَنَا أَبُو حَفْصٍ عَمْرُو بْنُ عَلِيٍّ الْفَلَّاسُ حَدَّثَنَا غُنْدَرٌ عَنْ شُعْبَةَ عَنْ وَرْقَاءَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Abu 'Ashim] dari [Zakaria bin Ishaq] dari ['Amru bin Dinar] dari [Sulaiman bin Yasar] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila telah didirikan shalat maka tidak ada shalat kecuali shalat wajib.\" Telah mengabarkan kepada kami [Abu Hafsh 'Amru bin Ali Al Fallas] telah menceritakan kepada kami [Ghundar] dari [Syu'bah] dari [Warqa`] dari ['Amru bin Dinar] dari ['Atha` bin Yasar] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam seperti hadits itu.\" "},"1060":{"ar":" حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا شُعْبَةُ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ عَنْ حَفْصِ بْنِ عَاصِمِ بْنِ عُمَرَ عَنْ ابْنِ بُحَيْنَةَ قَالَ أُقِيمَتْ الصَّلَاةُ فَرَأَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلًا يُصَلِّي الرَّكْعَتَيْنِ فَلَمَّا قَضَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاتَهُ لَاثَ بِهِ النَّاسُ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتُصَلِّي الصُّبْحَ أَرْبَعًا","id":"Telah menceritakan kepada kami [Hasyim bin Al Qasim] telah menceritakan kepada kami [Syu'bah] dari [Sa'd bin Ibrahim] dari [Hafsh bin 'Ashim bin Umar] dari [Ibnu Buhainah] ia berkata, \"Ketika shalat telah didirikan Nabi shallallahu 'alaihi wasallam melihat seorang laki-laki melakukan shalat dua rakaat. Maka ketika Nabi shallallahu 'alaihi wasallam telah selesai dari mengerjakan shalat, orang-orang pun mengelilingi beliau. Lalu Nabi shallallahu 'alaihi wasallam berkata kepada orang tersebut: \"Apakah engkau mengerjakan shalat subuh empat rakaat?\""},"1061":{"ar":" حَدَّثَنَا مُسْلِمٌ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أُقِيمَتْ الصَّلَاةُ فَلَا صَلَاةَ إِلَّا الْمَكْتُوبَةُ قَالَ أَبُو مُحَمَّد إِذَا كَانَ فِي بَيْتِهِ فَالْبَيْتُ أَهْوَنُ","id":"Telah menceritakan kepada kami [Muslim] telah menceritakan kepada kami [Hammad bin Salamah] dari ['Amru bin Dinar] dari ['Atha` bin Yasar] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau berkata: \"Jika shalat telah didirikan maka tidak ada shalat kecuali shalat wajib.\" Abu Muhammad berkata, \"Apabila ia shalat di rumahnya, maka (shalat di) rumah adalah lebih ringan.\" "},"1062":{"ar":" أَخْبَرَنَا أَبُو النُّعْمَانِ حَدَّثَنَا مُعْتَمِرُ بْنُ سُلَيْمَانَ عَنْ بُرْدٍ حَدَّثَنِي سُلَيْمَانُ بْنُ مُوسَى عَنْ مَكْحُولٍ عَنْ كَثِيرِ بْنِ مُرَّةَ الْحَضْرَمِيِّ عَنْ قَيْسٍ الْجُذَامِيِّ عَنْ نُعَيْمِ بْنِ هَمَّارٍ الْغَطَفَانِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قَالَ اللَّهُ تَعَالَى ابْنَ آدَمَ صَلِّ لِي أَرْبَعَ رَكَعَاتٍ مِنْ أَوَّلِ النَّهَارِ أَكْفِكَ آخِرَهُ","id":"Telah mengabarkan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Mu'tamir bin Sulaiman] dari [Burd] telah menceritakan kepadaku [Sulaiman bin Musa] dari [Makhul] dari [Katsir bin Murrah Al Hadlrami] dari [Qais Al Judzami] dari [Nu'aim bin Hammar Al Ghathafani] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Allah Ta'ala berfirman: 'Wahai anak Adam, shalatlah untukku empat rakaat sejak awal siang, maka akan Aku cukupi kamu hingga sore hari.\" "},"1063":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا شُعْبَةُ قَالَ عَمْرُو بْنُ مُرَّةَ أَنْبَأَنِي قَالَ سَمِعْتُ ابْنَ أَبِي لَيْلَى يَقُولُ مَا أَخْبَرَنَا أَحَدٌ أَنَّهُ رَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي الضُّحَى غَيْرُ أُمِّ هَانِئٍ فَإِنَّهَا ذَكَرَتْ أَنَّهُ يَوْمَ فَتْحِ مَكَّةَ اغْتَسَلَ فِي بَيْتِهَا ثُمَّ صَلَّى ثَمَانَ رَكَعَاتٍ قَالَتْ وَلَمْ أَرَهُ صَلَّى صَلَاةً أَخَفَّ مِنْهَا غَيْرَ أَنَّهُ يُتِمُّ الرُّكُوعَ وَالسُّجُودَ","id":"Telah mengabarkan kepada kami [Abu Al Walid Ath Thayalisi] telah menceritakan kepada kami [Syu'bah] berkata, ['Amru bin Murrah] telah memberitakan kepadaku, ia berkata, \"Aku mendengar [Ibnu Abu Laila] berkata, \"Tidak ada seorangpun yang mengabarkan kepada kami bahwa ia pernah melihat Nabi shallallahu 'alaihi wasallam shalat dluha selain Ummu Hani`. Ia menyebutkan bahwa pada saat penaklukan Makkah Rasulullah mandi di rumahnya, setelah itu beliau shalat delapan rakaat. [Ummu Hani`] berkata, \"Aku belum pernah melihat beliau melaksanakan shalat yang lebih ringan darinya, hanya saja beliau menyempurnakan rukuk dan sujud.\" "},"1064":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ الْمَجِيدِ حَدَّثَنَا مَالِكٌ عَنْ أَبِي النَّضْرِ أَنَّ أَبَا مُرَّةَ مَوْلَى عَقِيلِ بْنِ أَبِي طَالِبٍ أَخْبَرَهُ أَنَّهُ سَمِعَ أُمَّ هَانِئٍ بِنْتَ أَبِي طَالِبٍ تُحَدِّثُ أَنَّهَا ذَهَبَتْ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَ الْفَتْحِ فَوَجَدَتْهُ يَغْتَسِلُ وَفَاطِمَةُ بِنْتُهُ تَسْتُرُهُ بِثَوْبٍ قَالَتْ فَسَلَّمْتُ عَلَيْهِ وَذَلِكَ ضُحًى فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ هَذِهِ فَقُلْتُ أَنَا أُمُّ هَانِئٍ قَالَتْ فَلَمَّا فَرَغَ مِنْ غُسْلِهِ قَامَ فَصَلَّى ثَمَانَ رَكَعَاتٍ مُلْتَحِفًا فِي ثَوْبٍ وَاحِدٍ ثُمَّ انْصَرَفَ فَقُلْتُ يَا رَسُولَ اللَّهِ زَعَمَ ابْنُ أُمِّي أَنَّهُ قَاتِلٌ رَجُلًا أَجَرْتُهُ فُلَانَ بْنَ هُبَيْرَةَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ أَجَرْنَا مَنْ أَجَرْتِ يَا أُمَّ هَانِئٍ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Abdul Majid] telah menceritakan kepada kami [Malik] dari [Abu An Nadlar] bahwa [Abu Murrah] mantan budak 'Uqail bin Abu Thalib mengabarkan kepadanya, bahwa ia mendengar [Ummu Hani` binti Abu Thalib] menceritakan kepadanya, bahwa ia pergi menemui Rasulullah shallallahu 'alaihi wasallam pada saat penaklukan Makkah. Kemudian ia mendapati beliau sedang mandi, sementara anaknya, Fatimah menutupinya dengan kain. Ummu Hani` berkata, \"Kemudian aku mengucapkan salam kepadanya, dan itu terjadi pada waktu dluha. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapakah ini?\" Aku lantas menjawab, \"Saya Ummu Hani`\". Ummu Hani` melanjutkan, \"Selesai mandi beliau berdiri dan mengerjakan shalat delapan rakaat dengan hanya mengenakan satu kain, lalu berlalu. Aku lantas berkata, \"Wahai Rasulullah! Anak laki-laki ibuku mengaku bahwa ia akan membunuh seseorang yang telah aku lindungi, yaitu Fulan bin Hubairah.\" Kemudian beliau berkata: \"Kami telah melindungi orang yang engkau lindungi wahai Ummu Hani`.\""},"1065":{"ar":" حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا شُعْبَةُ عَنْ عَبَّاسٍ الْجُرَيْرِيِّ عَنْ أَبِي عُثْمَانَ عَنْ أَبِي هُرَيْرَةَ قَالَ أَوْصَانِي خَلِيلِي بِثَلَاثٍ لَا أَدَعُهُنَّ حَتَّى أَمُوتَ الْوِتْرِ قَبْلَ أَنْ أَنَامَ وَصَوْمِ ثَلَاثَةِ أَيَّامٍ مِنْ كُلِّ شَهْرٍ وَمِنْ الضُّحَى رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Syu'bah] dari [Abbas Al Jurairi] dari [Abu Utsman] dari [Abu Hurairah] ia berkata, \"Kekasihku berwasiat kepadaku dengan tiga perkara agar tidak aku tinggalkan hingga aku meninggal; witir sebelum tidur, berpuasa tiga hari setiap bulan, dan melakukan shalat dluha dua rakaat.\""},"1066":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْ مَا صَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُبْحَةَ الضُّحَى فِي سَفَرٍ وَلَا حَضَرٍ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Al Auza'i] dari [Az Zuhri] dari ['Urwah] dari [Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam tidak melakukan shalat dluha pada saat bersafar dan bermukim.\" "},"1067":{"ar":" حَدَّثَنَا صَدَقَةُ بْنُ الْفَضْلِ حَدَّثَنَا مُعَاذُ بْنُ مُعَاذٍ حَدَّثَنَا شُعْبَةُ عَنْ الْفُضَيْلِ بْنِ فَضَالَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرَةَ أَنَّ أَبَاهُ رَأَى أُنَاسًا يُصَلُّونَ صَلَاةَ الضُّحَى فَقَالَ أَمَا إِنَّهُمْ لَيُصَلُّونَ صَلَاةً مَا صَلَّاهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا عَامَّةُ أَصْحَابِهِ","id":"Telah menceritakan kepada kami [Shadaqah bin Al Fadll] telah menceritakan kepada kami [Mu'adz bin Mu'adz] telah menceritakan kepada kami [Syu'bah] dari [Al Fudlail bin Fadlalah] dari [Abdurrahman bin Abu Bakrah], bahwa [ayahnya] melihat beberapa orang melakukan shalat dluha, kemudian ia berkata, \"Sesungguhnya mereka mengerjakan shalat yang tidak pernah dilakukan oleh Rasulullah shallallahu 'alaihi wasallam dan tidak pula para sahabatnya.\" "},"1068":{"ar":" أَخْبَرَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا هِشَامٌ الدَّسْتَوَائِيُّ عَنْ الْقَاسِمِ بْنِ عَوْفٍ عَنْ زَيْدِ بْنِ أَرْقَمَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ عَلَيْهِمْ وَهُمْ يُصَلُّونَ بَعْدَ طُلُوعِ الشَّمْسِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةُ الْأَوَّابِينَ إِذَا رَمِضَتْ الْفِصَالُ","id":"Telah mengabarkan kepada kami [Wahb bin Jarir] telah menceritakan kepada kami [Hisyam Ad Dastawa`i] dari [Al Qasim bin 'Auf] dari [Zaid bin Arqam], bahwa Rasulullah shallallahu 'alaihi wasallam keluar menemui mereka sementara mereka melakukan shalat setelah matahari terbit. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Shalat orang-orang yang taat adalah apabila matahari telah terang (panas).\""},"1069":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ وَغُنْدَرٌ عَنْ شُعْبَةَ عَنْ يَعْلَى بْنِ عَطَاءٍ عَنْ عَلِيٍّ الْأَزْدِيِّ عَنْ ابْنِ عُمَرَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةُ اللَّيْلِ وَالنَّهَارِ مَثْنَى مَثْنَى وَقَالَ أَحَدُهُمَا رَكْعَتَيْنِ رَكْعَتَيْنِ","id":"Telah mengabarkan kepada kami [Abdullah bin Muhammad bin Abu Syaibah] telah menceritakan kepada kami [Waki'] dan [Ghudar] dari [Syu'bah] dari [Ya'la bin 'Atho`] dari [Ali Al Azdi] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Shalat malam dan siang adalah dua dua.\" Salah seorang dari mereka menyebutkan, \"Dua rakaat, dua rakaat.\""},"1070":{"ar":" أَخْبَرَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَ سَأَلَ رَجُلٌ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ صَلَاةِ اللَّيْلِ فَقَالَ مَثْنَى مَثْنَى فَإِذَا خَشِيَ أَحَدُكُمْ الصُّبْحَ فَلْيُصَلِّ رَكْعَةً وَاحِدَةً تُوتِرُ مَا قَدْ صَلَّى","id":"Telah mengabarkan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Malik] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Seorang laki-laki bertanya kepada Rasulullah shallallahu 'alaihi wasallam mengenai shalat malam. Kemudian beliau bersabda: \"Dua, dua. Kemudian apabila salah seorang di antara kalian khawatir datangnya waktu subuh, maka hendaknya ia shalat satu rakaat sebagai witir dari shalat yang telah ia kerjakan.\""},"1071":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ عَوْفٍ عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ عَبْدِ اللَّهِ بْنِ سَلَامَ قَالَ لَمَّا قَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةَ اسْتَشْرَفَهُ النَّاسُ فَقَالُوا قَدِمَ رَسُولُ اللَّهِ قَدِمَ رَسُولُ اللَّهِ فَخَرَجْتُ فِيمَنْ خَرَجَ فَلَمَّا رَأَيْتُ وَجْهَهُ عَرَفْتُ أَنَّ وَجْهَهُ لَيْسَ بِوَجْهِ كَذَّابٍ فَكَانَ أَوَّلُ مَا سَمِعْتُهُ يَقُولُ يَا أَيُّهَا النَّاسُ أَفْشُوا السَّلَامَ وَأَطْعِمُوا الطَّعَامَ وَصِلُوا الْأَرْحَامَ وَصَلُّوا وَالنَّاسُ نِيَامٌ تَدْخُلُوا الْجَنَّةَ بِسَلَامٍ","id":"Telah mengabarkan kepada kami [Sa'id? bin 'Amir] dari ['Auf] dari [Zurarah bin Aufa] dari [Abdullah bin Salam] ia berkata, \"Tatkala Rasulullah shallallahu 'alaihi wasallam datang ke Madinah, orang-orang menyambut beliau dan berkata, \"Rasulullah telah datang, Rasulullah telah datang! Kemudian aku keluar di antara orang-orang yang keluar itu, maka ketika aku melihat wajahnya aku mengetahui bahwa wajahnya bukanlah wajah seorang pendusta. Dan pertama yang aku dengar beliau mengatakan: \"Wahai manusia, sebarkanlah salam, berilah makan, sambunglah hubungan kekerabatan dan shalatlah saat orang-orang sedang tidur maka kalian akan masuk surga dengan selamat.\" "},"1072":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ عَنْ الْأَوْزَاعِيِّ عَنْ هَارُونَ بْنِ رِئَابٍ عَنْ الْأَحْنَفِ بْنِ قَيْسٍ قَالَ دَخَلْتُ مَسْجِدَ دِمَشْقَ فَإِذَا رَجُلٌ يُكْثِرُ الرُّكُوعَ وَالسُّجُودَ قُلْتُ لَا أَخْرُجُ حَتَّى أَنْظُرَ أَعَلَى شَفْعٍ يَدْرِي هَذَا يَنْصَرِفُ أَمْ عَلَى وِتْرٍ فَلَمَّا فَرَغَ قُلْتُ يَا عَبْدَ اللَّهِ أَعَلَى شَفْعٍ تَدْرِي انْصَرَفْتَ أَمْ عَلَى وِتْرٍ فَقَالَ إِنْ لَا أَدْرِي فَإِنَّ اللَّهَ يَدْرِي ثُمَّ قَالَ إِنِّي سَمِعْتُ خَلِيلِي أَبَا الْقَاسِمِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا مِنْ عَبْدٍ يَسْجُدُ لِلَّهِ سَجْدَةً إِلَّا رَفَعَهُ اللَّهُ بِهَا دَرَجَةً وَحَطَّ عَنْهُ بِهَا خَطِيئَةً قُلْتُ مَنْ أَنْتَ رَحِمَكَ اللَّهُ قَالَ أَنَا أَبُو ذَرٍّ قَالَ فَتَقَاصَرَتْ إِلَيَّ نَفْسِي","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] dari [Al Auza'i] dari [Harun bin Riab] dari [Al Ahnaf bin Qais] ia berkata, \"Aku memasuki masjid Damaskus, dan ternyata terdapat seorang laki-laki yang memperbanyak rukuk dan sujud. Maka aku berkata, \"Aku tidak akan keluar hingga melihat apakah orang ini tahu saat ia menyelesaikan shalat dengan jumlah genap atau ganjil? Maka ketika selesai aku katakan, \"Wahai hamba Allah, apakah engkau tahu menyelesaikan shalat dengan jumlah genap atau ganjil? Ia lalu menjawab, \"Apabila aku tidak mengetahui maka sesungguhnya Allah mengetahui.\" Kemudian ia berkata lagi, \"Aku mendengar kekasihku Abu Al Qasim shallallahu 'alaihi wasallam berkata: \"Tidaklah seorang hamba sujud kepada Allah satu kali sujud melainkan Allah mengangkatnya dengan sujud tersebut satu derajat, dan menghapus darinya satu kesalahan.\" Aku lantas bertanya, \"Siapakah anda? Semoga Allah merahmati anda?\" Laki-laki itu menjawab, \" Aku adalah [Abu Dzar].\"?Al Ahnaf bin Qais berkata, \"Maka diriku menganggap kelalaian tersebut berasal dariku.\" "},"1073":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سَلَمَةُ بْنُ رَجَاءٍ حَدَّثَتْنَا شَعْثَاءُ قَالَتْ رَأَيْتُ ابْنَ أَبِي أَوْفَى صَلَّى رَكْعَتَيْنِ وَقَالَ صَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الضُّحَى رَكْعَتَيْنِ حِينَ بُشِّرَ بِالْفَتْحِ أَوْ بِرَأْسِ أَبِي جَهْلٍ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Salamah bin Raja`] telah menceritakan kepada kami [Sya'tsa`] ia berkata, \"Aku melihat [Ibnu Abu Aufa] melakukan shalat dua rakaat lalu berkata, \"Rasulullah shallallahu 'alaihi wasallam melakukan shalat dluha dua rakaat ketika diberi kabar mengenai kemenangan atau saat dibawanya kepala Abu Jahl.\" "},"1074":{"ar":" أَخْبَرَنَا عَمْرُو بْنُ عَوْنٍ حَدَّثَنَا إِسْحَقُ الْأَزْرَقُ عَنْ شَرِيكٍ عَنْ حُصَيْنٍ عَنْ الشَّعْبِيِّ عَنْ قَيْسِ بْنِ سَعْدٍ قَالَ أَتَيْتُ الْحِيرَةَ فَرَأَيْتُهُمْ يَسْجُدُونَ لِمَرْزُبَانَ لَهُمْ فَقُلْتُ يَا رَسُولَ اللَّهِ أَلَا نَسْجُدُ لَكَ فَقَالَ لَوْ أَمَرْتُ أَحَدًا لَأَمَرْتُ النِّسَاءَ أَنْ يَسْجُدْنَ لِأَزْوَاجِهِنَّ لِمَا جَعَلَ اللَّهُ عَلَيْهِنَّ مِنْ حَقِّهِمْ","id":"Telah mengabarkan kepada kami ['Amru bin 'Aun] telah menceritakan kepada kami [Ishaq Al Azraq] dari [Syarik] dari [Hushain] dari [Asy Sya'bi] dari [Qais bin Sa'd] ia berkata, \"Aku datang ke Al Hirah, kemudian aku melihat orang-orang sedang sujud kepada penunggang kuda mereka yang pemberani. Maka aku pun berkata, \"Wahai Rasulullah, tidakkah kami sujud kepadamu?\" Beliau menjawab: \"Seandainya aku boleh memerintahkan seseorang, niscaya aku perintahkan para wanita untuk sujud kepada suami-suami mereka karena hak yang Allah berikan atas mereka.\" "},"1075":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يَزِيدَ الْحِزَامِيُّ حَدَّثَنَا حِبَّانُ بْنُ عَلِيٍّ عَنْ صَالِحِ بْنِ حَيَّانَ عَنْ ابْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَ جَاءَ أَعْرَابِيٌّ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ ائْذَنْ لِي فَلِأَسْجُدَ لَكَ قَالَ لَوْ كُنْتُ آمِرًا أَحَدًا أَنْ يَسْجُدَ لِأَحَدٍ لَأَمَرْتُ الْمَرْأَةَ تَسْجُدُ لِزَوْجِهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Yazid Al Hizami] telah menceritakan kepada kami [Hibban bin Ali] dari [Shalih bin Hayyan] dari [Ibnu Buraidah] dari [Ayahnya] ia berkata, \"Seorang badui datang kepada Nabi shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, izinkan aku untuk sujud kepadamu! \" Beliau berkata: \"Seandainya aku diperbolehkan untuk memerintahkan seseorang sujud kepada orang lain, niscaya aku akan perintahkan seorang wanita untuk bersujud kepada suaminya.\" "},"1076":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ عَنْ الْأَسْوَدِ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَرَأَ النَّجْمَ فَسَجَدَ فِيهَا وَلَمْ يَبْقَ أَحَدٌ إِلَّا سَجَدَ إِلَّا شَيْخٌ أَخَذَ كَفًّا مِنْ حَصًى فَرَفَعَهُ إِلَى جَبْهَتِهِ وَقَالَ يَكْفِينِي هَذَا","id":"Telah mengabarkan kepada kami [Abu Al Walid Ath Thayalisi] telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] dari [Al Aswad] dari [Abdullah bin Mas'ud], bahwa Rasulullah shallallahu 'alaihi wasallam saat membaca surat An Najm beliau sujud, dan tidak ada seorangpun melainkan ia ikut sujud kecuali seorang laki-laki tua, ia mengambil satu genggam pasir kemudian menempelkannya pada kening seraya berkata, 'Ini cukup bagiku'.\""},"1077":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنِي اللَّيْثُ حَدَّثَنِي خَالِدٌ يَعْنِي ابْنَ يَزِيدَ عَنْ سَعِيدٍ يَعْنِي ابْنَ أَبِي هِلَالٍ عَنْ عِيَاضِ بْنِ عَبْدِ اللَّهِ بْنِ سَعْدٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ أَنَّهُ قَالَ خَطَبَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا فَقَرَأَ ص فَلَمَّا مَرَّ بِالسَّجْدَةِ نَزَلَ فَسَجَدَ وَسَجَدْنَا مَعَهُ وَقَرَأَهَا مَرَّةً أُخْرَى فَلَمَّا بَلَغَ السَّجْدَةَ تَيَسَّرْنَا لِلسُّجُودِ فَلَمَّا رَآنَا قَالَ إِنَّمَا هِيَ تَوْبَةُ نَبِيٍّ وَلَكِنِّي أَرَاكُمْ قَدْ اسْتَعْدَدْتُمْ لِلسُّجُودِ فَنَزَلَ فَسَجَدَ وَسَجَدْنَا","id":"Telah menceritakan kepada kami [Abdullah bin Shalih] telah menceritakan kepadaku [Al Laits] telah menceritakan kepadaku [Khalid] -yaitu Ibnu Yazid- dari [Sa'id] -yaitu Ibnu Abu Hilal- dari ['Iyadl bin Abdullah bin Sa'd] dari [Abu Sa'id Al Khudri], bahwa ia berkata, \"Pada suatu hari Rasulullah shallallahu 'alaihi wasallam berkhutbah kepada kami lalu beliau membaca Surat Shaad. Kemudian ketika sampai pada ayat sajdah beliau turun dan sujud, maka kami ikut sujud bersamanya. Beliau membacanya lagi, kemudian tatkala sampai ayat sajdah kami telah merasa siap untuk sujud. Maka ketika beliau melihat kami, beliau berkata: \"Sesungguhnya itu adalah taubat seorang nabi, akan tetapi aku melihat kalian telah bersiap untuk bersujud.\" Kemudian beliau turun, lalu sujud dan kami pun bersujud.\""},"1078":{"ar":" أَخْبَرَنَا عَمْرُو بْنُ زُرَارَةَ حَدَّثَنَا إِسْمَعِيلُ هُوَ ابْنُ عُلَيَّةَ حَدَّثَنَا أَيُّوبُ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ أَنَّهُ قَالَ فِي السُّجُودِ فِي ص لَيْسَتْ مِنْ عَزَائِمِ السُّجُودِ وَقَدْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَجَدَ فِيهَا","id":"Telah mengabarkan kepada kami ['Amru bin Zurarah] telah menceritakan kepada kami [Ismail] -yaitu Ibnu 'Ulaiyyah- telah menceritakan kepada kami [Ayyub] dari ['Ikrimah] dari [Ibnu Abbas], bahwa ia berkomentar tentang sujud pada surat Shaad, \"Surat tersebut bukanlah termasuk di antara kewajiban-kewajiban untuk sujud. Tetapi aku melihat Rasulullah shallallahu 'alaihi wasallam bersujud pada surat tersebut.\" "},"1079":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو عَنْ أَبِي سَلَمَةَ قَالَ رَأَيْتُ أَبَا هُرَيْرَةَ يَسْجُدُ فِي إِذَا السَّمَاءُ انْشَقَّتْ فَقِيلَ لَهُ تَسْجُدُ فِي سُورَةٍ مَا يُسْجَدُ فِيهَا فَقَالَ إِنِّي رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْجُدُ فِيهَا","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah menceritakan kepada kami [Muhammad bin 'Amru] dari [Abu Salamah] ia berkata, \"Aku melihat [Abu Hurairah] sujud pada IDZAS SAMAA`UN SYAQQAT (surat Al Insyiqaaq).\" Kemudian ia ditanya, \"Apakah anda sujud pada surat yang tidak ada sujud padanya?\" Abu Hurairah menjawab, \"Sesungguhnya aku melihat Rasulullah shallallahu 'alaihi wasallam sujud pada surat tersebut.\" "},"1080":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ قَالَ رَأَيْتُ أَبَا هُرَيْرَةَ يَسْجُدُ فِي إِذَا السَّمَاءُ انْشَقَّتْ فَقُلْتُ يَا أَبَا هُرَيْرَةَ أَرَاكَ تَسْجُدُ فِي إِذَا السَّمَاءُ انْشَقَّتْ فَقَالَ لَوْ لَمْ أَرَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَجَدَ فِيهَا لَمْ أَسْجُدْ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Al Auza'i] dari [Yahya] dari [Abu Salamah] ia berkata, \"Aku melihat [Abu Hurairah] sujud pada IDZAS SAMAA`UN SYAQQAT (surat Al Insyiqaaq). Maka aku pun bertanya, \"Wahai Abu Hurairah, aku lihat engkau sujud pada IDZAS SAMAA`UN SYAQQAT?\" Abu Hurairah lalu menjawab, \"Seandainya aku tidak melihat Rasulullah shallallahu 'alaihi wasallam sujud pada surat tersebut maka aku tidak akan sujud.\" "},"1081":{"ar":" أَخْبَرَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ أَبِي بَكْرِ بْنِ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ عَنْ عُمَرَ بْنِ عَبْدِ الْعَزِيزِ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ هِشَامٍ عَنْ أَبِي هُرَيْرَةَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَجَدَ فِي إِذَا السَّمَاءُ انْشَقَّتْ","id":"Telah mengabarkan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Sufyan] dari [Yahya bin Sa'id] dari [Abu Bakr bin Muhammad bin 'Amru bin Hazm] dari [Umar bin Abdul Aziz] dari [Abu Bakr bin Abdurrahman bin Al Harits bin Hisyam] dari [Abu Hurairah], bahwa Nabi shallallahu 'alaihi wasallam sujud pada IDZAS SAMAA`UN SYAQQAT (surat Al Insyiqaaq).\""},"1082":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ أَيُّوبَ بْنِ مُوسَى عَنْ عَطَاءِ بْنِ مِينَا عَنْ أَبِي هُرَيْرَةَ قَالَ سَجَدْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي إِذَا السَّمَاءُ انْشَقَّتْ وَاقْرَأْ بِاسْمِ رَبِّكَ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] Telah menceritakan kepada kami [Sufyan] dari [Ayyub bin Musa] dari [Atha` bin Mina] dari [Abu Hurairah] ia berkata, \"Kami sujud bersama Rasulullah shallallahu 'alaihi wasallam pada IDZAS SAMAA`UN SYAQQAT (surat Al Insyiqaaq) dan IQRA` BISMIRABBIKA (surat Al 'Alaq).\" "},"1083":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ قُسَيْطٍ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ زَيْدِ بْنِ ثَابِتٍ قَالَ قَرَأْتُ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النَّجْمَ فَلَمْ يَسْجُدْ فِيهَا","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Musa] dari [Ibnu Abu Dzi`b] dari [Yazid bin Abdullah bin Qusaith] dari ['Atha` bin Yasar] dari [Zaid bin Tsabit] ia berkata, \"Aku membaca surat An Najm di sisi Rasulullah shallallahu 'alaihi wasallam, dan beliau tidak sujud padanya.\" "},"1084":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي مَا بَيْنَ الْعِشَاءِ إِلَى الْفَجْرِ إِحْدَى عَشْرَةَ رَكْعَةً يُسَلِّمُ فِي كُلِّ رَكْعَتَيْنِ وَيُوتِرُ بِوَاحِدَةٍ وَيَسْجُدُ فِي سُبْحَتِهِ بِقَدْرِ مَا يَقْرَأُ أَحَدُكُمْ خَمْسِينَ آيَةً قَبْلَ أَنْ يَرْفَعَ رَأْسَهُ فَإِذَا سَكَتَ الْمُؤَذِّنُ مِنْ الْأَذَانِ الْأَوَّلِ رَكَعَ رَكْعَتَيْنِ خَفِيفَتَيْنِ ثُمَّ اضْطَجَعَ حَتَّى يَأْتِيَهُ الْمُؤَذِّنُ فَيَخْرُجَ مَعَهُ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] dari [Ibnu Abu Dzi`b] dari [Az Zuhri] dari ['Urwah] dari [Aisyah] radliallahu 'anha, ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melakukan shalat antara shalat Isya hingga subuh sebanyak sebelas rakaat. Beliau mengucapkan salam pada setiap dua rakaat dan melakukan witir satu rakaat, serta sujud pada shalat sunah seukuran salah seorang di antara kalian membaca lima puluh ayat sebelum mengangkat kepalanya. Kemudian apabila muadzin selesai dari adzan (diam) pertama beliau melakukan shalat dua rakaat ringan kemudian berbaring hingga datang muadzin, baru kemudian beliau pergi bersamanya (shalat subuh).\" "},"1085":{"ar":" حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ وَوَهْبُ بْنُ جَرِيرٍ قَالَا حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ قَالَ سَأَلْتُ عَائِشَةَ عَنْ صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِاللَّيْلِ فَقَالَتْ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي ثَلَاثَ عَشْرَةَ رَكْعَةً يُصَلِّي ثَمَانَ رَكَعَاتٍ ثُمَّ يُوتِرُ ثُمَّ يُصَلِّي رَكْعَتَيْنِ وَهُوَ جَالِسٌ فَإِذَا أَرَادَ أَنْ يَرْكَعَ قَامَ فَرَكَعَ وَيُصَلِّي رَكْعَتَيْنِ بَيْنَ النِّدَاءِ وَالْإِقَامَةِ مِنْ صَلَاةِ الصُّبْحِ","id":"Telah menceritakan kepada kami [Yazid bin Harun] dan [Wahb bin Jarir] mereka berkata; telah menceritakan kepada kami [Hisyam] dari [Yahya] dari [Abu Salamah] ia berkata, \"Aku bertanya [Aisyah] mengenai shalat Rasulullah shallallahu 'alaihi wasallam pada malam hari. Kemudian ia berkata, \"Nabi shallallahu 'alaihi wasallam shalat tiga belas rakaat; beliau shalat delapan rakaat lalu mengerjakan witir. Kemudian beliau mengerjakan shalat dua rakaat dalam keadaan duduk, jika beliau ingin melakukan rukuk, maka beliau berdiri dahulu kemudian rukuk. Beliau juga mengerjakan shalat dua rakaat antara adzan dan iqamah pada saat shalat subuh.\" "},"1086":{"ar":" حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ سَعْدِ بْنِ هِشَامٍ أَنَّهُ طَلَّقَ امْرَأَتَهُ وَأَتَى الْمَدِينَةَ لِبَيْعِ عَقَارِهِ فَيَجْعَلَهُ فِي السِّلَاحِ وَالْك��رَاعِ فَلَقِيَ رَهْطًا مِنْ الْأَنْصَارِ فَقَالُوا أَرَادَ ذَلِكَ سِتَّةٌ مِنَّا عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَنَعَهُمْ وَقَالَ أَمَا لَكُمْ فِيَّ أُسْوَةٌ ثُمَّ إِنَّهُ قَدِمَ الْبَصْرَةَ فَحَدَّثَنَا أَنَّهُ لَقِيَ عَبْدَ اللَّهِ بْنَ عَبَّاسٍ فَسَأَلَهُ عَنْ الْوِتْرِ فَقَالَ أَلَا أُحَدِّثُكَ بِأَعْلَمِ النَّاسِ بِوِتْرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْتُ بَلَى قَالَ أُمُّ الْمُؤْمِنِينَ عَائِشَةُ فَأْتِهَا فَاسْأَلْهَا ثُمَّ ارْجِعْ إِلَيَّ فَحَدِّثْنِي بِمَا تُحَدِّثُكَ فَأَتَيْتُ حَكِيمَ بْنَ أَفْلَحَ فَقُلْتُ لَهُ انْطَلِقْ مَعِي إِلَى أُمِّ الْمُؤْمِنِينَ عَائِشَةَ قَالَ إِنِّي لَا آتِيهَا إِنِّي نَهَيْتُ عَنْ هَذِهِ الشِّيعَتَيْنِ فَأَبَتْ إِلَّا مُضِيًّا قُلْتُ أَقْسَمْتُ عَلَيْكَ لَمَا انْطَلَقْتَ فَانْطَلَقْنَا فَسَلَّمْنَا فَعَرَفَتْ صَوْتَ حَكِيمٍ فَقَالَتْ مَنْ هَذَا قُلْتُ سَعْدُ بْنُ هِشَامٍ قَالَتْ مَنْ هِشَامٌ قُلْتُ هِشَامُ بْنُ عَامِرٍ قَالَتْ نِعْمَ الْمَرْءُ قُتِلَ يَوْمَ أُحُدٍ قُلْتُ أَخْبِرِينَا عَنْ خُلُقِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ أَلَسْتَ تَقْرَأُ الْقُرْآنَ قُلْتُ بَلَى قَالَتْ فَإِنَّهُ خُلُقُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَرَدْتُ أَنْ أَقُومَ وَلَا أَسْأَلَ أَحَدًا عَنْ شَيْءٍ حَتَّى أَلْحَقَ بِاللَّهِ فَعَرَضَ لِي الْقِيَامُ فَقُلْتُ أَخْبِرِينَا عَنْ قِيَامِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ أَلَسْتَ تَقْرَأُ يَا أَيُّهَا الْمُزَّمِّلُ قُلْتُ بَلَى قَالَتْ فَإِنَّهَا كَانَتْ قِيَامَ رَسُولِ اللَّهِ أُنْزِلَ أَوَّلُ السُّورَةِ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابُهُ حَتَّى انْتَفَخَتْ أَقْدَامُهُمْ وَحُبِسَ آخِرُهَا فِي السَّمَاءِ سِتَّةَ عَشَرَ شَهْرًا ثُمَّ أُنْزِلَ فَصَارَ قِيَامُ اللَّيْلِ تَطَوُّعًا بَعْدَ أَنْ كَانَ فَرِيضَةً فَأَرَدْتُ أَنْ أَقُومَ وَلَا أَسْأَلَ أَحَدًا عَنْ شَيْءٍ حَتَّى أَلْحَقَ بِاللَّهِ فَعَرَضَ لِي الْوِتْرُ فَقُلْتُ أَخْبِرِينَا عَنْ وِتْرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا نَامَ وَضَعَ سِوَاكَهُ عِنْدِي فَيَبْعَثُهُ اللَّهُ لِمَا شَاءَ أَنْ يَبْعَثَهُ فَيُصَلِّي تِسْعَ رَكَعَاتٍ لَا يَجْلِسُ إِلَّا فِي الثَّامِنَةِ فَيَحْمَدُ اللَّهَ وَيَدْعُو رَبَّهُ ثُمَّ يَقُومُ وَلَا يُسَلِّمُ ثُمَّ يَجْلِسُ فِي التَّاسِعَةِ فَيَحْمَدُ اللَّهَ وَيَدْعُو رَبَّهُ وَيُسَلِّمُ تَسْلِيمَةً يُسْمِعُنَا ثُمَّ يُصَلِّي رَكْعَتَيْنِ وَهُوَ جَالِسٌ فَتِلْكَ إِحْدَى عَشْرَةَ رَكْعَةً يَا بُنَيَّ فَلَمَّا أَسَنَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَحَمَلَ اللَّحْمَ صَلَّى سَبْعَ رَكَعَاتٍ لَا يَجْلِسُ إِلَّا فِي السَّادِسَةِ فَيَحْمَدُ اللَّهَ وَيَدْعُو رَبَّهُ ثُمَّ يَقُومُ وَلَا يُسَلِّمُ ثُمَّ يَجْلِسُ فِي السَّابِعَةِ فَيَحْمَدُ اللَّهَ وَيَدْعُو رَبَّهُ ثُمَّ يُسَلِّمُ تَسْلِيمَةً ثُمَّ يُصَلِّي رَكْعَتَيْنِ وَهُوَ جَالِسٌ فَتِلْكَ تِسْعٌ يَا بُنَيَّ وَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا غَلَبَهُ نَوْمٌ أَوْ مَرَضٌ صَلَّى مِنْ النَّهَارِ ثِنْتَيْ عَشْرَةَ رَكْعَةً وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَخَذَ خُلُقًا أَحَبَّ أَنْ يُدَاوِمَ عَلَيْهِ وَمَا قَامَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلَةً حَتَّى يُصْبِحَ وَلَا قَرَأَ الْقُرْآنَ كُلَّهُ فِي لَيْلَةٍ وَلَا صَامَ شَهْرًا كَامِلًا غَيْرَ رَمَضَانَ فَأَتَيْتُ ابْنَ عَبَّاسٍ فَحَدَّثْتُهُ فَقَالَ صَدَقَتْكَ أَمَا إِنِّي لَوْ كُنْتُ أَدْخُلُ عَلَيْهَا لَشَافَهْتُهَا مُشَافَهَةً قَالَ فَقُلْتُ أَمَا إِنِّي لَوْ شَعَرْتُ أَنَّكَ لَا تَدْخُلُ عَلَيْهَا مَا حَدَّثْتُكَ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah menceritakan kepada kami [Mu'adz bin Hisyam] telah menceritakan kepadaku [Ayahku] dari [Qatadah] dari [Zurarah bin Aufa] dari [Sa'd bin Hisyam], bahwa ia telah mencerai isterinya lalu datang ke Madinah untuk menjual tanahnya kemudian menjadikannya untuk membeli senjata dan perlengkapan perang. Kemudian ia bertemu dengan beberapa orang Anshar, mereka lalu berkata, \"Pada masa Rasulullah shallallahu 'alaihi wasallam ada enam orang di antara kami yang menghendaki hal tersebut, kemudian Rasulullah shallallahu 'alaihi wasallam melarang mereka. Beliau mengatakan: \"Bukankah pada diriku terdapat suri tauladan?\" Kemudian laki-laki itu datang ke Bashrah dan menceritakan kepada kami bahwa ia pernah bertemu Abdullah bin Abbas dan bertanya kepadanya mengenai witir. Kemudian Abdullah bin Abbas menjawab, \"Maukah aku ceritakan kepadamu orang yang paling tahu mengenai witir Rasulullah shallallahu 'alaihi wasallam?\" Ia berkata, \"Ya.\" Abdullah bin Abbas berkata, \"Ummul mukminin, [Aisyah]. Datanglah kepadanya dan bertanyalah. Setelah itu kembalilah kepadaku, kamu ceritakan kepadaku apa yang ia ceritakan kepadamu.\" Lalu aku datang kepada Hakim bin Aflah dan berkata kepadanya, \"Pergilah bersamaku menemui Ummul Mukminin, Aisyah.\" Hakim berkata, \"Aku tidak akan datang kepadanya! Sungguh aku telah melarang dari berbicara tentang dua kelompok (yang terlibat dalam peperangan -pent) ini, namun ia (Aisyah) tetap membicarakannya.\" Aku katakan, \"Aku menyumpahmu, sungguh engkau akan pergi.\" Kemudian kamipun pergi dan mengucapkan salam. Ternyata Aisyah mengenal suara Hakim, ia lantas bertanya, \"Siapa ini?\" aku menjawab, \"Sa'd bin Hisyam.\" Ia bertanya lagi, \"Hisyam siapa?\" Aku katakan, \"Hisyam bin 'Amir.\" Aisyah lalu berkata, \"Sebaik-baik orang adalah yang terbunuh pada saat perang Uhud.\" Aku lalu berkata, \"Beritahukan kepada kami bagaimana akhlak Rasulullah shallallahu 'alaihi wasallam?\" Aisyah berkata, \"Bukankah engkau membaca Al Qur'an?\" Aku katakan, \"Ya.\" Aisyah lantas berkata, \"Sesungguhnya itu adalah akhlak Rasulullah shallallahu 'alaihi wasallam.\" Kemudian aku ingin berdiri dan tidak bertanya kepada seorangpun mengenai sesuatu hingga aku bertemu dengan Allah. Kemudian terlintas padaku tentang shalat malam, lalu aku katakan, \"Beritahukan kepada kami mengenai shalat malam Rasulullah! Aisyah berkata, \"Bukankah engkau membaca surat 'YAA AYYUHAL MUZZAMMIL? ' Aku menjawab, \"Ya.\" Aisyah lalu berkata, \"Itulah shalat malam Rasulullah shallallahu 'alaihi wasallam. Telah diturunkan awal surat tersebut kemudian Rasulullah shallallahu 'alaihi wasallam dan para sahabatnya melaksanakan hingga kaki mereka bengkak, dan akhir surat tersebut tertahan di langit selama enam belas bulan, kemudian diturunkan. Lalu shalat malam menjadi sesuatu yang sunah setelah menjadi sesuatu yang wajib.\" Kemudian aku ingin berdiri dan tidak bertanya kepada seorang pun mengenai sesuatu hingga aku bertemu dengan Allah. Kemudian terlintas padaku tentang shalat witir, lalu aku katakan, \"Beritahukan kepada kami mengenai witir Rasulullah shallallahu 'alaihi wasallam?\" Aisyah lalu berkata, \"Jika Rasulullah shallallahu 'alaihi wasallam tidur, beliau meletakkan siwaknya di sisiku, kemudian Allah membangunkannya dengan sekehendak Allah untuk membangunkannya, kemudian beliau melakukan shalat sembilan rakaat dan tidak duduk (untuk tasyahud) kecuali pada rakaat kedelapan. Beliau lalu memuji Allah dan berdoa kepada Tuhannya. Kemudian berdiri dan tidak mengucapkan salam. Kemudian duduk pada rakaat kesembilan, beliau lalu memuji Allah dan berdoa kepada Tuhannya serta mengucapkan salam satu kali, dan beliau memperdengarkannya kepada kami. Setelah itu beliau melakukan shalat dua rakaat dalam keadaan duduk. Itulah shalat sebelas rakaat wahai anakku. Kemudian tatkala Rasulullah shallallahu 'alaihi wasallam telah berumur dan gemuk maka beliau melakukan shalat tujuh rakaat, tidak duduk (untuk tasyahud) kecuali pada rakaat keenam, lalu memuji Allah serta berdoa kepada Tuhannya. Kemudian berdiri dan tidak mengucapkan salam. Kemudian beliau duduk pada rakaat ketujuh lalu memuji Allah dan berdoa kepada Tuhannya, kemudian mengucapkan salam satu kali. Kemudian melakukan shalat dua rakaat dalam keadaan duduk, maka itulah sembilan rakaat wahai anakku. Jika Nabi shallallahu 'alaihi wasallam apabila ketiduran atau sedang sakit, maka beliau melakukan shalat pada siang harinya dua belas rakaat. Rasulullah shallallahu 'alaihi wasallam apabila melakukan suatu pekerjaan, maka beliau senang untuk melakukannya secara kontinyu. Nabi shallallahu 'alaihi wasallam tidak shalat malam hingga pagi hari, tidak membaca Al Qur'an seluruhnya dalam satu malam, dan beliau tidak pernah puasa satu bulan penuh selain pada bulan Ramadhan.\" Kemudian aku datang kepada Ibnu Abbas dan menceritakan hal tersebut, lalu ia berkata, \"Aisyah telah berkata benar kepadamu. Sekiranya aku bisa bertemu dengannya, maka aku akan berbicara secara langsung kepadanya.\" Sa'd berkata, \"Aku lalu berkata, \"Jika aku tahu bahwa engkau enggan menemuinya maka aku tidak akan menceritakan kepadamu.\" "},"1087":{"ar":" أَخْبَرَنَا زَيْدُ بْنُ عَوْفٍ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ مُحَمَّدِ بْنِ الْمُنْتَشِرِ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَفْضَلُ الصَّلَاةِ بَعْدَ الْفَرِيضَةِ الصَّلَاةُ فِي جَوْفِ اللَّيْلِ","id":"Telah mengabarkan kepada kami [Zaid bin 'Auf] telah menceritakan kepada kami [Abu 'Awanah] dari [Abdul Malik bin 'Umair] dari [Muhammad bin Al Muntasyir] dari [Humaid bin Abdurrahman] dari [Abu Hurairah], bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Shalat paling utama setelah shalat wajib adalah shalat di tengah malam.\""},"1088":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنِي اللَّيْثُ حَدَّثَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي السَّائِبُ بْنُ يَزِيدَ وَعُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ أَنَّ عَبْدَ الرَّحْمَنِ بْنَ عَبْدٍ قَالَ سَمِعْتُ عُمَرَ بْنَ الْخَطَّابِ يَقُولُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ نَامَ عَنْ حِزْبِهِ أَوْ عَنْ شَيْءٍ مِنْهُ فَقَرَأَهُ فِيمَا بَيْنَ صَلَاةِ الْفَجْرِ وَصَلَاةِ الظُّهْرِ كُتِبَ لَهُ كَأَنَّمَا قَرَأَهُ مِنْ اللَّيْلِ","id":"Telah mengabarkan kepada kami [Abdullah bin Shalih] telah menceritakan kepadaku [Al Laits] telah menceritakan kepadaku [Yunus] dari [Ibnu Syihab] telah mengabarkan kepadaku [As Sa`ib bin Yazid] serta ['Ubaidullah bin Abdurrahman bin Abd] bahwa [Abdurrahman bin 'Abd] berkata, aku mendengar [Umar bin Al Khathab] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa tertidur dari dzikirnya atau sebagian darinya kemudian ia membacanya antara shalat subuh dan shalat zhuhur, maka tercatat baginya seolah-olah ia telah membacanya pada malam hari.\""},"1089":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا مُحَمَّدُ بْنُ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْزِلُ اللَّهُ تَعَالَى إِلَى السَّمَاءِ الدُّنْيَا كُلَّ لَيْلَةٍ لِنِصْفِ اللَّيْلِ الْآخِرِ أَوْ لِثُلُثِ اللَّيْلِ الْآخِرِ فَيَقُولُ مَنْ ذَا الَّذِي يَدْعُونِي فَأَسْتَجِيبَ لَهُ مَنْ ذَا الَّذِي يَسْأَلُنِي فَأُعْطِيَهُ مَنْ ذَا الَّذِي يَسْتَغْفِرُنِي فَأَغْفِرَ لَهُ حَتَّى يَطْلُعَ الْفَجْرُ أَوْ يَنْصَرِفَ الْقَارِئُ مِنْ صَلَاةِ الْفَجْرِ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Muhammad bin 'Amru] dari [Abu Salamah] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah Ta'ala turun ke langit dunia pada pertengahan malam akhir, atau sepertiga malam terakhir, lalu berfirman: 'Siapa yang berdoa kepada-Ku maka Aku akan mengabulkan baginya, siapakah yang memohon kepada-Ku maka Aku akan memberinya, siapakah yang meminta ampun kepada-Ku maka Aku akan mengampuninya? ' sampai terbit fajar atau orang yang shalat selesai dari shalat subuh.\""},"1090":{"ar":" حَدَّثَنَا الْحَكَمُ بْنُ نَافِعٍ عَنْ شُعَيْبِ بْنِ أَبِي حَمْزَةَ عَنْ الزُّهْرِيِّ حَدَّثَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ وَأَبُو عَبْدِ اللَّهِ الْأَغَرُّ صَاحِبَا أَبِي هُرَيْرَةَ أَنَّ أَبَا هُرَيْرَةَ أَخْبَرَهُمَا أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَنْزِلُ رَبُّنَا تَبَارَكَ اسْمُهُ كُلَّ لَيْلَةٍ حِينَ يَبْقَى ثُلُثُ اللَّيْلِ الْآخِرُ إِلَى السَّمَاءِ الدُّنْيَا فَيَقُولُ مَنْ يَدْعُونِي فَأَسْتَجِيبَ لَهُ مَنْ يَسْتَغْفِرُنِي فَأَغْفِرَ لَهُ مَنْ يَسْأَلُنِي فَأُعْطِيَهُ حَتَّى الْفَجْرِ","id":"Telah menceritakan kepada kami [Al Hakam bin Nafi'] dari [Syu'aib bin Abu Hamzah] dari [Az Zuhri] telah menceritakan kepadaku [Abu Salamah bin Abdurrahman] dan [Abu Abdullah Al Aghar] dua orang sahabat Abu Hurairah, bahwa [Abu Hurairah] mengabarkan kepada mereka berdua, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tuhan kita Yang Maha Suci nama-Nya turun ke langit dunia pada setiap malam di sepertiga malam terakhir, kemudian berfirman: 'Siapakah yang berdoa kepada-Ku maka Aku akan mengabulkan baginya, siapakah yang memohon kepada-Ku maka Aku akan memberinya, siapakah yang meminta ampun kepada-Ku maka Aku akan mengampuninya? ' hingga terbit fajar.\" "},"1091":{"ar":" أَخْبَرَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ حَدَّثَنَا عَمْرُو بْنُ دِينَارٍ عَنْ نَافِعِ بْنِ جُبَيْرِ بْنِ مُطْعِمٍ عَنْ أَبِيهِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَنْزِلُ اللَّهُ تَعَالَى كُلَّ لَيْلَةٍ إِلَى السَّمَاءِ الدُّنْيَا فَيَقُولُ هَلْ مِنْ سَائِلٍ فَأُعْطِيَهُ هَلْ مِنْ مُسْتَغْفِرٍ فَأَغْفِرَ لَهُ","id":"Telah mengabarkan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Hammad bin Salamah] telah menceritakan kepada kami ['Amru bin Dinar] dari [Nafi' bin Jubair bin Muth'im] dari [Ayahnya], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pada setiap malam Allah Ta'ala turun ke langit dunia, kemudian berfirman: 'Apakah ada orang yang memohon hingga Aku memberinya? Apakah ada orang yang meminta ampunan hingga Aku mengampuninya?\""},"1092":{"ar":" أَخْبَرَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ هِلَالِ بْنِ أَبِي مَيْمُونَةَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ رِفَاعَةَ بْنِ عَرَابَةَ الْجُهَنِيِّ قَالَ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا مَضَى مِنْ اللَّيْلِ نِصْفُهُ أَوْ ثُلُثَاهُ هَبَطَ اللَّهُ إِلَى السَّمَاءِ الدُّنْيَا ثُمَّ يَقُولُ لَا أَسْأَلُ عَنْ عِبَادِي غَيْرِي مَنْ ذَا الَّذِي يَسْأَلُنِي فَأُعْطِيَهُ مَنْ ذَا الَّذِي يَسْتَغْفِرُنِي فَأَغْفِرَ لَهُ مَنْ ذَا الَّذِي يَدْعُونِي فَأَسْتَجِيبَ لَهُ حَتَّى يَطْلُعَ الْفَجْرُ حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى عَنْ هِلَالِ بْنِ أَبِي مَيْمُونَةَ عَنْ عَطَاءِ بْنِ يَسَارٍ أَنَّ رِفَاعَةَ أَخْبَرَهُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنَحْوِهِ","id":"Telah mengabarkan kepada kami [Abu Al Mughirah] telah menceritakan kepada kami [Al Auza'i] telah menceritakan kepada kami [Yahya bin Abu Katsir] dari [Hilal bin Abu Maimunah] dari ['Atha` bin Yasar] dari [Rifa'ah bin 'Arabah Al Juhani] ia berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Apabila telah berlalu setengah malam atau dua pertiga malam Allah turun ke langit dunia, kemudian berfirman: 'Tidak ada yang bertanya mengenai hamba-hambaKu selain diri-Ku, siapakah yang memohon kepada-Ku hingga Aku memberinya, siapakah yang meminta ampunan kepada-Ku hingga Aku mengampuninya? Siapakah yang berdoa kepada-Ku hingga Aku mengabulkannya? ' sehingga terbit fajar.\" Telah menceritakan kepada kami [Wahb bin Jarir] telah menceritakan kepada kami [Hisyam] dari [Yahya] dari [Hilal bin Abu Maimunah] dari ['Atha` bin Yasar] bahwa [Rifa'ah] telah mengabarkan kepadanya dari Nabi shallallahu 'alaihi wasallam dengan hadits seperti itu.\" "},"1093":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ حُمَيْدٍ حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُخْتَارٍ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ عَمِّهِ عَبْدِ الرَّحْمَنِ بْنِ يَسَارٍ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي رَافِعٍ عَنْ عَلِيٍّ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا كَانَ ثُل��ثُ اللَّيْلِ أَوْ نِصْفُ اللَّيْلِ فَذَكَرَ النُّزُولَ","id":"Telah mengabarkan kepada kami [Muhammad bin Humaid] telah menceritakan kepada kami [Ibrahim bin Mukhtar] dari [Muhammad bin Ishaq] dari pamannya [Abdurrahman bin Yasar] dari ['Ubaidullah bin Abu Rafi'] dari [Ali] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila telah datang sepertiga malam atau pertengahan malam…\" kemudian ia menyebutkan hadits mengenai turunnya Allah.\" "},"1094":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبِي عَنْ ابْنِ إِسْحَقَ حَدَّثَنِي سَعِيدُ بْنُ أَبِي سَعِيدٍ الْمَقْبُرِيُّ عَنْ عَطَاءٍ مَوْلَى أُمِّ صُبَيَّةَ عَنْ أَبِي هُرَيْرَةَ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَوْلَا أَنْ أَشُقَّ عَلَى أُمَّتِي لَأَمَرْتُهُمْ بِالسِّوَاكِ عِنْدَ كُلِّ صَلَاةٍ وَلَأَخَّرْتُ الْعِشَاءَ الْآخِرَةَ إِلَى ثُلُثِ اللَّيْلِ فَإِنَّهُ إِذَا مَضَى ثُلُثُ اللَّيْلِ الْأَوَّلُ هَبَطَ اللَّهُ إِلَى السَّمَاءِ الدُّنْيَا فَلَمْ يَزَلْ هُنَالِكَ حَتَّى يَطْلُعَ الْفَجْرُ يَقُولُ قَائِلٌ أَلَا سَائِلٌ يُعْطَى أَلَا دَاعٍ يُجَابُ أَلَا سَقِيمٌ يَسْتَشْفِي فَيُشْفَى أَلَا مُذْنِبٌ يَسْتَغْفِرُ فَيُغْفَرَ لَهُ أَخْبَرَنَا مُحَمَّدٌ حَدَّثَنَا يَعْقُوبُ حَدَّثَنِي أَبِي عَنْ ابْنِ إِسْحَقَ حَدَّثَنِي عَمِّي عَبْدُ الرَّحْمَنِ بْنُ يَسَارٍ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي رَافِعٍ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ أَبِيهِ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَ حَدِيثِ أَبِي هُرَيْرَةَ","id":"Telah mengabarkan kepada kami [Muhammad bin Yahya] telah menceritakan kepada kami [Ya'qub bin Ibrahim] telah menceritakan kepada kami [Ayahku] dari [Ibnu Ishaq] telah menceritakan kepadaku [Sa'id? bin Abu Sa'id Al Maqburi] dari ['Atha`] mantan budak Ummu Shubayyah, dari [Abu Hurairah] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sekiranya tidak memberatkan umatku niscaya akan aku memerintahkan mereka untuk bersiwak (gosok gigi) setiap kali akan melakukan shalat, dan aku akan menunda shalat Isya hingga sepertiga malam. Sesungguhnya apabila telah berlalu sepertiga malam pertama, Allah turun ke langit dunia dan akan tetap berada di sana hingga terbit fajar. Lalu seorang penyeru (Allah) berkata, 'Adakah orang yang memohon sehingga ia diberi? Adakah orang yang berdoa sehingga dikabulkan doanya? Adakah orang sakit yang memohon kesembuhan hingga ia disembuhkan? Adakah orang yang berbuat dosa dan meminta ampun hingga ia diampuni?\" Telah mengabarkan kepada kami [Muhammad] telah menceritakan kepada kami [Ya'qub] telah menceritakan kepadaku [Ayahku] dari [Abu Ishaq] telah menceritakan kepadaku pamanku [Abdurrahman bin Yasar] dari ['Ubaidullah bin Abu Rafi'] mantan budak Rasulullah shallallahu 'alaihi wasallam, dari [Ayahnya] dari [Ali bin Abu Thalib] dari Rasulullah shallallahu 'alaihi wasallam seperti hadits Abu Hurairah.\" "},"1095":{"ar":" حَدَّثَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا سُفْيَانُ هُوَ ابْنُ عُيَيْنَةَ عَنْ سُلَيْمَانَ الْأَحْوَلِ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَامَ يَتَهَجَّدُ مِنْ اللَّيْلِ قَالَ اللَّهُمَّ لَكَ الْحَمْدُ أَنْتَ نُورُ السَّمَوَاتِ وَالْأَرْضِ وَمَنْ فِيهِنَّ وَلَكَ الْحَمْدُ أَنْتَ قَيِّمُ السَّمَوَاتِ وَالْأَرْضِ وَمَنْ فِيهِنَّ وَلَكَ الْحَمْدُ أَنْتَ مَلِكُ السَّمَوَاتِ وَالْأَرْضِ وَمَنْ فِيهِنَّ أَنْتَ الْحَقُّ وَقَوْلُكَ الْحَقُّ وَوَعْدُكَ الْحَقُّ وَلِقَاؤُكَ حَقٌّ وَالْجَنَّةُ حَقٌّ وَالنَّارُ حَقٌّ وَالْبَعْثُ حَقٌّ وَالنَّبِيُّونَ حَقٌّ وَمُحَمَّدٌّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَقٌّ اللَّهُمَّ لَكَ أَسْلَمْتُ وَبِكَ آمَنْتُ وَعَلَيْكَ تَوَكَّلْتُ وَإِلَيْكَ أَنَبْتُ وَبِكَ خَاصَمْتُ وَإِلَيْكَ حَاكَمْتُ فَاغْفِرْ لِي مَا قَدَّمْتُ وَمَا أَخَّرْتُ وَمَا أَعْلَنْتُ وَمَا أَسْرَرْتُ أَنْتَ الْمُقَدِّمُ وَأَنْتَ الْمُؤَخِّرُ لَا إِلَهَ إِلَّا أَنْتَ وَلَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِكَ","id":"Telah menceritakan kepada kami [Yahya bin Hassan] telah menceritakan kepada kami [Sufyan] -yaitu Ibnu 'Uyainah- dari [Sulaiman Al Ahwal] dari [Thawus] dari [Ibnu Abbas] ia berkata, \"Jika Rasulullah shallallahu 'alaihi wasallam shalat tahajjud di malam hari, beliau berdoa: 'ALLAAHUMMA LAKAL HAMDU ANTA NUURUS SAMAAWAATI WAL ARDLI WA MAN FIIHINNA WALAKAL HAMDU ANTA QAYYIMUS SAMAAWAATI WAL ARDLI WA MAN FIIHINNA. WA LAKAL HAMDU ANTA MALIKUS SAMAAWAATI WAL ARDLI WA MAN FIIHINNA, ANTAL HAQQU WA QAULUKAL HAQQU WA WA'DUKAL HAQQU WA LIQAAUKA HAQQUN WAL JANNATU HAQQUN WAN NAARU HAQQUN WAL BA'TSU HAQQUN WAN NABIYUUNA HAQQUN WA MUHAMMADUN shallallahu 'alaihi wasallam HAQQUN. ALLAAHUMMA LAKA ASLAMTU WA BIKA AAMANTU WA 'ALAIKA TAWAKKKALTU, WA ILAIKA ANABTU WA BIKA KHAASHAMTU WA ILAIKA HAAKAMTU, FAGHFIR LII MAA QADDAMTU WA MAA AKHKHARTU WA MAA A'LANTU WA MAA ASRARTU. ANTAL MUQADDIMU WA ANTAL MUAKHKHIRU LAA ILAAHA ILLAA ANTA. WA LAA HAULA WA LAA QUWWATA ILLAA BIKA (Ya Allah, segala puji bagi-Mu, Engkau adalah cayaha langit dan bumi dan orang-orang yang ada di antaranya, segala puji bagi-Mu, Engkau Yang selalu mengatur langit dan bumi dan orang-orang yang ada padanya, segala puji bagi-Mu, Engkau Raja langit dan bumi dan orang-orang yang ada padanya, Engkau adalah Al Haq, perkataan-Mu adalah benar, janji-Mu benar, pertemuan dengan-Mu adalah benar, Surga adalah benar, Neraka adalah benar, pembangkitan adalah benar, para nabi adalah benar, dan Muhammad shallallahu 'alaihi wasallam adalah benar. Ya Allah, kepada-Mu aku berserah diri, dan kepada-Mu aku beriman, kepada-Mu aku bertawakal dan kepada-Mu aku kembali, dengan-Mu aku menghadapi lawan, dan kepada-Mu aku berhukum. Maka ampunilah untukku apa yang telah aku lakukan dan apa yang aku tunda, yang aku perlihatkan dan yang aku sembunyikan. Engkau yang mendahulukan dan mengakhirkan, tidak ada tuhan yang berhak disembah kecuali Engkau dan tidak ada daya serta kekuatan kecuali karena-Mu).\""},"1096":{"ar":" حَدَّثَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ شُعْبَةَ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ أَبِي مَسْعُودٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَنْ قَرَأَ الْآيَتَيْنِ الْآخِرَتَيْنِ مِنْ سُورَةِ الْبَقَرَةِ فِي لَيْلَةٍ كَفَتَاهُ","id":"Telah menceritakan kepada kami [Sa'id? bin 'Amir] dari [Syu'bah] dari [Manshur] dari [Ibrahim] dari [Abdurrahman bin Yazid] dari [Abu Mas'ud] dari Nabi shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Barangsiapa membaca dua ayat terakhir dari surat Al Baqarah pada malam hari, maka keduanya akan memberikan perlindungan kepadanya.\""},"1097":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا مُحَمَّدُ بْنُ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أَذِنَ اللَّهُ لِشَيْءٍ كَإِذْنِهِ لِنَبِيٍّ يَتَغَنَّى بِالْقُرْآنِ يَجْهَرُ بِهِ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Muhammad bin 'Amru] dari [Abu Salamah] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah Allah memberikan izin kepada sesuatu seperti Dia memberikan izin kepada seorang Nabi melantunkan Al Qur'an dan mengeraskannya.\""},"1098":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ قَالَ ابْنُ عُيَيْنَةَ أُرَاهُ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْ سَمِعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبَا مُوسَى وَهُوَ يَقْرَأُ فَقَالَ لَقَدْ أُوتِيَ هَذَا مِنْ مَزَامِيرِ آلِ دَاوُدَ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Ibnu 'Uyainah] dari [Az Zuhri], [Ibnu 'Uyainah] berkata, menurutku dari ['Urwah] dari [Aisyah] ia berkata, \"Nabi shallallahu 'alaihi wasallam mendengar Abu Musa membaca Al-Qur'an, kemudian beliau berkata: \"Sungguh orang ini telah diberi sebagian dari seruling keluarga Daud.\""},"1099":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ أَحْمَدَ بْنِ أَبِي خَلَفٍ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو يَعْنِي ابْنَ دِينَارٍ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي نَهِيكٍ عَنْ سَعْدٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْسَ مِنَّا مَنْ لَمْ يَتَغَنَّ بِالْقُرْآنِ","id":"Telah mengabarkan kepada kami [Muhammad bin Ahmad bin Abu Khalaf] telah menceritakan kepada kami [Sufyan] dari ['Amru] -yaitu Ibnu Dinar- dari [Ibnu Abu Mulaikah] dari ['Ubaidullah bin Abu Nuhaik] dari [Sa'd], bahwa Nabi shallallahu 'alaihi wasallam berkata: \"Bukan dari golongan kami orang yang tidak melantunkan Al Qur'an.\""},"1100":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ أَحْمَدَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا أَذِنَ اللَّهُ لِشَيْءٍ مَا أَذِنَ لِنَبِيٍّ يَتَغَنَّى بِالْقُرْآنِ قَالَ أَبُو مُحَمَّد يُرِيدُ بِهِ الِاسْتِغْنَاءَ","id":"Telah mengabarkan kepada kami [Muhammad bin Ahmad] telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Abu Salamah] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidaklah Allah memberikan izin kepada sesuatu seperti Dia memberikan izin kepada seorang Nabi untuk melantunkan Al Qur'an.\" Abu Muhammad berkata, \"Yang beliau inginkan adalah merasa cukup.\" "},"1101":{"ar":" أَخْبَرَنَا بِشْرُ بْنُ عُمَرَ الزَّهْرَانِيُّ حَدَّثَنَا شُعْبَةُ عَنْ خُبَيْبِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ حَفْصِ بْنِ عَاصِمٍ عَنْ أَبِي سَعِيدِ بْنِ الْمُعَلَّى قَالَ مَرَّ بِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَلَمْ يَقُلْ اللَّهُ { يَا أَيُّهَا الَّذِينَ آمَنُوا اسْتَجِيبُوا لِلَّهِ وَلِلرَّسُولِ إِذَا دَعَاكُمْ } ثُمَّ قَالَ أَلَا أُعَلِّمُكَ سُورَةً أَعْظَمَ سُورَةٍ مِنْ الْقُرْآنِ قَبْلَ أَنْ أَخْرُجَ مِنْ الْمَسْجِدِ فَلَمَّا أَرَادَ أَنْ يَخْرُجَ قَالَ الْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَ وَهِيَ السَّبْعُ الْمَثَانِي وَالْقُرْآنُ الْعَظِيمُ الَّذِي أُوتِيتُمْ","id":"Telah mengabarkan kepada kami [Bisyr bin Umar Az Zahrani] telah menceritakan kepada kami [Syu'bah] dari [Khubaib bin Abdurrahman] dari [Hafsh bin 'Ashim] dari [Abu Sa'id bin Al Mu'alla] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melewatiku dan berkata: \"Bukankah Allah berfirman: 'Penuhilah seruan Allah dan seruan Rasul apabila Rasul menyeru kamu'.? (Qs.?Al Anfal: 24) Kemudian beliau bersabda: \"Maukah aku ajarkan kepadamu surat terbesar dari Al Qur'an sebelum aku keluar dari masjid?\" Maka ketika akan keluar beliau mengucapkan: \"Al HAMDU LILLAAHI RABBIL 'AALAMIIN (Surat Al Faatihah), itu adalah As Sab'u Al Matsaani, dan Al Qur'an Al 'Azhiim yang diberikan kepada kalian.\""},"1102":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ الْمِنْهَالِ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَبِي الْعَلَاءِ يَزِيدَ بْنِ عَبْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَفْقَهُ مَنْ قَرَأَ الْقُرْآنَ فِي أَقَلَّ مِنْ ثَلَاثٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Minhal] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Abu Al 'Ala` Yazid bin Abdullah] dari [Abdullah bin 'Amru] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak akan paham orang yang membaca Al Qur'an kurang dari tiga hari.\""},"1103":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا نُودِيَ بِالْأَذَانِ أَدْبَرَ الشَّيْطَانُ لَهُ ضُرَاطٌ حَتَّى لَا يَسْمَعَ الْأَذَانَ فَإِذَا قُضِيَ الْأَذَانُ أَقْبَلَ فَإِذَا ثُوِّبَ أَدْبَرَ فَإِذَا قُضِيَ التَّثْوِيبُ أَقْبَلَ حَتَّى يَخْطِرَ بَيْنَ الْمَرْءِ وَنَفْسِهِ فَيَقُولُ اذْكُرْ كَذَا اذْكُرْ كَذَا لِمَا لَمْ يَكُنْ يَعْنِي يَذْكُرُ حَتَّى يَظَلَّ الرَّجُلُ إِنْ يَدْرِي كَمْ صَلَّى فَإِذَا لَمْ يَدْرِ أَحَدُكُمْ كَمْ صَلَّى ثَلَاثًا أَمْ أَرْبَعًا فَلْيَسْجُدْ سَجْدَتَيْنِ وَهُوَ جَالِسٌ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah menceritakan kepada kami [Hisyam] dari [Yahya] dari [Abu Salamah] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Apabila diserukan adzan, maka setan lari berpaling darinya dan mengeluarkan kentut hingga ia tidak mendengar adzan. Jika adzan telah selesai maka ia kembali, kemudian apabila dikumandangkan maka ia akan lari lagi. Jika telah selesai dikumandangkan maka ia kembali hingga ia membisikkan antara seseorang dan hatinya, ia katakan, 'Ingatlah ini, ingatlah ini', sesuatu yang sebelumnya tidak pernah terlintas olehnya. Sehingga orang tersebut tidak mengetahui berapa rakaat yang telah ia kerjakan. Kemudian apabila salah seorang di antara kalian tidak mengetahui berapa rakaat yang telah dikerjakannya, tiga atau empat, maka hendaknya ia sujud dua kali ketika ia dalam keadaan duduk.\""},"1104":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا عَبْدُ الْعَزِيزِ هُوَ ابْنُ أَبِي سَلَمَةَ الْمَاجِشُونُ أَخْبَرَنَا زَيْدُ بْنُ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا لَمْ يَدْرِ أَحَدُكُمْ أَثَلَاثًا صَلَّى أَمْ أَرْبَعًا فَلْيَقُمْ فَلْيُصَلِّ رَكْعَةً ثُمَّ يَسْجُدُ بَعْدَ ذَلِكَ سَجْدَتَيْنِ فَإِنْ كَانَ صَلَّى خَمْسًا شَفَعَتَا لَهُ صَلَاتَهُ وَإِنْ كَانَ صَلَّى أَرْبَعًا كَانَتَا تَرْغِيمًا لِلشَّيْطَانِ قَالَ أَبُو مُحَمَّد آخُذُ بِهِ","id":"Telah mengabarkan kepada kami [Ahmad bin Abdullah] telah menceritakan kepada kami [Abdul Aziz] -yaitu Ibnu Abu Salamah Al Majisyun- telah mengabarkan kepada kami [Zaid bin Aslam] dari ['Atha` bin Yasar] dari [Abu Sa'id Al Khudri] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang di antara kalian tidak mengetahui apakah ia melakukan shalat tiga rakaat atau empat rakaat, maka hendaknya ia berdiri dan shalat satu rakaat, setelah itu sujud dua kali. Jika ia telah mengerjakan lima rakaat maka dua sujud tersebut telah mengembalikannya kepada bilangan genap, dan apabila ia melakukan shalat empat rakaat maka kedua sujud tersebut menjadi sebab kemarahan setan.\" Abu Muhammad berkata, \"Aku berpendapat seperti itu.\" "},"1105":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا ابْنُ عَوْنٍ عَنْ مُحَمَّدٍ عَنْ أَبِي هُرَيْرَةَ قَالَ صَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِحْدَى صَلَاتَيْ الْعَشِيِّ فَصَلَّى رَكْعَتَيْنِ ثُمَّ سَلَّمَ وَقَامَ إِلَى خَشَبَةٍ مُعْتَرِضَةٍ فِي الْمَسْجِدِ فَوَضَعَ يَدَهُ عَلَيْهَا قَالَ يَزِيدُ وَأَرَانَا ابْنُ عَوْنٍ وَوَضَعَ كَفَّيْهِ إِحْدَاهُمَا عَلَى ظَهْرِ الْأُخْرَى وَأَدْخَلَ أَصَابِعَهُ الْعُلْيَا فِي السُّفْلَى وَاضِعًا وَقَامَ كَأَنَّهُ غَضْبَانُ قَالَ فَخَرَجَ السَّرَعَانُ مِنْ النَّاسِ وَجَعَلُوا يَقُولُونَ قُصِرَتْ الصَّلَاةُ قُصِرَتْ الصَّلَاةُ وَفِي الْقَوْمِ أَبُو بَكْرٍ وَعُمَرُ فَلَمْ يَتَكَلَّمَا وَفِي الْقَوْمِ رَجُلٌ طَوِيلُ الْيَدَيْنِ يُسَمَّى ذُو الْيَدَيْنِ فَقَالَ يَا رَسُولَ اللَّهِ أَنَسِيتَ الصَّلَاةَ أَمْ قُصِرَتْ فَقَالَ مَا نَسِيتُ وَلَا قُصِرَتْ الصَّلَاةُ فَقَالَ أَوَ كَذَلِكَ قَالُوا نَعَمْ قَالَ فَرَجَعَ فَأَتَمَّ مَا بَقِيَ ثُمَّ سَلَّمَ وَكَبَّرَ فَسَجَدَ طَوِيلًا ثُمَّ رَفَعَ رَأْسَهُ فَكَبَّرَ وَسَجَدَ مِثْلَ مَا سَجَدَ ثُمَّ رَفَعَ رَأْسَهُ وَانْصَرَفَ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Ibnu 'Aun] dari [Muhammad] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam shalat dari salah satu shalat ?Al 'Asyi (zhuhur dan asar), beliau shalat dua rakaat dan salam. Kemudian beliau berdiri menuju kayu yang membentang di masjid seraya meletakkan tangan di atas kayu tersebut -Yazid berkata, \"Ibnu 'Aun memperlihatkan kepada kami. Ia meletakkan salah satu telapak tangannya di atas punggung tangan yang lainnya, lalu memasukkan jari-jarinya yang di atas pada jari-jari yang di bawah-, beliau berdiri seolah-olah sedang marah.\" Abu Hurairah berkata, \"Lalu ada beberapa orang keluar dengan cepat, mereka mengatakan, 'Shalat telah diringkas, shalat telah diringkas.' Padahal di antara para sahabat tersebut terdapat Abu Bakr dan Umar, namun mereka tidak berbicara apa pun. Dan di antara mereka ada seorang laki-laki yang panjang kedua tangannya, ia biasa dipanggil Dzul Yadain, laki-laki itu berkata, \"Wahai Rasulullah, apakah anda lupa shalat atau shalat tersebut diringkas?\" Beliau lalu mengatakan: \"Aku tidak lupa dan shalatnya juga tidak diringkas.\" Setelah itu beliau bertanya: \"Apakah demikian?\" Orang-orang menjawab, \"Ya.\" Abu Hurairah berkata, \"Kemudian beliau kembali dan menyempurnakan shalat yang tersisa, selesai salam beliau takbir dan sujud lama, kemudian mengangkat kepalanya dan sujud seperti sujud yang pertama (lama). Kemudian beliau mengangkat kepalanya dan berlalu pergi.\" "},"1106":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنِي اللَّيْثُ حَدَّثَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي ابْنُ الْمُسَيَّبِ وَأَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ وَأَبُو بَكْرِ بْنُ عَبْدِ الرَّحْمَنِ وَعُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ أَنَّ أَبَا هُرَيْرَةَ قَالَ صَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةَ الظُّهْرِ أَوْ الْعَصْرِ فَسَلَّمَ فِي رَكْعَتَيْنِ مِنْ إِحْدَاهُمَا فَقَالَ لَهُ ذُو الشِّمَالَيْنِ بْنُ عَبْدِ عَمْرِو بْنِ نَضْلَةَ الْخُزَاعِيُّ وَهُوَ حَلِيفُ بَنِي زُهْرَةَ أَقُصِرَتْ أَمْ نَسِيتَ يَا رَسُولَ اللَّهِ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ أَنْسَ وَلَمْ تُقْصَرْ فَقَالَ ذُو الشِّمَالَيْنِ قَدْ كَانَ بَعْضُ ذَلِكَ يَا رَسُولَ اللَّهِ فَأَقْبَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى النَّاسِ فَقَالَ أَصَدَقَ ذُو الْيَدَيْنِ قَالُوا نَعَمْ يَا رَسُولَ اللَّهِ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَمَّ الصَّلَاةَ وَلَمْ يُحَدِّثْنِي أَحَدٌ مِنْهُمْ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَجَدَ سَجْدَتَيْنِ وَهُوَ جَالِسٌ فِي تِلْكَ الصَّلَاةِ وَذَلِكَ فِيمَا نُرَى وَاللَّهُ أَعْلَمُ مِنْ أَجْلِ أَنَّ النَّاسَ يَقَّنُوا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى اسْتَيْقَنَ","id":"Telah mengabarkan kepada kami [Abdullah bin Shalih] telah menceritakan kepadaku [Al Laits] telah menceritakan kepadaku [Yunus] dari [Ibnu Syihab] telah mengabarkan kepadaku [Ibnu Al Musayyab] dan [Abu Salamah bin Abdurrahman] dan [Abu Bakr bin Abdurrahman] dan ['Ubaidullah bin Abdullah] bahwa [Abu Hurairah] berkata, \"Rasulullah shallallahu 'alaihi wasallam melakukan shalat zhuhur atau asar, lalu beliau salam pada rakaat kedua di antara kedua shalat tersebut. Lalu Dzusy Syimalain bin 'Abdu 'Amru bin Nadllah Al Khuza'I -sekutu Bani Zuhrah- berkata, \"Wahai Rasulullah, apakah shalat tersebut diringkas atau anda yang lupa?\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku tidak lupa dan shalat tersebut juga tidak diringkas.\" Kemudian Dzusy Syimalain berkata, \"Wahai Rasulullah, sebagian (yang engkau katakan) itu telah terjadi! \" Kemudian Rasulullah shallallahu 'alaihi wasallam menghadap kepada orang-orang dan berkata: \"Apakah Dzul Yadain berkata jujur?\" Mereka menjawab, \"Benar wahai Rasulullah! \" Rasulullah shallallahu 'alaihi wasallam lalu berdiri menyempurnakan shalat, dan tidak seorangpun di antara mereka menceritakan kepadaku bahwa saat itu Rasulullah shallallahu 'alaihi wasallam sujud dua kali dalam keadaan duduk. Dan hal tersebut dalam perkara yang diperlihatkan kepada kami. Wallahu a'lam, karena orang-orang telah meyakinkan Rasulullah shallallahu 'alaihi wasallam hingga beliau merasa yakin.\""},"1107":{"ar":" حَدَّثَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ شُعْبَةَ عَنْ الْحَكَمِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ صَلَّى الظُّهْرَ خَمْسًا فَقِيلَ لَهُ فَسَجَدَ سَجْدَتَيْنِ","id":"Telah menceritakan kepada kami [Sa'id? bin 'Amir] dari [Syu'bah] dari [Al Hakam] dari [Ibrahim] dari ['Alqamah] dari [Abdullah] dari Nabi shallallahu 'alaihi wasallam, bahwa beliau pernah melaksanakan shalat zhuhur lima rakaat, kemudian hal itu diberitahukan kepadanya hingga beliau pun sujud dua kali.\" "},"1108":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ الْمَجِيدِ حَدَّثَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ هُرْمُزَ الْأَعْرَجِ عَنْ ابْنِ بُحَيْنَةَ قَالَ صَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَكْعَتَيْنِ ثُمَّ قَامَ وَلَمْ يَجْلِسْ وَقَامَ النَّاسُ فَلَمَّا قَضَى الصَّلَاةَ نَظَرْنَا تَسْلِيمَهُ فَكَبَّرَ فَسَجَدَ سَجْدَتَيْنِ وَهُوَ جَالِسٌ قَبْلَ أَنْ يُسَلِّمَ ثُمَّ سَلَّمَ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Abdul Majid] telah menceritakan kepada kami [Malik] dari [Ibnu Syihab] dari [Abdurrahman bin Hurmuz Al A'raj] dari [Ibnu Buhainah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam shalat bersama kami dua rakaat, kemudian berdiri dan tidak duduk hingga orang-orang pun berdiri. Ketika beliau menyelesaikan shalat, kami melihat salam beliau, lalu beliau takbir dan sujud dua kali dalam keadaan duduk sebelum mengucapkan salam, kemudian beliau mengucapkan salam.\" "},"1109":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ الْفَضْلِ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَبْدِ الرَّحْمَنِ الْأَعْرَجِ عَنْ مَالِكِ ابْنِ بُحَيْنَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَامَ فِي الرَّكْعَتَيْنِ مِنْ الظُّهْرِ أَوْ الْعَصْرِ فَلَمْ يَرْجِعْ حَتَّى فَرَغَ مِنْ صَلَاتِهِ ثُمَّ سَجَدَ سَجْدَتَيْ الْوَهْمِ ثُمَّ سَلَّمَ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Fadlal] telah menceritakan kepada kami [Hammad bin Salamah] dari [Yahya bin Sa'id] dari [Abdurrahman Al A'raj] dari [Malik bin Buhainah], bahwa Rasulullah shallallahu 'alaihi wasallam berdiri pada dua rakaat saat mengerjakan shalat zhuhur atau asar, dan tidak kembali (duduk untuk tasyahud) hingga selesai dari shalatnya. Kemudian beliau sahwi dengan dua kali sujud, lalu mengucapkan salam.\" "},"1110":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ عَنْ الْمَسْعُودِيِّ عَنْ زِيَادِ بْنِ عِلَاقَةَ قَالَ صَلَّى بِنَا الْمُغِيرَةُ بْنُ شُعْبَةَ فَلَمَّا صَلَّى رَكْعَتَيْنِ قَامَ وَلَمْ يَجْلِسْ فَسَبَّحَ بِهِ مَنْ خَلْفَهُ فَأَشَارَ إِلَيْهِمْ أَنْ قُومُوا فَلَمَّا فَرَغَ مِنْ صَلَاتِهِ سَلَّمَ وَسَجَدَ سَجْدَتَيْ السَّهْوِ وَسَلَّمَ وَقَالَ هَكَذَا صَنَعَ بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَزِيدُ يُصَحِّحُونَهُ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] dari [Al Mas'udi] dari [Ziyad bin 'Ilaqah] ia berkata, [Al Mughirah bin Syu'bah] shalat bersama kami, kemudian ketika telah mendapatkan dua rakaat ia berdiri dan tidak duduk (untuk tasyahud), sehingga orang-orang yang di belakangnya mengucapkan tasbih. Tetapi ia memberikan isyarat kepada mereka agar berdiri, maka telah selesai ia mengucapkan salam dan sujud sahwi dengan dua kali sujud, lalu mengucapkan salam seraya mengatakan, \"Demikianlah yang Rasulullah shallallahu 'alaihi wasallam lakukan bersama kami.\" Yazid berkata, \"Orang-orang pun membenarkannya.\" "},"1111":{"ar":" حَدَّثَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ يَحْيَى عَنْ هِلَالِ بْنِ أَبِي مَيْمُونَةَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ مُعَاوِيَةَ بْنِ الْحَكَمِ السُّلَمِيِّ قَالَ بَيْنَا أَنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الصَّلَاةِ إِذْ عَطَسَ رَجُلٌ مِنْ الْقَوْمِ فَقُلْتُ يَرْحَمُكَ اللَّهُ قَالَ فَحَدَّقَنِي الْقَوْمُ بِأَبْصَارِهِمْ فَقُلْتُ وَا ثُكْلَاهُ مَا لَكُمْ تَنْظُرُونَ إِلَيَّ قَالَ فَضَرَبَ الْقَوْمُ بِأَيْدِيهِمْ عَلَى أَفْخَاذِهِمْ فَلَمَّا رَأَيْتُهُمْ يُسْكِتُونَنِي قُلْتُ مَا لَكُمْ تُسْكِتُونَنِي لَكِنِّي سَكَتُّ قَالَ فَلَمَّا انْصَرَفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبِأَبِي هُوَ وَأُمِّي مَا رَأَيْتُ مُعَلِّمًا قَبْلَهُ وَلَا بَعْدَهُ أَحْسَنَ تَعْلِيمًا مِنْهُ وَاللَّهِ مَا ضَرَبَنِي وَلَا كَهَرَنِي وَلَا سَبَّنِي وَلَكِنْ قَالَ إِنَّ صَلَاتَنَا هَذِهِ لَا يَصْلُحُ فِيهَا شَيْءٌ مِنْ كَلَامِ النَّاسِ إِنَّمَا هِيَ التَّسْبِيحُ وَالتَّكْبِيرُ وَتِلَاوَةُ الْقُرْآنِ حَدَّثَنَا صَدَقَةُ أَخْبَرَنَا ابْنُ عُلَيَّةَ وَيَحْيَى بْنُ سَعِيدٍ عَنْ حَجَّاجٍ الصَّوَّافِ عَنْ يَحْيَى عَنْ هِلَالٍ عَنْ عَطَاءٍ عَنْ مُعَاوِيَةَ بِنَحْوِهِ","id":"Telah menceritakan kepada kami [Abu Al Mughirah] telah menceritakan kepada kami [Al Auza'i] dari [Yahya] dari [Hilal bin Abu Maimunah] dari ['Atha` bin Yasar] dari [Mu'awiyah bin Al Hakam As Sulami] ia berkata, \"Ketika aku bersama Rasulullah shallallahu 'alaihi wasallam sedang mengerjakan shalat, tiab-tiab ada seseorang yang bersin, lalu aku mengucapkan 'YARHAMUKALLAAH.'\" Mu'awiyah berkata, \"Kemudian orang-orang melihat tajam kepadaku dengan mata mereka. Aku lalu berkata, \"Aduhai, kenapa kalian melihat kepadaku?\" Mu'awiyah berkata, \"Kemudian orang-orang tersebut memukul paha mereka menggunakan tangan mereka. Saat aku melihat, ternyata mereka menyuruhku diam. Maka aku katakan, 'Kenapa kalian menyuruh aku diam? ' Akan tetapi aku telah diam.\" Mu'awiyah berkata, \"Ketika Rasulullah shallallahu 'alaihi wasallam selesai shalat, maka debi bapak dan ibuku, aku tidak pernah melihat seorang pengajar sebelum dan setelahnya yang lebih baik dari beliau. Demi Allah! Beliau tidak memukulku, tidak membentak dan tidak mencelaku, akan tetapi beliau berkata: \"Sungguh, shalat kita ini tidak layak jika diselingi dengan perkataan manusia. Sesungguhnya shalat tersebut adalah tasbih, takbir dan membaca Al Qur'an.\" Telah menceritakan kepada kami [Shadaqah] telah mengabarkan kepada kami [Ibnu 'Ulayyah] dan [Yahya bin Sa'd] dari [Hajjaj Ash Shawwaf] dari [Yahya] dari [Hilal] dari ['Atha`] dari [Mu'awiyah] dengan hadits seperti itu.\" "},"1112":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا هِشَامٌ عَنْ يَحْيَى عَنْ ضَمْضَمٍ عَنْ أَبِي هُرَيْرَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ بِقَتْلِ الْأَسْوَدَيْنِ فِي الصَّلَاةِ قَالَ يَحْيَى وَالْأَسْوَدَيْنِ الْحَيَّةُ وَالْعَقْرَبُ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Hisyam] dari [Yahya] dari [Dlamdlam] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam memerintahkan untuk membunuh ?Al Aswadaini dalam shalat.\" Yahya berkata, \"Al Aswadaini adalah ular dan kalajengking.\" "},"1113":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ عَنْ ابْنِ أَبِي عَمَّارٍ عَنْ عَبْدِ اللَّهِ بْنِ بَابَيْهِ عَنْ يَعْلَى بْنِ أُمَيَّةَ قَالَ قُلْتُ لِعُمَرَ بْنِ الْخَطَّابِ قَالَ اللَّهُ تَعَالَى { أَنْ تَقْصُرُوا مِنْ الصَّلَاةِ إِنْ خِفْتُمْ } فَقَدْ أَمِنَ النَّاسُ قَالَ عَجِبْتُ مِمَّا عَجِبْتَ مِنْهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَدَقَةٌ تَصَدَّقَ اللَّهُ بِهَا عَلَيْكُمْ فَاقْبَلُوهَا","id":"Telah mengabarkan kepada kami [Abu 'Ashim] dari [Ibnu Juraij] dari [Ibnu Abu 'Ammar] dari [Abdullah bin Babaih] dari [Ya'la bin Umayyah] ia berkata, \"Aku katakan kepada [Umar bin Al Khathab, \"Allah Ta'ala berfirman: '(Kamu men-qashar sembahyang(mu), jika kamu takut) ' (Qs. An Nisa: 101). Sementara orang-orang sekarang telah merasa aman?\" Umar menjawab, \"Aku juga pernah heran sebagaimana engkau heran. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Itu adalah sedekah yang telah Allah berikan kepada kalian, maka terimalah sedekah-Nya.\""},"1114":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ الْأَوْزَاعِيِّ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى بِمِنًى رَكْعَتَيْنِ وَأَبُو بَكْرٍ رَكْعَتَيْنِ وَعُمَرُ رَكْعَتَيْنِ وَعُثْمَانُ رَكْعَتَيْنِ صَدْرًا مِنْ إِمَارَتِهِ ثُمَّ أَتَمَّهَا بَعْدَ ذَلِكَ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Al Auza'i] dari [Az Zuhri] dari [Salim] dari [Ayahnya], bahwa Rasulullah shallallahu 'alaihi wasallam mengerjakan shalat dua rakaat di Mina, Abu Bakr dua rakaat, Umar dua rakaat, dan Utsman dua rakaat di awal pemerintahannya, kemudian ia menyempurnakannya setelah itu.\" "},"1115":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَ صَلَّيْنَا الظُّهْرَ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْمَدِينَةِ أَرْبَعًا وَصَلَّيْنَا مَعَهُ بِذِي الْحُلَيْفَةِ رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Muhammad bin Al Munkadir] dari [Anas bin Malik] ia berkata, \"Di Madinah kami shalat zhuhur bersama Nabi shallallahu 'alaihi wasallam empat rakaat, dan di Dzul Hulaifah kami shalat bersama beliau dua rakaat.\" "},"1116":{"ar":" حَدَّثَنَا عُثْمَانُ بْنُ مُحَمَّدٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ إِبْرَاهِيمَ بْنِ مَيْسَرَةَ وَمُحَمَّدِ بْنِ الْمُنْكَدِرِ أَنَّهُمَا سَمِعَا أَنَسَ بْنَ مَالِكٍ يَقُولُ صَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْمَدِينَةِ أَرْبَعًا وَبِذِي الْحُلَيْفَةِ رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami [Utsman bin Muhammad] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Ibrahim bin Maisarah] dan [Muhammad bin Al Munkadir] bahwa keduanya mendengar [Anas bin Malik] berkata, \"Rasulullah shallallahu 'alaihi wasallam mengerjakan shalat di Madinah empat rakaat dan di Dzul Hulaifah dua rakaat.\" "},"1117":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ قَالَ سَمِعْتُ الزُّهْرِيَّ يَذْكُرُ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ قَالَتْ إِنَّ الصَّلَاةَ أَوَّلَ مَا فُرِضَتْ رَكْعَتَيْنِ فَأُقِرَّتْ صَلَاةُ السَّفَرِ وَأُتِمَّتْ صَلَاةُ الْحَضَرِ فَقُلْتُ مَا لَهَا كَانَتْ تُتِمُّ الصَّلَاةَ فِي السَّفَرِ قَالَ إِنَّهَا تَأَوَّلَتْ كَمَا تَأَوَّلَ عُثْمَانُ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan bin 'Uyainah] ia berkata, aku mendengar [Az Zuhri] menyebutkan dari ['Urwah bin Az Zubair] dari [Aisyah] ia berkata, \"Sesungguhnya shalat pertama kali diwajibkan adalah dua rakaat, kemudian ditetapkan sebagai shalat safar dan shalat disempurnakan ketika bermukim.\" Kemudian aku katakan, \"Kenapa Aisyah menyempurnakan shalat di saat melakukan safar?\" Az Zuhri menjawab, \"Ia mentakwil (memahami tidak seperti zhahirnya hadits) sebagaimana Utsman mentakwil.\""},"1118":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ يَحْيَى هُوَ ابْنُ أَبِي إِسْحَقَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَ خَرَجْنَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَعَلَ يَقْصُرُ حَتَّى قَدِمْنَا مَكَّةَ فَأَقَامَ بِهَا عَشَرَةَ أَيَّامٍ يَقْصُرُ حَتَّى رَجَعَ وَذَلِكَ فِي حَجِّهِ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Yahya] -yaitu Ibnu Abu Ishaq- dari [Anas bin Malik] ia berkata, \"Kami pernah keluar bersama Nabi shallallahu 'alaihi wasallam, kemudian beliau mengqashar (shalat) hingga kami sampai di Makkah, beliau bermukim di sana selama sepuluh hari, dan beliau tetap mengqashar shalat hingga kembali. Hal itu terjadi pada saat beliau haji.\""},"1119":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ عَنْ إِسْمَعِيلَ بْنِ مُحَمَّدٍ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ عَنْ السَّائِبِ بْنِ يَزِيدَ عَنْ الْعَلَاءِ بْنِ الْحَضْرَمِيِّ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُكْثُ الْمُهَاجِرِ بَعْدَ قَضَاءِ نُسُكِهِ ثَلَاثٌ","id":"Telah mengabarkan kepada kami [Abu 'Ashim] dari [Ibnu Juraij] dari [Isma'il bin Muhammad] dari [Humaid bin Abdurrahman bin 'Auf] dari [As Sa`ib bin Yazid] dari [Al 'Ala` bin Al Hadlrami] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang hijrah boleh tinggal di Makkah selama tiga hari setelah ibadah hajinya selesai.\" "},"1120":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا حَفْصٌ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ عَنْ السَّائِبِ بْنِ يَزِيدَ عَنْ الْعَلَاءِ بْنِ الْحَضْرَمِيِّ قَالَ رَخَّصَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلْمُهَاجِرِينَ أَنْ يُقِيمُوا ثَلَاثًا بَعْدَ الصَّدَرِ بِمَكَّةَ قَالَ أَبُو مُحَمَّد أَقُولُ بِهِ","id":"Telah menceritakan kepada kami [Abdullah bin Sa'id] telah menceritakan kepada kami [Hafsh] telah menceritakan kepada kami [Abdurrahman bin Humaid bin Abdurrahman bin 'Auf] dari [As Sa`ib bin Yazid] dari [Al 'Ala` bin Al Hadlrami] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam memberikan rukhshah bagi orang-orang untuk bermukim selama tiga hari setelah sampai di Makkah.\" Abu Muhammad berkata, \"Aku berpendapat seperti itu.\" "},"1121":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا هِشَامٌ الدَّسْتَوَائِيُّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ ثَوْبَانَ عَنْ جَابِرٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي عَلَى رَاحِلَتِهِ نَحْوَ الْمَشْرِقِ فَإِذَا أَرَادَ أَنْ يُصَلِّيَ الْمَكْتُوبَةَ نَزَلَ فَاسْتَقْبَلَ الْقِبْلَةَ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Hisyam Ad Dastawai] dari [Yahya bin Abu Katsir] dari [Muhammad bin Abdurrahman bin Tsauban] dari [Jabir], bahwa Rasulullah shallallahu 'alaihi wasallam melakukan shalat di atas kendaraannya menghadap ke timur, apabila beliau hendak melakukan shalat wajib beliau turun dan menghadap ke kiblat.\" "},"1122":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنِي اللَّيْثُ حَدَّثَنِي عُقَيْلٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ عَامِرِ بْنِ رَبِيعَةَ أَنَّ عَامِرَ بْنَ رَبِيعَةَ قَالَ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُسَبِّحُ وَهُوَ عَلَى الرَّاحِلَةِ وَيُومِي بِرَأْسِهِ قِبَلَ أَيِّ وَجْهٍ تَوَجَّهَ وَلَمْ يَكُنْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصْنَعُ ذَلِكَ فِي الصَّلَاةِ الْمَكْتُوبَةِ","id":"Telah mengabarkan kepada kami [Abdullah bin Shalih] telah menceritakan kepadaku [Al Laits] telah menceritakan kepadaku ['Uqail] dari [Az Zuhri] ia berkata, telah mengabarkan kepadaku [Abdullah bin 'Amir bin Rabi'ah] bahwa ['Amir bin Rabi'ah] berkata, \"Aku melihat Rasulullah shallallahu 'alaihi wasallam melakukan shalat sementara beliau berada di atas kendaraannya, beliau memberikan isyarat menggunakan kepalanya ke arah manapun beliau mengarah, namun Rasulullah shallallahu 'alaihi wasallam tidak pernah melakukan hal itu pada shalat wajib.\" "},"1123":{"ar":" أَخْبَرَنَا أَبُو عَلِيٍّ الْحَنَفِيُّ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ أَبِي الزُّبَيْرِ الْمَكِّيِّ أَنَّ أَبَا الطُّفَيْلِ عَامِرَ بْنَ وَاثِلَةَ أَخْبَرَهُ أَنَّ مُعَاذَ بْنَ جَبَلٍ أَخْبَرَهُ قَالَ خَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَ غَزْوَةِ تَبُوكَ وَكَانَ يَجْمَعُ الصَّلَاةَ فَصَلَّى الظُّهْرَ وَالْعَصْرَ جَمِيعًا ثُمَّ دَخَلَ ثُمَّ خَرَجَ بَعْدَ ذَلِكَ فَصَلَّى الْمَغْرِبَ وَالْعِشَاءَ جَمِيعًا","id":"Telah mengabarkan kepada kami [Abu Ali Al Hanafi] telah menceritakan kepada kami [Malik bin Anas] dari [Abu Az Zubair Al Makki] bahwa [Abu Ath Thufail 'Amir bin Watsilah] telah mengabarkan kepadanya, bahwa [Mu'adz bin Jabal] telah mengabarkan kepadanya, ia berkata, \"Kami keluar bersama Rasulullah shallallahu 'alaihi wasallam di tahun terjadinya perang Tabuk. Beliau menjamak shalat, beliau kerjakan shalat zhuhur dan asar secara jamak, beliau kemudian masuk dan keluar lagi setelah itu, lalu beliau shalat Maghrib dan Isya secara jamak.\""},"1124":{"ar":" حَدَّثَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَدِيِّ بْنِ ثَابِتٍ عَنْ عَبْدِ اللَّهِ بْنِ يَزِيدَ الْخَطْمِيِّ عَنْ أَبِي أَيُّوبَ الْأَنْصَارِيِّ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى الْمَغْرِبَ وَالْعِشَاءَ بِجَمْعٍ فَجَمَعَ بَيْنَهُمَا","id":"Telah menceritakan kepada kami [Yahya bin Hassan] telah menceritakan kepada kami [Hammad bin Zaid] dari [Yahya bin Sa'id] dari [Adi bin Tsabit] dari [Abdullah bin Yazid Al Khathmi] dari [Abu Ayyub Al Anshari], bahwa Rasulullah shallallahu 'alaihi wasallam melakukan Maghrib serta Isya secara jamak, beliau pun menjamak antara keduanya.\" "},"1125":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَجْمَعُ بَيْنَ الْمَغْرِبِ وَالْعِشَاءِ إِذَا جَدَّ بِهِ السَّيْرُ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Ibnu 'Uyainah] dari [Az Zuhri] dari [Salim] dari [Abdullah bin Umar], bahwa Rasulullah shallallahu 'alaihi wasallam menjamak antara Maghrib dan Isya jika akan segera berangkat (untuk safar).\""},"1126":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا شُعْبَةُ أَخْبَرَنِي الْحَكَمُ وَسَلَمَةُ بْنُ كُهَيْلٍ قَالَا صَلَّى بِنَا سَعِيدُ بْنُ جُبَيْرٍ بِجَمْعٍ بِإِقَامَةٍ الْمَغْرِبَ ثَلَاثًا فَلَمَّا سَلَّمَ قَامَ فَصَلَّى رَكْعَتَيْنِ الْعِشَاءَ ثُمَّ حَدَّثَ عَنْ ابْنِ عُمَرَ أَنَّهُ صَنَعَ بِهِمْ فِي ذَلِكَ الْمَكَانِ مِثْلَ ذَلِكَ وَحَدَّثَ ابْنُ عُمَرَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَنَعَ فِي ذَلِكَ الْمَكَانِ مِثْلَ ذَلِكَ حَدَّثَنَا سَعِيدُ بْنُ الرَّبِيعِ قَالَ حَدَّثَنَا شُعْبَةُ بِإِسْنَادِهِ نَحْوَهُ","id":"Telah mengabarkan kepada kami [Abu Al Walid Ath Thayalisi] telah menceritakan kepada kami [Syu'bah] telah mengabarkan kepadaku [Al Hakam] dan [Salamah bin Kuhail] mereka berkata, \" [Sa'id bin Jubair] shalat bersama kami secara jamak, ia mengerjakan shalat maghrib sebanyak tiga rakaat, setelah salam ia berdiri dan shalat dua rakaat isya. Setelah itu ia menceritakan dari Ibnu Umar, bahwa ia pernah melakukan yang seperti itu bersama mereka di tempat itu juga, dan [Ibnu Umar] menceritakan bahwa Rasulullah shallallahu 'alaihi wasallam juga melakukan hal yang seperti itu di tempat tersebut.\" Telah menceritakan kepada kami [Sa'id? bin Ar Rabi'] ia berkata, telah menceritakan kepada kami [Syu'bah] dengan sanadnya seperti itu.\" "},"1127":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ عَنْ ابْنِ شِهَابٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ اللَّهِ بْنِ كَعْبِ بْنِ مَالِكٍ عَنْ أَبِيهِ عَبْدِ اللَّهِ وَعَمِّهِ عُبَيْدِ اللَّهِ ابْنَيْ كَعْبٍ عَنْ كَعْبِ بْنِ مَالِكٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ لَا يَقْدَمُ مِنْ سَفَرٍ إِلَّا بِالنَّهَارِ ضُحًى ثُمَّ يَدْخُلُ الْمَسْجِدَ فَيُصَلِّي رَكْعَتَيْنِ ثُمَّ يَجْلِسُ لِلنَّاسِ","id":"Telah mengabarkan kepada kami [Abu 'Ashim] dari [Ibnu Juraij] dari [Ibnu Syihab] dari [Abdurrahman bin Abdullah bin Ka'b bin Malik] dari ayahnya [Abdullah] dan pamannya ['Ubaidullah] dua anak Ka'b, dari [Ka'b bin Malik], bahwa Rasulullah shallallahu 'alaihi wasallam tidak pernah kembali dari safar melainkan pada siang hari di waktu dluha, beliau kemudian masuk masjid dan shalat dua rakaat, kemudian duduk bersama orang-orang.\" "},"1128":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ نَافِعٍ عَنْ شُعَيْبٍ عَنْ الزُّهْرِيِّ أَخْبَرَنِي سَالِمُ بْنُ عَبْدِ اللَّهِ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ قَالَ غَزَوْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَزْوَةً قِبَلَ نَجْدٍ فَوَازَيْنَا الْعَدُوَّ وَصَافَفْنَاهُمْ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي لَنَا فَقَامَ طَائِفَةٌ مِنَّا مَعَهُ وَأَقْبَلَ طَائِفَةٌ عَلَى الْعَدُوِّ فَرَكَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَنْ مَعَهُ رَكْعَةً وَسَجْدَتَيْنِ ثُمَّ انْصَرَفُوا فَكَانُوا مَكَانَ الطَّائِفَةِ الَّتِي لَمْ تُصَلِّ وَجَاءَتْ الطَّائِفَةُ الَّتِي لَمْ تُصَلِّ فَرَكَعَ بِهِمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَكْعَةً وَسَجْدَتَيْنِ ثُمَّ سَلَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَامَ كُلُّ رَجُلٍ مِنْ الْمُسْلِمِينَ فَرَكَعَ لِنَفْسِهِ رَكْعَةً وَسَجْدَتَيْنِ","id":"Telah mengabarkan kepada kami [Al Hakam bin Nafi'] dari [Syu'aib] dari [Az Zuhri] telah mengabarkan kepadaku [Salim bin Abdullah] bahwa [Abdullah bin Umar] berkata, \"Aku pernah mengikuti peperangan bersama Rasulullah shallallahu 'alaihi wasallam menuju Najd, kemudian kami berhadapan dengan musuh dan berbaris untuk menghadapi mereka. Kemudian Rasulullah shallallahu 'alaihi wasallam berdiri melakukan shalat bersama kami. Lalu sekelompok di antara kami bersama beliau dan kelompok yang lain menghadap musuh. Rasulullah shallallahu 'alaihi wasallam shalat dengan satu rukuk dan dua sujud bersama orang-orang yang bersamanya, kemudian mereka pergi menempati posisi kelompok yang belum melakukan shalat. Dan kelompok yang belum shalat datang, kemudian beliau rukuk bersama mereka satu kali dan sujud dua kali. Kemudian beliau mengucapkan salam, lalu setiap orang dari muslimin berdiri dan melakukan rukuk sendiri satu kali dan bersujud dua kali.\" "},"1129":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ يَحْيَى بْنِ سَعِيدٍ الْأَنْصَارِيِّ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ صَالِحِ بْنِ خَوَّاتٍ عَنْ سَهْلِ بْنِ أَبِي حَثْمَةَ فِي صَلَاةِ الْخَوْفِ قَالَ يُصَلِّي الْإِمَامُ بِطَائِفَةٍ وَطَائِفَةٌ مُوَاجِهَةُ الْعَدُوِّ فَيُصَلِّي بِالَّذِينَ مَعَهُ رَكْعَةً وَيَذْهَبُ هَؤُلَاءِ إِلَى مَصَافِّ أَصْحَابِهِمْ وَيَجِيءُ أُولَئِكَ فَيُصَلِّي بِهِمْ رَكْعَةً وَيَقْضُونَ رَكْعَةً لِأَنْفُسِهِمْ حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى عَنْ شُعْبَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ صَالِحِ بْنِ خَوَّاتٍ عَنْ سَهْلِ بْنِ أَبِي حَثْمَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Yahya bin Sa'id Al Anshari] dari [Al Qasim bin Muhammad] dari [Shalih bin Khawwat] dari [Sahl bin Abu Hatsmah] tentang shalat Khauf, ia berkata, \"Seorang imam melakukan shalat bersama satu kelompok sementara kelompok yang lain menghadapi musuh. Kemudian imam tersebut melakukan shalat bersama orang-orang yang bersamanya satu rakaat, kemudian mereka pergi menuju barisan para sahabat mereka, dan mereka (kelompok yang belum shalat) datang, kemudian imam shalat bersama mereka satu rakaat, sementara mereka menyelesaikan sendiri satu rakaat.\" Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Yahya] dari [Syu'bah] dari [Abdurrahman bin Al Qasim] dari [Ayahnya] dari [Shalih bin Khawwat] dari [Sahl bin Abu Hatsmah] dari Nabi shallallahu 'alaihi wasallam seperti itu.\" "},"1130":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ الْمَقْبُرِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي سَعِيدٍ الْخُدْرِيِّ عَنْ أَبِيهِ قَالَ حُبِسْنَا يَوْمَ الْخَنْدَقِ حَتَّى ذَهَبَ هَوِيٌّ مِنْ اللَّيْلِ حَتَّى كُفِينَا وَذَلِكَ قَوْلُ اللَّهِ تَعَالَى { وَكَفَى اللَّهُ الْمُؤْمِنِينَ الْقِتَالَ وَكَانَ اللَّهُ قَوِيًّا عَزِيزًا } فَدَعَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِلَالًا فَأَمَرَهُ فَأَقَامَ فَصَلَّى الظُّهْرَ فَأَحْسَنَ كَمَا كَانَ يُصَلِّيهَا فِي وَقْتِهَا ثُمَّ أَمَرَهُ فَأَقَامَ الْعَصْرَ فَصَلَّاهَا ثُمَّ أَمَرَهُ فَأَقَامَ الْمَغْرِبَ فَصَلَّاهَا ثُمَّ أَمَرَهُ فَأَقَامَ الْعِشَاءَ فَصَلَّاهَا وَذَلِكَ قَبْلَ أَنْ يَنْزِلَ { فَإِنْ خِفْتُمْ فَرِجَالًا أَوْ رُكْبَانًا }","id":"Telah mengabarkan kepada kami [Yazid bin Harun] dari [Ibnu Abu Dzi`b] dari [Al Maqburi] dari [Abdurrahman bin Abu Sa'id Al Khudri] dari [Ayahnya] ia berkata, \"Kami tertahan pada saat perang Khandaq hingga berlalu sebagian malam hingga kami dihindarkan dari peperangan, dan hal tersebut sebagaimana yang Allah firmankan: '(Dan Allah menghindarkan orang-orang mukmin dari peperangan. Dan adalah Allah Maha Kuat lagi Maha Perkasa) ' (Qs.?Al Ahzab: 25). Kemudian Nabi shallallahu 'alaihi wasallam memanggil Bilal dan memerintahkannya agar mengumandangkan iqamah. Beliau lalu mengerjakan shalat Zhuhur dan melakukannya dengan baik sebagaimana biasa beliau melakukannya pada waktunya, kemudian memerintahkannya untuk mengumandangkan iqamah shalat Asar, lalu beliau mengerjakan shalat Asar. Kemudian memerintahkannya untuk mengumandangkan iqamah shalat Maghrib, lalu beliau mengerjakan shalat Maghrib, kemudian memerintahkannya untuk mengumandangkan iqamah shalat Isya, lalu beliau mengerjakan shalat Isya. Dan itu sebelum turunnya ayat: '(Jika kamu dalam keadaan takut (bahaya), maka shalatlah sambil berjalan atau berkendaraan…) ' (QS. Al Baqarah: 139)."},"1131":{"ar":" حَدَّثَنَا يَعْلَى حَدَّثَنَا إِسْمَعِيلُ عَنْ قَيْسٍ عَنْ أَبِي مَسْعُودٍ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الشَّمْسَ وَالْقَمَرَ لَيْسَا يَنْكَسِفَانِ لِمَوْتِ أَحَدٍ مِنْ النَّاسِ وَلَكِنَّهُمَا آيَتَانِ مِنْ آيَاتِ اللَّهِ فَإِذَا رَأَيْتُمُوهُمَا فَقُومُوا فَصَلُّوا","id":"Telah menceritakan kepada kami [Ya'la] telah menceritakan kepada kami [Isma'il] dari [Qais] dari [Abu Mas'ud] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya Matahari dan bulan tidak mengalami gerhana karena kematian seseorang, tetapi keduanya adalah dua tanda di antara tanda-tanda kekuasaan Allah, apabila kalian melihatnya maka bangkit dan lakukanlah shalat.\""},"1132":{"ar":" أَخْبَرَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ الْمَدِينِيُّ وَمُسَدَّدٌ قَالَا حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ عَنْ سُفْيَانَ بْنِ سَعِيدٍ حَدَّثَنِي حَبِيبُ بْنُ أَبِي ثَابِتٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى فِي كُسُوفٍ ثَمَانَ رَكَعَاتٍ فِي أَرْبَعِ سَجَدَاتٍ","id":"Telah mengabarkan kepada kami [Ali bin Abdullah Al Madini] serta [Musaddad] mereka berkata; telah menceritakan kepada kami [Yahya bin Sa'id Al Qaththan] dari [Sufyan bin Sa'id] telah menceritakan kepadaku [Habib bin Abu Tsabit] dari [Thawus] dari [Ibnu Abbas], bahwa Nabi shallallahu 'alaihi wasallam melakukan shalat gerhana delapan rukuk pada empat sujud.\" "},"1133":{"ar":" حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عَمْرَةَ بِنْتِ عَبْدِ الرَّحْمَنِ عَنْ عَائِشَةَ أَنَّ يَهُودِيَّةً دَخَلَتْ عَلَيْهَا فَقَالَتْ أَعَاذَكِ اللَّهُ مِنْ عَذَابِ الْقَبْرِ فَلَمَّا جَاءَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَأَلَتْهُ أَيُعَذَّبُ النَّاسُ فِي قُبُورِهِمْ قَالَ عَائِذٌ بِاللَّهِ قَالَتْ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَكِبَ يَوْمًا مَرْكَبًا فَخَسَفَتْ الشَّمْسُ فَجَاءَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَزَلَ ثُمَّ عَمَدَ إِلَى مَقَامِهِ الَّذِي كَانَ يُصَلِّي فِيهِ فَقَامَ النَّاسُ خَلْفَهُ فَأَطَالَ الْقِيَامَ ثُمَّ رَكَعَ فَأَطَالَ الرُّكُوعَ ثُمَّ رَفَعَ فَأَطَالَ الْقِيَامَ وَهُوَ دُونَ الْقِيَامِ الْأَوَّلِ ثُمَّ رَكَعَ فَأَطَالَ الرُّكُوعَ وَهُوَ دُونَ الرُّكُوعِ الْأَوَّلِ ثُمَّ سَجَدَ سَجْدَتَيْنِ ثُمَّ قَامَ فَفَعَلَ مِثْلَ ذَلِكَ ثُمَّ تَجَلَّتْ الشَّمْسُ فَدَخَلَ عَلَيَّ فَقَالَ إِنِّي أُرَاكُمْ تُفْتَنُونَ فِي قُبُورِكُمْ كَفِتْنَةِ الدَّجَّالِ سَمِعْتُهُ يَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ عَذَابِ الْقَبْرِ وَأَعُوذُ بِكَ مِنْ عَذَابِ النَّارِ","id":"Telah menceritakan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Hammad bin Zaid] telah menceritakan kepada kami [Yahya bin Sa'id] dari ['Amrah binti Abdurrahman] dari [Aisyah], bahwa seorang wanita Yahudi menemuinya dan berkata, \"Semoga Allah melindungimu dari siksa kubur.\" Kemudian tatkala Nabi shallallahu 'alaihi wasallam datang ia bertanya kepada beliau, \"Apakah manusia disiksa dalam kuburan mereka?\" Beliau menjawab: \"Aku berlindung kepada Allah dari siksa kubur.\" Aisyah berkata, \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam pernah suatu hari mengendarai kendaraan, kemudian terjadi gerhana matahari. Lalu Nabi shallallahu 'alaihi wasallam datang dan turun dari kendaraannya dan menuju tempat beliau melakukan shalat. Orang-orang lalu berdiri di belakang beliau, beliau lalu berdiri lama, kemudian rukuk dan memperlama rukuknya, kemudian mengangkat kepala dari rukuk dan memperlama berdiri, namun tidak seperti berdirinya yang pertama. Kemudian beliau rukuk lagi dan memperlama rukuknya, namun tidak seperti rukuknya yang pertama, kemudian sujud dua kali, kemudian berdiri dan melakukan seperti itu hingga matahari muncul. Setelah itu beliau menemuiku dan berkata: \"Seseungguhnya aku melihat kalian sedang difitnah dalam kubur kalian seperti fitnah Dajjal.\" Aku mendengar beliau mengucapkan: \"ALLAAHUMMA INNII A'UUDZU BIKA MIN 'ADZAABIL QABRI WA A'UUDZU BIKA MIN 'ADZAABIN NAARI (Ya Allah, aku berlindung kepada-Mu dari siksa kubur, dan aku berlindung kepada-Mu dari siksa neraka).\" "},"1134":{"ar":" حَدَّثَنَا أَبُو يَعْقُوبَ يُوسُفُ الْبُوَيْطِيُّ عَنْ مُحَمَّدِ بْنِ إِدْرِيسَ هُوَ الشَّافِعِيُّ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ ابْنِ عَبَّاسٍ قَالَ خَسَفَتْ الشَّمْسُ فَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَحَكَى ابْنُ عَبَّاسٍ أَنَّ صَلَاتَهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَكْعَتَيْنِ فِي كُلِّ رَكْعَةٍ رَكْعَتَيْنِ ثُمَّ خَطَبَهُمْ فَقَالَ إِنَّ الشَّمْسَ وَالْقَمَرَ آيَتَانِ مِنْ آيَاتِ اللَّهِ لَا يَخْسِفَانِ لِمَوْتِ أَحَدٍ وَلَا لِحَيَاتِهِ فَإِذَا رَأَيْتُمْ ذَلِكَ فَافْزَعُوا إِلَى ذِكْرِ اللَّهِ","id":"Telah menceritakan kepada kami [Abu Ya'qub Yusuf Al Buwaithi] dari [Muhammad bin Idris Asy Syafi'i] telah menceritakan kepada kami [Malik bin Anas] dari [Zaid bin Aslam] dari ['Atha` bin Yasar] dari [Ibnu Abbas] ia berkata, \"Terjadi gerhana matahari, kemudian Rasulullah shallallahu 'alaihi wasallam melakukan shalat.\" Ibnu Abbas menceritakan bahwa shalat beliau shallallahu 'alaihi wasallam adalah dua rakaat, pada setiap rakaat terdapat dua rukuk. Kemudian beliau berkhutbah kepada mereka dan berkata: \"Sesungguhnya matahari dan bulan adalah dua tanda di antara tanda-tanda kekuasaan Allah. Keduanya tidak mengalami gerhana karena kematian seseorang dan tidak pula karena hidupnya seseorang. Apabila kalian melihat hal tersebut maka bersegeralah untuk berdzikir kepada Allah.\""},"1135":{"ar":" قَالَ وَأَخْبَرَنَا مَالِكٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ ح قَالَ وَأَخْبَرَنَا مَالِكٌ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَمْرَةَ عَنْ عَائِشَةَ قَالَتْ خَسَفَتْ الشَّمْسُ فَصَلَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَحَكَتْ أَنَّهُ صَلَّى رَكْعَتَيْنِ فِي كُلِّ رَكْعَةٍ رَكْعَتَيْنِ","id":"Ia berkata; telah mengabarkan kepada kami [Malik] dari [Hisyam bin 'Urwah] dari [Ayahnya] dari [Aisyah]. (dalam jalur lain disebutkan) Ia berkata; telah mengabarkan kepada kami [Malik] dari [Yahya bin Sa'id] dari ['Amrah] dari [Aisyah] ia berkata, \"Telah terjadi gerhana matahari, kemudian Nabi shallallahu 'alaihi wasallam melakukan shalat.\" Aisyah menceritakan bahwa beliau melakukan shalat dua rakaat, dalam setiap rakaat terdapat dua rukuk.\""},"1136":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ الْمُبَارَكِ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ فَاطِمَةَ بِنْتِ الْمُنْذِرِ عَنْ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ حِينَ كَسَفَتْ الشَّمْسُ بِعَتَاقَةٍ قَالَ حَدَّثَنِي أَبُو حُذَيْفَةَ مُوسَى بْنُ مَسْعُودٍ عَنْ زَائِدَةَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ فَاطِمَةَ عَنْ أَسْمَاءَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah mengabarkan kepada kami [Al Hakam bin Al Mubarak] telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Hisyam bin 'Urwah] dari [Fatimah binti Al Mundzir] dari [Asma` binti Abu Bakr], bahwa saat terjadi gerhana matahari Nabi shallallahu 'alaihi wasallam memerintahkan untuk membebaskan seorang budak.\" Ia (perawi) berkata; telah menceritakan kepadaku [Abu Hudzaifah Musa bin Mas'ud] dari [Zaidah] dari [Hisyam bin 'Urwah] dari [Fatimah] dari [Asma`] dari Nabi shallallahu 'alaihi wasallam, seperti hadits tersebut.\" "},"1137":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ الْأَنْصَارِيُّ أَنَّ أَبَا بَكْرِ بْنَ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ أَخْبَرَهُ عَنْ عَبَّادِ بْنِ تَمِيمٍ أَنَّهُ سَمِعَ عَبْدَ اللَّهِ بْنَ زَيْدٍ يَذْكُرُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ بِالنَّاسِ إِلَى الْمُصَلَّى يَسْتَسْقِي فَاسْتَقْبَلَ الْقِبْلَةَ وَحَوَّلَ رِدَاءَهُ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah menceritakan kepada kami [Yahya bin Sa'id Al Anshari] bahwa [Abu Bakr bin Muhammad 'Amru bin Hazm] mengabarkan kepadanya dari ['Abbad bin Tamim] bahwa ia mendengar [Abdullah bin Zaid] menyebutkan, bahwa Rasulullah shallallahu 'alaihi wasallam keluar bersama orang-orang menuju tanah lapang meminta hujan, beliau lalu menghadap kiblat dan membalikkan selendangnya.\" "},"1138":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ نَافِعٍ عَنْ شُعَيْبٍ عَنْ الزُّهْرِيِّ أَخْبَرَنِي عَبَّادُ بْنُ تَمِيمٍ أَنَّ عَمَّهُ أَخْبَرَهُ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ بِالنَّاسِ إِلَى الْمُصَلَّى يَسْتَسْقِي لَهُمْ فَقَامَ فَدَعَا اللَّهَ قَائِمًا ثُمَّ تَوَجَّهَ قِبَلَ الْقِبْلَةِ فَحَوَّلَ رِدَاءَهُ فَأُسْقُوا","id":"Telah mengabarkan kepada kami [Al Hakam bin Nafi'] dari [Syu'aib] dari [Az Zuhri] telah mengabarkan kepada kami ['Abbad bin Tamim] bahwa [Pamannya] mengabarkan kepadanya, bahwa Nabi shallallahu 'alaihi wasallam keluar bersama orang-orang menuju tanah lapang meminta turunnya hujan untuk mereka. Beliau berdiri dan berdoa kepada Allah dalam keadaan berdiri, kemudian beliau menghadap Kiblat dan membalikkan selendangnya, maka mereka pun mendapatkan hujan.\" "},"1139":{"ar":" حَدَّثَنَا عُثْمَانُ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدَةُ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَرْفَعُ يَدَيْهِ فِي شَيْءٍ مِنْ الدُّعَاءِ إِلَّا فِي الِاسْتِسْقَاءِ","id":"Telah menceritakan kepada kami [Utsman bin Muhammad] Telah menceritakan kepada kami ['Abdah] dari [Sa'id] dari [Qatadah] dari [Anas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam tidak mengangkat kedua tangannya pada doa apapun kecuali saat memohon hujan.\""},"1140":{"ar":" أَخْبَرَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا جَاءَ أَحَدُكُمْ الْجُمُعَةَ فَلْيَغْتَسِلْ","id":"Telah mengabarkan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Malik] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang di antara kalian datang untuk melakukan shalat Jum'at, maka hendaknya ia mandi.\" "},"1141":{"ar":" حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا مَالِكٌ عَنْ صَفْوَانَ بْنِ سُلَيْمٍ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غُسْلُ يَوْمِ الْجُمُعَةِ وَاجِبٌ عَلَى كُلِّ مُحْتَلِمٍ أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ صَفْوَانَ بْنِ سُلَيْمٍ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Malik] dari [Shafwan bin Sulaim] dari ['Atha` bin Yasar bin Abu Sa'id Al Khudri] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mandi pada hari Jum'at adalah wajib bagi orang yang telah baligh.\" Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Ibnu 'Uyainah] dari [Shafwan bin Sulaim] dari ['Atha` bin Yasar] dari [Abu Sa'id Al Khudri] dari Nabi shallallahu 'alaihi wasallam seperti itu.\" "},"1142":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ حَدَّثَنِي أَبُو هُرَيْرَةَ قَالَ بَيْنَمَا عُمَرُ بْنُ الْخَطَّابِ يَخْطُبُ إِذْ دَخَلَ رَجُلٌ فَعَرَّضَ بِهِ عُمَرُ فَقَالَ يَا أَمِيرَ الْمُؤْمِنِينَ مَا زِدْتُ أَنْ تَوَضَّأْتُ حِينَ سَمِعْتُ النِّدَاءَ فَقَالَ وَالْوُضُوءَ أَيْضًا أَلَمْ تَسْمَعْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا جَاءَ أَحَدُكُمْ إِلَى الْجُمُعَةِ فَلْيَغْتَسِلْ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Al Auza'i] dari [Yahya bin Abu Katsir] dari [Abu Salamah bin Abdurrahman] telah menceritakan kepadaku [Abu Hurairah] ia berkata, \"Ketika Umar bin Al Khaththab sedang khutbah, tiba-tiba ada seorang laki-laki yang masuk ke dalam masjid, Umar kemudian menyindirnya. Maka orang itu pun berkata, \"Wahai Amirul Mukminin, saat mendengar adzan aku tidak sempat melakukan apa pun selain berwudlu! \" [Umar] kemudian menyahut, \"Meskipun itu wudlu. Tidakkah kamu mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang di antara kalian datang untuk melakukan shalat Jum'at, maka hendaknya ia mandi.\""},"1143":{"ar":" أَخْبَرَنَا عَفَّانُ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ عَنْ الْحَسَنِ عَنْ سَمُرَةَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ تَوَضَّأَ لِلْجُمُعَةِ فَبِهَا وَنِعْمَتْ وَمَنْ اغْتَسَلَ فَهُوَ أَفْضَلُ","id":"Telah mengabarkan kepada kami ['Affan] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Qatadah] dari [Al Hasan] dari [Samurah], bahwa Nabi shallallahu 'alaihi wasallam berkata: \"Barangsiapa berwudlu untuk melakukan shalat Jum'at maka wudlu adalah cukup dan baik, dan barangsiapa mandi, maka hal itu adalah lebih baik.\""},"1144":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ الْمَجِيدِ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ الْمَقْبُرِيِّ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ وَدِيعَةَ عَنْ سَلْمَانَ الْفَارِسِيِّ صَاحِبِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ اغْتَسَلَ يَوْمَ الْجُمُعَةِ فَتَطَهَّرَ بِمَا اسْتَطَاعَ مِنْ طُهْرٍ ثُمَّ ادَّهَنَ مِنْ دُهْنِهِ أَوْ مَسَّ مِنْ طِيبِ بَيْتِهِ ثُمَّ رَاحَ فَلَمْ يُفَرِّقْ بَيْنَ اثْنَيْنِ وَصَلَّى مَا كُتِبَ لَهُ فَإِذَا خَرَجَ الْإِمَامُ أَنْصَتَ غُفِرَ لَهُ مَا بَيْنَهُ وَبَيْنَ الْجُمُعَةِ الْأُخْرَى","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Abdul Majid] telah menceritakan kepada kami [Ibnu Abu Dzi`b] dari [Al Maqburi] dari [Ayahnya] dari [Abdullah bin Wadi'ah] dari [Salman Al Farisi] sahabat Rasulullah shallallahu 'alaihi wasallam, bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mandi pada hari Jum'at dan bersuci semampunya, kemudian memakai minyak dari minyak yang ada di rumahnya, kemudian pergi (ke masjid) dan tidak memisahkan antara dua orang lalu melaksanakan shalat yang telah diwajibkan baginya, kemudian apabila imam keluar ia diam, maka dosanya antara jum'at tersebut hingga jum'at yang akan datang akan diampuni.\" "},"1145":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ هُرْمُزَ عَنْ أَبِي هُرَيْرَةَ قَالَ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ يَوْمَ الْجُمُعَةِ فِي صَلَاةِ الْغَدَاةِ تَنْزِيلُ السَّجْدَةَ وَهَلْ أَتَى عَلَى الْإِنْسَانِ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Sa'd bin Ibrahim] dari [Abdurrahman bin Hurmuz] dari [Abu Hurairah] ia berkata, \"Pada shalat subuh di hari jum'at Nabi shallallahu 'alaihi wasallam membaca surat Tanzil As Sajdah dan HAL ATAA 'ALAL INSAAN (surat Al Insaan).\" "},"1146":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُتَعَجِّلُ إِلَى الْجُمُعَةِ كَالْمُهْدِي جَزُورًا ثُمَّ الَّذِي يَلِيهِ كَالْمُهْدِي بَقَرَةً ثُمَّ الَّذِي يَلِيهِ كَالْمُهْدِي شَاةً فَإِذَا جَلَسَ الْإِمَامُ عَلَى الْمِنْبَرِ طُوِيَتْ الصُّحُفُ وَجَلَسُوا يَسْتَمِعُونَ الذِّكْرَ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Al Auza'i] dari [Yahya] dari [Abu Salamah bin Abdurrahman] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang bersegera menuju shalat Jum'at seperti orang yang mengorbankan unta, kemudian setelah itu seperti orang yang mengorbankan sapi, kemudian setelah itu seperti orang yang mengorbankan kambing. Maka jika imam berdiri di atas mimbar, lembaranan catatan dilipat dan para Malaikat duduk mendengarkan Dzikir (khutbah).\""},"1147":{"ar":" أَخْبَرَنَا نَصْرُ بْنُ عَلِيٍّ حَدَّثَنَا عَبْدُ الْأَعْلَى عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ الْأَغَرِّ أَبِي عَبْدِ اللَّهِ صَاحِبِ أَبِي هُرَيْرَةَ عَنْ أَبِي هُرَيْرَةَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا كَانَ يَوْمُ الْجُمُعَةِ قَعَدَتْ الْمَلَائِكَةُ عَلَى أَبْوَابِ الْمَسْجِدِ فَكَتَبُوا مَنْ جَاءَ إِلَى الْجُمُعَةِ فَإِذَا رَاحَ الْإِمَامُ طَوَتْ الْمَلَائِكَةُ الصُّحُفَ وَدَخَلَتْ تَسْتَمِعُ الذِّكْرَ قَالَ وَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُتَهَجِّرُ إِلَى الْجُمُعَةِ كَالْمُهْدِي بَدَنَةً ثُمَّ كَالْمُهْدِي بَقَرَةً ثُمَّ كَالْمُهْدِي شَاةً ثُمَّ كَالْمُهْدِي بَطَّةً ثُمَّ كَالْمُهْدِي دَجَاجَةً ثُمَّ كَالْمُهْدِي بَيْضَةً","id":"Telah mengabarkan kepada kami [Nashr bin Ali] telah menceritakan kepada kami [Abdul A'la] dari [Ma'mar] dari [Az Zuhri] dari [Al Aghar Abu Abdullah] sahabat Abu Hurairah, dari [Abu Hurairah], bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Pada hari Jum'at para Malaikat duduk di atas pintu masjid, kemudian mereka mencatat orang-orang yang mendatangi shalat Jum'at. Jika imam datang maka malaikat melipat lembaran catatan dan mereka masuk masjid untuk mendengarkan Dzikir (khutbah).\" Abu Hurairah berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang bersegera menuju shalat Jum'at seperti orang yang berkurban unta, kemudian seperti orang yang berkurban sapi, kemudian seperti orang yang berkurban kambing, kemudian seperti orang yang berkurban itik, kemudian seperti orang yang berkurban ayam, kemudian seperti orang yang berkurban telur.\""},"1148":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ مُسْلِمِ بْنِ جُنْدُبٍ عَنْ الزُّبَيْرِ بْنِ الْعَوَّامٍ قَالَ كُنَّا نُصَلِّي مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْجُمُعَةَ ثُمَّ نَرْجِعُ فَنَتَبَادَرُ الظِّلَّ فِي أُطُمِ بَنِي غَنْمٍ فَمَا هُوَ إِلَّا مَوَاضِعُ أَقْدَامِنَا","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Musa] dari [Ibnu Abu Dzi`b] dari [Muslim bin Jundab] dari [Az Zubair bin Al 'Awwam] ia berkata, \"Kami shalat Jum'at bersama Nabi shallallahu 'alaihi wasallam, kemudian kami kembali dan berlomba menuju bayangan di antara bangunan-bangunan rumah Bani Ghanm, dan kami tidak mendapatkan tempat untuk bernaung kecuali sekadar untuk meletakkan kaki.\" "},"1149":{"ar":" أَخْبَرَنَا عَفَّانُ بْنُ مُسْلِمٍ حَدَّثَنَا يَعْلَى بْنُ الْحَارِثِ قَالَ سَمِعْتُ إِيَاسَ بْنَ سَلَمَةَ بْنِ الْأَكْوَعِ يُحَدِّثُ عَنْ أَبِيهِ قَالَ كُنَّا نُصَلِّي مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْجُمُعَةَ ثُمَّ نَنْصَرِفُ وَلَيْسَ لِلْحِيطَانِ فَيْءٌ يُسْتَظَلُّ بِهِ","id":"Telah mengabarkan kepada kami ['Affan bin Muslim] Telah menceritakan kepada kami [Ya'la bin Al Harits] ia berkata, saya mendengar [Iyas bin Salamah bin Al Akwa'] menceritakan dari [Ayahnya] ia berkata, \"Kami pernah shalat Jum'at bersama Rasulullah shallallahu 'alaihi wasallam, kemudian beliau pergi (selesai shalat) sementara dinding-dinding tidak lagi memiliki bayangan yang dapat dijadikan naungan.\" "},"1150":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُبَارَكِ حَدَّثَنَا صَدَقَةُ هُوَ ابْنُ خَالِدٍ عَنْ يَحْيَى بْنِ الْحَارِثِ عَنْ أَبِي الْأَشْعَثِ الصَّنْعَانِيِّ يَرُدُّهُ إِلَى أَوْسِ بْنِ أَوْسٍ يَرُدُّهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ غَسَّلَ وَاغْتَسَلَ يَوْمَ الْجُمُعَةِ ثُمَّ غَدَا وَابْتَكَرَ ثُمَّ جَلَسَ قَرِيبًا مِنْ الْإِمَامِ وَأَنْصَتَ وَلَمْ يَلْغُ حَتَّى يَنْصَرِفَ الْإِمَامُ كَانَ لَهُ بِكُلِّ خُطْوَةٍ يَخْطُوهَا كَعَمَلِ سَنَةٍ صِيَامِهَا وَقِيَامِهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mubarak] telah menceritakan kepada kami [Shadaqah] -yaitu Ibnu Khalid- dari [Yahya bin Al Harits] dari [Abu Al Asy'ats Ash Shan'ani] ia menisbatkannya kepada [Aus bin Aus], ia menisbatkanya kepada Nabi shallallahu 'alaihi wasallam, beliau berkata: \"Barangsiapa mandi pada hari Jum'at kemudian pergi dan bersegera datang ke masjid, kemudian duduk dekat dengan imam, ia diam dan tidak melakukan perbuatan sia-sia hingga imam pergi, maka baginya dengan setiap langkah yang ia lakukan seperti amalan puasa satu tahun dan shalat malam satu tahun.\""},"1151":{"ar":" حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا مَالِكٌ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قُلْتَ لِصَاحِبِكَ أَنْصِتْ وَالْإِمَامُ يَخْطُبُ فَقَدْ لَغَوْتَ","id":"Telah menceritakan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Malik] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila engkau mengatakan kepada sahabatmu 'diamlah' sementara imam sedang, berkhutbah maka sungguh engkau telah melakukan perbuatan yang sia-sia.\""},"1152":{"ar":" حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا مَالِكٌ عَنْ الزُّهْرِيِّ عَنْ سَعِيدٍ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قُلْتَ لِصَاحِبِكَ أَنْصِتْ وَالْإِمَامُ يَخْطُبُ فَقَدْ لَغَوْتَ أَخْبَرَنَا الْمُعَلَّى بْنُ أَسَدٍ حَدَّثَنَا وُهَيْبٌ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Malik] dari [Az Zuhri] dari [Sa'id] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila engkau mengatakan kepada sahabatmu 'diamlah' sementara imam sedang berkhutbah, maka sungguh engkau telah melakukan perbuatan yang sia-sia.\" Telah mengabarkan kepada kami [Al Mu'alla bin Asad] telah menceritakan kepada kami [Wuhaib] dari [Ma'mar] dari [Az Zuhri] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam seperti itu.\" "},"1153":{"ar":" حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ دِينَارٍ قَالَ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ يُحَدِّثُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا جَاءَ أَحَدُكُمْ وَالْإِمَامُ يَخْطُبُ أَوْ قَدْ خَرَجَ فَلْيُصَلِّ رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami [Hasyim bin Al Qasim] telah menceritakan kepada kami [Syu'bah] dari ['Amru bin Dinar] ia berkata, saya mendengar [Jabir bin Abdullah] menceritakan dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Apabila salah seorang di antara kalian datang sementara imam sedang berkhutbah, atau telah keluar, maka hendaknya ia melakukan shalat dua rakaat.\""},"1154":{"ar":" أَخْبَرَنَا صَدَقَةُ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ عَجْلَانَ عَنْ عِيَاضِ بْنِ عَبْدِ اللَّهِ قَالَ جَاءَ أَبُو سَعِيدٍ وَمَرْوَانُ يَخْطُبُ فَقَامَ يُصَلِّي رَكْعَتَيْنِ فَأَتَاهُ الْحَرَسُ يَمْنَعُونَهُ فَقَالَ مَا كُنْتُ أَتْرُكُهُمَا وَقَدْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْمُرُ بِهِمَا","id":"Telah mengabarkan kepada kami [Shadaqah] telah menceritakan kepada kami [Sufyan] dari [Ibnu 'Ajlan] dari ['Iyadl bin Abdullah] ia berkata, \" [Abu Sa'id] datang saat Marwan sedang berkhutbah, kemudian ia berdiri dan shalat dua rakaat tetapi para penjaga mendatanginya dan melarangnya untuk shalat. Maka Sa'id pun berkata, \"Aku tidak pernah meninggalkan dua rakaat tersebut dan aku melihat Rasulullah shallallahu 'alaihi wasallam memerintahkan untuk melakukan dua rakaat tersebut.\" "},"1155":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ الرَّبِيعِ هُوَ ابْنُ صَبِيحٍ الْبَصْرِيُّ قَالَ رَأَيْتُ الْحَسَنَ يُصَلِّي رَكْعَتَيْنِ وَالْإِمَامُ يَخْطُبُ وَقَالَ الْحَسَنُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا جَاءَ أَحَدُكُمْ وَالْإِمَامُ يَخْطُبُ فَلْيُصَلِّ رَكْعَتَيْنِ خَفِيفَتَيْنِ يَتَجَوَّزُ فِيهِمَا قَالَ أَبُو مُحَمَّد أَقُولُ بِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Ar Rabi'] -yaitu Ibnu Shabih Al Bashri- ia berkata, \"Aku melihat Al Hasan melakukan shalat dua rakaat sementara imam sedang berkhutbah. [Al Hasan] berkata, \"Rasulullah shallallahu 'alaihi wasallam shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang di antara kalian datang sementara imam sedang berkhutbah, maka hendaknya ia shalat dua rakaat yang ringan.\" Abu Muhammad berkata, \"Aku berpendapat dengannya.\" "},"1156":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنِي اللَّيْثُ أَخْبَرَنِي خَالِدٌ يَعْنِي ابْنَ يَزِيدَ عَنْ سَعِيدِ بْنِ أَبِي هِلَالٍ عَنْ عِيَاضِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَ خَطَبَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا فَقَرَأَ ص فَلَمَّا مَرَّ بِالسَّجْدَةِ نَزَلَ فَسَجَدَ","id":"Telah mengabarkan kepada kami [Abdullah bin Shalih] telah menceritakan kepadaku [Al Laits] telah mengabarkan kepadaku [Khalid] -yaitu Ibnu Yazid- dari [Sa'id? bin Abu Hilal] dari ['Iyadl bin Abdullah] dari [Abu Sa'id Al Khudri] ia berkata, \"Suatu hari Rasulullah shallallahu 'alaihi wasallam berkhutbah kepada kami, beliau lalu membaca surat Shaad, saat melewati ayat sajdah beliau turun dan sujud.\" "},"1157":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ عَمْرِو بْنِ دِينَارٍ قَالَ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُ دَخَلَ رَجُلٌ الْمَسْجِدَ يَوْمَ الْجُمُعَةِ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ فَقَالَ أَصَلَّيْتَ قَالَ لَا قَالَ فَصَلِّ رَكْعَتَيْنِ قَالَ أَبُو مُحَمَّد أَقُولُ بِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Ibnu 'Uyainah] dari ['Amru bin Dinar] ia berkata, saya mendengar [Jabir bin Abdullah] berkata, \"Pada hari jum'at ada seorang laki-laki masuk ke dalam masjid saat Rasulullah shallallahu 'alaihi wasallam sedang berkhutbah, kemudian beliau bertanya: \"Apakah engkau telah melakukan shalat?\" orang tersebut menjawab, \"Belum.\" Beliau berkata: \"Lakukanlah shalat dua rakaat.\" Abu Muhammad berkata, \"Aku berpendapat dengannya.\" "},"1158":{"ar":" أَخْبَرَنَا الْعَلَاءُ بْنُ عُصَيْمٍ الْجُعْفِيُّ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ الْمَلِكِ بْنِ أَبْجَرَ حَدَّثَنِي أَبِي عَبْدُ الْمَلِكِ بْنُ أَبْجَرَ عَنْ وَاصِلِ بْنِ حَيَّانَ عَنْ أَبِي وَائِلٍ قَالَ خَطَبَنَا عَمَّارُ بْنُ يَاسِرٍ فَأَبْلَغَ وَأَوْجَزَ فَقُلْنَا يَا أَبَا الْيَقْظَانِ لَوْ كُنْتَ نَفَّسْتَ شَيْئًا قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ طُولَ صَلَاةِ الرَّجُلِ وَقِصَرَ خُطْبَتِهِ مَئِنَّةٌ مِنْ فِقْهِهِ فَأَطِيلُوا هَذِهِ الصَّلَاةَ وَاقْصُرُوا هَذِهِ الْخُطَبَ وَإِنَّ مِنْ الْبَيَانِ سِحْرًا","id":"Telah mengabarkan kepada kami [Al 'Ala` bin 'Ushaim Al Ju'fi] telah menceritakan kepada kami [Abdurrahman bin Abdul Malik bin Abjar] telah menceritakan kepadaku ayahku [Abdul Malik bin Abjar] dari [Washil bin Hayyan] dari [Abu Wail] ia berkata, \" [Ammar bin Yasir] berkhutbah di hadapan kami, ia menyampaikan dengan jelas dan ringkas. Kemudian kami katakan, \"Wahai Abu Al Yaqzhan, seandainya engkau sedikit memperpanjang! \" Ia menjawab, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh, panjangnya shalat dan ringkasnya khutbah seorang laki-laki adalah tanda pemahamannya, maka panjangkanlah shalat dan perpendeklah khutbah, dan sesungguhnya di antara penjelasan ada sesuatu yang menyihir.\" "},"1159":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ سِمَاكٍ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَ صَلَّيْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَانَتْ صَلَاتُهُ قَصْدًا وَخُطْبَتُهُ قَصْدًا","id":"Telah menceritakan kepada kami [Muhammad bin Sa'id] telah menceritakan kepada kami [Abu Al Ahwash] dari [Simak] dari [Jabir bin Samurah] ia berkata, \"Aku pernah shalat bersama Nabi shallallahu 'alaihi wasallam, shalat dan khutbah beliau sedang.\" "},"1160":{"ar":" حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَخْطُبُ خُطْبَتَيْنِ وَهُوَ قَائِمٌ وَكَانَ يَفْصِلُ بَيْنَهُمَا بِجُلُوسٍ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Bisyr bin Al Mufadldlal] telah menceritakan kepada kami ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar], bahwa Rasulullah shallallahu 'alaihi wasallam berkhutbah dengan dua kali dalam keadaan berdiri, dan beliau memisahkan antara keduanya dengan duduk.\" "},"1161":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ سِمَاكٍ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَ كَانَتْ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خُطْبَتَانِ يَجْلِسُ بَيْنَهُمَا يَقْرَأُ الْقُرْآنَ وَيُذَكِّرُ النَّاسَ","id":"Telah mengabarkan kepada kami [Muhammad bin Sa'id] telah menceritakan kepada kami [Abu Al Ahwash] dari [Simak] dari [Jabir bin Samurah] ia berkata, \"Nabi shallallahu 'alaihi wasallam memiliki dua khutbah dan beliau duduk di antara keduanya, beliau membaca Al Qur'an serta mengingatkan manusia.\" "},"1162":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا أَبُو زُبَيْدٍ حَدَّثَنَا حُصَيْنٌ قَالَ رَأَى عُمَارَةُ بْنُ رُوَيْبَةَ بِشْرَ بْنَ مَرْوَانَ عَلَى الْمِنْبَرِ رَافِعًا يَدَيْهِ فَقَالَ قَبَّحَ اللَّهُ هَذِهِ الْيَدَيْنِ لَقَدْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْمِنْبَرِ وَمَا يُشِيرُ إِلَّا بِأُصْبُعِهِ","id":"Telah mengabarkan kepada kami [Ahmad bin Abdullah] telah menceritakan kepada kami [Abu Zubaid] telah menceritakan kepada kami [Hushain] ia berkata, ['Umarah bin Ruwaibah] melihat Bisyr bin Marwan di atas mimbar dalam keadaan mengangkat kedua tangannya, maka ia pun berkata, \"Semoga Allah memburukkan kedua tangan ini. Sungguh aku melihat Rasulullah shallallahu 'alaihi wasallam berada di atas mimbar dan beliau tidak memberi isyarat kecuali dengan jari-jarinya.\" "},"1163":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ حُصَيْنِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عُمَارَةَ بْنِ رُوَيْبَةَ قَالَ رَأَى بِشْرَ بْنَ مَرْوَانَ رَافِعًا يَدَيْهِ يَدْعُو عَلَى الْمِنْبَرِ يَوْمَ الْجُمُعَةِ قَالَ فَسَبَّهُ وَقَالَ لَقَدْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْمِنْبَرِ وَمَا يَقُولُ بِأُصْبُعِهِ إِلَّا هَكَذَا وَأَشَارَ بِالسَّبَّابَةِ عِنْدَ الْخَاصِرَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Hushain bin Abdurrahman] dari ['Umarah bin Ruwaibah] ia berkata, \"'Umarah melihat Bisyr bin Marwan berdoa dengan mengangkat kedua tangannya di atas mimbar pada hari Jum'at.\" Hushain berkata, \"Kemudian 'Umarah mencelanya seraya berkata, 'Sungguh aku telah melihat Rasulullah shallallahu 'alaihi wasallam di atas mimbar dan beliau tidak berkata menggunakan jari-jarinya kecuali seperti ini.' Dan ia memberi isyarat menggunakan jari telunjuk di sisi lambung.\" "},"1164":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ كَثِيرٍ عَنْ سُلَيْمَانَ بْنِ كَثِيرٍ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُومُ إِلَى جِذْعٍ قَبْلَ أَنْ يُجْعَلَ الْمِنْبَرُ فَلَمَّا جُعِلَ الْمِنْبَرُ حَنَّ ذَلِكَ الْجِذْعُ حَتَّى سَمِعْنَا حَنِينَهُ فَوَضَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهُ عَلَيْهِ فَسَكَنَ","id":"Telah mengabarkan kepada kami [Muhammad bin Katsir] dari [Sulaiman bin Katsir] dari [Az Zuhri] dari [Sa'id? bin Al Musayyab] dari [Jabir bin Abdullah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam berdiri menuju batang kurma sebelum dibuat menjadi mimbar, kemudian tatkala telah dijadikan mimbar batang tersebut merintih hingga kami mendengar rintihannya. Rasulullah shallallahu 'alaihi wasallam lantas meletakkan tangannya di atas batang tersebut hingga ia pun terdiam.\" "},"1165":{"ar":" حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَمَّارِ بْنِ أَبِي عَمَّارٍ عَنْ ابْنِ عَبَّاسٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَخْطُبُ إِلَى جِذْعٍ قَبْلَ أَنْ يَتَّخِذَ الْمِنْبَرَ فَلَمَّا اتَّخَذَ الْمِنْبَرَ تَحَوَّلَ إِلَيْهِ حَنَّ الْجِذْعُ فَاحْتَضَنَهُ فَسَكَنَ وَقَالَ لَوْ لَمْ أَحْتَضِنْهُ لَحَنَّ إِلَى يَوْمِ الْقِيَامَةِ حَدَّثَنَا حَجَّاجٌ حَدَّثَنَا حَمَّادٌ عَنْ ثَابِتٍ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Hammad bin Salamah] dari ['Ammar bin Abu 'Ammar] dari [Ibnu Abbas], bahwa Nabi shallallahu 'alaihi wasallam berkhutbah menghadap ke arah sebatang pohon kurma sebelum mempunyai mimbar, ketika telah mempunyai mimbar beliau pindah kepadanya hingga batang pohon kurma tersebut merintih, beliau lalu memeluk batang kurma tersebut hingga ia pun diam. Beliau berkata: \"Seandainya aku tidak memeluknya niscaya ia akan merintih hingga hari Kiamat.\" Telah menceritakan kepada kami [Hajjaj] telah menceritakan kepada kami [Hammad] dari [Tsabit] dari [Anas] dari Nabi shallallahu 'alaihi wasallam seperti itu.\" "},"1166":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ حَدَّثَنَا الْمَسْعُودِيُّ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَ لَمَّا كَثُرَ النَّاسُ بِالْمَدِينَةِ جَعَلَ الرَّجُلُ يَجِيءُ وَالْقَوْمُ يَجِيئُونَ فَلَا يَكَادُونَ أَنْ يَسْمَعُوا كَلَامَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى يَرْجِعُوا مِنْ عِنْدِهِ فَقَالَ لَهُ النَّاسُ يَا رَسُولَ اللَّهِ إِنَّ النَّاسَ قَدْ كَثُرُوا وَإِنَّ الْجَائِيَ يَجِيءُ فَلَا يَكَادُ يَسْمَعُ كَلَامَكَ قَالَ فَمَا شِئْتُمْ فَأَرْسِلْ إِلَى غُلَامٍ لِامْرَأَةٍ مِنْ الْأَنْصَارِ نَجَّارٍ وَإِلَى طَرْفَاءِ الْغَابَةِ فَجَعَلُوا لَهُ مِرْقَاتَيْنِ أَوْ ثَلَاثَةً فَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَجْلِسُ عَلَيْهِ وَيَخْطُبُ عَلَيْهِ فَلَمَّا فَعَلُوا ذَلِكَ حَنَّتْ الْخَشَبَةُ الَّتِي كَانَ يَقُومُ عِنْدَهَا فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَيْهَا فَوَضَعَ يَدَهُ عَلَيْهَا فَسَكَنَتْ ","id":"Telah menceritakan kepada kami [Abdullah bin Yazid] telah menceritakan kepada kami [Al Mas'udi] dari [Abu Hazim] dari [Sahl bin Sa'd] ia berkata, \"Tatkala orang-orang telah banyak di Madinah, maka berdatanganlah baik itu perseorangan maupun berkelompok sehingga mereka hampir tidak mendengar perkataan Rasulullah shallallahu 'alaihi wasallam, sampai mereka kembali dari sisi beliau. Kemudian orang-orang berkata kepada beliau, \"Wahai Rasulullah, sesungguhnya orang-orang telah banyak dan selalu ada yang terus datang, hampi-hampir mereka tidak dapat mendengar perkataanmu.\" Beliau berkata: \"Apa yang kalian kehendaki?\" Mereka mengatakan, \"Kirimkan utusan kepada budak seorang wanita anshar yang bekerja sebagai tukang kayu, dan ke Tharfa` Al Ghabah.\" Kemudian mereka membuatkan untuk mereka dua tangga atau tiga tangga. Lalu Rasulullah shallallahu 'alaihi wasallam duduk dan berkhutbah di atasnya. Kemudian tatkala mereka melakukan hal tersebut kayu yang di sisinya Rasulullah shallallahu 'alaihi wasallam berdiri merintih, Rasulullah shallallahu 'alaihi wasallam lantas berdiri menuju kayu tersebut seraya meletakkan tangannya di atasnya hingga ia pun terdiam.\""},"1167":{"ar":" أَخْبَرَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا مَالِكٌ عَنْ ضَمْرَةَ بْنِ سَعِيدٍ الْمَازِنِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ أَنَّ الضَّحَّاكَ بْنَ قَيْسٍ سَأَلَ النُّعْمَانَ بْنَ بَشِيرٍ الْأَنْصَارِيَّ مَا كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ يَوْمَ الْجُمُعَةِ عَلَى إِثْرِ سُورَةِ الْجُمُعَةِ قَالَ هَلْ أَتَاكَ حَدِيثُ الْغَاشِيَةِ","id":"Telah mengabarkan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Malik] dari [Dlamrah bin Sa'id Al Mazini] dari ['Ubaidullah bin Abdullah bin 'Utbah] bahwa [Adl Dlahhak bin Qais] bertanya kepada [An Nu'man bin Basyir Al Anshari], \"Apa yang dibaca Rasulullah shallallahu 'alaihi wasallam pada hari Jum'at setelah surat Al Jumu'ah?\" Ia menjawab, \"HAL ATAAKA HADIITSUL QHAASYIYAH (surat Al Insaan).\""},"1168":{"ar":" حَدَّثَنَا إِسْمَعِيلُ بْنُ أَبَانَ حَدَّثَنَا أَبُو أُوَيْسٍ عَنْ ضَمْرَةَ بْنِ سَعِيدٍ الْمَازِنِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ الضَّحَّاكِ بْنِ قَيْسٍ الْفِهْرِيِّ عَنْ النُّعْمَانِ بْنِ بَشِيرٍ الْأَنْصَارِيِّ قَالَ سَأَلْنَاهُ مَا كَانَ يَقْرَأُ بِهِمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْجُمُعَةِ مَعَ السُّورَةِ الَّتِي ذُكِرَتْ فِيهَا الْجُمُعَةُ قَالَ كَانَ يَقْرَأُ مَعَهَا هَلْ أَتَاكَ حَدِيثُ الْغَاشِيَةِ","id":"Telah menceritakan kepada kami [Isma'il bin Aban] telah menceritakan kepada kami [Abu Uwais] dari [Dlamrah bin Sa'id Al Mazini] dari ['Ubaidullah bin Abdullah bin 'Utbah] dari [Adl Dlahhak bin Qais Al Fihri] dari [An Nu'man bin Basyir Al Anshari] ia berkata, \"Kami bertanya kepadanya apa yang dibacakan Nabi shallallahu 'alaihi wasallam kepada mereka pada hari Jum'at bersama surat yang disebutkan di dalamnya ?Al Jumu'ah?\" Ia menjawab, \"Beliau membaca bersamanya HAL ATAAKA HADIITSUL GHAASYIYAH (surat Al Ghaasyiyah).\" "},"1169":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ إِبْرَاهِيمَ بْنِ مُحَمَّدِ بْنِ الْمُنْتَشِرِ عَنْ أَبِيهِ عَنْ حَبِيبِ بْنِ سَالِمٍ عَنْ النُّعْمَانِ بْنِ بَشِيرٍ قَالَ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الْعِيدَيْنِ وَالْجُمُعَةِ بِسَبِّحِ اسْمَ رَبِّكَ الْأَعْلَى وَهَلْ أَتَاكَ حَدِيثُ الْغَاشِيَةِ وَرُبَّمَا اجْتَمَعَا فَقَرَأَ بِهِمَا","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Ibrahim bin Muhammad bin Al Muntasyir] dari [Ayahnya] dari [Habib bin Salim] dari [An Nu'man bin Basyir] ia berkata, \"Nabi shallallahu 'alaihi wasallam membaca SABBIHISMA RABBIKAL A'LAA dan HAL ATAAKA HADIITSUL GHAASYIYAH pada shalat dua hari raya dan hari Jum'at. Bila kedua hari tersebut bertemu dalam satu hari beliau juga membaca keduanya.\" "},"1170":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ كَثِيرٍ عَنْ مَخْلَدِ بْنِ حُسَيْنٍ عَنْ هِشَامٍ عَنْ ابْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ قَالَ الْتَقَيْتُ أَنَا وَكَعْبٌ فَجَعَلْتُ أُحَدِّثُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَجَعَلَ يُحَدِّثُنِي عَنْ التَّوْرَاةِ حَتَّى أَتَيْنَا عَلَى ذِكْرِ يَوْمِ الْجُمُعَةِ فَقُلْتُ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ فِيهَا لَسَاعَةً لَا يُوَافِقُهَا عَبْدٌ مُسْلِمٌ يُصَلِّي يَسْأَلُ اللَّهَ فِيهَا خَيْرًا إِلَّا أَعْطَاهُ إِيَّاهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Katsir] dari [Makhlad bin Husain] dari [Hisyam] dari [Ibnu Sirin] dari [Abu Hurairah] ia berkata, \"Aku dan Ka'b bertemu, kemudian aku menceritakan dari Rasulullah shallallahu 'alaihi wasallam sementara ia menceritakan dari Taurat, hingga ketika kami menyebutkan hari Jum'at, maka aku katakan, \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya padanya ada satu waktu, tidaklah seorang Muslim menepati waktu itu dengan melakukan shalat dan memohon kebaikan kepada Allah, kecuali Allah akan memberikan kepadanya.\""},"1171":{"ar":" حَدَّثَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا مُعَاوِيَةُ بْنُ سَلَّامٍ أَخْبَرَنِي زَيْدُ بْنُ سَلَّامٍ أَنَّهُ سَمِعَ أَبَا سَلَّامٍ قَالَ حَدَّثَنِي الْحَكَمُ بْنُ مِينَا أَنَّ ابْنَ عُمَرَ حَدَّثَهُ وَأَبَا هُرَيْرَةَ أَنَّهُمَا سَمِعَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ وَهُوَ عَلَى أَعْوَادِ مِنْبَرِهِ لَيَنْتَهِيَنَّ أَقْوَامٌ عَنْ وَدَعِهِمْ الْجُمُعَاتِ أَوْ لَيَخْتِمَنَّ اللَّهُ عَلَى قُلُوبِهِمْ ثُمَّ لَيَكُونُنَّ مِنْ الْغَافِلِينَ","id":"Telah menceritakan kepada kami [Yahya bin Hassan] telah menceritakan kepada kami [Mu'awiyah bin Sallam] telah mengabarkan kepadaku [Zaid bin Sallam] bahwa ia mendengar [Abu Sallam] berkata, telah menceritakan kepadaku [Al Hakam bin Mina] bahwa [Ibnu Umar] dan [Abu Hurairah] menceritakan kepadanya, bahwa mereka mendengar Rasulullah shallallahu 'alaihi wasallam bersabda di atas kayu mimbarnya: \"Sungguh orang-orang berhenti dari meninggalkan shalat Jum'at, atau Allah menutup hati mereka, kemudian mereka akan termasuk orang-orang yang lalai.\""},"1172":{"ar":" حَدَّثَنَا يَعْلَى حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو عَنْ عَبِيدَةَ بْنِ سُفْيَانَ عَنْ أَبِي الْجَعْدِ الضَّمْرِيِّ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَرَكَ الْجُمُعَةَ تَهَاوُنًا بِهَا طَبَعَ اللَّهُ عَلَى قَلْبِهِ ","id":"Telah menceritakan kepada kami [Ya'la] telah menceritakan kepada kami [Muhammad bin 'Amru] dari ['Ubaidullah bin Sufyan] dari [Abu Al Ja'd Adl Dlamri] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa meninggalkan shalat Jum'at karena meremehkannya, maka Allah akan menutup hatinya.\" "},"1173":{"ar":" أَخْبَرَنَا عُثْمَانُ بْنُ مُحَمَّدٍ حَدَّثَنَا الْحُسَيْنُ بْنُ عَلِيٍّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ بْنِ جَابِرٍ عَنْ أَبِي الْأَشْعَثِ الصَّنْعَانِيِّ عَنْ أَوْسِ بْنِ أَوْسٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَفْضَلَ أَيَّامِكُمْ يَوْمُ الْجُمُعَةِ فِيهِ خُلِقَ آدَمُ وَفِيهِ النَّفْخَةُ وَفِيهِ الصَّعْقَةُ فَأَكْثِرُوا عَلَيَّ مِنْ الصَّلَاةِ فِيهِ فَإِنَّ صَلَاتَكُمْ مَعْرُوضَةٌ عَلَيَّ قَالَ رَجُلٌ يَا رَسُولَ اللَّهِ كَيْفَ تُعْرَضُ صَلَاتُنَا عَلَيْكَ وَقَدْ أَرَمْتَ يَعْنِي بَلِيتَ قَالَ إِنَّ اللَّهَ حَرَّمَ عَلَى الْأَرْضِ أَنْ تَأْكُلَ أَجْسَادَ الْأَنْبِيَاءِ","id":"Telah mengabarkan kepada kami [Utsman bin Muhammad] telah menceritakan kepada kami [Al Husain bin Ali] dari [Abdurrahman bin Yazid bin Jabir] dari [Abu Al Asy'ats Ash Shan'ani] dari [Aus bin Aus] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda, \"Sesungguhnya hari kalian yang paling utama adalah hari Jum'at, padanya Adam di ciptakan, padanya ia diberi ruh, dan padanya terjadi Ash sha'qah (suara keras yang menyebabkan orang-orang pingsan). Maka perbanyaklah bershalawat kepadaku pada hari itu, sesungguhnya shalawat kalian akan diperlihatkan kepadaku.\" Seorang laki-laki lalu bertanya, \"Wahai Rasulullah, bagaimana shalawat kami diperlihatkan kepadamu, sementara anda telah meninggal? Beliau bersabda: \"Sesungguhnya Allah mengharamkan atas tanah untuk memakan jasad para Nabi.\""},"1174":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي بَعْدَ الْجُمُعَةِ رَكْعَتَيْنِ فِي بَيْتِهِ","id":"Telah mengabarkan kepada kami [Abu 'Ashim] dari [Malik] dari [Nafi'] dari [Ibnu Umar], bahwa Nabi shallallahu 'alaihi wasallam melakukan shalat dua rakaat di rumahnya setelah shalat Jum'at.\" "},"1175":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ أَحْمَدَ بْنِ أَبِي خَلَفٍ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو يَعْنِي ابْنَ دِينَارٍ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمٍ عَنْ أَبِيهِ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي بَعْدَ الْجُمُعَةِ رَكْعَتَيْنِ","id":"Telah mengabarkan kepada kami [Muhammad bin Ahmad bin Abu Khalaf] telah menceritakan kepada kami [Sufyan] dari ['Amru] -yaitu Ibnu Dinar- dari [Ibnu Syihab] dari [Salim] dari [Ayahnya], bahwa Nabi shallallahu 'alaihi wasallam melakukan shalat dua rakaat setelah shalat Jum'at.\" "},"1176":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ كَانَ مِنْكُمْ مُصَلِّيًا بَعْدَ الْجُمُعَةِ فَلْيُصَلِّ بَعْدَهَا أَرْبَعًا قَالَ أَبُو مُحَمَّد أُصَلِّي بَعْدَ الْجُمُعَةِ رَكْعَتَيْنِ أَوْ أَرْبَعًا","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Suhail bin Abu Shalih] dari [Ayahnya] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa di antara kalian mengerjakan shalat setelah Jum'at, maka hendaknya ia melakukan shalat empat rakaat.\" Abu Muhammad berkata, \"Aku melakukan shalat dua rakaat atau empat rakaat setelah shalat Jum'at.\""},"1177":{"ar":" حَدَّثَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا لَيْثٌ هُوَ ابْنُ سَعْدٍ حَدَّثَنَا يَزِيدُ بْنُ أَبِي حَبِيبٍ عَنْ عَبْدِ اللَّهِ بْنِ رَاشِدٍ الزَّوْفِيِّ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي مُرَّةَ الزَّوْفِيِّ عَنْ خَارِجَةَ بْنِ حُذَافَةَ الْعَدَوِيِّ قَالَ خَرَجَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ اللَّهَ قَدْ أَمَدَّكُمْ بِصَلَاةٍ هِيَ خَيْرٌ لَكُمْ مِنْ حُمْرِ النَّعَمِ جَعَلَهُ لَكُمْ فِيمَا بَيْنَ صَلَاةِ الْعِشَاءِ إِلَى أَنْ يَطْلُعَ الْفَجْرُ","id":"Telah menceritakan kepada kami [Abu Al Walid Ath Thayalisi] telah menceritakan kepada kami [Laits] -yaitu Ibnu Sa'd- telah menceritakan kepada kami [Yazid bin Abu Habib] dari [Abdullah bin Rasyid Az Zaufi] dari [Abdullah bin Abu Murrah] dari [Kharijah bin Hudzafah Al 'Adawi] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam keluar menemui kami seraya bersabda: \"Sesungguhnya Allah telah memberikan kepada kalian Shalat yang lebih baik daripada unta merah, Allah menjadikannya untuk kalian berada di antara shalat Isya hingga terbit fajar.\" "},"1178":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا يَحْيَى بْنُ سَعِيدٍ الْأَنْصَارِيُّ أَنَّ مُحَمَّدَ بْنَ يَحْيَى بْنِ حَبَّانَ أَخْبَرَهُ أَنَّ ابْنَ مُحَيْرِيزٍ الْقُرَشِيَّ ثُمَّ الْجُمَحِيَّ أَخْبَرَهُ وَكَانَ يَسْكُنُ بِالشَّامِ وَكَانَ أَدْرَكَ مُعَاوِيَةَ أَنَّ الْمُخْدَجِيَّ رَجُلٌ مِنْ بَنِي كِنَانَةَ أَخْبَرَهُ أَنَّ رَجُلًا مِنْ أَهْلِ الشَّامِ وَكَانَتْ لَهُ صُحْبَةٌ يُكْنَى أَبَا مُحَمَّدٍ أَخْبَرَهُ أَنَّ الْوِتْرَ وَاجِبٌ فَرَاحَ الْمُخْدَجِيُّ إِلَى عُبَادَةَ بْنِ الصَّامِتِ فَذَكَرَ ذَلِكَ لَهُ فَقَالَ عُبَادَةُ كَذَبَ أَبُو مُحَمَّدٍ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ خَمْسُ صَلَوَاتٍ كَتَبَهُنَّ اللَّهُ عَلَى الْعِبَادِ مَنْ أَتَى بِهِنَّ لَمْ يُضَيِّعْ مِنْ حَقِّهِنَّ شَيْئًا اسْتِخْفَافًا بِحَقِّهِنَّ كَانَ لَهُ عِنْدَ اللَّهِ عَهْدٌ أَنْ يُدْخِلَهُ الْجَنَّةَ وَمَنْ لَمْ يَأْتِ بِهِنَّ جَاءَ وَلَيْسَ لَهُ عِنْدَ اللَّهِ عَهْدٌ إِنْ شَاءَ عَذَّبَهُ وَإِنْ شَاءَ أَدْخَلَهُ الْجَنَّةَ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Yahya bin Sa'id Al Anshari] bahwa [Muhammad bin Yahya bin Habban] telah mengabarkan kepadanya, bahwa [Ibnu Muhairiz Al Qurasyi Al Jumahi] -ia tinggal di Syam dan pernah bertemu dengan Mu'awiyah- mengabarkan kepadanya, bahwa [Al Mukhdaji] seorang laki-laki dari Bani Kinanah, mengabarkan kepadanya bahwa seorang laki-laki dari penduduk Syam yang biasa dipanggil Abu Muhammad, dan ia adalah seorang sahabat, telah mengabarkan kepadanya bahwa shalat witir adalah wajib. Kemudian Al Mukhdaji pergi menemui 'Ubadah bin Ash Shamit dan menyebutkan hal tersebut kepadanya, ['Ubadah] lantas berkata, \"Abu Muhammad telah berdusta, aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Lima shalat yang telah Allah wajibkan atas para hamba, barangsiapa melakukannya dan tidak menyia-nyiakan haknya sedikitpun karena sikap meremehkan terhadap haknya, maka baginya janji di sisi Allah untuk memasukkannya ke dalam Surga. Dan barangsiapa tidak melakukannya maka ia datang tidak memiliki janji di sisi Allah, apabila Allah menghendaki maka Dia akan menyiksanya dan apabila Allah menghendaki maka Dia akan memasukkannya ke dalam Surga.\" "},"1179":{"ar":" أَخْبَرَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا إِسْمَعِيلُ بْنُ جَعْفَرٍ عَنْ أَبِي سُهَيْلٍ نَافِعِ بْنِ مَالِكٍ عَنْ أَبِيهِ عَنْ طَلْحَةَ بْنِ عُبَيْدِ اللَّهِ أَنَّ أَعْرَابِيًّا جَاءَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَائِرَ الرَّأْسِ فَقَالَ يَا رَسُولَ اللَّهِ مَاذَا فَرَضَ اللَّهُ عَلَيَّ مِنْ الصَّلَاةِ قَالَ الصَّلَوَاتِ الْخَمْسَ و��الصِّيَامَ فَأَخْبَرَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِشَرَائِعِ الْإِسْلَامِ فَقَالَ وَالَّذِي أَكْرَمَكَ لَا أَتَطَوَّعُ شَيْئًا وَلَا أَنْقُصُ مِمَّا فَرَضَ اللَّهُ عَلَيَّ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفْلَحَ وَأَبِيهِ إِنْ صَدَقَ أَوْ دَخَلَ الْجَنَّةَ وَأَبِيهِ إِنْ صَدَقَ","id":"Telah mengabarkan kepada kami [Yahya bin Hassan] telah menceritakan kepada kami [Isma'il bin Ja'far] dari [Abu Suhail Nafi' bin Malik] dari [Ayahnya] dari [Thalhah bin 'Ubaidullah], bahwa seorang Arab badui datang kepada Rasulullah shallallahu 'alaihi wasallam dengan rambut acak-acakan, ia lalu berkata, \"Wahai Rasulullah, shalat apakah yang telah Allah wajibkan kepadaku? Beliau bersabda: \"Shalat lima waktu, dan berpuasa.\" Kemudian Rasulullah shallallahu 'alaihi wasallam mengabarkan kepadanya mengenai syari'at-syari'at Islam. Lalu orang tersebut berkata, \"Demi Dzat yang telah memuliakanmu, aku tidak akan melakukan perkara sunah sedikitpun, dan tidak akan mengurangi apa yang telah Allah wajibkan atas diriku.\" Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ia beruntung apabila berkata benar.\" Atau \"Ia akan masuk Surga apabila berkata benar.\""},"1180":{"ar":" حَدَّثَنَا عَفَّانُ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ قَالَ سَمِعْتُ عَاصِمَ بْنَ ضَمْرَةَ قَالَ سَمِعْتُ عَلِيًّا يَقُولُ إِنَّ الْوِتْرَ لَيْسَ بِحَتْمٍ كَالصَّلَاةِ وَلَكِنَّهُ سُنَّةٌ فَلَا تَدَعُوهُ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] ia berkata, saya mendengar ['Ashim bin Dlamrah] ia berkata, saya mendengar [Ali] berkata, \"Sesungguhnya witir tidaklah wajib seperti shalat, ia adalah sunnah, maka janganlah kalian meninggalkannya.\" "},"1181":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ مُوسَى عَنْ هِقْلِ بْنِ زِيَادٍ عَنْ هِشَامٍ عَنْ ابْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ وِتْرٌ يُحِبُّ الْوِتْرَ","id":"Telah mengabarkan kepada kami [Al Hakam bin Musa] dari [Hiql bin Ziyad] dari [Hisyam] dari [Ibnu Sirin dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya Allah adalah ganjil dan menyukai witir (shalat ganjil).\""},"1182":{"ar":" أَخْبَرَنَا جَعْفَرُ بْنُ عَوْنٍ حَدَّثَنَا هِشَامٌ عَنْ أَبِيهِ عَنْ عَائِشَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَتْ صَلَاتُهُ مِنْ اللَّيْلِ ثَلَاثَ عَشْرَةَ رَكْعَةً يُوتِرُ مِنْهَا بِخَمْسٍ لَا يَجْلِسُ فِي شَيْءٍ مِنْ الْخَمْسِ حَتَّى يَجْلِسَ فِي الْآخِرَةِ فَيُسَلِّمَ","id":"Telah mengabarkan kepada kami [Ja'far bin 'Aun] telah menceritakan kepada kami [Hisyam] dari [Ayahnya] dari [Aisyah], bahwa shalat Rasulullah shallallahu 'alaihi wasallam pada waktu malam adalah tiga belas rakaat, lima rakaat darinya adalah witir, dan pada lima rakaat tersebut beliau tidak duduk kecuali pada rakaat terakhir.\" "},"1183":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا سُفْيَانُ بْنُ حُسَيْنٍ عَنْ الزُّهْرِيِّ عَنْ عَطَاءِ بْنِ يَزِيدَ اللَّيْثِيِّ عَنْ أَبِي أَيُّوبَ الْأَنْصَارِيِّ قَالَ قَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْتِرْ بِخَمْسٍ فَإِنْ لَمْ تَسْتَطِعْ فَبِثَلَاثٍ فَإِنْ لَمْ تَسْتَطِعْ فَبِوَاحِدَةٍ فَإِنْ لَمْ تَسْتَطِعْ فَأَوْمِ إِيمَاءً أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ الْأَوْزَاعِيِّ عَنْ الزُّهْرِيِّ عَنْ عَطَاءِ بْنِ يَزِيدَ اللَّيْثِيِّ عَنْ أَبِي أَيُّوبَ الْأَنْصَارِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah menceritakan kepada kami [Sufyan bin Husain] dari [Az Zuhri] dari ['Atha` bin Yazid Al Laitsi] dari [Abu Ayyub Al Anshari] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam berkata kepadaku: \"Lakukan shalat Witir dengan lima rakaat, apabila engkau tidak mampu maka dengan tiga rakaat, dan apabila engkau tidak mampu maka dengan satu rakaat, dan apabila engkau tidak mampu maka lakukan dengan memberi isyarat.\" Telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Al Auza'i] dari [Az Zuhri] dari ['Atha` bin Yazid Al Laits] dari [Abu Ayyub Al Anshari] dari Nabi shallallahu 'alaihi wasallam seperti itu.\" "},"1184":{"ar":" أَخْبَرَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَ سَأَلَ رَجُلٌ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ صَلَاةِ اللَّيْلِ فَقَالَ مَثْنَى مَثْنَى فَإِذَا خَشِيَ أَحَدُكُمْ الصُّبْحَ فَلْيُصَلِّ رَكْعَةً وَاحِدَةً تُوتِرُ مَا قَدْ صَلَّى قِيلَ لِأَبِي مُحَمَّدٍ تَأْخُذُ بِهِ قَالَ نَعَمْ","id":"Telah mengabarkan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Malik] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Seseorang bertanya kepada Rasulullah shallallahu 'alaihi wasallam mengenai shalat malam, kemudian beliau bersabda: \"Dua rakaat, dua rakaat. Jika salah seorang dari kalian kawatir dengan datangnya waktu subuh, maka hendaklah ia shalat satu rakaat sebagai witir dari shalat yang telah ia kerjakan.\" Abu Muhammad ditanya, \"Apakah engkau berpendapat dengannya?\" Ia menjawab, \"Ya.\" "},"1185":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي مَا بَيْنَ الْعِشَاءِ إِلَى الْفَجْرِ إِحْدَى عَشْرَةَ رَكْعَةً يُسَلِّمُ فِي كُلِّ رَكْعَتَيْنِ وَيُوتِرُ بِوَاحِدَةٍ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] dari [Ibnu Abu Dzi`b] dari [Az Zuhri] dari ['Urwah] dari [Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melakukan shalat antara Isya dan Subuh sebanyak sebelas rakaat. Beliau mengucapkan salam pada setiap dua rakaat dan melakukan witir dengan satu rakaat.\" "},"1186":{"ar":" أَخْبَرَنَا مَالِكُ بْنُ إِسْمَعِيلَ حَدَّثَنَا إِسْرَائِيلُ عَنْ أَبِي إِسْحَقَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُوتِرُ بِثَلَاثٍ بِسَ��ِّحِ اسْمَ رَبِّكَ الْأَعْلَى وَقُلْ يَا أَيُّهَا الْكَافِرُونَ وَقُلْ هُوَ اللَّهُ أَحَدٌ","id":"Telah mengabarkan kepada kami [Malik bin Isma'il] telah menceritakan kepada kami [Israil] dari [Abu Ishaq] dari [Sa'id? bin Jubair] dari [Ibnu Abbas] ia berkata, \"Nabi shallallahu 'alaihi wasallam shalat Witir tiga rakaat dengan membaca SABBIHISMA RABBIKAL A'LAA (Al A'laa) dan QUL YAA AYYUHAL KAAFIRUUN (surat Al Kaafiruun), serta QUL HUWALLAAHU AHAD (surat Al Ikhlash).\" "},"1187":{"ar":" أَخْبَرَنَا قَبِيصَةُ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي حَصِينٍ عَنْ يَحْيَى بْنِ وَثَّابٍ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْ فِي كُلِّ الْوَقْتِ قَدْ أَوْتَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَانْتَهَى وِتْرُهُ إِلَى السَّحَرِ","id":"Telah mengabarkan kepada kami [Qabishah] telah menceritakan kepada kami [Sufyan] dari [Abu Hashin] dari [Yahya bin Watstsab] dari [Masruq] dari [Aisyah] ia berkata, \"Pada setiap waktu Rasulullah shallallahu 'alaihi wasallam telah melakukan witir, dan witir beliau berhenti hingga waktu sahur.\" "},"1188":{"ar":" حَدَّثَنَا عَفَّانُ حَدَّثَنَا أَبَانُ بْنُ يَزِيدَ الْعَطَّارُ حَدَّثَنِي يَحْيَى بْنُ أَبِي كَثِيرٍ حَدَّثَنِي أَبُو نَضْرَةَ أَنَّ أَبَا سَعِيدٍ الْخُدْرِيَّ حَدَّثَهُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ عَنْ الْوِتْرِ فَقَالَ أَوْتِرُوا قَبْلَ الْفَجْرِ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Aban bin Yazid Al 'Aththar] telah menceritakan kepadaku [Yahya bin Abu Katsir] telah menceritakan kepadaku [Abu Nadlrah] bahwa [Abu Sa'id Al Khudri] telah menceritakan kepadanya, bahwa Rasulullah shallallahu 'alaihi wasallam ditanya mengenai shalat Witir, kemudian beliau bersabda: \"Lakukanlah witir sebelum shalat Subuh.\""},"1189":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو أُسَامَةَ قَالَ زَكَرِيَّاءُ حَدَّثَنِي عَنْ أَبِي إِسْحَقَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُوتِرُ بِثَلَاثٍ يَقْرَأُ فِي الْأُولَى بِسَبِّحِ اسْمَ رَبِّكَ الْأَعْلَى وَفِي الثَّانِيَةِ بِقُلْ يَا أَيُّهَا الْكَافِرُونَ وَفِي الثَّالِثَةِ بِقُلْ هُوَ اللَّهُ أَحَدٌ","id":"Telah menceritakan kepada kami [Abdullah bin Sa'id] telah menceritakan kepada kami [Abu Usamah] ia berkata, [Zakaria] telah menceritakan kepadaku dari [Abu Ishaq] dari [Sa'id bin Jubair] dari [Ibnu Abbas] ia berkata, \"Nabi shallallahu 'alaihi wasallam melakukan witir dengan tiga rakaat, pada rakaat pertama beliau membaca SABBIHISMA RABBIKAL A'LAA (surat Al A'laa), pada rakaat kedua dengan QUL YAA AYYUHAL KAAFIRUUN (surat Al Kaafiruun), dan pada rakaat ketiga dengan QUL HUWALLAAHU AHAD (surat Al Ikhlas).\" "},"1190":{"ar":" أَخْبَرَنَا مَرْوَانُ بْنُ مُحَمَّدٍ حَدَّثَنَا مَالِكٌ حَدَّثَنِي أَبُو بَكْرِ بْنُ عُمَرَ عَنْ سَعِيدِ بْنِ يَسَارٍ عَنْ ابْنِ عُمَرَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُوتِرُ عَلَى الْبَعِيرِ قِيلَ لِأَبِي مُحَمَّدٍ تَقُولُ بِهِ قَالَ نَعَمْ","id":"Telah mengabarkan kepada kami [Marwan bin Muhammad] telah menceritakan kepada kami [Malik] telah menceritakan kepadaku [Abu Bakr] dari [Sa'id bin Yasar] dari [Ibnu Umar], bahwa Nabi shallallahu 'alaihi wasallam pernah melakukan witir di atas unta.\" Abu Muhammad ditanya, \"Apakah engkau berpendapat dengannya?\" Ia menjawab, \"Ya.\" "},"1191":{"ar":" حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ بُرَيْدِ بْنِ أَبِي مَرْيَمَ عَنْ أَبِي الْحَوْرَاءِ السَّعْدِيِّ قَالَ قُلْتُ لِلْحَسَنِ بْنِ عَلِيٍّ مَا تَذْكُرُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ حَمَلَنِي عَلَى عَاتِقِهِ فَأَخَذْتُ تَمْرَةً مِنْ تَمْرِ الصَّدَقَةِ فَأَدْخَلْتُهَا فِي فَمِي فَقَالَ أَلْقِهَا أَمَا شَعَرْتَ أَنَّا لَا تَحِلُّ لَنَا الصَّدَقَةُ قَالَ وَكَانَ يَدْعُو بِهَذَا الدُّعَاءِ اللَّهُمَّ اهْدِنِي فِيمَنْ هَدَيْتَ وَعَافِنِي فِيمَنْ عَافَيْتَ وَتَوَلَّنِي فِيمَنْ تَوَلَّيْتَ وَبَارِكْ لِي فِيمَا أَعْطَيْتَ وَقِنِي شَرَّ مَا قَضَيْتَ إِنَّكَ تَقْضِي وَلَا يُقْضَى عَلَيْكَ وَإِنَّهُ لَا يَذِلُّ مَنْ وَالَيْتَ تَبَارَكْتَ وَتَعَالَيْتَ أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ عَنْ بُرَيْدِ بْنِ أَبِي مَرْيَمَ عَنْ أَبِي الْحَوْرَاءِ عَنْ الْحَسَنِ بْنِ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَ عَلَّمَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَلِمَاتٍ أَقُولُهُنَّ فِي الْقُنُوتِ فِي الْوِتْرِ فَذَكَرَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Utsman bin Umar] telah menceritakan kepada kami [Syu'bah] dari [Buraid bin Abu Maryam] dari [Abu Al Haura` As Sa'di] ia berkata, \"Aku katakan kepada [Al Hasan bin Ali], \"Apa yang engkau ingat dari Rasulullah shallallahu 'alaihi wasallam?\" Ia berkata, \"Beliau menggendongku di atas pundaknya, kemudian aku mengambil satu buah kurma zakat. Aku lalu masukkannya ke dalam mulutku sehingga beliau pun bersabda: \"Buanglah kurma tersebut, tidakkah engkau merasa bahwa zakat tidak halal bagi kita?\" Dan dahulu beliau berdoa dengan doa ini: \"ALLAAHUMMAHDINII FIIMAN HADAIT, WA 'AAFINII FIIMAN 'AAFAIT, WA TAWALLANII FIIMAN TAWALLAIT, WA BAARIK LII FIIMAA A'THAIT, WA QINII SYARRA MAA QADLAIT, INNAKA TAQDLII WA LAA YUQDLAA 'ALAIK, WA INNAHUU LAA YADZILLU MAN WAALAIT. TABAARAKTA WA TA'AALAIT (Ya Allah, berilah aku petunjuk di antara orang-orang yang Engkau beri petunjuk, dan selamatkanlah aku di antara orang-orang yang Engkau beri keselamatan, uruslah aku di antara orang-orang yang Engkau urus, berkahilah untukku apa yang telah Engkau berikan kepadaku, dan lindungilah aku dari keburukan apa yang telah Engkau putuskan. Sesungguhnya Engkau memutuskan dan tidak diberi keputusan, sesungguhnya tidak akan hina orang yang Engkau tolong dan, Maha Suci Engkau dan Maha Tinggi).\" Telah mengabarkan kepada kami ['Ubaidullah bin Musa] dari [Israil] dari [Abu Ishaq] dari [Buraid bin Abu Maryam] dari [Abu Al Haura`] dari [Al Hasan bin Ali radliallahu 'anhu] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam mengajarkan kepadaku beberapa kalimat yang aku ucapkan ketika qunut pada shalat Witir… kemudian ia menyebutkan seperti itu.\""},"1192":{"ar":" أَخْبَرَنَا يَحْيَى بْنُ حَسَّانَ قَالَ حَدَّثَنِي أَبُو الْأَحْوَصِ عَنْ أَبِي إِسْحَقَ عَنْ بُرَيْدِ بْنِ أَبِي مَرْيَمَ عَنْ أَبِي الْحَوْرَاءِ السَّعْدِيِّ عَنْ الْحَسَنِ بْنِ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَ عَلَّمَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَلِمَاتٍ أَقُولُهُنَّ فِي قُنُوتِ الْوِتْرِ اللَّهُمَّ اهْدِنِي فِيمَنْ هَدَيْتَ وَعَافِنِي فِيمَنْ عَافَيْتَ وَتَوَلَّنِي فِيمَنْ تَوَلَّيْتَ وَبَارِكْ لِي فِيمَا أَعْطَيْتَ وَقِنِي شَرَّ مَا قَضَيْتَ فَإِنَّكَ تَقْضِي وَلَا يُقْضَى عَلَيْكَ وَإِنَّهُ لَا يَذِلُّ مَنْ وَالَيْتَ تَبَارَكْتَ وَتَعَالَيْتَ قَالَ أَبُو مُحَمَّد أَبُو الْحَوْرَاءِ اسْمُهُ رَبِيعَةُ بْنُ شَيْبَانَ","id":"Telah mengabarkan kepada kami [Yahya bin Hassan] ia berkata, telah menceritakan kepadaku [Abu Al Ahwash] dari [Abu Ishaq] dari [Buraid bin Abu Maryam] dari [Abu Al Haura` As Sa'di] dari [Al Hasan bin Ali radliallahu 'anhu] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam mengajariku beberapa kalimat yang aku ucapkan ketika qunut witir, yaitu: \"ALLAAHUMMAHDINII FIIMAN HADAIT, WA 'AAFINII FIIMAN 'AAFAIT, WA TAWALLANII FIIMAN TAWALLAIT, WA BAARIK LII FIIMAA A'THAIT, WA QINII SYARRA MAA QADLAIT, INNAKA TAQDLII WA LAA YUQDLAA 'ALAIK, WA INNAHUU LAA YADZILLU MAN WAALAIT. TABAARAKTA WA TA'AALAIT (Ya Allah, berilah aku petunjuk di antara orang-orang yang Engkau beri petunjuk, dan selamatkanlah aku di antara orang-orang yang Engkau beri keselamatan, uruslah aku di antara orang-orang yang Engkau urus, berkahilah untukku apa yang telah Engkau berikan kepadaku, dan lindungilah aku dari keburukan apa yang telah Engkau putuskan. Sesungguhnya Engkau memutuskan dan tidak diberi keputusan, sesungguhnya tidak akan hina orang yang Engkau tolong dan, Maha Suci Engkau dan Maha Tinggi).\" Abu Muhammad berkata, \"Abu Al Haura` namanya adalah Rabi'ah bin Syaiban.\" "},"1193":{"ar":"أَخْبَرَنَا مَرْوَانُ عَنْ عَبْدِ اللَّهِ بْنِ وَهْبٍ عَنْ مُعَاوِيَةَ بْنِ صَالِحٍ عَنْ شُرَيْحِ بْنِ عُبَيْدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ أَبِيهِ عَنْ ثَوْبَانَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ هَذَا السَّهَرَ جَهْدٌ وَثِقَلٌ فَإِذَا أَوْتَرَ أَحَدُكُمْ فَلْيَرْكَعْ رَكْعَتَيْنِ فَإِنْ قَامَ مِنْ اللَّيْلِ وَإِلَّا كَانَتَا لَهُ","id":"Telah mengabarkan kepada kami [Marwan] dari [Abdullah bin Wahb] dari [Mu'awiyah bin Shalih] dari [Syuraih bin 'Ubaid] dari [Abdurrahman bin Jubair bin Nufair] dari [Ayahnya] dari [Tsauban] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya begadang (dalam mentaati Allah) ini sulit dan berat, jika salah seorang di antara kalian melakukan witir, maka hendaknya ia melakukan shalat dua rakaat jika terbangun di malam hari, jika tidak maka kedua rakaat tersebut adalah untuknya.\""},"1194":{"ar":" حَدَّثَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ الزُّهْرِيِّ عَنْ ابْنِ الْمُسَيَّبِ وَأَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا أَرَادَ أَنْ يَدْعُوَ عَلَى أَحَدٍ أَوْ يَدْعُوَ لِأَحَدٍ قَنَتَ بَعْدَ الرُّكُوعِ فَرُبَّمَا قَالَ إِذَا قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ رَبَّنَا وَلَكَ الْحَمْدُ اللَّهُمَّ أَنْجِ الْوَلِيدَ بْنَ الْوَلِيدِ وَسَلَمَةَ بْنَ هِشَامٍ وَعَيَّاشَ بْنَ أَبِي رَبِيعَةَ وَالْمُسْتَضْعَفِينَ مِنْ الْمُؤْمِنِينَ اللَّهُمَّ اشْدُدْ وَطْأَتَكَ عَلَى مُضَرَ وَاجْعَلْهَا سِنِينَ كَسِنِي يُوسُفَ وَيَجْهَرُ بِذَلِكَ يَقُولُ فِي بَعْضِ صَلَاتِهِ فِي صَلَاةِ الْفَجْرِ اللَّهُمَّ الْعَنْ فُلَانًا وَفُلَانًا لِحَيَّيْنِ مِنْ أَحْيَاءِ الْعَرَبِ فَأَنْزَلَ اللَّهُ تَعَالَى { لَيْسَ لَكَ مِنْ الْأَمْرِ شَيْءٌ أَوْ يَتُوبَ عَلَيْهِمْ أَوْ يُعَذِّبَهُمْ فَإِنَّهُمْ ظَالِمُونَ }","id":"Telah menceritakan kepada kami [Yahya bin Hassan] telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Az Zuhri] dari [Ibnu Al Musayyab] dan [Abu Salamah bin Abdurrahman] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam jika ingin mendoakan keburukan atas seseorang atau mendoakan kebaikan untuk seseorang, maka beliau melakukan qunut setelah rukuk. Barangkali setelah mengucapkan SAMI'ALLAAHU LIMAN HAMIDAH, RABBANAA WA LAKAL HAMDU (Semoga Allah mendengar pujian orang yang memuji-Nya. Ya Rabb kami, kepada-Mu lah segala pujian), beliau berdoa: \"Ya Allah, selamatkan Al Walid bin Al Walid, Salamah bin Hisyam, 'Ayyasy bin Abu Rabi'ah dan orang-orang Mukmin yang lemah. Ya Allah, keraskan siksa-Mu atas Mudlar, timpakahlah kepada mereka masa paceklik sebagaimana paceklik pada masa Yusuf.\" Beliau mengeraskan doa tersebut. Dan beliau mengucapkan pada sebagian shalatnya; shalat subuh: \"Ya Allah, laknatlah Fulan dan Fulan.\" Beliau menyebutkan dua kampung dari kampung-kampung Arab. Kemudian Allah Ta'ala menurunkan ayat: '(Tak ada sedikitpun campur tanganmu dalam urusan mereka itu atau Allah menerima taubat mereka, atau mengazab mereka karena sesungguhnya mereka itu orang-orang yang zalim) ' (Qs. Ali Imran: 128)."},"1195":{"ar":" أَخْبَرَنَا أَبُو النُّعْمَانِ حَدَّثَنَا ثَابِتُ بْنُ يَزِيدَ حَدَّثَنَا عَاصِمٌ قَالَ سَأَلْتُ أَنَسَ بْنَ مَالِكٍ عَنْ الْقُنُوتِ فَقَالَ قَبْلَ الرُّكُوعِ قَالَ فَقُلْتُ إِنَّ فُلَانًا زَعَمَ أَنَّكَ قُلْتَ بَعْدَ الرُّكُوعِ قَالَ كَذَبَ ثُمَّ حَدَّثَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَنَتَ شَهْرًا بَعْدَ الرُّكُوعِ يَدْعُو عَلَى حَيٍّ مِنْ بَنِي سُلَيْمٍ","id":"Telah mengabarkan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Tsabit bin Yazid] telah menceritakan kepada kami ['Ashim] ia berkata, aku bertanya kepada [Anas bin Malik] mengenai Qunut, kemudian ia menjawab, \"Sebelum rukuk.\" 'Ashim berkata, \"Kemudian aku katakan, \"Sesungguhnya Fulan mengaku bahwa engkau mengatakan setelah rukuk?\" Anas menjawab, \"Ia berdusta! \" Kemudian Anas menceritakan bahwa Nabi shallallahu 'alaihi wasallam melakukan qunut selama sebulan setelah rukuk, mendoakan kecelakaan atas sebuah kampung dari Bani Sulaim.\" "},"1196":{"ar":" حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ ابْنِ أَبِي لَيْلَى عَنْ الْبَرَاءِ بْنِ عَازِبٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْنُتُ فِي الصُّبْحِ حَدَّثَنَا أَبُو نُعَيْمٍ عَنْ شُعْبَةَ بِإِسْنَادِهِ نَحْوَهُ","id":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah] dari ['Amru bin Murrah] dari [Ibnu Abu Laila] dari [Al Bara` bin 'Azib], bahwa Nabi shallallahu 'alaihi wasallam melakukan qunut pada shalat Subuh.\" Telah menceritakan kepada kami [Abu Nu'aim] dari [Syu'bah] dengan sanadnya seperti itu.\" "},"1197":{"ar":" حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ مُحَمَّدٍ قَالَ سُئِلَ أَنَسُ بْنُ مَالِكٍ أَقَنَتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي صَلَاةِ الصُّبْحِ قَالَ نَعَمْ فَقِيلَ لَهُ أَوَ قُلْتَ لَهُ قَبْلَ الرُّكُوعِ أَوْ بَعْدَ الرُّكُوعِ قَالَ بَعْدَ الرُّكُوعِ يَسِيرًا قَالَ أَبُو مُحَمَّد أَقُولُ بِهِ وَآخُذُ بِهِ وَلَا أَرَى أَنْ آخُذَ بِهِ إِلَّا فِي الْحَرْبِ","id":"Telah menceritakan kepada kami [Musadddad] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Muhammad] ia berkata, [Anas bin Malik] ditanya, \"Apakah Rasulullah shallallahu 'alaihi wasallam melakukan qunut saat shalat subuh?\" Ia menjawab, \"Ya.\" Kemudian ia ditanya, \"Apakah engkau mengatakan kepadanya sebelum rukuk atau setelah rukuk?\" Anas menjawab, \"Sesaat setelah rukuk.\" Abu Muhammad berkata, \"Aku berpendapat dan beramal dengannya, namun aku tidak mengamalkannya kecuali saat perang.\" "},"1198":{"ar":" أَخْبَرَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا عُقْبَةُ بْنُ الْأَصَمِّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بُرَيْدَةَ عَنْ أَبِيهِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَطْعَمُ يَوْمَ الْفِطْرِ قَبْلَ أَنْ يَخْرُجَ وَكَانَ إِذَا كَانَ يَوْمُ النَّحْرِ لَمْ يَطْعَمْ حَتَّى يَرْجِعَ فَيَأْكُلَ مِنْ ذَبِيحَتِهِ حَدَّثَنَا عَمْرُو بْنُ عَوْنٍ حَدَّثَنَا هُشَيْمٌ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ حَفْصِ بْنِ عُبَيْدِ اللَّهِ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنَحْوِهِ","id":"Telah mengabarkan kepada kami [Yahya bin Hassan] telah menceritakan kepada kami ['Uqbah bin Al Asham] telah menceritakan kepada kami [Abdullah bin Buraidah] dari [Ayahnya], bahwa Rasulullah shallallahu 'alaihi wasallam pada hari ?dul Fithri makan sebelum keluar (shalat), sedangkan pada hari ?dul Adlha beliau tidak makan kecuali setelah kembali dari shalat, dan beliau makan dengan daging sembelihannya.\" Telah menceritakan kepada kami ['Amru bin 'Aun] telah menceritakan kepada kami [Husyaim] dari [Muhammad bin Ishaq] dari [Hafsh bin 'Ubaidullah] dari [Anas] dari Nabi shallallahu 'alaihi wasallam dengan hadits seperti itu.\" "},"1199":{"ar":" أَخْبَرَنَا يَعْلَى حَدَّثَنَا عَبْدُ الْمَلِكِ عَنْ عَطَاءٍ عَنْ جَابِرٍ قَالَ شَهِدْتُ الصَّلَاةَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي يَوْمِ عِيدٍ فَبَدَأَ بِالصَّلَاةِ قَبْلَ الْخُطْبَةِ بِغَيْرِ أَذَانٍ وَلَا إِقَامَةٍ","id":"Telah mengabarkan kepada kami [Ya'la] telah menceritakan kepada kami [Abdul Malik] dari ['Atha`] dari [Jabir] ia berkata, \"Pada hari raya Id aku menghadiri shalat bersama Rasulullah shallallahu 'alaihi wasallam, beliau memulai shalat sebelum khutbah, tanpa adzan dan iqamah.\" "},"1200":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنِي ابْنُ عُيَيْنَةَ حَدَّثَنِي أَيُّوبُ السَّخْتِيَانِيُّ قَالَ سَمِعْتُ عَطَاءً يَقُولُ سَمِعْتُ ابْنَ عَبَّاسٍ يَقُولُ أَشْهَدُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ بَدَأَ بِالصَّلَاةِ قَبْلَ الْخُطْبَةِ يَوْمَ الْعِيدِ ثُمَّ خَطَبَ فَرَأَى أَنَّهُ لَمْ يُسْمِعْ النِّسَاءَ فَأَتَاهُنَّ فَذَكَّرَهُنَّ وَوَعَظَهُنَّ وَأَمَرَهُنَّ أَنْ يَتَصَدَّقْنَ وَبِلَالٌ قَابِضٌ بِثَوْبِهِ فَجَعَلَتْ الْمَرْأَةُ تَجِيءُ بِالْخُرْصِ وَالشَّيْءِ ثُمَّ تُلْقِيهِ فِي ثَوْبِ بِلَالٍ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepadaku [Ibnu 'Uyainah] telah menceritakan kepadaku [Ayyub As Sakhtiyani] ia berkata, aku mendengar ['Atha`] berkata, aku mendengar [Ibnu Abbas] berkata, \"Aku bersaksi atas Rasulullah shallallahu 'alaihi wasallam bahwa pada hari Id beliau memulai shalat sebelum khutbah, baru kemudian beliau berkhutbah. Setelah itu beliau merasa bahwa kaum wanita tidak bisa mendengarkan khutbahnya, maka beliau pun datang menemui mereka, beliau mengingatkan mereka, memberi nasehat dan memerintah agar mereka bersedekah. Sementara Bilal membawa kainnya, lalu seorang wanita datang dengan membawa anting dan sesuatu yang lain, untuk kemudian melemparkannya ke dalam kain yang di bawa oleh Bilal.\" "},"1201":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ أَخْبَرَنَا الْحَسَنُ بْنُ مُسْلِمٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ قَالَ شَهِدْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبَا بَكْرٍ وَعُمَرَ وَعُثْمَانَ يُصَلُّونَ قَبْلَ الْخُطْبَةِ فِي الْعِيدِ","id":"Telah mengabarkan kepada kami [Abu 'Ashim] dari [Ibnu Juraij] telah mengabarkan kepada kami [Al Hasan bin Muslim] dari [Thawus] dari [Ibnu Abbas] ia berkata, \"Aku menyaksikan Nabi shallallahu 'alaihi wasallam, Abu Bakr, Umar dan Utsman melakukan shalat sebelum khutbah pada hari raya.\" "},"1202":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا شُعْبَةُ حَدَّثَنِي عَدِيُّ بْنُ ثَابِتٍ قَالَ سَمِعْتُ سَعِيدَ بْنَ جُبَيْرٍ يُحَدِّثُ عَنْ ابْنِ عَبَّاسٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ يَوْمَ الْفِطْرِ فَصَلَّى رَكْعَتَيْنِ وَلَمْ يُصَلِّ قَبْلَهَا وَلَا بَعْدَهَا قِيلَ لِأَبِي مُحَمَّدٍ تَقُولُ بِهَذَا قَالَ لِي وَأَوْمَأَ إِي نَعَمْ","id":"Telah mengabarkan kepada kami [Abu Al Walid Ath Thayalisi] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepadaku [Adi bin Tsabit] ia berkata, saya mendengar [Sa'id? bin Jubair] menceritakan dari [Ibnu Abbas], bahwa Nabi shallallahu 'alaihi wasallam keluar pada hari Idul Fithri, lalu beliau shalat dua rakaat dan tidak mengerjakan shalat baik sebelum atau sesudahnya.\" Abu Muhammad ditanya, \"Apakah engkau berpendapat dengan hal ini?\" Ia lalu berkata kepadaku dengan memberikan isyarat, yakni, \"Ya.\" "},"1203":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ الْحَجَّاجِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ سَعْدِ بْنِ عَمَّارِ بْنِ سَعْدٍ الْمُؤَذِّنِ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَمَّارٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُكَبِّرُ فِي الْعِيدَيْنِ فِي الْأُولَى سَبْعًا وَفِي الْأُخْرَى خَمْسًا وَكَانَ يَبْدَأُ بِالصَّلَاةِ قَبْلَ الْخُطْبَةِ","id":"Telah mengabarkan kepada kami [Ahmad bin Al Hajjaj] dari [Abdurrahman bin Sa'd bin 'Ammar bin Sa'd Al Muadzdzin] dari [Abdullah bin Muhammad bin 'Ammar] dari [Ayahnya] dari [Kakeknya] ia berkata, \"Nabi shallallahu 'alaihi wasallam bertakbir pada dua shalat Id, pada rakaat pertama tujuh kali dan pada rakaat kedua lima kali. Dan beliau memulai dengan shalat sebelum khutbah.\" "},"1204":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ إِبْرَاهِيمَ بْنِ مُحَمَّدِ بْنِ الْمُنْتَشِرِ عَنْ أَبِيهِ عَنْ حَبِيبِ بْنِ سَالِمٍ عَنْ النُّعْمَانِ بْنِ بَشِيرٍ قَالَ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الْعِيدَيْنِ وَالْجُمُعَةِ بِسَبِّحِ اسْمَ رَبِّكَ الْأَعْلَى وَهَلْ أَتَاكَ حَدِيثُ الْغَاشِيَةِ وَرُبَّمَا اجْتَمَعَا فَقَرَأَ بِهِمَا","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Ibrahim bin Muhammad bin Al Muntasyir] dari [Ayahnya] dari [Habib bin Salim] dari [An Nu'man bin Basyir] ia berkata, \"Nabi shallallahu 'alaihi wasallam membaca pada shalat dua hari raya dan shalat Jum'at dengan SABBIHISMA RABBIKAL A'LAA (surat Al A'laa) dan HAL ATAAKA HADIITSUL GHAASYIYAH (surat Al Ghaasyiyah). Jika keduanya bertemu dalam satu hari maka beliau juga membaca kedua surat tersebut.\""},"1205":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سَلَمَةُ يَعْنِي ابْنَ نُبَيْطٍ حَدَّثَنِي أَبِي أَوْ نُعَيْمُ بْنُ أَبِي هِنْدٍ عَنْ أَبِي قَالَ حَجَجْتُ مَعَ أَبِي وَعَمِّي فَقَالَ لِي أَبِي تَرَى ذَلِكَ صَاحِبَ الْجَمَلِ الْأَحْمَرِ الَّذِي يَخْطُبُ ذَلِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Salamah] -yaitu Ibnu Nubaith- telah menceritakan kepadaku Ayahku, atau [Nu'aim bin Abu Hindun] dari [Ayahku] ia berkata, \"Aku berhaji bersama ayahku dan pamanku, kemudian bapakku berkata kepadaku, \"Apakah engkau melihat pemilik unta merah yang sedang berkhutbah itu? Itu adalah Rasulullah shallallahu 'alaihi wasallam.\" "},"1206":{"ar":" أَخْبَرَنَا إِبْرَاهِيمُ بْنُ مُوسَى حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ الصَّمَدِ عَنْ هِشَامٍ عَنْ حَفْصَةَ عَنْ أُمِّ عَطِيَّةَ قَالَتْ أَمَرَنَا بِأَبِي هُوَ أَنْ نُخْرِجَ يَوْمَ الْفِطْرِ وَيَوْمَ النَّحْرِ الْعَوَاتِقَ وَذَوَاتِ الْخُدُورِ فَأَمَّا الْحُيَّضُ فَإِنَّهُنَّ يَعْتَزِلْنَ الصَّفَّ وَيَشْهَدْنَ الْخَيْرَ وَدَعْوَةَ الْمُسْلِمِينَ قَالَتْ قُلْتُ يَا رَسُولَ اللَّهِ فَإِنْ لَمْ يَكُنْ لِإِحْدَاهُنَّ الْجِلْبَابُ قَالَ تُلْبِسُهَا أُخْتُهَا مِنْ جِلْبَابِهَا","id":"Telah mengabarkan kepada kami [Ibrahim bin Musa] telah menceritakan kepada kami [Abdul Aziz bin Abdush Shamad] dari [Hisyam] dari [Hafshah] dari [Ummu 'Athiyyah] ia berkata, \"Demi bapakku! Sungguh beliau memerintahkan kami agar pada Idul Fithri dan hari Raya Kurban mengeluarkan anak-anak wanita yang baru baligh serta para remaja puteri, adapun para wanita yang sedang haid maka mereka menjauhi shaf dan mereka menyaksikan kebaikan serta doa orang-orang Muslim.\" Ummu Athiyyah berkata, \"Aku lalu bertanya, \"Wahai Rasulullah, bagaimana jika salah seorang di antara mereka tidak memiliki Jilbab?\" Beliau menjawab: \"Hendaklah saudara perempuannya memakaikannya dari jilbab miliknya.\""},"1207":{"ar":" أَخْبَرَنَا يَعْلَى بْنُ عُبَيْدٍ حَدَّثَنَا عَبْدُ الْمَلِكِ عَنْ عَطَاءٍ عَنْ جَابِرٍ قَالَ شَهِدْتُ الصَّلَاةَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي يَوْمِ عِيدٍ فَبَدَأَ بِالصَّلَاةِ قَبْلَ الْخُطْبَةِ ثُمَّ قَامَ مُتَوَكِّئًا عَلَى بِلَالٍ حَتَّى أَتَى النِّسَاءَ فَوَعَظَهُنَّ وَذَكَّرَهُنَّ وَأَمَرَهُنَّ بِتَقْوَى اللَّهِ قَالَ تَصَدَّقْنَ فَذَكَرَ شَيْئًا مِنْ أَمْرِ جَهَنَّمَ فَقَامَتْ امْرَأَةٌ مِنْ سَفِلَةِ النِّسَاءِ سَفْعَاءُ الْخَدَّيْنِ فَقَالَتْ لِمَ يَا رَسُولَ اللَّهِ قَالَ لِأَنَّكُنَّ تُفْشِينَ الشَّكَاءَ وَاللَّعْنَ وَتَكْفُرْنَ الْعَشِيرَ فَجَعَلْنَ يَأْخُذْنَ مِنْ حُلِيِّهِنَّ وَأَقْرَاطِهِنَّ وَخَوَاتِيمِهِنَّ يَطْرَحْنَهُ فِي ثَوْبِ بِلَالٍ يَتَصَدَّقْنَ بِهِ أَخْبَرَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ عَدِيِّ بْنِ ثَابِتٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَ هَذَا","id":"Telah mengabarkan kepada kami [Ya'la bin 'Ubaid] telah menceritakan kepada kami [Abdul Malik] dari ['Atha`] dari [Jabir] ia berkata, \"Pada hari Id aku pernah shalat bersama Rasulullah shallallahu 'alaihi wasallam, beliau memulainya dengan shalat sebelum khutbah. Beliau kemudian berdiri dengan bersandar pada Bilal, hingga beliau datang kepada para wanita dan memberi nasehat mereka serta mengingatkan dan memerintahkan agar mereka bertakwa kepada Allah. Beliau bersabda: \"Bersedekahlah.\" Kemudian beliau menyebutkan sebagian perkara Jahannam. Maka berdirilah seorang wanita dari tengah-tengah mereka yang kedua pipinya kehitam-hitaman. Wanita itu lalu berkata, \"Kenapa wahai Rasulullah? Beliau menjawab: \"Karena kalian banyak mengeluh, banyak melaknat, dan suka ingkar kepada suami.\" Kemudian mereka mengambil sebagian dari perhiasan, anting dan cincin mereka lalu melemparkannya ke dalam kain yang dibawa oleh Bilal sebagai sedekah.\" Telah mengabarkan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah] dari [Adi bin Tsabit] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam seperti ini.\" "},"1208":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ إِسْرَائِيلَ عَنْ عُثْمَانَ بْنِ الْمُغِيرَةِ عَنْ إِيَاسِ بْنِ أَبِي رَمْلَةَ قَالَ شَهِدْتُ مُعَاوِيَةَ يَسْأَلُ زَيْدَ بْنَ أَرْقَمَ أَشَهِدْتَ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِيدَيْنِ اجْتَمَعَا فِي يَوْمٍ قَالَ نَعَمْ قَالَ فَكَيْفَ صَنَعَ قَالَ صَلَّى الْعِيدَ ثُمَّ رَخَّصَ فِي الْجُمُعَةِ فَقَالَ مَنْ شَاءَ أَنْ يُصَلِّيَ فَلْيُصَلِّ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Musa] dari [Israil] dari [Utsman bin Al Mughirah] dari [Iyas bin Abu Ramlah] ia berkata, aku menyaksikan Mu'awiyah bertanya kepada [Zaid bin Arqam], \"Apakah engkau pernah menyaksikan bersama Nabi shallallahu 'alaihi wasallam dua hari raya berkumpul dalam satu hari?\" Zaid menjawab, \"Ya.\" Mu'awiyah bertanya lagi, \"Apa yang beliau lakukan?\" Zaid menjawab, \"Beliau laksanakan shalat Id, lalu memberi keringanan dalam pelaksanakaan shalat jum'at.\" Beliau bersabda: \"Barangsiapa ingin melakukan shalat Jum'at, maka silahkan ia melakukannya! \""},"1209":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ الصَّلْتِ حَدَّثَنَا فُلَيْحٌ عَنْ سَعِيدِ بْنِ الْحَارِثِ عَنْ أَبِي هُرَيْرَةَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا خَرَجَ إِلَى الْعِيدِ رَجَعَ فِي طَرِيقٍ آخَرَ","id":"Telah mengabarkan kepada kami [Muhammad bin Ash Shalt] telah menceritakan kepada kami [Fulaih] dari [Sa'id bin Al Harits] dari [Abu Hurairah], bahwa Nabi shallallahu 'alaihi wasallam jika keluar untuk shalat Is, maka beliau akan kembali melalui jalan yang lain.\""},"1210":{"ar":" حَدَّثَنَا أَبُو عَاصِمٍ عَنْ زَكَرِيَّا بْنِ إِسْحَقَ عَنْ يَحْيَى بْنِ عَبْدِ اللَّهِ بْنِ صَيْفِيٍّ عَنْ أَبِي مَعْبَدٍ عَنْ ابْنِ عَبَّاسٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا بَعَثَ مُعَاذًا إِلَى الْيَمَنِ قَالَ إِنَّكَ تَأْتِي قَوْمًا أَهْلَ كِتَابٍ فَادْعُهُمْ إِلَى أَنْ يَشْهَدُوا أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّ مُحَمَّدًا رَسُولُ اللَّهِ فَإِنْ أَطَاعُوا لَكَ فِي ذَلِكَ فَأَخْبِرْهُمْ أَنَّ اللَّهَ فَرَضَ عَلَيْهِمْ خَمْسَ صَلَوَاتٍ فِي كُلِّ يَوْمٍ وَلَيْلَةٍ فَإِنْ هُمْ أَطَاعُوا لَكَ فِي ذَلِكَ فَأَخْبِرْهُمْ أَنَّ اللَّهَ فَرَضَ عَلَيْهِمْ صَدَقَةً فِي أَمْوَالِهِمْ تُؤْخَذُ مِنْ أَغْنِيَائِهِمْ وَتُرَدُّ عَلَى فُقَرَائِهِمْ فَإِنْ هُمْ أَطَاعُوا لَكَ فِي ذَلِكَ فَإِيَّاكَ وَكَرَائِمَ أَمْوَالِهِمْ وَإِيَّاكَ وَدَعْوَةَ الْمَظْلُومِ فَإِنَّهُ لَيْسَ لَهَا مِنْ دُونِ اللَّهِ حِجَابٌ","id":"Telah mengabarkan kepada kami [Abu 'Ashim] dari [Zakaria bin Ishaq] dari [Yahya bin Abdullah bin Shaifi] dari [Abu Ma'bad] dari [Ibnu Abbas], bahwa Nabi shallallahu 'alaihi wasallam saat mengutus Mu'adz ke Yaman, beliau bersabda: \"Sesungguhnya engkau akan datang kepada kaum ahli kitab, maka ajaklah mereka untuk bersaksi bahwa tidak ada tuhan yang berhak disembah kecuali Allah, dan Muhammad adalah Rasulullah. Kemudian jika mereka mentaatimu dalam hal itu maka kabarkanlah kepada mereka bahwa Allah mewajibkan atas mereka shalat lima waktu dalam setiap sehari semalam. Kemudian jika mereka mentaatimu dalam hal itu maka kabarkanlah kepada mereka bahwa Allah telah mewajibkan zakat pada harta mereka yang diambil dari orang-orang kaya mereka dan diberikan kepada orang-orang fakir mereka. Kemudian jika mereka mentaatimu dalam hal itu, maka jauhilah harta berharga mereka dan berhati-hatilah engkau terhadap doa orang yang terzhalimi, sesungguhnya tidak ada penghalang baginya dari Allah.\" "},"1211":{"ar":" أَخْبَرَنَا هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا شُعْبَةُ عَنْ مُحَمَّدِ بْنِ زِيَادٍ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ يُحَدِّثُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ لَيْسَ الْمِسْكِينُ الَّذِي تَرُدُّهُ اللُّقْمَةُ وَاللُّقْمَتَانِ وَالْكِسْرَةُ وَالْكِسْرَتَانِ وَالتَّمْرَةُ وَالتَّمْرَتَانِ وَلَكِنْ الْمِسْكِينُ الَّذِي لَيْسَ لَهُ غِنًى يُغْنِيهِ يَسْتَحْيِي أَنْ يَسْأَلَ النَّاسَ إِلْحَافًا أَوْ لَا يَسْأَلُ النَّاسَ إِلْحَافًا","id":"Telah mengabarkan kepada kami [Hasyim bin Al Qasim] telah menceritakan kepada kami [Syu'bah] dari [Muhammad bin Ziyad] ia berkata, saya mendengar [Abu Hurairah] menceritakan dari Nabi shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Orang miskin bukanlah orang yang tertolak untuk mendapatkan satu atau dua suap makanan, sepotong atau dua potong roti, sebutir atau dua butir kurma. Akan tetapi orang miskin adalah orang yang tidak memiliki sesuatu yang mencukupinya dan malu untuk meminta kepada manusia dengan mendesak, atau orang yang tidak meminta kepada manusia dengan mendesak.\" "},"1212":{"ar":" أَخْبَرَنَا يَعْلَى بْنُ عُبَيْدٍ حَدَّثَنَا عَبْدُ الْمَلِكِ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ صَاحِبِ إِبِلٍ وَلَا بَقَرٍ وَلَا غَنَمٍ لَا يُؤَدِّي حَقَّهَا إِلَّا أُقْعِدَ لَهَا يَوْمَ الْقِيَامَةِ بِقَاعٍ قَرْقَرٍ تَطَؤُهُ ذَاتُ الظِّلْفِ بِظِلْفِهَا وَتَنْطَحُهُ ذَاتُ الْقَرْنِ بِقَرْنِهَا لَيْسَ فِيهَا يَوْمَئِذٍ جَمَّاءُ وَلَا مَكْسُورَةُ الْقَرْنِ قَالُوا يَا رَسُولَ اللَّهِ وَمَا حَقُّهَا قَالَ إِطْرَاقُ فَحْلِهَا وَإِعَارَةُ دَلْوِهَا وَمِنْحَتُهَا وَحَلَبُهَا عَلَى الْمَاءِ وَحَمْلٌ عَلَيْهَا فِي سَبِيلِ اللَّهِ","id":"Telah mengabarkan kepada kami [Ya'la bin 'Ubaid] telah menceritakan kepada kami [Abdul Malik] dari [Abu Az Zubair] dari [Jabir] ia berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Tidaklah pemilik unta, sapi dan kambing yang tidak menunaikan haknya kecuali ia akan didudukkan di hadapan hewan tersebut pada Hari Kiamat di tanah terbuka yang datar, kemudian hewan yang memiliki sepatu akan menginjak dengan sepatunya dan yang memiliki tanduk akan menanduk dengan tanduknya. Pada saat itu tidak ada hewan yang tak bertanduk atau tidak ada hewan yang bertanduk patah.\" Mereka berkata, \"Wahai Rasulullah, apakah hak hewan-hewan tersebut?\" Beliau menjawab: \"Mengawinkan pejantannya, meminjamkan embernya, meminjamkannya (untuk diambil manfaatnya), memeras susunya setelah diberi minum dan memberinya muatan di jalan Allah.\""},"1213":{"ar":" حَدَّثَنَا بِشْرُ بْنُ الْحَكَمِ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي أَبُو الزُّبَيْرِ أَنَّهُ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا مِنْ صَاحِبِ إِبِلٍ لَا يَفْعَلُ فِيهَا حَقَّهَا إِلَّا جَاءَ يَوْمَ الْقِيَامَةِ أَكْثَرُ مَا كَانَتْ قَطُّ وَأُقْعِدَ لَهَا بِقَاعٍ قَرْقَرٍ تَسْتَنُّ عَلَيْهِ بِقَوَائِمِهَا وَأَخْفَافِهَا وَلَا صَاحِبِ بَقَرٍ لَا يَفْعَلُ فِيهَا حَقَّهَا إِلَّا جَاءَ يَوْمَ الْقِيَامَةِ أَكْثَرُ مَا كَانَتْ قَطُّ وَأُقْعِدَ لَهَا بِقَاعٍ قَرْقَرٍ تَنْطَحُهُ بِقُرُونِهَا وَتَطَؤُهُ بِقَوَائِمِهَا وَلَا صَاحِبِ غَنَمٍ لَا يَفْعَلُ فِيهَا حَقَّهَا إِلَّا جَاءَ يَوْمَ الْقِيَامَةِ أَكْثَرُ مَا كَانَتْ وَأُقْعِدَ لَهَا بِقَاعٍ قَرْقَرٍ تَنْطَحُهُ بِقُرُونِهَا وَتَطَؤُهُ بِأَظْلَافِهَا لَيْسَ فِيهَا جَمَّاءُ وَلَا مَكْسُورَةٌ قَرْنُهَا وَلَا صَاحِبِ كَنْزٍ لَا يَفْعَلُ فِيهِ حَقَّهُ إِلَّا جَاءَ كَنْزُهُ يَوْمَ الْقِيَامَةِ شُجَاعًا أَقْرَعَ يَتْبَعُهُ فَاتِحًا فَاهُ فَإِذَا أَتَاهُ فَرَّ مِنْهُ فَيُنَادِيهِ خُذْ كَنْزَكَ الَّذِي خَبَّأْتَهُ قَالَ فَأَنَا عَنْهُ غَنِيٌّ فَإِذَا رَأَى أَنَّهُ لَا بُدَّ مِنْهُ سَلَكَ يَدَهُ فِي فَمِهِ فَيَقْضِمُهَا قَضْمَ الْفَحْلِ قَالَ أَبُو الزُّبَيْرِ سَمِعْتُ عُبَيْدَ بْنَ عُمَيْرٍ يَقُولُ هَذَا الْقَوْلَ ثُمَّ سَأَلْنَا جَابِرَ بْنَ عَبْدِ اللَّهِ فَقَالَ مِثْلَ قَوْلِ عُبَيْدِ بْنِ عُمَيْرٍ قَالَ وَقَالَ أَبُو الزُّبَيْرِ سَمِعْتُ عُبَيْدَ بْنَ عُمَيْرٍ يَقُولُ قَالَ رَجُلٌ يَا رَسُولَ اللَّهِ مَا حَقُّ الْإِبِلِ قَالَ حَلَبُهَا عَلَى الْمَاءِ وَإِعَارَةُ دَلْوِهَا وَإِعَارَةُ فَحْلِهَا وَمَنْحُهَا وَحَمْلٌ عَلَيْهَا فِي سَبِيلِ اللَّهِ أَخْبَرَنَا الْحَسَنُ بْنُ الرَّبِيعِ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ الْأَعْمَشِ عَنْ الْمَعْرُورِ بْنِ سُوَيْدٍ عَنْ أَبِي ذَرٍّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِبَعْضِ هَذَا الْحَدِيثِ","id":"Telah menceritakan kepada kami [Bisyr bin Al Hakam] telah menceritakan kepada kami [Abdurrazzaq] telah mengabarkan kepada kami [Ibnu Juraij] ia berkata, telah mengabarkan kepadaku [Abu Az Zubair] bahwa ia mendengar [Jabir bin Abdullah] berkata, \"Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah pemilik unta yang tidak melakukan haknya melainkan ia akan datang pada hari Kiamat lebih banyak daripada dahulunya dan orang tersebut didudukkan di hadapannya pada tanah terbuka yang datar, hewan-hewan tersebut menyepak pemiliknya dengan kaki dan sepatunya. Dan tidaklah pemilik sapi yang tidak melakukan haknya kecuali melainkan ia akan datang pada hari Kiamat lebih banyak daripada dahulunya dan pemiliknya didudukkan di hadapannya pada tanah terbuka yang datar, hewan tersebut menanduknya dengan tanduknya dan menginjaknya dengan kaki-kakinya. Dan tidaklah pemilik kambing yang tidak melakukan haknya melainkan ia akan datang pada hari Kiamat lebih banyak daripada dahulunya dan pemiliknya di dudukkan di hadapannya pada tanah terbuka yang datar, hewan tersebut menanduknya dengan tanduknya dan menginjaknya dengan sepatu-sepatunya. Pada hari Kiamat tidak ada kambing yang tidak bertanduk dan tidak ada yang bertanduk patah. Dan tidaklah orang yang memiliki barang timbunan yang tidak melakukan haknya melainkan barang timbunannya akan datang pada hari Kiamat sebagai ular botak yang mengikutinya dengan membuka mulutnya. Apabila ular tersebut datang kepadanya, maka ia akan lari darinya, kemudian ular tersebut berseru kepadany, 'Ambillah barang timbunanmu yang telah engkau sembunyikan.' Pemiliknya berkata, 'Aku tidak butuh kepadanya.' Kemudian apabila ia melihat bahwa ia harus mengambilnya, maka ia memasukkan tangannya ke dalam mulutnya, kemudian ular tersebut mematahkannya dengan giginya sebagaimana pejantan menggigit menggunakan giginya.\" [Abu Az Zubair] berkata, \"Saya mendengar ['Ubaid bin 'Umair] mengatakan perkataan ini, maka kami pun bertanya kepada [Jabir bin Abdullah], dan ia juga mengatakan sebagaimana perkataan 'Ubaid bin 'Umair.\" Ibnu Juraij berkata, \" [Abu Az Zubair] berkata, \"Saya mendengar ['Ubaid bin 'Umair] berkata, \"Seorang laki-laki berkata, \"Wahai Rasulullah, apakah hak unta?\" Beliau menjawab: \"Memerahnya setelah memberi minum, meminjamkan embernya, meminjamkan pejantannya, meminjamkan (untuk diambil manfaatnya) dan memberinya muatan di jalan Allah.\" Telah mengabarkan kepada kami [Al Hasan bin Ar Rabi'] telah menceritakan kepada kami [Abu Al Ahwash] dari [Al A'masy] dari [Al Ma'rur bin Suwaid] dari [Abu Dzar] dari Nabi shallallahu 'alaihi wasallam dengan sebagian hadits ini.\" "},"1214":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ الْمُبَارَكِ حَدَّثَنَا عَبَّادُ بْنُ الْعَوَّامِ وَإِبْرَاهِيمُ بْنُ صَدَقَةَ عَنْ سُفْيَانَ بْنِ حُسَيْنٍ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَتَبَ الصَّدَقَةَ فَكَانَ فِي الْغَنَمِ فِي كُلِّ أَرْبَعِينَ سَائِمَةً شَاةٌ إِلَى عِشْرِينَ وَمِائَةٍ فَإِذَا زَادَتْ فَفِيهَا شَاتَانِ إِلَى مِائَتَيْنِ فَإِذَا زَادَتْ فَفِيهَا ثَلَاثُ شِيَاهٍ إِلَى ثَلَاثِ مِائَةٍ فَإِذَا زَادَتْ شَاةً لَمْ يَجِبْ فِيهَا إِلَّا ثَلَاثُ شِيَاهٍ حَتَّى تَبْلُغَ أَرْبَعَ مِائَةٍ فَإِذَا بَلَغَتْ أَرْبَعَ مِائَةِ شَاةٍ فَفِي كُلِّ مِائَةٍ شَاةٌ وَلَا تُؤْخَذُ فِي الصَّدَقَةِ هَرِمَةٌ وَلَا ذَاتُ عَوَارٍ وَلَا ذَاتُ عَيْبٍ","id":"Telah mengabarkan kepada kami [Al Hakam bin Al Mubarak] telah menceritakan kepada kami ['Abbad bin Al 'Awwam] dan [Ibrahim bin Shadaqah] dari [Sufyan bin Husain] dari [Az Zuhri] dari [Salim] dari [Ibnu Umar], bahwa Nabi shallallahu 'alaihi wasallam telah menetapkan tentang zakat: \"Pada kambing setiap empat puluh hingga seratus dua puluh ekor yang digembala terdapat satu ekor sebagai zakat, jika ada kelebihan hingga jumlah dua ratus ekor maka zakatnya adalah dua ekor, jika ada kelebihan hingga jumlah tiga ratus ekor maka zakatnya adalah tiga ekor kambing. Jika jumlahlah lebih satu ekor dari jumlah tiga ratus ekor, maka tidak ada zakat hingga penambahan itu hingga sampai jumlah empat ratus. Dan jika telah mencapai empat ratus ekor kambing, maka pada setiap seratus terdapat zakat satu ekor kambing, dan dalam zakat tidak diambil kambing yang tua, bukan kambing yang telah tanggal giginya, atau kambing yang memiliki aib.\" "},"1215":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ مُوسَى حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ عَنْ سُلَيْمَانَ بْنِ دَاوُدَ الْخَوْلَانِيِّ عَنْ الزُّهْرِيِّ عَنْ أَبِي بَكْرِ بْنِ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ عَنْ أَبِيهِ عَنْ جَدِّهِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَتَبَ إِلَى أَهْلِ الْيَمَنِ مَعَ عَمْرِو بْنِ حَزْمٍ بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ مِنْ مُحَمَّدٍ النَّبِيِّ إِلَى شُرَحْبِيلَ بْنِ عَبْدِ كُلَالٍ وَالْحَارِثِ بْنِ عَبْدِ كُلَالٍ وَنُعَيْمِ بْنِ عَبْدِ كُلَالٍ فِي أَرْبَعِينَ شَاةً شَاةٌ إِلَى أَنْ تَبْلُغَ عِشْرِينَ وَمِائَةٍ فَإِذَا زَادَتْ عَلَى عِشْرِينَ وَمِائَةٍ وَاحِدَةً فَفِيهَا شَاتَانِ إِلَى أَنْ تَبْلُغَ مِائَتَيْنِ فَإِذَا زَادَتْ وَاحِدَةً فَفِيهَا ثَلَاثَةٌ إِلَى أَنْ تَبْلُغَ ثَلَاثَ مِائَةٍ فَمَا زَادَ فَفِي كُلِّ مِائَةِ شَاةٍ شَاةٌ حَدَّثَنَا بِشْرُ بْنُ الْحَكَمِ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرِ بْنِ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ عَنْ أَبِيهِ عَنْ جَدِّهِ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَتَبَ لَهُمْ كِتَابًا فَذَكَرَ نَحْوَهُ","id":"Telah mengabarkan kepada kami [Al Hakam bin Musa] telah menceritakan kepada kami [Yahya bin Hamzah] dari [Sulaiman bin Daud Al Khaulani] dari [Az Zuhri] dari [Abu Bakr bin Muhammad bin 'Amru bin Hazm] dari [Ayahnya] dari [Kakeknya], bahwa Rasulullah shallallahu 'alaihi wasallam telah menulis surat kepada penduduk Yaman yang dibawa bersama 'Amru bin Hazm: \"Bismillaahirrahmaanirrahiim. Dari Muhammad seorang Nabi kepada Syurahbil bin Abdu Kulal, Al Harits bin Abdu Kulal, dan Nu'aim bin Abdu Kulal; pada setiap empat puluh ekor kambing hingga mencapai seratus dua puluh terdapat zakat satu ekor kambing, kemudian apabila melebihi seratus dua puluh hingga dua ratus maka padanya terdapat zakat dua ekor kambing, kemudian apabila lebih dari satu hingga tiga ratus maka padanya terdapat zakat tiga ekor, dan selebihnya maka pada setiap seratus ekor kambing terdapat zakat satu ekor kambing.\" Telah menceritakan kepada kami [Bisyr bin Al Hakam] telah menceritakan kepada kami [Abdurrazzaq] telah mengabarkan kepada kami [Ma'mar] dari [Abdullah bin Abu Bakr bin Muhammad bin 'Amru bin Hazm] dari [Ayahnya] dari [Kakeknya], bahwa Nabi shallallahu 'alaihi wasallam telah menulis untuk mereka…kemudian ia menyebutkan seperti itu.\" "},"1216":{"ar":" حَدَّثَنَا يَعْلَى بْنُ عُبَيْدٍ حَدَّثَنَا الْأَعْمَشُ عَنْ شَقِيقٍ عَنْ مَسْرُوقٍ وَالْأَعْمَشُ عَنْ إِبْرَاهِيمَ قَالَا قَالَ مُعَاذٌ بَعَثَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْيَمَنِ فَأَمَرَنِي أَنْ آخُذَ مِنْ كُلِّ أَرْبَعِينَ بَقَرَةً مُسِنَّةً وَمِنْ كُلِّ ثَلَاثِينَ تَبِيعًا أَوْ تَبِيعَةً","id":"Telah menceritakan kepada kami [Ya'la bin 'Ubaid] telah menceritakan kepada kami [Al A'masy] dari [Syaqiq] dari [Masruq] serta [Al A'masy] dari [Ibrahim] mereka berkata, [Mu'adz] berkata, \"Rasulullah shallallahu 'alaihi wasallam mengutusku ke Yaman dan memerintahkanku untuk mengambil dari setiap empat puluh ekor sapi satu ekor musinnah, dan dari setiap tiga puluh ekor satu tabi' atau tabi'ah.\" "},"1217":{"ar":" أَخْبَرَنَا عَاصِمُ بْنُ يُوسُفَ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ عَاصِمٍ عَنْ أَبِي وَائِلٍ عَنْ مَسْرُوقٍ عَنْ مُعَاذٍ قَالَ بَعَثَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْيَمَنِ فَأَمَرَنِي أَنْ آخُذَ مِنْ الْبَقَرِ مِنْ ثَلَاثِينَ تَبِيعًا حَوْلِيًّا وَمِنْ أَرْبَعِينَ بَقَرَةً مُسِنَّةً حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ عَنْ أَبِي بَكْرِ بْنِ عَيَّاشٍ بِنَحْوِهِ","id":"Telah mengabarkan kepada kami ['Ashim bin Yusuf] telah menceritakan kepada kami [Abu Bakr bin 'Ayyasy] dari ['Ashim] dari [Abu Wail] dari [Masruq] dari [Mu'adz] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam mengutusku ke Yaman, kemudian beliau memerintahkanku agar mengambil sapi dari setiap jumlah tiga puluh ekor satu ekor tabi', dan dari setiap empat puluh ekor sapi satu ekor musinnah.\" Telah menceritakan kepada kami [Ahmad bin Yunus] dari [Abu Bakr bin 'Ayyasy] dengan seperti itu.\" "},"1218":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ الْمُبَارَكِ حَدَّثَنَا عَبَّادُ بْنُ الْعَوَّامِ وَإِبْرَاهِيمُ بْنُ صَدَقَةَ عَنْ سُفْيَانَ بْنِ حُسَيْنٍ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَتَبَ الصَّدَقَةَ فَلَمْ تُخْرَجْ إِلَى عُمَّالِهِ حَتَّى قُبِضَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا قُبِضَ أَخَذَهَا أَبُو بَكْرٍ فَعَمِلَ بِهَا مِنْ بَعْدِهِ فَلَمَّا قُبِضَ أَبُو بَكْرٍ أَخَذَهَا عُمَرُ فَعَمِلَ بِهَا مِنْ بَعْدِهِمَا وَلَقَدْ قُتِلَ عُمَرُ وَإِنَّهَا لَمَقْرُونَةٌ بِسَيْفِهِ أَوْ بِوَصِيَّتِهِ وَكَانَ فِي صَدَقَةِ الْإِبِلِ فِي كُلِّ خَمْسٍ شَاةٌ إِلَى خَمْسٍ وَعِشْرِينَ فَإِذَا بَلَغَتْ خَمْسًا وَعِشْرِينَ فَفِيهَا بِنْتُ مَخَاضٍ إِلَى خَمْسٍ وَثَلَاثِينَ فَإِنْ لَمْ تَكُنْ بِنْتُ مَخَاضٍ فَابْنُ لَبُونٍ ذَكَرٌ فَإِذَا زَادَتْ فَفِيهَا بِنْتُ لَبُونٍ إِلَى خَمْسٍ وَأَرْبَعِينَ فَإِذَا زَادَتْ فَفِيهَا حِقَّةٌ إِلَى سِتِّينَ فَإِذَا زَادَتْ فَفِيهَا جَذَعَةٌ إِلَى خَمْسٍ وَسَبْعِينَ فَإِذَا زَادَتْ فَفِيهَا بِنْتَا لَبُونٍ إِلَى تِسْعِينَ فَإِذَا زَادَتْ فَفِيهَا حِقَّتَانِ إِلَى عِشْرِينَ وَمِائَةٍ فَإِذَا زَادَتْ فَفِيهَا فِي كُلِّ خَمْسِينَ حِقَّةٌ وَفِي كُلِّ أَرْبَعِينَ بِنْتُ لَبُونٍ حَدَّثَنَا مُحَمَّدُ بْنُ عُيَيْنَةَ عَنْ أَبِي إِسْحَقَ الْفَزَارِيِّ عَنْ سُفْيَانَ بْنِ حُسَيْنٍ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah mengabarkan kepada kami [Al Hakam bin Al Mubarak] telah menceritakan kepada kami ['Abbad bin Al Awwam] dan [Ibrahim bin Shadaqah] dari [Sufyan bin Husain] dari [Az Zuhri] dari [Salim] dari [Ibnu Umar], bahwa Nabi shallallahu 'alaihi wasallam telah menetapkan hukum zakat, namun belum disampaikan kepada para petugasnya hingga Rasulullah shallallahu 'alaihi wasallam meninggal. Maka ketika beliau telah meninggal catatan tersebut diambil Abu Bakr, dan ia melaksanakannya sepeninggal beliau. Kemudian tatkala Abu Bakr meninggal, maka Umar mengambilnya dan melaksanakannya setelah mereka berdua, dan ketika Umar terbunuh, maka sungguh catatan tersebut disertakan pada pedangnya atau pada wasiatnya. Mengenai zakat unta, maka pada setiap lima ekor hingga dua puluh lima terdapat zakat satu ekor kambing. Jika telah mencapai dua puluh lima hingga tiga puluh lima, maka zakatnya adalah Bintu Makhadl, jika tidak ada Bintu Makhadl maka Ibnu Labun jantan. Jika lebih hingga mencapai jumlah empat puluh lima, maka zakatnya adalah satu ekor Bintu Labun. Jika lebih hingga sejumlah enam puluh, maka zakatnya adalah satu Hiqqah. Jika lebih hingga sejumlah tujuh puluh lima, maka zakatnya adalah Jadza'ah. Jika lebih hingga sejumlah sembilan puluh, maka zakatnya adalah dua ekor Bintu Labun. Jika lebih hingga sejumlah seratus dua puluh, maka zakatnya adalah dua ekor Hiqqah. Jika lebih, maka pada setiap penambahan lima puluh terdapat zakat satu hiqqah, dan setiap empat puluh satu ekor bintu labun.\" Telah menceritakan kepada kami [Muhammad bin 'Uyainah] dari [Abu Ishaq Al Fazari] dari [Sufyan bin Husain] dari [Az Zuhri] dari [Salim] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam seperti itu.\" "},"1219":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ مُوسَى حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ عَنْ سُلَيْمَانَ بْنِ دَاوُدَ الْخَوْلَانِيِّ حَدَّثَنِي الزُّهْرِيُّ عَنْ أَبِي بَكْرِ بْنِ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ عَنْ أَبِيهِ عَنْ جَدِّهِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَتَبَ مَعَ عَمْرِو بْنِ حَزْمٍ إِلَى شُرَحْبِيلَ بْنِ عَبْدِ كُلَالٍ وَالْحَارِثِ بْنِ عَبْدِ كُلَالٍ وَنُعَيْمِ بْنِ عَبْدِ كُلَالٍ إِنَّ فِي كُلِّ خَمْسِ أَوَاقٍ مِنْ الْوَرِقِ خَمْسَةَ دَرَاهِمَ فَمَا زَادَ فَفِي كُلِّ أَرْبَعِينَ دِرْهَمًا دِرْهَمٌ وَلَيْسَ فِيمَا دُونَ خَمْسِ أَوَاقٍ شَيْءٌ","id":"Telah mengabarkan kepada kami [Al Hakam bin Musa] telah menceritakan kepada kami [Yahya bin Hamzah] dari [Sulaiman bin Daud Al Khaulani] telah menceritakan kepadaku [Az Zuhri] dari [Abu Bakr bin Muhammad bin 'Amru bin Hazm] dari [Ayahnya] dari [Kakeknya], bahwa Rasulullah shallallahu 'alaihi wasallam menulis surat dititipkan kepada 'Amru bin Hazm untuk ditujukan kepada Syurahbil bin Abdu Kulal, Al Harits bin Abdu Kulal, dan Nu'aim bin Abdu Kulal, yakni bahwa pada setiap lima uqiyah perak terdapat zakat lima dirham, jika ada lebih maka pada setiap empat puluh dirham adalah satu dirham, dan yang kurang dari lima uqiyah tidak ada kewajiban zakat padanya.\" "},"1220":{"ar":" أَخْبَرَنَا الْمُعَلَّى بْنُ أَسَدٍ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي إِسْحَقَ عَنْ عَاصِمِ بْنِ ضَمْرَةَ عَنْ عَلِيٍّ رَفَعَهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عَفَوْتُ عَنْ صَدَقَةِ الْخَيْلِ وَالرَّقِيقِ هَاتُوا صَدَقَةَ الرِّقَةِ مِنْ كُلِّ أَرْبَعِينَ دِرْهَمًا دِرْهَمٌ وَلَيْسَ فِي تِسْعِينَ وَمِائَةٍ شَيْءٌ حَتَّى تَبْلُغَ مِائَتَيْنِ","id":"Telah mengabarkan kepada kami [Al Mu'alla bin Asad] telah menceritakan kepada kami [Abu 'Awanah] dari [Abu Ishaq] dari ['Ashim bin Dlamrah] dari [Ali] dan ia merafa'kannya kepada Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Aku telah memaafkan dari zakat kuda dan budak. Maka berikanlah zakat perak, pada setiap empat puluh dirham sebanyak satu dirham, dan pada seratus sembilan puluh tidak ada kewajiban zakat, sehingga mencapai dua ratus.\""},"1221":{"ar":" أَخْبَرَنَا الْأَسْوَدُ بْنُ عَامِرٍ حَدَّثَنَا شَرِيكٌ عَنْ عُثْمَانَ الثَّقَفِيِّ عَنْ أَبِي لَيْلَى هُوَ الْكِنْدِيُّ عَنْ سُوَيْدِ بْنِ غَفَلَةَ قَالَ أَتَانَا مُصَدِّقُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخَذْتُ بِيَدِهِ فَقَرَأْتُ فِي عَهْدِهِ أَنْ لَا يُجْمَعَ بَيْنَ مُتَفَرِّقٍ وَلَا يُفَرَّقَ بَيْنَ مُجْتَمِعٍ خَشْيَةَ الصَّدَقَةِ","id":"Telah mengabarkan kepada kami [Al Aswad bin 'Amir] telah menceritakan kepada kami [Syarik] dari [Utsman Ats Tsaqafi] dari [Abu Laila] -yaitu Al Kindi- dari [Suwaid bin Ghafalah] ia berkata, \" [Petugas zakat Nabi shallallahu 'alaihi wasallam] datang kepada kami, kemudian aku gandeng tangannya dan aku baca pada perjanjiannya, 'Tidak boleh digabungkan antara hewan yang terpisah, dan tidak boleh dipisahkan antara hewan yang digabungkan karena khawatir membayar zakat.\""},"1222":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ زَكَرِيَّا عَنْ يَحْيَى بْنِ عَبْدِ اللَّهِ بْنِ صَيْفِيٍّ عَنْ أَبِي مَعْبَدٍ مَوْلَى ابْنِ عَبَّاسٍ عَنْ ابْنِ عَبَّاسٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا بَعَثَ مُعَاذًا إِلَى الْيَمَنِ قَالَ إِيَّاكَ وَكَرَائِمَ أَمْوَالِهِمْ","id":"Telah mengabarkan kepada kami [Abu 'Ashim] dari [Zakaria] dari [Yahya bin Abdullah bin Shaifi] dari [Abu Ma'bad] mantan budak Ibnu Abbas, dari [Ibnu Abbas], bahwa saat Nabi shallallahu 'alaihi wasallam mengutus Mu'adz ke Yaman, beliau bersabda: \"Jauhilah harta berharga mereka.\""},"1223":{"ar":" حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا شُعْبَةُ قَالَ عَبْدُ اللَّهِ بْنُ دِينَارٍ أَخْبَرَنِي قَالَ سَمِعْتُ سُلَيْمَانَ بْنَ يَسَارٍ يُحَدِّثُ عَنْ عِرَاكِ بْنِ مَالِكٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْسَ عَلَى فَرَسِ الْمُسْلِمِ وَلَا عَلَى غُلَامِهِ صَدَقَةٌ","id":"Telah menceritakan kepada kami [Hasyim bin Al Qasim] telah menceritakan kepada kami [Syu'bah] ia berkata, [Abdullah bin Dinar] telah mengabarkan kepadaku, ia berkata; saya mendengar [Sulaiman bin Yasar] menceritakan dari ['Irak bin Malik] dari [Abu Hurairah], dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Seorang Muslim tidak ada kewajiban mengeluarkan zakat pada kuda dan budaknya.\" "},"1224":{"ar":" حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ سُفْيَانَ عَنْ عَمْرِو بْنِ يَحْيَى عَنْ أَبِيهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْسَ فِيمَا دُونَ خَمْسَةِ أَوْسُقٍ صَدَقَةٌ وَلَا فِيمَا دُونَ خَمْسِ أَوَاقٍ صَدَقَةٌ وَلَا فِيمَا دُونَ خَمْسِ ذَوْدٍ صَدَقَةٌ قَالَ أَبُو مُحَمَّد الْوَسْقُ سِتُّونَ صَاعًا وَالصَّاعُ مَنَوَانِ وَنِصْفٌ فِي قَوْلِ أَهْلِ الْحِجَازِ وَأَرْبَعَةُ أَمْنَاءٍ فِي قَوْلِ أَهْلِ الْعِرَاقِ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Musa] dari [Sufyan] dari ['Amru bin Yahya] dari [Ayahnya] dari [Abu Sa'id Al Khudri] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak ada zakat pada biji-bijian serta kurma yang kurang dari lima wasaq, dan tidak ada zakat pada perak yang kurang dari lima uqiyah, dan tidak ada zakat pada unta yang kurang dari lima dzaud.\" Abu Muhammad berkata, \"Satu wasaq adalah enam puluh sha', dan satu sha' adalah dua setengah Mana (nama timbangan) menurut pendapat penduduk Hijaz, dan empat Mana menurut pendapat penduduk Irak.\" "},"1225":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ إِسْمَعِيلَ بْنِ أُمَيَّةَ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ يَحْيَى بْنِ عُمَارَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ فِيمَا دُونَ خَمْسَةِ أَوْسُقٍ صَدَقَةٌ مِنْ حَبٍّ وَلَا تَمْرٍ وَلَا فِيمَا دُونَ خَمْسِ أَوَاقٍ صَدَقَةٌ وَلَا فِيمَا دُونَ خَمْسِ ذَوْدٍ صَدَقَةٌ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] dari [Sufyan] dari [Isma'il bin Umayyah] dari [Muhammad bin Yahya bin Habban] dari [Yahya bin 'Umarah] dari [Abu Sa'id Al Khudri] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada zakat pada biji-bijian serta kurma yang kurang dari lima wasaq, dan tidak ada zakat pada perak yang kurang dari lima uqiyah, dan tidak ada zakat pada unta yang kurang dari lima dzaud.\" "},"1226":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ مُوسَى حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ عَنْ سُلَيْمَانَ بْنِ دَاوُدَ الْخَوْلَانِيِّ حَدَّثَنِي الزُّهْرِيُّ عَنْ أَبِي بَكْرِ بْنِ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ عَنْ أَبِيهِ عَنْ جَدِّهِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَتَبَ مَعَ عَمْرِو بْنِ حَزْمٍ إِلَى شُرَحْبِيلَ بْنِ عَبْدِ كُلَالٍ وَالْحَارِثِ بْنِ عَبْدِ كُلَالٍ وَنُعَيْمِ بْنِ عَبْدِ كُلَالٍ إِنَّ فِي كُلِّ خَمْسِ أَوَاقٍ مِنْ الْوَرِقِ خَمْسَةَ دَرَاهِمَ فَمَا زَادَ فَفِي كُلِّ أَرْبَعِينَ دِرْهَمًا دِرْهَمٌ وَلَيْسَ فِيمَا دُونَ خَمْسِ أَوَاقٍ شَيْءٌ","id":"Telah mengabarkan kepada kami [Al Hakam bin Musa] telah menceritakan kepada kami [Yahya bin Hamzah] dari [Sulaiman bin Daud Al Khaulani] telah menceritakan kepadaku [Az Zuhri] dari [Abu Bakr bin Muhammad bin 'Amru bin Hazm] dari [Ayahnya] dari [Kakeknya], bahwa Rasulullah shallallahu 'alaihi wasallam menulis surat yang dititipkan kepada 'Amru bin Hazm untuk ditujukan kepada Syurahbil bin 'Abdu Kulal, Al Harits bin Abdu Kulal, serta Nu'aim bin Abdu Kulal, bahwa pada setiap lima wasaq perak terdapat zakat lima dirham, jika ada kelebihan maka pada setiap empat puluh dirham terdapat zakat satu dirham, dan yang kurang dari lima wasaq tidak ada zakat padanya.\" "},"1227":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ زَكَرِيَّا عَنْ الْحَجَّاجِ بْنِ دِينَارٍ عَنْ الْحَكَمِ بْنِ عُتَيْبَةَ عَنْ حُجَيَّةَ بْنِ عَدِيٍّ عَنْ عَلِيٍّ أَنَّ الْعَبَّاسَ سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي تَعْجِيلِ صَدَقَتِهِ قَبْلَ أَنْ تَحِلَّ فَرَخَّصَ فِي ذَلِكَ قَالَ أَبُو مُحَمَّد آخُذُ بِهِ وَلَا أَرَى فِي تَعْجِيلِ الزَّكَاةِ بَأْسًا","id":"Telah mengabarkan kepada kami [Sa'id? bin Manshur] telah menceritakan kepada kami [Isma'il bin Zakaria] dari [Al Hajjaj bin Dinar] dari [Al Hakam bin 'Utaibah] dari [Hujayyah bin 'Adi] dari [Ali], bahwa Al Abbas bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang hukum menyegerakan dalam memberikan zakat sebelum wajib. Kemudian beliau memberikan keringanan dalam hal tersebut.\" Abu Muhammad berkata, \"Aku mengamalkan hadits tersebut, dan menyegerakan zakat tidak ada masalah.\" "},"1228":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ الطُّفَيْلِ حَدَّثَنَا شَرِيكٌ عَنْ أَبِي حَمْزَةَ عَنْ عَامِرٍ عَنْ فَاطِمَةَ بِنْتِ قَيْسٍ قَالَتْ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ فِي أَمْوَالِكُمْ حَقًّا سِوَى الزَّكَاةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Ath Thufail] telah menceritakan kepada kami [Syarik] dari [Abu Hamzah] dari ['Amir] dari [Fatimah binti Qais] ia berkata, \"Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya di dalam harta kalian terdapat hak selain zakat.\""},"1229":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا إِسْرَائِيلُ حَدَّثَنَا أَبُو الْجُوَيْرِيَةِ الْجَرْمِيُّ أَنَّ مَعْنَ بْنَ يَزِيدَ حَدَّثَهُ قَالَ بَايَعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَا وَأَبِي وَجَدِّي وَخَطَبَ عَلَيَّ فَأَنْكَحَنِي وَخَاصَمْتُ إِلَيْهِ كَانَ أَبِي يَزِيدُ أَخْرَجَ دَنَانِيرَ يَتَصَدَّقُ بِهَا فَوَضَعَهَا عِنْدَ رَجُلٍ فِي الْمَسْجِدِ فَجِئْتُ فَأَخَذْتُهَا فَأَتَيْتُهُ بِهَا فَقَالَ وَاللَّهِ مَا إِيَّاكَ أَرَدْتُ بِهَا فَخَاصَمْتُهُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَكَ مَا نَوَيْتَ يَا يَزِيدُ وَلَكَ يَا مَعْنُ مَا أَخَذْتَ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Israil] telah menceritakan kepada kami [Abu Al Juwairiyah Al Jurmi] bahwa [Ma'n bin Yazid] telah menceritakan kepadanya, ia berkata, \"Aku bersama bapak dan kakekku membaiat Rasulullah shallallahu 'alaihi wasallam. Ayahku lalu meminang dan menikahkan aku. Dan aku juga mengajukan perkara kepada Rasulullah shallallahu 'alaihi wasallam; ayahku yang bernama Yazid pernah mengeluarkan beberapa dinar untuk bersedekah, kemudian ia meletakkannya pada seorang laki-laki di masjid. Aku lalu datang dan mengambilnya, kemudian aku membawa uang tersebut kepadanya. Maka ia pun berkata, \"Demi Allah, bukan engkau yang aku inginkan dengan sedekah itu! \" Kemudian aku mengajukan perkara tersebut kepada Rasulullah shallallahu 'alaihi wasallam, beliau pun bersabda: \"Bagimu apa yang telah engkau niatkan wahai Yazid dan untukmu apa yang telah engkau ambil wahai Ma'n.\""},"1230":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ وَأَبُو نُعَيْمٍ عَنْ سُفْيَانَ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ عَنْ رَيْحَانَ بْنِ يَزِيدَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَحِلُّ الصَّدَقَةُ لِغَنِيٍّ وَلَا لِذِي مِرَّةٍ سَوِيٍّ قَالَ أَبُو مُحَمَّد يَعْنِي قَوِيٍّ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] dan [Abu Nu'aim] dari [Sufyan] dari [Sa'd bin Ibrahim] dari [Raihan bin Yazid] dari [Abdullah bin 'Amru] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak halal sedekah bagi orang kaya dan orang sehat yang kuat.\" Abu Muhammad berkata, \"Yaitu orang yang kuat.\" "},"1231":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا شَرِيكٌ عَنْ حَكِيمِ بْنِ جُبَيْرٍ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ سَأَلَ عَنْ ظَهْرِ غِنًى جَاءَ يَوْمَ الْقِيَامَةِ وَفِي وَجْهِهِ خُمُوشٌ أَوْ كُدُوحٌ أَوْ خُدُوشٌ قِيلَ يَا رَسُولَ اللَّهِ وَمَا الْغِنَى قَالَ خَمْسُونَ دِرْهَمًا أَوْ قِيمَتُهَا مِنْ الذَّهَبِ أَخْبَرَنَا أَبُو عَاصِمٍ وَمُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ حَكِيمِ بْنِ جُبَيْرٍ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنَحْوِهِ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Syarik] dari [Hakim bin Jubair] dari [Muhammad bin Abdurrahman bin Yazid] dari [Ayahnya] dari [Abdullah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa meminta-minta sementara ia memiliki kelebihan, maka pada hari Kiamat ia akan datang dalam keadaan pada wajahnya terdapat luka cakaran.\" Rasulullah shallallahu 'alaihi wasallam ditanya, \"Wahai Rasulullah, berapakah kecukupan tersebut?\" Beliau bersabda: \"Lima puluh dirham, atau emas yang senilai dengannya.\" Telah mengabarkan kepada kami [Abu 'Ashim] dan [Muhammad bin Yusuf] dari [Sufyan] dari [Hakim bin Jubair] dari [Muhammad bin Abdurrahman] dari [Ayahnya] dari [Abdullah] dari Nabi shallallahu 'alaihi wasallam dengan seperti hadits tersebut.\" "},"1232":{"ar":" أَخْبَرَنَا هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا شُعْبَةُ أَخْبَرَنِي مُحَمَّدُ بْنُ زِيَادٍ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ قَالَ أَخَذَ الْحَسَنُ تَمْرَةً مِنْ تَمْرِ الصَّدَقَةِ فَجَعَلَهَا فِي فِيهِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كِخْ كِخْ أَلْقِهَا أَمَا شَعَرْتَ أَنَّا لَا نَأْكُلُ الصَّدَقَةَ","id":"Telah mengabarkan kepada kami [Hasyim bin Al Qasim] telah menceritakan kepada kami [Syu'bah] telah mengabarkan kepadaku [Muhammad bin Ziyad] ia berkata, saya mendengar [Abu Hurairah] berkata, \"Al Hasan mengambil satu biji dari kurma zakat dan memasukkannya ke dalam mulutnya, maka Nabi shallallahu 'alaihi wasallam pun bersabda: \"Kikh, kikh, buang! Tidakkah engkau merasa bahwa kita tidak makan sedekah?\""},"1233":{"ar":" أَخْبَرَنَا الْأَسْوَدُ بْنُ عَامِرٍ حَدَّثَنَا زُهَيْرٌ عَنْ عَبْدِ اللَّهِ بْنِ عِيسَى عَنْ عِيسَى عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ أَبِي لَيْلَى قَالَ كُنْتُ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعِنْدَهُ الْحَسَنُ بْنُ عَلِيٍّ فَأَخَذَ تَمْرَةً مِنْ تَمْرِ الصَّدَقَةِ فَانْتَزَعَهَا مِنْهُ وَقَالَ أَمَا عَلِمْتَ أَنَّهُ لَا تَحِلُّ لَنَا الصَّدَقَةُ","id":"Telah mengabarkan kepada kami [Al Aswad bin 'Amir] telah menceritakan kepada kami [Zuhair] dari [Abdullah bin Isa] dari [Isa] dari [Abdurrahman bin Abu Laila] dari [Abu Laila] ia berkata, \"Aku pernah bersama Nabi shallallahu 'alaihi wasallam dan di sisi beliau terdapat Al Hasan bin Ali, kemudian ia mengambil satu biji kurma zakat, maka beliau mengambil kurma tersebut darinya dan berkata: \"Tidakkah engkau mengetahui bahwa sedekah tidak halal bagi kita?\""},"1234":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ وَهْبِ بْنِ مُنَبِّهٍ عَنْ أَخِيهِ عَنْ مُعَاوِيَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُلْحِفُوا بِي فِي الْمَسْأَلَةِ فَوَاللَّهِ لَا يَسْأَلُنِي أَحَدٌ شَيْئًا فَأُعْطِيَهُ وَأَنَا كَارِهٌ فَيُبَارَكَ لَهُ فِيهِ","id":"Telah mengabarkan kepada kami [Sa'id? bin Manshur] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari ['Amru bin Dinar] dari [Wahb bin Munabbih] dari [Saudaranya] dari [Mu'awiyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian mendesakku dalam meminta! Demi Allah, seseorang meminta sesuatu kepadaku kemudian aku memberinya, sementara aku tidak suka, lalu ia diberi berkah di dalamnya.\" "},"1235":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الرَّقَاشِيُّ حَدَّثَنَا يَزِيدُ هُوَ ابْنُ زُرَيْعٍ أَخْبَرَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ مَعْدَانَ بْنِ أَبِي طَلْحَةَ عَنْ ثَوْبَانَ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ سَأَلَ النَّاسَ مَسْأَلَةً وَهُوَ عَنْهَا غَنِيٌّ كَانَتْ شَيْنًا فِي وَجْهِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah Ar Raqasyi] telah menceritakan kepada kami [Yazid] -yaitu Ibnu Zurai'- telah mengabarkan kepada kami [Sa'id?] dari [Qatadah] dari [Salim bin Abu Al Ja'd] dari [Ma'dan bin Abu Thalhah] dari [Tsauban] mantan budak Rasulullah shallallahu 'alaihi wasallam, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa meminta sesuatu kepada manusia, sementara dirinya tidak memerlukan sesuatu itu, kecuali sesuatu itu akan menjadi aib di wajahnya.\" "},"1236":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ الْمُبَارَكِ حَدَّثَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ عَطَاءِ بْنِ يَزِيدَ اللَّيْثِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ أَنَّ نَاسًا مِنْ الْأَنْصَارِ سَأَلُوا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَعْطَاهُمْ ثُمَّ سَأَلُوهُ فَأَعْطَاهُمْ حَتَّى إِذَا نَفِدَ مَا عِنْدَهُ قَالَ مَا يَكُونُ عِنْدِي مِنْ خَيْرٍ فَلَنْ أَدَّخِرَهُ عَنْكُمْ وَمَنْ يَسْتَعِفَّ يُعِفَّهُ اللَّهُ وَمَنْ يَسْتَغْنِ يُغْنِهِ اللَّهُ وَمَنْ يَتَصَبَّرْ يُصَبِّرْهُ اللَّهُ وَمَا أُعْطِيَ أَحَدٌ عَطَاءً هُوَ خَيْرٌ وَأَوْسَعُ مِنْ الصَّبْرِ","id":"Telah mengabarkan kepada kami [Al Hakam bin Al Mubarak] telah menceritakan kepada kami [Malik] dari [Ibnu Syihab] dari ['Atha` bin Yazid Al Laitsi] dari [Abu Sa'id Al Khudri], bahwa beberapa orang Anshar meminta kepada Rasulullah shallallahu 'alaihi wasallam kemudian beliau memberi, kemudian mereka meminta meminta lagi dan beliau memberi hingga habis apa yang ada pada beliau. Kemudian beliau bersabda: \"Tidak ada kebaikan yang aku simpan dari kalian, barangsiapa menjaga kehormatan dirinya maka Allah akan jaga kehormatan dirinya, barangsiapa merasa cukup maka Allah akan beri dia kecukupan, barangsiapa berusaha untuk bersabar maka Allah akan menjadikannya bersabar. Dan tidaklah seseorang diberi suatu pemberian yang lebih baik dan lebih luas daripada kesabaran.\""},"1237":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ قَالَ حَدَّثَنِي اللَّيْثُ حَدَّثَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمٍ أَنَّهُ قَالَ قَالَ عَبْدُ اللَّهِ سَمِعْتُ عُمَرَ بْنَ الْخَطَّابِ يَقُولُ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعْطِينِي الْعَطَاءَ فَأَقُولُ أَعْطِهِ مَنْ هُوَ أَفْقَرُ إِلَيْهِ مِنِّي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خُذْهُ وَمَا آتَاكَ اللَّهُ مِنْ هَذَا الْمَالِ وَأَنْتَ غَيْرُ مُشْرِفٍ وَلَا سَائِلٍ فَخُذْهُ وَمَا لَا فَلَا تُتْبِعْهُ نَفْسَكَ أَخْبَرَنَا الْحَكَمُ بْنُ نَافِعٍ عَنْ شُعَيْبِ بْنِ أَبِي حَمْزَةَ عَنْ الزُّهْرِيِّ حَدَّثَنِي السَّائِبُ بْنُ يَزِيدَ أَنَّ حُوَيْطِبَ بْنَ عَبْدِ الْعُزَّى أَخْبَرَهُ أَنَّ عَبْدَ اللَّهِ بْنَ السَّعْدِيِّ أَخْبَرَهُ عَنْ عُمَرَ بِنَحْوِهِ أَخْبَرَنَا أَبُو الْوَلِيدِ حَدَّثَنَا اللَّيْثُ عَنْ بُكَيْرٍ عَنْ بُسْرِ بْنِ سَعِيدٍ عَنْ ابْنِ السَّعْدِيِّ قَالَ اسْتَعْمَلَنِي عُمَرُ فَذَكَرَ نَحْوًا مِنْهُ","id":"Telah mengabarkan kepada kami [Abdullah bin Shalih] ia berkata, telah menceritakan kepadaku [Al Laits] telah menceritakan kepadaku [Yunus] dari [Ibnu Syihab] dari [Salim] bahwa ia berkata, [Abdullah] berkata, aku mendengar [Umar bin Al Khathab] berkata, \"Rasulullah shallallahu 'alaihi wasallam memberiku sebuah pemberian, kemudian aku katakan, \"Berikanlah kepada orang yang lebih membutuhkannya dariku. Lalu beliau berkata: \"Ambillah apa yang Allah berikan kepadamu dari harta ini, sesuatu yang engkau tidak mengharapkan dan tidak memintanya, ambillah! Dan apa yang tidak demikian maka janganlah engkau perturutkan dirimu.\" Telah mengabarkan kepada kami [Al Hakam bin Nafi'] dari [Syu'aib bin Abu Hamzah] dari [Az Zuhri] telah menceritakan kepadaku [As Sa`ib bin Yazid] bahwa [Huwaithib bin Abdul 'Uzza] telah mengabarkan kepadanya, bahwa [Abdullah bin As Suddi] telah mengabarkan kepadanya dari [Umar] seperti itu.\" Telah mengabarkan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Al Laits] dari [Bukair] dari [Busr bin Sa'id] dari [Ibnu As Suddi] ia berkata, \" [Umar] mengangkatku sebagai pegawai ….. kemudian ia menyebutkan hadits seperti itu.\" "},"1238":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ الْأَوْزَاعِيِّ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ وَعُرْوَةَ بْنِ الزُّبَيْرِ أَنَّ حَكِيمَ بْنَ حِزَامٍ قَالَ سَأَلْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَعْطَانِي ثُمَّ سَأَلْتُهُ فَأَعْطَانِي ثُمَّ سَأَلْتُهُ فَأَعْطَانِي ثُمَّ سَأَلْتُهُ فَقَالَ يَا حَكِيمُ إِنَّ هَذَا الْمَالَ خَضِرٌ حُلْوٌ فَمَنْ أَخَذَهُ بِسَخَاوَةِ نَفْسٍ بُورِكَ لَهُ فِيهِ وَمَنْ أَخَذَهُ بِإِشْرَافِ نَفْسٍ لَمْ يُبَارَكْ لَهُ فِيهِ وَكَانَ كَالَّذِي يَأْكُلُ وَلَا يَشْبَعُ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Al Auza'i] dari [Ibnu Syihab] dari [Sa'id? bin Al Musayyab] dan ['Urwah bin Az Zubair] bahwa [Hakim bin Hizam] berkata, \"Aku meminta kepada Nabi shallallahu 'alaihi wasallam lalu beliau memberiku, kemudian aku meminta kepadanya dan beliau memberiku lagi, kemudian aku meminta kepadanya lalu beliau memberiku lagi, kemudian aku meminta kepadanya lalu beliau bersabda: \"Wahai Hakim, sesungguhnya harta ini adalah hijau dan manis, maka barangsiapa mengambilnya dengan kemurahan hati, maka ia akan diberkahi pada harta tersebut. Dan barangsiapa mengambilnya dengan ketamakan jiwa, maka ia tidak akan diberkahi pada hartanya. Dan ia seperti orang yang makan namun tidak kenyang.\""},"1239":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنِي اللَّيْثُ حَدَّثَنِي هِشَامٌ عَنْ عُرْوَةَ عَنْ أَبِي هُرَيْرَةَ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ خَيْرُ الصَّدَقَةِ مَا تُصُدِّقَ بِهِ عَنْ ظَهْرِ غِنًى وَلْيَبْدَأْ أَحَدُكُمْ بِمَنْ يَعُولُ","id":"Telah mengabarkan kepada kami [Abdullah bin Shalih] telah menceritakan kepadaku [Al Laits] telah menceritakan kepadaku [Hisyam] dari ['Urwah] dari [Abu Hurairah] ia berkata, \"Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik sedekah adalah sesuatu yang disedekahkan setelah merasa cukup, dan hendaknya salah seorang di antara kalian memulai dengan orang yang ia tanggung.\""},"1240":{"ar":" أَخْبَرَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْيَدُ الْعُلْيَا خَيْرٌ مِنْ الْيَدِ السُّفْلَى قَالَ وَالْيَدُ الْعُلْيَا يَدُ الْمُعْطِي وَالْيَدُ السُّفْلَى يَدُ السَّائِلِ","id":"Telah mengabarkan kepada kami [Sulaiman bin Hazb] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tangan di atas lebih baik daripada tangan yang di bawah.\" Dan beliau bersabda: \"Dan tangan yang di atas adalah tangan orang yang memberi, sedangkan tangan yang di bawah adalah tangan orang yang meminta.\""},"1241":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا عَمْرُو بْنُ عُثْمَانَ قَالَ سَمِعْتُ مُوسَى بْنَ طَلْحَةَ يَذْكُرُ عَنْ حَكِيمِ بْنِ حِزَامٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْرُ الصَّدَقَةِ عَنْ ظَهْرِ غِنًى وَالْيَدُ الْعُلْيَا خَيْرٌ مِنْ الْيَدِ السُّفْلَى وَابْدَأْ بِمَنْ تَعُولُ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami ['Amru bin Utsman] ia berkata, saya mendengar [Musa bin Thalhah] menyebutkan hadits dari [Hakim bin Hizam] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik sedekah adalah setelah merasa cukup, dan tangan yang di atas lebih baik daripada tangan yang di bawah, mulailah dari orang yang engkau tanggung.\" "},"1242":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا شُعْبَةُ قَالَ سُلَيْمَانُ أَخْبَرَنِي قَالَ سَمِعْتُ أَبَا وَائِلٍ يُحَدِّثُ عَنْ عَمْرِو بْنِ الْحَارِثِ عَنْ زَيْنَبَ امْرَأَةِ عَبْدِ اللَّهِ أَنَّهَا قَالَتْ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَا مَعْشَرَ النِّسَاءِ تَصَدَّقْنَ وَلَوْ مِنْ حُلِيِّكُنَّ وَكَانَ عَبْدُ اللَّهِ خَفِيفَ ذَاتِ الْيَدِ فَجِئْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَسْأَلُهُ فَوَافَقَتْ زَيْنَبَ امْرَأَةٌ مِنْ الْأَنْصَارِ تَسْأَلُ عَمَّا أَسْأَلُ عَنْهُ فَقُلْتُ لِبِلَالٍ سَلْ لِي رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيْنَ أَضَعُ صَدَقَتِي عَلَى عَبْدِ اللَّهِ أَوْ فِي قَرَابَتِي فَسَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَيُّ الزَّيَانِبِ فَقَالَ امْرَأَةُ عَبْدِ اللَّهِ فَقَالَ لَهَا أَجْرَانِ أَجْرُ الْقَرَابَةِ وَأَجْرُ الصَّدَقَةِ","id":"Telah mengabarkan kepada kami [Abu Al Walid Ath Thayalisi] telah menceritakan kepada kami [Syu'bah] ia berkata, [Sulaiman] telah mengabarkan kepadaku, ia berkata, saya mendengar [Abu Wail] menceritakan dari ['Amru bin Al Harits] dari [Zainab] isteri Abdullah, bahwa ia berkata, \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai para wanita bersedekahlah walaupun dari perhiasan kalian.\" Sementara Abdullah adalah orang yang miskin, kemudian aku datang kepada Rasulullah shallallahu 'alaihi wasallam bertanya kepada beliau.\" Kemudian Zainab berpapasan dengan seorang wanita Anshar yang juga ingin bertanya mengenai apa yang akan aku tanyakan. Kemudian kukatakan kepada Bilal, \"Tanyakanlah kepada Rasulullah shallallahu 'alaihi wasallam, dimanakah aku harus memberikan sedekahku, kepada Abdullah (suamiku) atau kepada kerabatku?\" Kemudian Bilal bertanya kepada Nabi shallallahu 'alaihi wasallam, lantas beliau balik bertanya, \"Zainab yang manakah?\" Bilal menjawab, \"Isteri Abdullah.\" Kemudian beliau bersabda: \"Baginya dua pahala, pahala kekerabatan dan pahala sedekah.\""},"1243":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ الْمُبَارَكِ حَدَّثَنَا مَالِكٌ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسٍ قَالَ كَانَ أَبُو طَلْحَةَ أَكْثَرَ أَنْصَارِيٍّ بِالْمَدِينَةِ مَالًا نَخْلًا وَكَانَتْ أَحَبَّ أَمْوَالِهِ إِلَيْهِ بَيْرُحَاءُ وَكَانَتْ مُسْتَقْبِلَةَ الْمَسْجِدِ وَكَانَ يَدْخُلُهَا وَيَشْرَبُ مِنْ مَائِهَا طَيِّبٌ فَقَالَ أَنَسٌ فَلَمَّا أُنْزِلَتْ هَذِهِ الْآيَةُ { لَنْ تَنَالُوا الْبِرَّ حَتَّى تُنْفِقُوا مِمَّا تُحِبُّونَ } قَالَ إِنَّ أَحَبَّ أَمْوَالِي إِلَيَّ بَيْرُحَاءُ وَإِنَّهَا صَدَقَةٌ لِلَّهِ أَرْجُو بِرَّهَا وَذُخْرَهَا عِنْدَ اللَّهِ فَضَعْهَا يَا رَسُولَ اللَّهِ حَيْثُ شِئْتَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَخٍ ذَلِكَ مَالٌ رَابِحٌ أَوْ رَائِحٌ وَقَدْ سَمِعْتُ مَا قُلْتَ فِيهِ وَإِنِّي أَرَى أَنْ تَجْعَلَهُ فِي الْأَقْرَبِينَ فَقَالَ أَبُو طَلْحَةَ أَفْعَلُ يَا رَسُولَ اللَّهِ فَقَسَّمَهُ أَبُو طَلْحَةَ فِي قَرَابَةِ بَنِي عَمِّهِ","id":"Telah mengabarkan kepada kami [Al Hakam bin Al Mubarak] telah menceritakan kepada kami [Malik] dari [Ishaq bin Abdullah bin Abu Thalhah] dari [Anas] ia berkata, \"Abu Thalhah adalah orang anshar yang paling banyak hartanya di kota Madinah, yaitu pohon kurma. Harta yang paling ia senangi adalah Bairuha` (kebun kurma) yang menghadap ke masjid. Ia biasa masuk untuk makan (buha) dan meminum airnya yang jernih.\" Anas berkata, \"Kemudian tatkala ayat: '(Kamu sekali-kali tidak sampai kepada kebajikan (yang sempurna), sebelum kamu menafkahkan sehahagian harta yang kamu cintai) ' (Qs. Ali Imran: 92). Abu Thalhah berkata, \"Sungguh, hartaku yang paling aku senangi adalah Bairuha`, dan sesungguhnya kebun tersebut adalah sedekah untuk Allah, aku mengharapkan kebaikan dan simpanan pahalanya di sisi Allah. Maka pergunakan di mana engkau kehendaki wahai Rasul! \" Rasulullah shallallahu 'alaihi wasallam kemudian bersabda: \"Bakh, itu adalah harta yang menguntungkan, sungguh aku telah mendengar apa yang engkau katakan. Namun menurutku, sebaiknya itu engkau berikan kepada para kerabat.\" Kemudian Abu Thalhah berkata, \"Aku akan melakukannya wahai Rasulullah! \" Abu Thalhah lalu membaginya di antara para kerabat anak pamannya.\""},"1244":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ حَدَّثَنَا أَبِي عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ هَيَّاجِ بْنِ عِمْرَانَ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ قَالَ مَا خَطَبَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا أَمَرَنَا فِيهَا بِالصَّدَقَةِ وَنَهَانَا عَنْ الْمُثْلَةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] Telah menceritakan kepada kami [Mu'adz bin Hisyam] telah menceritakan kepada kami [Ayahku] dari [Qatadah] dari [Al Hasan] dari [Hayyaj bin Imran] dari [Imran bin Hushain] ia berkata, \"Tidaklah Rasulullah shallallahu 'alaihi wasallam berkhutbah kepada kami kecuali beliau memerintahkan kami untuk bersedekah, dan melarang kami dari mencincang.\" "},"1245":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا شُعْبَةُ أَخْبَرَنِي عَمْرُو بْنُ مُرَّةَ قَالَ سَمِعْتُ خَيْثَمَةَ عَنْ عَدِيِّ بْنِ حَاتِمٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اتَّقُوا النَّارَ وَلَوْ بِشِقِّ تَمْرَةٍ فَإِنْ لَمْ تَجِدُوا فَبِكَلِمَةٍ طَيِّبَةٍ","id":"Telah mengabarkan kepada kami [Abu Al Walid Ath Thayalisi] telah menceritakan kepada kami [Syu'bah] telah mengabarkan kepada kami ['Amru bin Murrah] ia berkata, saya mendengar [Khaitsamah] dari [Adi bin Hatim] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Takutlah kepada Neraka walaupun hanya dengan sebelah kurma. Jika tidak kalian dapatkan, maka dengan perkataan yang baik.\""},"1246":{"ar":" أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ دُحَيْمٌ حَدَّثَنَا سَعِيدُ بْنُ مَسْلَمَةَ عَنْ إِسْمَعِيلَ بْنِ أُمَيَّةَ عَنْ الزُّهْرِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لُبَابَةَ أَنَّ أَبَا لُبَابَةَ أَخْبَرَهُ أَنَّهُ لَمَّا رَضِيَ عَنْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَا رَسُولَ اللَّهِ إِنَّ مِنْ تَوْبَتِي أَنْ أَهْجُرَ دَارَ قَوْمِي وَأُسَاكِنَكَ وَأَنْخَلِعَ مِنْ مَالِي صَدَقَةً لِلَّهِ وَلِرَسُولِهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُجْزِي عَنْكَ الثُّلُثُ","id":"Telah mengabarkan kepada kami [Abdurrahman bin Ibrahim Ad Dimasyqi Duhaim] telah menceritakan kepada kami [Sa'id? bin Maslamah] dari [Isma'il bin Umayyah] dari [Az Zuhri] dari [Abdurrahman bin Abu Lubabah] bahwa [Abu Lubabah] telah mengabarkan kepadanya, bahwa tatkala Rasulullah shallallahu 'alaihi wasallam ridla kepadanya, ia berkata, \"Wahai Rasulullah, sesungguhnya di antara bukti dari taubatku adalah meninggalkan kaumku dan tinggal di dekatmu, serta memberikan sebagian dari hartaku sebagai sedekah kepada Allah dan rasul-Nya.\" Kemudian Rasulullah shallallahu 'alaihi wasallam berkata: \"Cukup bagimu mensedekahkan sepertiga hartamu.\""},"1247":{"ar":" أَخْبَرَنَا يَعْلَى وَأَحْمَدُ بْنُ خَالِدٍ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ عَاصِمِ بْنِ عُمَرَ بْنِ قَتَادَةَ عَنْ مَحْمُودِ بْنِ لَبِيدٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَ بَيْنَا نَحْنُ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ جَاءَ رَجُلٌ بِمِثْلِ الْبَيْضَةِ مِنْ ذَهَبٍ أَصَابَهَا فِي بَعْضِ الْمَغَازِي قَالَ أَحْمَدُ فِي بَعْضِ الْمَعَادِنِ وَهُوَ الصَّوَابُ فَقَالَ يَا رَسُولَ اللَّهِ خُذْهَا مِنِّي صَدَقَةً فَوَاللَّهِ مَا لِي مَالٌ غَيْرَهَا فَأَعْرَضَ عَنْهُ ثُمَّ جَاءَهُ عَنْ رُكْنِهِ الْأَيْسَرِ فَقَالَ مِثْلَ ذَلِكَ ثُمَّ جَاءَهُ مِنْ بَيْنِ يَدَيْهِ فَقَالَ مِثْلَ ذَلِكَ ثُمَّ قَالَ هَاتِهَا مُغْضَبًا فَحَذَفَهُ بِهَا حَذْفَةً لَوْ أَصَابَهُ لَأَوْجَعَهُ أَوْ عَقَرَهُ ثُمَّ قَالَ يَعْمِدُ أَحَدُكُمْ إِلَى مَالِهِ لَا يَمْلِكُ غَيْرَهُ فَيَتَصَدَّقُ بِهِ ثُمَّ يَقْعُدُ يَتَكَفَّفُ النَّاسَ إِنَّمَا الصَّدَقَةُ عَنْ ظَهْرِ غِنًى خُذْ الَّذِي لَكَ لَا حَاجَةَ لَنَا بِهِ فَأَخَذَ الرَّجُلُ مَالَهُ وَذَهَبَ قَالَ أَبُو مُحَمَّد كَانَ مَالِكٌ يَقُولُ إِذَا جَعَلَ الرَّجُلُ مَالَهُ فِي الْمَسَاكِينِ يَتَصَدَّقُ بِثُلُثِ مَالِهِ","id":"Telah mengabarkan kepada kami [Ya'la] dan [Ahmad bin Khalid] dari [Muhammad bin Ishaq] dari ['Ashim bin Umar bin Qatadah] dari [Mahmud bin Labid] dari [Jabir bin Abdullah] ia berkata, \"Ketika kami bersama Rasulullah shallallahu 'alaihi wasallam, tiba-tiba ada seorang laki-laki yang datang membawa emas seperti telur yang ia dapatkan di sebagian peperangan.\" Ahmad menyebutkan, 'Pada sebagian barang tambang.' Dan itu adalah yang benar. Laki-laki itu lalu berkata, \"Wahai Rasulullah, ambillah ini dariku sebagai sedekah. Demi Allah, aku tidak memiliki harta selainnya.\" Lalu beliau berpaling darinya, laki-laki itu lalu datang dari sisi kanan beliau dan berkata seperti itu. Kemudian datang lagi dari depan beliau dan berkata seperti itu. Kemudian dalam keadaan marah beliau berkata: \"Berikan.\" Kemudian beliau melemparkan emas tersebut, sekiranya mengenai laki-laki tersebut niscaya akan membuatnya sakit dan terluka. Setelah itu beliau beliau bersabda: \"Salah seorang di antara kalian mengambil hartanya, lalu mensedekahkannya, padahal ia tidak memiliki selainnya. Kemudian ia duduk dan meminta-minta kepada orang. Sesungguhnya sedekah adalah dalam keadaan lebih. Ambillah milikmu, kami tidak membutuhkannya.\" Kemudian orang tersebut mengambil hartanya dan pergi.\" Abu Muhammad berkata, \"Malik berkata, \"Jika seseorang memberikan hartanya untuk orang-orang miskin, maka hendaknya ia bersedekah dari sepertiga hartanya.\""},"1248":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا هِشَامُ بْنُ سَعْدٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِيهِ قَالَ سَمِعْتُ عُمَرَ قَالَ أَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نَتَصَدَّقَ فَوَافَقَ ذَلِكَ مَالًا عِنْدِي فَقُلْتُ الْيَوْمَ أَسْبِقُ أَبَا بَكْرٍ إِنْ سَبَقْتُهُ يَوْمًا فَجِئْتُ بِنِصْفِ مَالِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أَبْقَيْتَ لِأَهْلِكَ قُلْتُ مِثْلَهُ قَالَ فَأَتَى أَبُو بَكْرٍ بِكُلِّ مَا عِنْدَهُ فَقَالَ يَا أَبَا بَكْرٍ مَا أَبْقَيْتَ لِأَهْلِكَ فَقَالَ أَبْقَيْتُ لَهُمْ اللَّهَ وَرَسُولَهُ فَقُلْتُ لَا أُسَابِقُكَ إِلَى شَيْءٍ أَبَدًا","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Hisyam bin Sa'd] dari [Zaid bin Aslam] dari [Ayahnya] ia berkata, aku mendengar [Umar] berkata, \"Rasulullah shallallahu 'alaihi wasallam memerintahkan kami agar bersedekah, dan saat itu bertepatan saat aku mempunyai uang. Maka aku pun berkata, \"Jika hari ini aku bisa bersegera, maka aku akan dapat mendahului Abu Bakar.\" Kemudian aku datang dengan membawa setengah hartaku, lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apakah yang engkau tinggalkan untuk keluargamu?\" Aku lantas menjawab, \"Harta yang sama seperti itu.\" Umar berkata, \"Abu Bakar kemudian datang dengan membawa seluruh yang ia miliki.\" Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Wahai Abu Bakar, apa yang engkau tinggalkan untuk keluargamu?\" Ia menjawab, \"Aku tinggalkan untuk mereka Allah dan Rasul-Nya.\" Maka aku katakan, \"Selamanya aku tidak akan bisa mendahuluimu dalam beramal apapun.\" "},"1249":{"ar":" أَخْبَرَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَ فَرَضَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَكَاةَ الْفِطْرِ مِنْ رَمَضَانَ صَاعًا مِنْ تَمْرٍ أَوْ صَاعًا مِنْ شَعِيرٍ عَلَى كُلِّ حُرٍّ وَعَبْدٍ ذَكَرٍ أَوْ أُنْثَى مِنْ الْمُسْلِمِينَ قِيلَ لِأَبِي مُحَمَّدٍ تَقُولُ بِهِ قَالَ مَالِكٌ كَانَ يَقُولُ بِهِ","id":"Telah mengabarkan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Malik] dari [Nafi'] dari [Abdullah bin Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam telah mewajibkan zakat fitrah pada bulan Ramadan satu sha' kurma atau satu sha' gandum atas setiap orang yang merdeka, hamba sahaya, laki-laki atau perempuan dari kalangan Muslimin.\" Abu Muhammad ditanya, \"Apakah engkau berpendapat seperti itu?\" Ia menjawab, \"Malik berpendapat seperti itu.\" "},"1250":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَ أَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِزَكَاةِ الْفِطْرِ عَنْ كُلِّ صَغِيرٍ وَكَبِيرٍ حُرٍّ أَوْ عَبْدٍ صَاعًا مِنْ شَعِيرٍ أَوْ صَاعًا مِنْ تَمْرٍ قَالَ ابْنُ عُمَرَ فَعَدَلَهُ النَّاسُ بِمُدَّيْنِ مِنْ بُرٍّ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Sufyan] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam memerintahkan kami untuk mengeluarkan zakat fitrah dari setiap anak kecil dan orang dewasa, orang merdeka atau hamba sahaya, yakni satu sha' gandum atau satu sha' kurma.\" Ibnu Umar berkata, \"Orang-orang menyamakannya dengan dua mud gandum.\" "},"1251":{"ar":" حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ حَدَّثَنَا دَاوُدُ بْنُ قَيْسٍ عَنْ عِيَاضِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَ كُنَّا نُخْرِجُ زَكَاةَ الْفِطْرِ إِذْ كَانَ فِينَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ كُلِّ صَغِيرٍ وَكَبِيرٍ حُرٍّ وَمَمْلُوكٍ صَاعًا مِنْ طَعَامٍ أَوْ صَاعًا مِنْ تَمْرٍ أَوْ صَاعًا مِنْ شَعِيرٍ أَوْ صَاعًا مِنْ أَقِطٍ أَوْ صَاعًا مِنْ زَبِيبٍ فَلَمْ يَزَلْ ذَلِكَ كَذَلِكَ حَتَّى قَدِمَ عَلَيْنَا مُعَاوِيَةُ الْمَدِينَةَ حَاجًّا أَوْ مُعْتَمِرًا فَقَالَ إِنِّي أَرَى مُدَّيْنِ مِنْ سَمْرَاءِ الشَّامِ يَعْدِلُ صَاعًا مِنْ التَّمْرِ فَأَخَذَ النَّاسُ بِذَلِكَ قَالَ أَبُو سَعِيدٍ أَمَّا أَنَا فَلَا أَزَالُ أُخْرِجُهُ كَمَا كُنْتُ أُخْرِجُهُ قَالَ أَبُو مُحَمَّد أَرَى صَاعًا مِنْ كُلِّ شَيْءٍ","id":"Telah mengabarkan kepada kami [Utsman bin Umar] telah menceritakan kepada kami [Daud bin Qais] dari ['Iyadl bin Abdullah] dari [Abu Sa'id Al Khudri] ia berkata, \"Saat Rasulullah shallallahu 'alaihi wasallam masih ada mengeluarkan zakat fitrah untuk setiap anak-anak, orang dewasa yang merdeka dan hamba sahaya satu sha' makanan, atau satu sha' kurma, atau satu sha' gandum, atau satu sha' keju, atau satu sha' kismis. Dan tetap seperti itu hingga Mu'awiyah datang kepada kami di Madinah dalam rangka ibadah haji atau umrah. Ia berkata, \"Aku melihat dua mud gandum Syam sama dengan satu sha' kurma.\" Kemudian orang-orang mengambil pendapat itu.\" Abu Sa'id berkata, \"Adapun aku, maka aku masih tetap mengeluarkannya sebagaimana dahulu aku mengeluarkannya.\" Abu Muhammad berkata, \"Menurutku satu sha' itu berlaku untuk semua jenis (makanan).\""},"1252":{"ar":" حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا مَالِكٌ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عِيَاضِ بْنِ عَبْدِ اللَّهِ بْنِ سَعْدِ بْنِ أَبِي سَرْحٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَ كُنَّا نُخْرِجُ زَكَاةَ الْفِطْرِ مِنْ رَمَضَانَ صَاعًا مِنْ طَعَامٍ أَوْ صَاعًا مِنْ تَمْرٍ أَوْ صَاعًا مِنْ شَعِيرٍ أَوْ صَاعًا مِنْ زَبِيبٍ أَوْ صَاعًا مِنْ أَقِطٍ أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ سُفْيَانَ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عِيَاضِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي سَعِيدٍ قَالَ كُنَّا نُعْطِي عَلَى عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ نَحْوَهُ","id":"Telah mengabarkan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Malik] dari [Zaid bin Aslam] dari ['Iyadl bin Abdullah bin Sa'd bin Abu Sarh] dari [Abu Sa'id Al Khudri] ia berkata, \"Dahulu kami mengeluarkan zakat fitrah pada bulan Ramadan satu sha' makanan, atau satu sha' kurma, atau satu sha' gandum, atau satu sha' kismis, atau satu sha keju.\" Telah mengabarkan kepada kami ['Ubaidullah bin Musa] dari [Sufyan] dari [Zaid bin Aslam] dari ['Iyadl bin Abdullah] dari [Abu Sa'id] ia berkata, \"Dahulu kami pada masa Nabi shallallahu 'alaihi wasallam memberi.... kemudian ia menyebutkan seperti itu.\""},"1253":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ خَالِدٍ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ شِمَاسَةَ قَالَ سَمِعْتُ عُقْبَةَ بْنَ عَامِرٍ يَقُولُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَدْخُلُ الْجَنَّةَ صَاحِبُ مَكْسٍ قَالَ قَالَ أَبُو مُحَمَّد يَعْنِي عَشَّارًا","id":"Telah mengabarkan kepada kami [Ahmad bin Khalid] telah menceritakan kepada kami [Muhammad bin Ishaq] dari [Yazid bin Abu Habib] dari ['Abdurrahman bin Syamasah] ia berkata, aku mendengar ['Uqbah bin 'Amir] berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak masuk Surga pemungut pajak.\" Abu Muhammad berkata, \"Yaitu orang yang mengambil berlawanan dengan hukum syari'at.\""},"1254":{"ar":" أَخْبَرَنَا عَاصِمُ بْنُ يُوسُفَ حَدَّثَنَا أَبُو بَكْرٍ عَنْ عَاصِمٍ عَنْ أَبِي وَائِلٍ عَنْ مَسْرُوقٍ عَنْ مُعَاذٍ قَالَ بَعَثَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْيَمَنِ فَأَمَرَنِي أَنْ آخُذَ مِنْ الثِّمَارِ مَا سُقِيَ بَعْلًا الْعُشْرَ وَمَا سُقِيَ بِالسَّانِيَةِ فَنِصْفَ الْعُشْرِ","id":"Telah mengabarkan kepada kami ['Ashim bin Yusuf] telah menceritakan kepada kami [Abu Bakr] dari ['Ashim] dari [Abu Wail] dari [Masruq] dari [Mu'adz] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam mengutusku ke Yaman dan memerintahkan agar aku mengambil buah-buahan yang disirami dengan hujan sepersepuluh, dan yang disirami menggunakan tenaga unta seperdua puluh.\" "},"1255":{"ar":" أَخْبَرَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ وَأَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ جُرْحُ الْعَجْمَاءِ جُبَارٌ وَالْبِئْرُ جُبَارٌ وَالْمَعْدِنُ جُبَارٌ وَفِي الرِّكَازِ الْخُمُسُ","id":"Telah mengabarkan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Malik] dari [Ibnu Syihab] dari [Sa'id bin Al Musayyab] dan [Abu Salamah] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Luka yang diakibatkan oleh binatang ternak tidak ada jaminannya, orang yang (mati) masuk sumur tidak ada jaminan, dan pada barang terpendam zakatnya adalah seperlima.\" "},"1256":{"ar":" أَخْبَرَنَا أَبُو الْيَمَانِ الْحَكَمُ بْنُ نَافِعٍ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ حَدَّثَنِي عُرْوَةُ بْنُ الزُّبَيْرِ عَنْ أَبِي حُمَيْدٍ الْأَنْصَارِيِّ ثُمَّ السَّاعِدِيِّ أَنَّهُ أَخْبَرَهُ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَعْمَلَ عَامِلًا عَلَى الصَّدَقَةِ فَجَاءَهُ الْعَامِلُ حِينَ فَرَغَ مِنْ عَمَلِهِ فَقَالَ يَا رَسُولَ اللَّهِ هَذَا الَّذِي لَكُمْ وَهَذَا أُهْدِيَ لِي فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَهَلَّا قَعَدْتَ فِي بَيْتِ أَبِيكَ وَأُمِّكَ فَنَظَرْتَ أَيُهْدَى لَكَ أَمْ لَا ثُمَّ قَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَشِيَّةً بَعْدَ الصَّلَاةِ عَلَى الْمِنْبَرِ فَتَشَهَّدَ وَأَثْنَى عَلَى اللَّهِ بِمَا هُوَ أَهْلُهُ ثُمَّ قَالَ أَمَّا بَعْدُ مَا بَالُ الْعَامِلِ نَسْتَعْمِلُهُ فَيَأْتِينَا فَيَقُولُ هَذَا مِنْ عَمَلِكُمْ وَهَذَا أُهْدِيَ لِي فَهَلَّا قَعَدَ فِي بَيْتِ أَبِيهِ وَأُمِّهِ فَيَنْظُرَ هَلْ يُهْدَى لَهُ أَمْ لَا وَالَّذِي نَفْسُ مُحَمَّدٍ بِيَدِهِ لَا يَغُلُّ أَحَدُكُمْ مِنْهَا شَيْئًا إِلَّا جَاءَ يَوْمَ الْقِيَامَةِ يَحْمِلُهُ عَلَى عُنُقِهِ إِنْ كَانَ بَعِيرًا جَاءَ بِهِ لَهُ رُغَاءٌ وَإِنْ كَانَتْ بَقَرَةً جَاءَ بِهَا لَهَا خُوَارٌ وَإِنْ كَانَتْ شَاةً جَاءَ بِهَا تَيْعَرُ فَقَدْ بَلَّغْتُ قَالَ أَبُو حُمَيْدٍ ثُمَّ رَفَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَيْهِ حَتَّى إِنَّا لَنَنْظُرُ إِلَى عُفْرَةِ إِبْطَيْهِ قَالَ أَبُو حُمَيْدٍ وَقَدْ سَمِعَ ذَلِكَ مَعِي مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَيْدُ بْنُ ثَابِتٍ فَسَلُوهُ","id":"Telah mengabarkan kepada kami [Abu Al Yaman Al Hakam bin Nafi'] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] telah menceritakan kepadaku ['Urwah bin Az Zubair] dari [Abu Humaid Al Anshari As Sa'idi], bahwa ia mengabarkan kepadanya, bahwa Nabi shallallahu 'alaihi wasallam menggunakan pekerja untuk mengurusi zakat. Kemudian pekerja tersebut datang kepadanya saat pekerjaannya telah selesai. Ia berkata, \"Wahai Rasulullah, ini yang menjadi bagian anda dan yang ini dihadiahkan kepadaku.\" Lalu Nabi shallallahu 'alaihi wasallam bersabda: \"Perhatikanlah, jika kamu duduk di rumah bapak dan ibumu, apakah engkau akan mendapatkan hadiah atau tidak?\" Kemudian setelah shalat, Nabi shallallahu 'alaihi wasallam berdiri di atas mimbar seraya mengucapkan syahadat dan memuji Allah dengan pujian yang menjadi milik-Nya. Kemudian beliau bersabda: \"Bagaimana dengan seorang pekerja yang kami pekerjakan, kemudian datang kepada kami dan berkata, 'Ini hasil dari kerja anda dan ini dihadiahkan kepadaku.' Lihatlah, jika engkau duduk di rumah bapak dan ibumu, apakah engkau akan diberi hadiah atau tidak? Demi Dzat yang jiwa Muhammad ada di tangan-Nya, tidaklah seseorang di antara kalian mengambil sesuatupun darinya yang bukan haknya kecuali pada hari Kiamat ia datang dengan membawanya pada lehernya, apabila sesuatu tersebut adalah unta maka ia datang membawanya dengan bersuara unta, apabila sesuatu tersebut adalah sapi maka ia datang membawanya dengan bersuara sapi, dan apabila sesuatu tersebut adalah kambing maka ia datang membawanya dengan suara kambing, sungguh aku telah menyampaikannya.\" Abu Humaid berkata, \"Kemudian Rasulullah shallallahu 'alaihi wasallam mengangkat kedua tangannya hingga kami melihat putihnya kedua ketiak beliau.\" Abu Humaid berkata, \"Sungguh, Zaid bin Tsabit bersamaku telah mendengar hal itu tersebut dari Nabi shallallahu 'alaihi wasallam, maka tanyakanlah kepada dia.\" "},"1257":{"ar":" أَخْبَرَنَا عَمْرُو بْنُ عَوْنٍ أَخْبَرَنَا هُشَيْمٌ عَنْ دَاوُدَ وَمُجَالِدٍ عَنْ الشَّعْبِيِّ عَنْ جَرِيرٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا جَاءَكُمْ الْمُصَدِّقُ فَلَا يَصْدُرَنَّ عَنْكُمْ إِلَّا وَهُوَ رَاضٍ حَدَّثَنِي مُحَمَّدُ بْنُ عُيَيْنَةَ عَنْ أَبِي إِسْحَقَ الْفَزَارِيِّ عَنْ دَاوُدَ بْنِ أَبِي هِنْدٍ عَنْ عَامِرٍ عَنْ جَرِيرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah mengabarkan kepada kami ['Amru bin 'Aun] telah mengabarkan kepada kami [Husyaim] dari [Daud] serta [Mujalid] dari [Asy Sya'bi] dari [Jarir] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila telah datang kepada kalian petugas pengambil zakat, maka janganlah kembali dari kalian kecuali ia dalam keadaan ridla.\" Telah menceritakan kepadaku [Muhammad bin 'Uyainah] dari [Abu Ishaq Al Fazari] dari [Daud bin Abu Hindun] dari ['Amir] dari [Jarir] dari Nabi shallallahu 'alaihi wasallam seperti itu.\" "},"1258":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ الْمُبَارَكِ أَخْبَرَنَا مَالِكٌ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَمْرِو بْنِ مُعَاذٍ الْأَشْهَلِيِّ عَنْ جَدَّتِهِ يُقَالُ لَهَا حَوَّاءُ قَالَتْ قَالَ رَسُولُ اللَّهِ يَا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نِسَاءَ الْمُسْلِمَاتِ لَا تَحْقِرَنَّ إِحْدَاكُنَّ لِجَارَتِهَا وَلَوْ كُرَاعُ شَاةٍ مُحَرَّقٌ","id":"Telah mengabarkan kepada kami [Al Hakam bin Al Mubarak] telah mengabarkan kepada kami [Malik] dari [Zaid bin Aslam] dari ['Amru bin Mu'adz Al Asyhali] dari neneknya yang dipanggil [Hawwa`], ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai para wanita Muslimah, jangan sekali-kali kalian meremehkan untuk berbuat baik kepada tetangganya meskipun hanya dengan betis kambing yang terbakar.\""},"1259":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا أَبَانُ بْنُ عَبْدِ اللَّهِ الْبَجَلِيُّ حَدَّثَنَا عُثْمَانُ بْنُ أَبِي حَازِمٍ عَنْ صَخْرِ بْنِ الْعَيْلَةِ قَالَ أُخِذَتْ عَمَّةُ الْمُغِيرَةِ بْنِ شُعْبَةَ فَقَدِمَتْ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَمَّتَهُ فَقَالَ يَا صَخْرُ إِنَّ الْقَوْمَ إِذَا أَسْلَمُوا أَحْرَزُوا أَمْوَالَهُمْ وَدِمَاءَهُمْ فَادْفَعْهَا إِلَيْهِ وَكَانَ مَاءٌ لِبَنِي سُلَيْمٍ فَأَسْلَمُوا فَسَأَلُوهُ ذَلِكَ فَدَعَانِي فَقَالَ يَا صَخْرُ إِنَّ الْقَوْمَ إِذَا أَسْلَمُوا أَحْرَزُوا أَمْوَالَهُمْ وَدِمَاءَهُمْ فَادْفَعْهَا إِلَيْهِمْ فَدَفَعْتُهُ أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا أَبَانُ بْنُ عَبْدِ اللَّهِ حَدَّثَنِي عُثْمَانُ بْنُ أَبِي حَازِمٍ عَنْ أَبِيهِ عَنْ جَدِّهِ صَخْرٍ أَطْوَلَ مِنْ حَدِيثِ أَبِي نُعَيْمٍ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Aban bin Abdullah Al Bajali] telah menceritakan kepada kami [Utsman bin Abu Hazim] dari [Shakhr bin Al 'Ailah] ia berkata, \"Bibi Al Mughirah bin Syu'bah tertawan dan menghadap Rasulullah shallallahu 'alaihi wasallam, lalu Al Mughirah meminta bibinya kepada Nabi shallallahu 'alaihi wasallam. Maka beliau pun bersabda: \"Wahai Shakhr, sesungguhnya sebuah kaum apabila telah masuk Islam maka mereka telah menjaga harta dan darah mereka, maka serahkan kepadanya.\" Dahulu Bani Sulaim memiliki air, kemudian mereka masuk Islam dan memintanya kepada beliau. Lalu beliau memanggilku bersabda: \"Wahai Shakhr, sesungguhnya sebuah kaum apabila telah masuk Islam maka mereka telah menjaga harta dan darah mereka, maka serahkan kepada mereka.\" Lalu aku menyerahkan air tersebut kepada mereka.\" Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Aban bin Abdullah] telah menceritakan kepadaku [Utsman bin Abu Hazim] dari [Ayahnya] dari kakeknya [Shakhr] dan haditsnya lebih panjang dari hadits Abu Nu'aim.\" "},"1260":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ الْمُغِيرَةِ عَنْ عِيسَى بْنِ يُونُسَ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ سَعِيدِ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا تَصَدَّقَ امْرُؤٌ بِصَدَقَةٍ مِنْ كَسْبٍ طَيِّبٍ وَلَا يَقْبَلُ اللَّهُ إِلَّا طَيِّبًا إِلَّا وَضَعَهَا حِينَ يَضَعُهَا فِي كَفِّ الرَّحْمَنِ وَإِنَّ اللَّهَ لَيُرَبِّي لِأَحَدِكُمْ التَّمْرَةَ كَمَا يُرَبِّي أَحَدُكُمْ فَلُوَّهُ أَوْ فَصِيلَهُ حَتَّى تَكُونَ مِثْلَ أُحُدٍ","id":"Telah mengabarkan kepada kami [Sa'id bin Al Mughirah] dari [Isa bin Yunus] dari [Yahya bin Sa'id] dari [Sa'id bin Yasar] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seseorang bersedekah dengan sesuatu yang berasal dari usaha yang baik, dan tidak Allah menerima kecuali yang baik, melainkan ia telah meletakkannya ketika ia meletakkannya di telapak tangan Allah yang Maha Pengasih. Dan sesungguhnya Allah akan mengembangkan satu biji kurma salah seorang dari kalian sebagaimana salah seorang dari kalian mengembangkan anak kuda atau anak unta hingga menjadi seperti gunung Uhud.\""},"1261":{"ar":" حَدَّثَنَا أَبُو الرَّبِيعِ الزَّهْرَانِيُّ حَدَّثَنَا إِسْمَعِيلُ بْنُ جَعْفَرٍ عَنْ الْعَلَاءِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا نَقَصَتْ صَدَقَةٌ مِنْ مَالٍ وَمَا زَادَ اللَّهُ عَبْدًا بِعَفْوٍ إِلَّا عِزًّا وَمَا تَوَاضَعَ أَحَدٌ لِلَّهِ إِلَّا رَفَعَهُ اللَّهُ","id":"Telah mengabarkan kepada kami [Abu Ar Rabi' Az Zahrani] telah menceritakan kepada kami [Isma'il bin Ja'far] dari [Al 'Ala`] dari [Ayahnya] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Harta tidak akan berkurang karena sedekah, dan tidaklah Allah menambahkan bagi seorang hamba karena sikap memberi maaf kecuali kemuliaan, dan tidaklah seseorang merendahkan diri karena Allah melainkan Allah mengangkat derajatnya.\""},"1262":{"ar":" أَخْبَرَنَا النَّضْرُ بْنُ شُمَيْلٍ حَدَّثَنَا بَهْزُ بْنُ حَكِيمٍ عَنْ أَبِيهِ عَنْ جَدَّهِ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِي كُلِّ إِبِلٍ سَائِمَةٍ فِي كُلِّ أَرْبَعِينَ بِنْتُ لَبُونٍ لَا تُفَرَّقُ إِبِلٌ عَنْ حِسَابِهَا مَنْ أَعْطَاهَا مُؤْتَجِرًا بِهَا فَلَهُ أَجْرُهَا وَمَنْ مَنَعَهَا فَإِنَّا آخِذُوهَا وَشَطْرَ إِبِلِهِ عَزْمَةٌ مِنْ عَزَمَاتِ اللَّهِ لَا يَحِلُّ لِآلِ مُحَمَّدٍ مِنْهَا شَيْءٌ","id":"Telah mengabarkan kepada kami [An Nadlr bin Syumail] telah menceritakan kepada kami [Bahz bin Hakim] dari [Ayahnya] dari [Kakeknya] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pada setiap empat puluh unta yang digembala, zakatnya adalah satu ekor bintu Labun (anak unta yang berumur dua tahun). Unta tidak boleh dipisahkan dari bilangan jumlahnya, barangsiapa memberinya dengan tujuan untuk mendapatkan pahala maka baginya pahalanya, dan barangsiapa menahannya maka kami akan mengambilnya ditambah setengah untanya. Itulah kewajiban di antara kewajiban-kewajiban dari Allah, dan tidak halal bagi keluarga Muhammad sedikitpun darinya.\""},"1263":{"ar":" حَدَّثَنَا مُسَدَّدٌ وَأَبُو نُعَيْمٍ قَالَا حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ هَارُونَ بْنِ رِيَابٍ حَدَّثَنِي كِنَانَةُ بْنُ نُعَيْمٍ عَنْ قَبِيصَةَ بْنِ مُخَارِقٍ الْهِلَالِيِّ قَالَ تَحَمَّلْتُ بِحَمَالَةٍ فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَسْأَلُهُ فِيهَا فَقَالَ أَقِمْ يَا قَبِيصَةُ حَتَّى تَأْتِيَنَا الصَّدَقَةُ فَنَأْمُرَ لَكَ بِهَا ثُمَّ قَالَ يَا قَبِيصَةُ إِنَّ الْمَسْأَلَةَ لَا تَحِلُّ إِلَّا لِأَحَدِ ثَلَاثَةٍ رَجُلٍ تَحَمَّلَ حَمَالَةً فَحَلَّتْ لَهُ الْمَسْأَلَةُ فَسَأَلَ حَتَّى يُصِيبَهَا ثُمَّ يُمْسِكَ وَرَجُلٍ أَصَابَتْهُ جَائِحَةٌ فَاجْتَاحَتْ مَالَهُ فَحَلَّتْ لَهُ الْمَسْأَلَةُ فَسَأَلَ حَتَّى يُصِيبَ قِوَامًا مِنْ عَيْشٍ أَوْ قَالَ سِدَادًا مِنْ عَيْشٍ وَرَجُلٍ أَصَابَتْهُ فَاقَةٌ حَتَّى يَقُولَ ثَلَاثَةٌ مِنْ ذَوِي الْحِجَى مِنْ قَوْمِهِ قَدْ أَصَابَ فُلَانًا الْفَاقَةُ فَحَلَّتْ لَهُ الْمَسْأَلَةُ فَسَأَلَ حَتَّى يُصِيبَ قِوَامًا مِنْ عَيْشٍ أَوْ سِدَادًا مِنْ عَيْشٍ ثُمَّ يُمْسِكَ وَمَا سِوَاهُنَّ مِنْ الْمَسْأَلَةِ سُحْتٌ يَا قَبِيصَةُ يَأْكُلُهَا صَاحِبُهَا سُحْتًا","id":"Telah menceritakan kepada kami [Musaddad] dan [Abu Nu'aim] mereka berkata, telah menceritakan kepada kami [Hammad bin Zaid] dari [Harun bin Riyab] telah menceritakan kepadaku [Kinanah bin Nu'aim] dari [Qabishah bin Mukhariq Al Hilali] ia berkata, \"Aku menanggung sebuah denda, maka aku pun datang menemui Nabi shallallahu 'alaihi wasallam dan menanyakannya kepada beliau, lalu beliau bersabda: \"Tunggulah wahai Qabishah, hingga datang Zakat kepada kami dan kami bisa memberikannya kepada kamu.\" Kemudian beliau bersabda lagi: \"Wahai Qabishah, sesungguhnya meminta-minta tidaklah halal kecuali bagi salah satu dari tiga orang; seseorang yang menanggung denda, ia boleh meminta. Maka hendaklah ia meminta-minta sampai mendapatkannya, kemudian ia menahan diri. Seorang laki-laki yang tertimpa musibah yang menghancurkan hartanya, ia boleh meminta-minta, maka hendaklah ia meminta hingga mendapatkan penopang hidup atau sesuatu yang dapat menutupi kebutuhan hidup. Dan seseorang yang tertimpa kefakiran hingga tiga orang yang berakal sempurna dari kaumnya mengatakan 'Fulan telah tertimpa kefakiran', ia boleh meminta-minta. Maka hendaklah ia meminta-minta sampai mendapatkan penopang hidup atau penutup kebutuhan hidup, kemudian menahan diri. Wahai Qabishah, meminta-minta dari selain itu adalah sesuatu yang dosa, jika ia makan maka itu dosa.\""},"1264":{"ar":" حَدَّثَنَا سَعِيدُ بْنُ سُلَيْمَانَ عَنْ عَبَّادِ بْنِ الْعَوَّامِ عَنْ سُفْيَانَ بْنِ حُسَيْنٍ عَنْ الزُّهْرِيِّ عَنْ أَيُّوبَ بْنِ بَشِيرٍ عَنْ حَكِيمِ بْنِ حِزَامٍ أَنَّ رَجُلًا سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الصَّدَقَاتِ أَيُّهَا أَفْضَلُ قَالَ عَلَى ذِي الرَّحِمِ الْكَاشِحِ","id":"Telah menceritakan kepada kami [Sa'id bin Sulaiman] dari ['Abbad bin Al 'Awwam] dari [Sufyan bin Husain] dari [Az Zuhri] dari [Ayyub bin Basyir] dari [Hakim bin Hizam], bahwa seorang laki-laki bertanya kepada Nabi shallallahu 'alaihi wasallam mengenai sedekah apakah yang paling utama?\" Beliau bersabda: \"Sedekah kepada orang yang memiliki hubungan kerabat yang menyembunyikan permusuhannya.\""},"1265":{"ar":" أَخْبَرَنَا أَبُو حَاتِمٍ الْبَصْرِيُّ حَدَّثَنَا ابْنُ عَوْنٍ عَنْ حَفْصَةَ بِنْتِ سِيرِينَ عَنْ أُمِّ الرَّائِحِ بِنْتِ صُلَيْعٍ عَنْ سَلْمَانَ بْنِ عَامِرٍ الضَّبِّيِّ ذَكَرَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الصَّدَقَةَ عَلَى الْمِسْكِينِ صَدَقَةٌ وَإِنَّهَا عَلَى ذِي الرَّحِمِ اثْنَتَانِ صَدَقَةٌ وَصِلَةٌ","id":"Telah mengabarkan kepada kami [Abu Hatim Al Bashri] telah menceritakan kepada kami [Ibnu 'Aun] dari [Hafshah binti Sirin] dari [Ummu Ar Raih binti Shulai'] dari [Salman bin 'Amir Adl Dlabbi] ia menyebutkan, bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya bersedekah kepada orang miskin hanya sebuah sedekah, dan sedekah kepada orang yang memiliki hubungan kerabat adalah dua pahala; pahala sedekah dan pahala menyambung hubungan kekerabatan.\""},"1266":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ ابْنِ عُيَيْنَةَ قَالَ وَقَدْ سَمِعْتُهُ مِنَ الثَّوْرِيِّ عَنْ عَاصِمٍ عَنْ حَفْصَةَ بِنْتِ سِيرِينَ عَنْ الرَّبَابِ عَنْ سَلْمَانَ بْنِ عَامِرٍ الضَّبِّيِّ يَرْفَعُهُ قَالَ الصَّدَقَةُ عَلَى الْمِسْكِينِ صَدَقَةٌ وَهِيَ عَلَى ذِي الرَّحِمِ اثْنَتَانِ صَدَقَةٌ وَصِلَةٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Ibnu 'Uyainah] ia berkata, aku telah mendengarnya dari [Ats Tsauri] dari ['Ashim] dari [Hafshah binti Sirin] dari [Ar Rabab] dari [Salman bin 'Amir Adl Dabbi] dan ia memarfu'kannya, ia berkata, \"Bersedekah kepada orang miskin bernilai satu sedekah, dan sedekah kepada orang yang memiliki hubungan kerabat mempunyai dua nilai; pahala sedekah dan pahala menyambung hubungan kekerabatan.\""},"1267":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ عَنْ عَمْرِو بْنِ قَيْسٍ عَنْ أَبِي إِسْحَقَ عَنْ صِلَةَ بْنِ زُفَرَ قَالَ كُنَّا عِنْدَ عَمَّارِ بْنِ يَاسِرٍ فَأُتِيَ بِشَاةٍ مَصْلِيَّةٍ فَقَالَ كُلُوا فَتَنَحَّى بَعْضُ الْقَوْمِ فَقَالَ إِنِّي صَائِمٌ فَقَالَ عَمَّارُ بْنُ يَاسِرٍ مَنْ صَامَ الْيَوْمَ الَّذِي يُشَكُّ فِيهِ فَقَدْ عَصَى أَبَا الْقَاسِمِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Abdullah bin Sa'id] telah menceritakan kepada kami [Abu Khalid Al Ahmar] dari ['Amru bin Qais] dari [Abu Ishaq] dari [Shilah bin Zufar] ia berkata, \"Kami pernah bersama ['Ammar bin Yasir], kemudian ia diberi seekor kambing bakar, lalu ia berkata, \"Makanlah.\" Lalu sebagian orang menjauh dan berkata, \"Aku sedang berpuasa.\" 'Ammar bin Yasir lantas berkata, \"Barangsiapa berpuasa pada hari yang diragukan, sungguh ia telah durhaka kepada Abu Al Qasim shallallahu 'alaihi wasallam.\" "},"1268":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ حَدَّثَنَا حَاتِمُ بْنُ أَبِي صَغِيرَةَ عَنْ سِمَاكِ بْنِ حَرْبٍ قَالَ أَصْبَحْتُ فِي يَوْمٍ قَدْ أُشْكِلَ عَلَيَّ مِنْ شَعْبَانَ أَوْ مِنْ شَهْرِ رَمَضَانَ فَأَصْبَحْتُ صَائِمًا فَأَتَيْتُ عِكْرِمَةَ فَإِذَا هُوَ يَأْكُلُ خُبْزًا وَبَقْلًا فَقَالَ هَلُمَّ إِلَى الْغَدَاءِ فَقُلْتُ إِنِّي صَائِمٌ فَقَالَ أُقْسِمُ بِاللَّهِ لَتُفْطِرَنَّ فَلَمَّا رَأَيْتُهُ حَلَفَ وَلَا يَسْتَثْنِي تَقَدَّمْتُ فَعَذَّرْتُ وَإِنَّمَا تَسَحَّرْتُ قُبَيْلَ ذَلِكَ ثُمَّ قُلْتُ هَاتِ الْآنَ مَا عِنْدَكَ فَقَالَ حَدَّثَنَا ابْنُ عَبَّاسٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صُومُوا لِرُؤْيَتِهِ وَأَفْطِرُوا لِرُؤْيَتِهِ فَإِنْ حَالَ بَيْنَكُمْ وَبَيْنَهُ سَحَابٌ فَكَمِّلُوا الْعِدَّةَ ثَلَاثِينَ وَلَا تَسْتَقْبِلُوا الشَّهْرَ اسْتِقْبَالًا","id":"Telah menceritakan kepada kami [Abdullah bin Sa'id] telah menceritakan kepada kami [Isma'il bin 'Ulaiyyah] telah menceritakan kepada kami [Hatim bin Abu Shaghirah] dari [Simak bin Harb] ia berkata, \"Aku berpuasa pada hari yang aku masih ragu, apakah bulan Sya'ban atau Ramadan. Maka aku datang menemui Ikrimah, ternyata ia sedang makan roti dan sayur, ia lalu berkata, 'Kemarilah makan siang.' Kemudian aku katakan, \"Aku sedang berpuasa.\" [Ikrimah] berkata lagi, \"Aku bersumpah dengan nama Allah, hendaklah engkau harus berbuka! \" Maka tatkala aku melihatnya bersumpah dan tidak mengucapkan insyaallah, aku maju dan mengungkapkan alasan, \"Sesungguhnya sebelum itu aku telah makan sahur. Sekarang sampaikanlah alasanmu kepadaku.\" Lalu ia berkata, \" [Ibnu Abbas] menceritakan kepada kami, ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berpuasalah karena melihatnya (hilal) dan berbukalah karena melihatnya. Jika terdapat awan yang menghalangi kalian untuk melihatnya, maka sempurnakanlah jumlah bulan menjadi tiga puluh hari, dan janganlah kalian menyambut bulan Ramadan dengan berpuasa.\""},"1269":{"ar":" حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ الْمَجِيدِ حَدَّثَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَكَرَ رَمَضَانَ فَقَالَ لَا تَصُومُوا حَتَّى تَرَوْا الْهِلَالَ وَلَا تُفْطِرُوا حَتَّى تَرَوْهُ فَإِنْ غُمَّ عَلَيْكُمْ فَاقْدُرُوا لَهُ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Abdul Majid] telah menceritakan kepada kami [Malik] dari [Nafi'] dari [Umar], bahwa Rasulullah shallallahu 'alaihi wasallam menyebut-nyebut tentang bulan Ramadan, beliau bersabda: \"Janganlah kalian berpuasa hingga melihat hilal, dan janganlah berbuka hingga kalian melihatnya. Jika kalian tertutup oleh awan, maka genapkan jumlahnya tiga puluh hari.\""},"1270":{"ar":" حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا شُعْبَةُ حَدَّثَنِي مُحَمَّدُ بْنُ زِيَادٍ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ قَالَ أَبُو الْقَاسِمِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صُومُوا لِرُؤْيَتِهِ وَأَفْطِرُوا لِرُؤْيَتِهِ فَإِنْ غُمَّ عَلَيْكُمْ الشَّهْرُ فَعُدُّوا ثَلَاثِينَ","id":"Telah menceritakan kepada kami [Hasyim bin Al Qasim] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepadaku [Muhammad bin Ziyad] ia berkata, aku mendengar [Abu Hurairah] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda, atau Abu Al Qasim shallallahu 'alaihi wasallam bersabda: \"Berpuasalah karena melihatnya dan berbukalah karena melihatnya, jika bulan tertutup oleh kalian maka genapkanlah menjadi tiga puluh hari.\""},"1271":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو يَعْنِي ابْنَ دِينَارٍ عَنْ مُحَمَّدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ أَنَّهُ عَجِبَ مِمَّنْ يَتَقَدَّمُ الشَّهْرَ وَيَقُولُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا رَأَيْتُمُوهُ فَصُومُوا وَإِذَا رَأَيْتُمُوهُ فَأَفْطِرُوا فَإِنْ غُمَّ عَلَيْكُمْ فَأَكْمِلُوا الْعِدَّةَ ثَلَاثِينَ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'id] telah menceritakan kepada kami [Sufyan] dari ['Amru] -yaitu Ibnu Dinar- dari [Muhammad bin Jubair] dari [Ibnu Abbas], bahwa ia heran terhadap orang yang mendahului bulan Ramadan, ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila kalian melihatnya maka berpuasalah dan apabila kalian melihatnya maka berbukalah. Jika kalian terhalang oleh awan maka sempurnakan jumlahnya tiga puluh hari.\""},"1272":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ سُلَيْمَانَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عُثْمَانَ بْنِ إِبْرَاهِيمَ حَدَّثَنِي أَبِي عَنْ أَبِيهِ وَعَمِّهِ عَنْ ابْنِ عُمَرَ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا رَأَى الْهِلَالَ قَالَ اللَّهُ أَكْبَرُ اللَّهُمَّ أَهِلَّهُ عَلَيْنَا بِالْأَمْنِ وَالْإِيمَانِ وَالسَّلَامَةِ وَالْإِسْلَامِ وَالتَّوْفِيقِ لِمَا يُحِبُّ رَبُّنَا وَيَرْضَى رَبُّنَا وَرَبُّكَ اللَّهُ","id":"Telah mengabarkan kepada kami [Sa'id bin Sulaiman] dari ['Abdurrahman bin Utsman bin Ibrahim] telah menceritakan kepadaku [Ayahku] dari [Ayahnya] dan [Pamannya] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam apabila melihat hilal beliau berkata: \"Allahu akbar! Ya Allah, nampakkan hilal kepada kami dengan aman, iman, keselamatan, Islam dan taufiq untuk melakukan apa yang dicintai dan diridlai Tuhan kami. Tuhan kami dan Tuhan kalian adalah Allah.\""},"1273":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يَزِيدَ الرِّفَاعِيُّ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا الْعَقَدِيُّ حَدَّثَنَا سُلَيْمَانُ بْنُ سُفْيَانَ الْمَدَنِيُّ عَنْ بِلَالِ بْنِ يَحْيَى بْنِ طَلْحَةَ عَنْ أَبِيهِ عَنْ طَلْحَةَ قَالَ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا رَأَى الْهِلَالَ قَالَ اللَّهُمَّ أَهِلَّهُ عَلَيْنَا بِالْأَمْنِ وَالْإِيمَانِ وَالسَّلَامَةِ وَالْإِسْلَامِ رَبِّي وَرَبُّكَ اللَّهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Yazid Ar Rifa'i], dan [Ishaq bin Ibrahim] telah menceritakan kepada kami [Al 'Aqadi] telah menceritakan kepada kami [Sulaiman bin Sufyan Al Madani] dari [Bilal bin Yahya bin Thalhah] dari [Ayahnya] dari [Thalhah] ia berkata, \"Nabi shallallahu 'alaihi wasallam apabila melihat hilal mengucapkan: \"Ya Allah, nampakkan hilal kepada kami dengan aman, iman, keselamatan, dan Islam. Tuhan kami dan Tuhan kalian adalah Allah.\""},"1274":{"ar":" أَخْبَرَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَقَدَّمُوا قَبْلَ رَمَضَانَ يَوْمًا وَلَا يَوْمَيْنِ إِلَّا أَنْ يَكُونَ رَجُلًا كَانَ يَصُومُ صَوْمًا فَلْيَصُمْهُ","id":"Telah menceritakan kepada kami [Wahb bin Jarir] telah menceritakan kepada kami [Hisyam] dari [Yahya] dari [Abu Salamah] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian mendahului Ramadan dengan berpuasa satu hari dan dua hari, kecuali seseorang yang biasa berpuasa maka hendaknya ia melakukannya.\""},"1275":{"ar":" حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا الشَّهْرُ تِسْعٌ وَعِشْرُونَ فَلَا تَصُومُوا حَتَّى تَرَوْهُ وَلَا تُفْطِرُوا حَتَّى تَرَوْهُ فَإِنْ غُمَّ عَلَيْكُمْ فَاقْدُرُوا لَهُ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya bulan ada dua puluh sembilan hari, janganlah kalian berpuasa hingga melihatnya dan janganlah kalian berbuka hingga melihatnya. Jika kalian terhalangi oleh awan, maka genapkan jumlahnya.\" "},"1276":{"ar":" حَدَّثَنَا مَرْوَانُ بْنُ مُحَمَّدٍ عَنْ عَبْدِ اللَّهِ بْنِ وَهْبٍ عَنْ يَحْيَى بْنِ سَالِمٍ عَنْ أَبِي بَكْرِ بْنِ نَافِعٍ عَنْ أَبِيهِ عَنْ ابْنِ عُمَرَ قَالَ تَرَاءَى النَّاسُ الْهِلَالَ فَأَخْبَرْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنِّي رَأَيْتُهُ فَصَامَ وَأَمَرَ النَّاسَ بِالصِّيَامِ","id":"Telah menceritakan kepada kami [Marwan bin Muhammad] dari [Abdullah bin Wahb] dari [Yahya bin Salim] dari [Abu Bakr bin Nafi'] dari [Ayahnya] dari [Ibnu Umar] ia berkata, \"Orang-orang saling melihat hilal, kemudian aku memberitahukan kepada Rasulullah shallallahu 'alaihi wasallam bahwa aku telah melihatnya, kemudian beliau berpuasa dan memerintahkan orang-orang untuk berpuasa.\""},"1277":{"ar":" حَدَّثَنِي عِصْمَةُ بْنُ الْفَضْلِ حَدَّثَنَا حُسَيْنٌ الْجُعْفِيُّ عَنْ زَائِدَةَ عَنْ سِمَاكٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ جَاءَ أَعْرَابِيٌّ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ إِنِّي رَأَيْتُ الْهِلَالَ فَقَالَ أَتَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنِّي رَسُولُ اللَّهِ قَالَ نَعَمْ قَالَ يَا بِلَالُ نَادِ فِي النَّاسِ فَلْيَصُومُوا غَدًا","id":"Telah menceritakan kepadaku ['Ishmah bin Al Fadll] telah menceritakan kepada kami [Husain Al Ju'fi] dari [Zaidah] dari [Simak] dari [Ikrimah] dari [Ibnu Abbas] ia berkata, \"Seorang Arab dusun datang menemui Nabi shallallahu 'alaihi wasallam dan berkata, \"Aku telah melihat hilal! \" Beliau lalu bersabda: \"Apakah engkau bersaksi bahwa tidak ada Tuhan yang berhak disembah kecuali Allah dan aku adalah Rasulullah?\" Ia menjawab, \"Ya.\" Beliau kemudian bersabda: \"Wahai Bilal, umumkan kepada manusia agar mereka besok berpuasa.\""},"1278":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ عَنْ الْبَرَاءِ قَالَ كَانَ أَصْحَابُ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا كَانَ الرَّجُلُ صَائِمًا فَحَضَرَ الْإِفْطَارُ فَنَامَ قَبْلَ أَنْ يُفْطِرَ لَمْ يَأْكُلْ لَيْلَتَهُ وَلَا يَوْمَهُ حَتَّى يُمْسِيَ وَإِنَّ قَيْسَ بْنَ صِرْمَةَ الْأَنْصَارِيَّ كَانَ صَائِمًا فَلَمَّا حَضَرَ الْإِفْطَارُ أَتَى امْرَأَتَهُ فَقَالَ عِنْدَكِ طَعَامٌ فَقَالَتْ لَا وَلَكِنْ أَنْطَلِقُ فَأَطْلُبُ لَكَ وَكَانَ يَوْمَهُ يَعْمَلُ فَغَلَبَتْهُ عَيْنُهُ وَجَاءَتْ امْرَأَتُهُ فَلَمَّا رَأَتْهُ قَالَتْ خَيْبَةً لَكَ فَلَمَّا انْتَصَفَ النَّهَارُ غُشِيَ عَلَيْهِ فَذُكِرَ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَزَلَتْ هَذِهِ الْآيَةُ { أُحِلَّ لَكُمْ لَيْلَةَ الصِّيَامِ الرَّفَثُ إِلَى نِسَائِكُمْ } فَفَرِحُوا بِهَا فَرَحًا شَدِيدًا { وَكُلُوا وَاشْرَبُوا حَتَّى يَتَبَيَّنَ لَكُمْ الْخَيْطُ الْأَبْيَضُ مِنْ الْخَيْطِ الْأَسْوَدِ }","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Musa] dari [Israil] dari [Abu Ishaq] dari [Al Bara`] ia berkata, \"Para sahabat Muhammad shallallahu 'alaihi wasallam; apabila seseorang berpuasa kemudian datang waktu berbuka, maka ia tidur sebelum berbuka, sehingga ia tidak berbuka sehari semalam hingga masuk pada waktu sore. Sesungguhnya Qais bin Shirmah Al Anshari pernah berpuasa, saat waktu berbuka tiba ia menemui isterinya dan bertanya, \"Apakah engkau memiliki makanan?\" Lalu isterinya mengatakan, \"Tidak, akan tetapi aku akan pergi dan mencari untukmu.\" Karena seharian ia lelah bekerja, maka ia pun tertidur. Maka saat isterinya melihatnya, ia berkata, \"Duhai, merugilah engkau.\" Kemudian tatkala pada pertengahan siang hari Qais bin Shirmah pingsan. Lalu hal itu diceritakan kepada Nabi shallallahu 'alaihi wasallam, kemudian turunlah ayat ini: '(Dihalalkan bagi kamu pada malam hari bulan puasa bercampur dengan isteri-isteri kamu) ' maka mereka sangat senang sekali '(dan makan minumlah hingga terang bagimu benang putih dari benang hitam) ' (Qs. Al Baqarah: 187)."},"1279":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شَرِيكٌ عَنْ حُصَيْنٍ عَنْ الشَّعْبِيِّ عَنْ عَدِيِّ بْنِ حَاتِمٍ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ لَقَدْ جَعَلْتُ تَحْتَ وِسَادَتِي خَيْطًا أَبْيَضَ وَخَيْطًا أَسْوَدَ فَمَا تَبَيَّنَ لِي شَيْءٌ قَالَ إِنَّكَ لَعَرِيضُ الْوِسَادِ وَإِنَّمَا ذَلِكَ اللَّيْلُ مِنْ النَّهَارِ فِي قَوْلِهِ { وَكُلُوا وَاشْرَبُوا حَتَّى يَتَبَيَّنَ لَكُمْ الْخَيْطُ الْأَبْيَضُ مِنْ الْخَيْطِ الْأَسْوَدِ مِنْ الْفَجْرِ }","id":"Telah mengabarkan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syarik] dari [Hushain] dari [Asy Sya'bi] dari ['Adi bin Hatim] ia berkata, \"Aku bertanya, \"Wahai Rasulullah, sungguh aku telah meletakkan di bawah bantalku benang putih dan benang hitam, namun tidak ada sesuatupun yang jelas bagiku?\" Beliau bersabda: \"Sungguh engkau sangat tidak faham, sesungguhnya hal itu adalah waktu malam dari waktu siang dalam firman-Nya: '(dan makan minumlah hingga terang bagimu benang putih dari benang hitam, yaitu fajar…) ' (Qs.?Al Baqarah: 187). "},"1280":{"ar":" أَخْبَرَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هِشَامٌ عَنْ قَتَادَةَ عَنْ أَنَسٍ عَنْ زَيْدِ بْنِ ثَابِتٍ قَالَ تَسَحَّرْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ثُمَّ قَامَ إِلَى الصَّلَاةِ قَالَ قُلْتُ كَمْ كَانَ بَيْنَ الْأَذَانِ وَالسُّحُورِ قَالَ قَدْرُ قِرَاءَةِ خَمْسِينَ آيَةً","id":"Telah mengabarkan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Hisyam] dari [Qatadah] dari [Anas] dari [Zaid bin Tsabit] ia berkata, \"Kami pernah sahur bersama Rasulullah shallallahu 'alaihi wasallam. Kemudian beliau bangkit untuk melakukan shalat.\" Anas berkata, \"Aku lalu bertanya, \"Berapakah waktu antara adzan dan sahur?\" Zaid menjawab, \"Seukuran lima puluh ayat.\""},"1281":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ شُعْبَةَ عَنْ عَبْدِ الْعَزِيزِ بْنِ صُهَيْبٍ عَنْ أَنَسٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَسَحَّرُوا فَإِنَّ فِي السُّحُورِ بَرَكَةً","id":"Telah mengabarkan kepada kami [Sa'id bin 'Amir] dari [Syu'bah] dari [Abdul Aziz bin Shuhaib] dari [Anas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hendaklah kalian makan sahur, sesungguhnya dalam sahur terdapat berkah.\""},"1282":{"ar":" حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا مُوسَى بْنُ عُلَيٍّ قَالَ سَمِعْتُ أَبِي يُحَدِّثُ عَنْ أَبِي قَيْسٍ مَوْلَى عَمْرِو بْنِ الْعَاصِ قَالَ كَانَ عَمْرُو بْنُ الْعَاصِ يَأْمُرُنَا أَنْ نَصْنَعَ لَهُ الطَّعَامَ يَتَسَحَّرُ بِهِ فَلَا يُصِيبُ مِنْهُ كَثِيرًا فَقُلْنَا لَهُ تَأْمُرُنَا بِهِ وَلَا تُصِيبُ مِنْهُ كَثِيرًا قَالَ إِنِّي لَا آمُرُكُمْ بِهِ أَنِّي أَشْتَهِيهِ وَلَكِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فَصْلُ مَا بَيْنَ صِيَامِنَا وَصِيَامِ أَهْلِ الْكِتَابِ أَكْلَةُ السَّحَرِ","id":"Telah menceritakan kepada kami [Wahb bin Jarir] telah menceritakan kepada kami [Musa bin Ali] ia berkata, aku mendengar [Ayahku] menceritakan dari [Abu Qais] mantan budak 'Amru bin Al 'Ash, ia berkata, \" ['Amru bin Al 'Ash] pernah memerintahkan kami untuk membuatkan makan sahur, namun ia hanya makan sedikit. Lalu kami bertanya kepadanya, \"Anda memerintahkan kami agar membuatnya, tapi anda hanya makan sedikit?\" Ia lantas menjawab, \"Sesungguhnya aku tidak memerintahkannya kepada kalian, aku berselera makan, tetapi aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pemisah antara puasa kita dengan puasa ahli kitab adalah makan sahur.\""},"1283":{"ar":" حَدَّثَنَا سَعِيدُ بْنُ شُرَحْبِيلَ حَدَّثَنَا لَيْثُ بْنُ سَعْدٍ عَنْ يَحْيَى بْنِ أَيُّوبَ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ ابْنِ عُمَرَ عَنْ حَفْصَةَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ لَمْ يُبَيِّتْ الصِّيَامَ قَبْلَ الْفَجْرِ فَلَا صِيَامَ لَهُ قَالَ عَبْد اللَّهِ فِي فَرْضِ الْوَاجِبِ أَقُولُ بِهِ","id":"Telah menceritakan kepada kami [Sa'id bin Syurahbil] telah menceritakan kepada kami [Laits bin Sa'd] dari [Yahya bin Ayyub] dari [Abdullah bin Abu Bakr] dari [Salim bin Abdullah bin Umar] dari [Ibnu Umar] dari [Hafshah] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa belum meniatkan puasa pada malam hari sebelum fajar, maka tidak ada puasa baginya.\" Abdullah berkata, \"Aku berpendapat bahwa itu dalam puasa wajib.\" "},"1284":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ الثَّوْرِيِّ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَزَالُ النَّاسُ بِخَيْرٍ مَا عَجَّلُوا الْفِطْرَ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Sufyan Ats Tsauri] dari [Abu Hazim] dari [Sahl bin Sa'd] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Manusia akan senantiasa berada dalam kebaikan selama mereka menyegerakan berbuka.\""},"1285":{"ar":" حَدَّثَنَا عُثْمَانُ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدَةُ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَاصِمِ بْنِ عُمَرَ عَنْ عُمَرَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَقْبَلَ اللَّيْلُ وَأَدْبَرَ النَّهَارُ وَغَابَتْ الشَّمْسُ فَقَدْ أَفْطَرْتَ","id":"Telah menceritakan kepada kami [Utsman bin Muhammad] telah menceritakan kepada kami ['Abdah bin Hisyam bin 'Urwah] dari [Ayahnya] dari ['Ashim bin Umar] dari [Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila malam telah datang dan siang telah pergi, kemudian matahari telah tenggelam maka engkau boleh berbuka.\""},"1286":{"ar":" أَخْبَرَنَا أَبُو النُّعْمَانِ حَدَّثَنَا ثَابِتُ بْنُ يَزِيدَ حَدَّثَنَا عَاصِمٌ عَنْ حَفْصَةَ عَنْ الرَّبَابِ الضَّبِّيَّةِ عَنْ عَمِّهَا سَلْمَانَ بْنِ عَامِرٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَفْطَرَ أَحَدُكُمْ فَلْيُفْطِرْ عَلَى تَمْرٍ فَإِنْ لَمْ يَجِدْ فَلْيُفْطِرْ عَلَى مَاءٍ فَإِنَّ الْمَاءَ طَهُورٌ","id":"Telah mengabarkan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Tsabit bin Yazid] telah menceritakan kepada kami ['Ashim] dari [Hafshah] dari [Ar Rabbab Adl Dlabbiyyah] dari pamannya [Salman bin 'Amir], bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian berbuka hendaknya dengan kurma, jika tidak mendapatkannya hendaknya dengan air, karena sesungguhnya air adalah sesuatu yang membersihkan.\""},"1287":{"ar":" أَخْبَرَنَا يَعْلَى حَدَّثَنَا عَبْدُ الْمَلِكِ عَنْ عَطَاءٍ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ فَطَّرَ صَائِمًا كُتِبَ لَهُ مِثْلُ أَجْرِهِ إِلَّا أَنَّهُ لَا يَنْقُصُ مِنْ أَجْرِ الصَّائِمِ","id":"Telah mengabarkan kepada kami [Ya'la] telah menceritakan kepada kami [Abdul Malik] dari ['Atha`] dari [Zaid bin Khalid Al Juhani] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa memberi makan orang yang berpuasa (untuk berbuka), maka ia memperoleh pahala orang yang berpuasa tersebut dengan tanpa mengurangi dari pahalanya sedikitpun.\" "},"1288":{"ar":" أَخْبَرَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا مَالِكٌ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِيَّاكُمْ وَالْوِصَالَ مَرَّتَيْنِ قَالُوا فَإِنَّكَ تُوَاصِلُ قَالَ إِنِّي لَسْتُ مِثْلَكُمْ إِنِّي أَبِيتُ يُطْعِمُنِي رَبِّي وَيَسْقِينِي","id":"Telah mengabarkan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Malik] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian berpuasa wishal.\" Beliau mengatakannya dua kali. Para sahabat berkata, \"Tetapi kenapa anda melakukan wishal!? Beliau menjawab: \"Sesungguhnya aku tidak seperti kalian, di malam hari aku diberi makan dan minum oleh Tuhanku.\""},"1289":{"ar":" حَدَّثَنَا سَعِيدُ بْنُ الرَّبِيعِ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُوَاصِلُوا قِيلَ إِنَّكَ تَفْعَلُ ذَاكَ قَالَ إِنِّي لَسْتُ كَأَحَدِكُمْ إِنِّي أُطْعَمُ وَأُسْقَى","id":"Telah menceritakan kepada kami [Sa'id bin Ar Rabi'] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Anas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian melakukan puasa wishal.\" Beliau ditanya, \"Tapi kenapa anda melakukan hal tersebut!? Beliau menjawab: \"Aku tidak seperti kalian, aku diberi makan dan minum.\""},"1290":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنِي اللَّيْثُ حَدَّثَنِي يَزِيدُ بْنُ عَبْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ خَبَّابٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ أَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تُوَاصِلُوا فَأَيُّكُمْ يُرِيدُ أَنْ يُوَاصِلَ فَلْيُوَاصِلْ إِلَى السَّحَرِ قَالُوا إِنَّكَ تُوَاصِلُ يَا رَسُولَ اللَّهِ قَالَ إِنِّي أَبِيتُ لِي مُطْعِمٌ يُطْعِمُنِي وَيَسْقِينِي","id":"Telah menceritakan kepada kami [Abdullah bin Shalih] telah menceritakan kepadaku [Al Laits] telah menceritakan kepadaku [Yazid bin Abdullah bin Khabab] dari [Abdullah bin Khabab] dari [Abu Sa'id Al Khudri], bahwa ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian melakukan puasa wishal, maka siapapun di antara kalian yang ingin melakukan wishal, hendaknya ia melakukannya hingga waktu sahur.\" Para sahabat bertanya, \"Akan tetapi anda melakukan wishal wahai Rasulullah!? Beliau menjawab: \"Sesungguhnya pada malam hari ada yang memberiku makan dan minum.\""},"1291":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنِي اللَّيْثُ حَدَّثَنِي عُقَيْلٌ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ أَبَا هُرَيْرَةَ قَالَ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْوِصَالِ فَقَالَ لَهُ رِجَالٌ مِنْ الْمُسْلِمِينَ فَإِنَّكَ تُوَاصِلُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي لَسْتُ مِثْلَكُمْ إِنِّي أَبِيتُ يُطْعِمُنِي رَبِّي وَيَسْقِينِي فَلَمَّا أَبَوْا أَنْ يَنْتَهُوا عَنْ الْوِصَالِ وَاصَلَ بِهِمْ يَوْمًا ثُمَّ يَوْمًا ثُمَّ رَأَوْا الْهِلَالَ فَقَالَ لَوْ تَأَخَّرَ لَزِدْتُكُمْ كَالْمُنَكِّلِ لَهُمْ حِينَ أَبَوْا أَنْ يَنْتَهُوا","id":"Telah menceritakan kepada kami [Abdullah bin Shalih] telah menceritakan kepadaku [Al Laits] telah menceritakan kepadaku ['Uqail] dari [Ibnu Syihab] telah mengabarkan kepadaku [Abu Salamah bin 'Abdurrahman] bahwa [Abu Hurairah] berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang dari melakukan puasa wishal. Lalu ada beberapa orang muslim yang berkata kepada beliau, \"Akan tetapi anda melakukan wishal!? Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya aku tidak seperti kalian, pada malam hari aku diberi makan dan minum oleh Tuhanku.\" Maka ketika mereka enggan untuk berhenti dari wishal, beliau melakukan wishal bersama mereka satu hari demi satu hari hingga mereka melihat hilal, beliau bersabda: \"Sekiranya hilal itu belum muncul, maka aku akan menambahkannya (puasa wishal) untuk kalian.\" Seakan beliau menantang saat mereka enggan untuk berhenti dari puasa wishal.\""},"1292":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ عُرْوَةَ عَنْ عَائِشَةَ أَنَّ حَمْزَةَ بْنَ عَمْرٍو الْأَسْلَمِيَّ سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي أُرِيدُ السَّفَرَ فَمَا تَأْمُرُنِي قَالَ إِنْ شِئْتَ فَصُمْ وَإِنْ شِئْتَ فَأَفْطِرْ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Sufyan] dari [Hisyam bin 'Urwah] dari ['Urwah] dari [Aisyah] bahwa Hamzah bin 'Amru Al Aslami bertanya kepada Rasulullah shallallahu 'alaihi wasallam, ia berkata, \"Wahai Rasulullah, sesungguhnya aku ingin bersafar, maka apakah yang anda perintahkan kepadaku?\" Beliau menjawab: \"Jika mau maka berpuasalah, dan jika mau maka berbukalah.\""},"1293":{"ar":" أَخْبَرَنَا خَالِدُ بْنُ مَخْل��دٍ حَدَّثَنَا مَالِكٌ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ خَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَ الْفَتْحِ فَصَامَ وَصَامَ النَّاسُ حَتَّى بَلَغَ الْكَدِيدَ ثُمَّ أَفْطَرَ فَأَفْطَرَ النَّاسُ فَكَانُوا يَأْخُذُونَ بِالْأَحْدَثِ فَالْأَحْدَثِ مِنْ فِعْلِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Malik] dari [Az Zuhri] dari ['Ubaidullah bin Abdullah bin 'Utbah] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam keluar saat penaklukan Makkah dalam keadaan berpuasa, dan orang-orang pun berpuasa hingga sampai di daerah Kadid, kemudian beliau berbuka dan orang-orang pun berbuka. Mereka mengambil sesuatu yang terbaru, kemudian yang terbaru dari perbuatan Rasulullah shallallahu 'alaihi wasallam.\""},"1294":{"ar":" أَخْبَرَنَا هَاشِمُ بْنُ الْقَاسِمِ وَأَبُو الْوَلِيدِ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ الْأَنْصَارِيِّ قَالَ سَمِعْتُ مُحَمَّدَ بْنَ عَمْرِو بْنِ الْحَسَنِ يُحَدِّثُ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ أَنَّهُ ذَكَرَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ فِي سَفَرٍ فَرَأَى زِحَامًا وَرَجُلٌ قَدْ ظُلِّلَ عَلَيْهِ فَقَالَ مَا هَذَا قَالُوا هَذَا صَائِمٌ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ مِنْ الْبِرِّ الصَّوْمُ فِي السَّفَرِ","id":"Telah mengabarkan kepada kami [Hisyam bin Al Qasim] dan [Abu Al Walid] mereka berkata; telah menceritakan kepada kami [Syu'bah] dari [Muhammad bin 'Abdurrahman Al Anshari] ia berkata, aku mendengar [Muhammad bin 'Amru bin Al Hasan] menceritakan dari [Jabir bin Abdullah] ia menyebutkan, bahwa Nabi shallallahu 'alaihi wasallam ketika berada dalam sebuah perjalanan, beliau melihat kerumunan orang yang di antara mereka ada seorang laki-laki yang dipayungi. Kemudian beliau bertanya: \"Ada apa ini?\" Mereka menjawab, \"Orang ini sedang berpuasa! \" Lalu Nabi shallallahu 'alaihi wasallam bersabda: \"Bukan termasuk kebaikan berpuasa ketika dalam perjalanan.\""},"1295":{"ar":" أَخْبَرَنَا عُثْمَانُ بْنُ عُمَرَ حَدَّثَنَا يُونُسُ عَنْ الزُّهْرِيِّ عَنْ صَفْوَانَ بْنِ عَبْدِ اللَّهِ عَنْ أُمِّ الدَّرْدَاءِ عَنْ كَعْبِ بْنِ عَاصِمٍ الْأَشْعَرِيِّ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْسَ مِنْ الْبِرِّ الصِّيَامُ فِي السَّفَرِ","id":"Telah mengabarkan kepada kami [Utsman bin Umar] telah menceritakan kepada kami [Yunus] dari [Az Zuhri] dari [Shafwan bin Abdullah] dari [Ummu Ad Darda`] dari [Ka'b bin 'Ashim Al Asy'ari], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bukanlah termasuk dari kebaikan berpuasa ketika dalam perjalanan.\""},"1296":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ أَحْمَدَ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا الزُّهْرِيُّ عَنْ صَفْوَانَ بْنِ عَبْدِ اللَّهِ بْنِ صَفْوَانَ عَنْ أُمِّ الدَّرْدَاءِ عَنْ كَعْبِ بْنِ عَاصِمٍ الْأَشْعَرِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْسَ مِنْ الْبِرِّ الصِّيَامُ فِي السَّفَرِ","id":"Telah menceritakan kepada kami [Muhammad bin Ahmad] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Az Zuhri] dari [Shafwan bin Abdullah bin Shafwan] dari [Ummu Ad Darda`] dari [Ka'b bin 'Ashim Al Asy'ari] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Bukanlah termasuk dari kebaikan berpuasa ketika dalam perjalanan.\""},"1297":{"ar":" حَدَّثَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ يَحْيَى عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْمُهَاجِرِ عَنْ أَبِي أُمَيَّةَ الضَّمْرِيِّ قَالَ قَدِمْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ سَفَرٍ فَسَلَّمْتُ عَلَيْهِ فَلَمَّا ذَهَبْتُ لِأَخْرُجَ قَالَ انْتَظِرْ الْغَدَاءَ يَا أَبَا أُمَيَّةَ قَالَ فَقُلْتُ إِنِّي صَائِمٌ يَا نَبِيَّ اللَّهِ فَقَالَ تَعَالَ أُخْبِرْكَ عَنْ الْمُسَافِرِ إِنَّ اللَّهَ وَضَعَ عَنْهُ الصِّيَامَ وَنِصْفَ الصَّلَاةِ قَالَ أَبُو مُحَمَّد إِنْ شَاءَ صَامَ وَإِنْ شَاءَ أَفْطَرَ","id":"Telah menceritakan kepada kami [Abu Al Mughirah] telah menceritakan kepada kami [Al Auza'i] dari [Yahya] dari [Abu Qilabah] dari [Abu Al Muhajir] dari [Abu Umayyah Adl Dlamri] ia berkata, \"Aku menghadap Rasulullah shallallahu 'alaihi wasallam saat kembali dari suatu perjalanan, aku lalu memberi salam kepada beliau. Kemudian ketika aku akan keluar, beliau berkata: \"Wahai Abu Umayya, tunggulah hingga makan siang.\" Mu'awiyah berkata, \"Lalu aku menjawab, \"Wahai Nabi Allah, aku sedang berpuasa.\" Kemudian beliau bersabda: \"Kemarilah, aku kabarkan kepadamu mengenai orang yang bersafar. Sesungguhnya Allah telah menggugurkan darinya puasa dan setengah shalat.\" Abu Muhammad berkata, \"Jika mau ia boleh puasa dan jika mau ia boleh berbuka.\" "},"1298":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ الْمُقْرِئُ حَدَّثَنَا سَعِيدُ بْنُ أَبِي أَيُّوبَ حَدَّثَنِي يَزِيدُ بْنُ أَبِي حَبِيبٍ أَنَّ كُلَيْبَ بْنَ ذُهْلٍ الْحَضْرَمِيَّ أَخْبَرَهُ عَنْ عُبَيْدِ بْنِ جُبَيْرٍ قَالَ رَكِبْتُ مَعَ أَبِي بَصْرَةَ الْغِفَارِيِّ سَفِينَةً مِنْ الْفُسْطَاطِ فِي رَمَضَانَ فَدَفَعَ فَقَرَّبَ غَدَاءَهُ ثُمَّ قَالَ اقْتَرِبْ فَقُلْتُ أَلَسْتَ تَرَى الْبُيُوتَ فَقَالَ أَبُو بَصْرَةَ أَرَغِبْتَ عَنْ سُنَّةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abdullah bin Yazid Al Muqri`] telah menceritakan kepada kami [Sa'id bin Abu Ayyub] telah menceritakan kepadaku [Yazid bin Abu Habib] bahwa [Kulaib bin Dzuhail Al Hadlrami] mengabarkan kepadanya dari ['Ubaid bin Jubair] berkata, \"Pada bulan Ramadan aku bersama Abu Bashrah Al Ghifari menaiki kapal dari Fusthath. Kemudian ia menyodorkan makan siangnya dan berkata, \"Mendekatlah.\" Aku lalu bertanya, \"Bukanlah engkau telah melihat rumah-rumah?\" [Abu Bashrah] balik bertanya, \"Apakah engkau membenci sunnah Rasulullah shallallahu 'alaihi wasallam?\""},"1299":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ قَالَ سَمِعْتُ عُمَارَةَ بْنَ عُمَيْرٍ يُحَدِّثُ عَنْ ابْنِ الْمُطَوِّسِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَفْطَرَ يَوْمًا مِنْ شَهْرِ رَمَضَانَ مِنْ غَيْرِ رُخْصَةٍ وَلَا مَرَضٍ فَلَنْ يَقْضِيَهُ صِيَامُ الدَّهْرِ كُلِّهِ وَلَوْ صَامَ الدَّهْرَ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Sufyan] dari [Habib bin Abu Tsabit] ia berkata, aku mendengar ['Umarah bin 'Umair] menceritakan dari [Ibnu Al Muthawwis] dari [Ayahnya] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa berbuka satu hari pada bulan Ramadan bukan karena rukhshah atau sakit, maka tidak akan dapat diganti oleh puasa satu tahun penuh, walaupun ia berpuasa setahun penuh.\""},"1300":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ أَخْبَرَنِي حَبِيبُ بْنُ أَبِي ثَابِتٍ قَالَ سَمِعْتُ عُمَارَةَ بْنَ عُمَيْرٍ يُحَدِّثُ عَنْ أَبِي الْمُطَوِّسِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَفْطَرَ يَوْمًا مِنْ رَمَضَانَ مِنْ غَيْرِ رُخْصَةٍ رَخَّصَهُ اللَّهُ لَهُ لَمْ يَقْضِ عَنْهُ صِيَامُ الدَّهْرِ","id":"Telah mengabarkan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah] telah mengabarkan kepadaku [Habib bin Abu Tsabit] ia berkata, aku mendengar ['Umarah bin 'Umair] menceritakan dari [Abu Al Muthawwif] dari [Ayahnya] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa berbuka satu hari pada bulan Ramadan bukan karena keringanan yang Allah berikan, maka tidak akan dapat diganti oleh puasa satu tahun.\""},"1301":{"ar":" حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ الْهَاشِمِيُّ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ الزُّهْرِيِّ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ قَالَ أَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلٌ فَقَالَ هَلَكْتُ فَقَالَ وَمَا أَهْلَكَكَ قَالَ وَاقَعْتُ امْرَأَتِي فِي شَهْرِ رَمَضَانَ قَالَ فَأَعْتِقْ رَقَبَةً قَالَ لَيْسَ عِنْدِي قَالَ فَصُمْ شَهْرَيْنِ مُتَتَابِعَيْنِ قَالَ لَا أَسْتَطِيعُ قَالَ فَأَطْعِمْ سِتِّينَ مِسْكِينًا قَالَ لَا أَجِدُ قَالَ فَأُتِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعَرَقٍ فِيهِ تَمْرٌ فَقَالَ أَيْنَ السَّائِلُ تَصَدَّقْ بِهَذَا فَقَالَ أَعَلَى أَفْقَرَ مِنْ أَهْلِي يَا رَسُولَ اللَّهِ فَوَاللَّهِ مَا بَيْنَ لَابَتَيْهَا أَهْلُ بَيْتٍ أَفْقَرَ مِنَّا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَنْتُمْ إِذًا وَضَحِكَ حَتَّى بَدَتْ أَنْيَابُهُ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ الْمَجِيدِ حَدَّثَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ أَنَّ رَجُلًا أَفْطَرَ فِي رَمَضَانَ فَذَكَرَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Sulaiman bin Daud Al Hasyimi] telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Az Zuhri] dari [Humaid bin 'Abdurrahman] dari [Abu Hurairah] ia berkata, \"Seseorang telah datang kepada Rasulullah shallallahu 'alaihi wasallam dan berkata, \"Aku telah binasa! \" Beliau bertanya: \"Apa yang membinasakanmu?\" Ia menjawab, \"Aku telah menggauli isteriku pada bulan Ramadan.\" Beliau bersabda: \"Bebaskanlah seorang budak.\" Ia berkata, \"Aku tidak memiliki budak.\" Beliau bersabda: \"Berpuasalah dua bulan berturut-turut.\" Ia berkata, \"Aku tidak mampu.\" Beliau bersabda: \"Berilah makan enam puluh orang miskin.\" Ia berkata, \"Aku tidak mendapatkan makanan.\" Abu Hurairah berkata, \"Kemudian Rasulullah shallallahu 'alaihi wasallam diberi keranjang yang berisi kurma, kemudian beliau berkata: \"Dimanakah orang yang bertanya? Bersedekahlah dengan ini.\" Orang itu lalu berkata, \"Wahai Rasulullah, apakah aku harus bersedekah kepada orang yang lebih fakir dari keluargaku? Demi Allah, tidak ada di antara dua daerah yang berbatu hitam (yaitu Madinah) yang lebih fakir daripada kami.\" Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kalau begitu untuk kalian saja.\" Beliau berikan kurma tersebut sambil tertawa hingga nampak gigi-gigi taringnya.\" Telah menceritakan kepada kami ['Ubaidullah bin Abdul Majid] telah menceritakan kepada kami [Malik] dari [Ibnu Syihab] dari [Humaid bin 'Abdurrahman] dari [Abu Hurairah], bahwa seorang laki-laki telah berbuka pada bulan Ramadan.... kemudian ia menyebutkan hadits tersebut.\" "},"1302":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا يَحْيَى يَعْنِي ابْنَ سَعِيدٍ الْأَنْصَارِيَّ أَنَّ عَبْدَ الرَّحْمَنِ بْنَ الْقَاسِمِ أَخْبَرَهُ أَنَّ مُحَمَّدَ بْنَ جَعْفَرِ بْنِ الزُّبَيْرِ أَخْبَرَهُ أَنَّهُ سَمِعَ عَبَّادَ بْنَ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ أَنَّهُ سَمِعَ عَائِشَةَ تَقُولُ إِنَّ رَجُلًا سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّهُ احْتَرَقَ فَسَأَلَهُ مَا لَهُ فَقَالَ أَصَابَ أَهْلَهُ فِي رَمَضَانَ فَأُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِكْتَلٍ يُدْعَى الْعَرَقَ فِيهِ تَمْرٌ فَقَالَ أَيْنَ الْمُحْتَرِقُ فَقَامَ الرَّجُلُ فَقَالَ تَصَدَّقْ بِهَذَا","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah menceritakan kepada kami [Yahya] -yaitu Ibnu Sa'id Al Anshari- bahwa ['Abdurrahman bin Al Qasim] mengabarkan kepadanya, bahwa [Muhammad bin Ja'far bin Az Zubair] mengabarkan kepadanya, bahwa ia mendengar ['Abbad bin Abdullah bin Az Zubair] bahwa ia mendengar [Aisyah] berkata, \"Seorang laki-laki bertanya kepada Nabi shallallahu 'alaihi wasallam, ia mengatakan bahwa ia berhak untuk dibakar (dalam neraka). Maka beliau pun menanyakan hal itu kepadanya, lalu laki-laki tersebut mengabarkan bahwa ia telah menggauli isterinya di bulan Ramadan. Kemudian Nabi shallallahu 'alaihi wasallam diberi satu keranjang yang disebut 'Araq berisi kurma. Beliau lalu berkata, \"Dimanakah orang yang melakukan sesuatu yang mengakibatkan dirinya dibakar di Neraka?\" Kemudian seorang laki-laki berdiri, beliau lalu bersabda: \"Bersedekahlah dengan ini.\""},"1303":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا شَرِيكٌ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ لِامْرَأَةٍ لَا تَصُومِي إِلَّا بِإِذْنِهِ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Syarik] dari [Al A'masy] dari [Abu Shalih] dari [Abu Sa'id Al Khudri] dari Nabi shallallahu 'alaihi wasallam, bahwa beliau berkata kepada seorang wanita: \"Janganlah berpuasa kecuali dengan seizinnya.\""},"1304":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ أَحْمَدَ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَصُومُ الْمَرْأَةُ يَوْمًا تَطَوُّعًا فِي غَيْرِ رَمَضَانَ وَزَوْجُهَا شَاهِدٌ إِلَّا بِإِذْنِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Ahmad] telah menceritakan kepada kami [Sufyan] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Seorang wanita tidak boleh berpuasa sunnah selain Ramadan meskipun sehari, tanpa seizin suaminya jika ia ada di rumah.\" "},"1305":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ أَبِي الزِّنَادِ عَنْ مُوسَى بْنِ أَبِي عُثْمَانَ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَصُومُ الْمَرْأَةُ يَوْمًا وَزَوْجُهَا شَاهِدٌ إِلَّا بِإِذْنِهِ مَعْنَاهُ قَالَ فِي النُّذُورِ تَفِي بِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Sufyan] dari [Abu Az Zinad] dari [Musa bin Abu Utsman] dari [Ayahnya] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak boleh seorang wanita berpuasa satu hari sementara suaminya hadir kecuali dengan seizinnya.\" Maknanya, beliau bersabda mengenai puasa nadzar yang ia tunaikan.\""},"1306":{"ar":" حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُقَبِّلُ وَهُوَ صَائِمٌ فَقَالَ عُرْوَةُ أَمَا إِنَّهَا لَا تَدْعُو إِلَى خَيْرٍ","id":"Telah menceritakan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Hammad bin Salamah] dari [Hisyam bin 'Urwah] dari [Ayahnya] dari [Aisyah], bahwa Rasulullah shallallahu 'alaihi wasallam pernah mencium saat sedang berpuasa.\" 'Urwah berkata, \"Adapun ia tidak menyeru kepada kebaikan.\" "},"1307":{"ar":" أَخْبَرَنَا سَعْدُ بْنُ حَفْصٍ الطَّلْحِيُّ حَدَّثَنَا شَيْبَانُ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ عُمَرَ بْنِ عَبْدِ الْعَزِيزِ عَنْ عُرْوَةَ عَنْ عَائِشَةَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُقَبِّلُهَا وَهُوَ صَائِمٌ","id":"Telah mengabarkan kepada kami [Sa'd bin Hafsh Ath Thalhi] telah menceritakan kepada kami [Syaiban] dari [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Umar bin Abdul Aziz] dari ['Urwah] dari [Aisyah], bahwa Nabi shallallahu 'alaihi wasallam pernah menciumnya dalam keadaan berpuasa.\""},"1308":{"ar":" حَدَّثَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا لَيْثُ بْنُ سَعْدٍ عَنْ بُكَيْرِ بْنِ عَبْدِ اللَّهِ بْنِ الْأَشَجِّ عَنْ عَبْدِ الْمَلِكِ بْنِ سَعِيدٍ الْأَنْصَارِيِّ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ عَنْ عُمَرَ بْنِ الْخَطَّابِ قَالَ هَشِشْتُ فَقَبَّلْتُ وَأَنَا صَائِمٌ فَجِئْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ إِنِّي صَنَعْتُ الْيَوْمَ أَمْرًا عَظِيمًا قَبَّلْتُ وَأَنَا صَائِمٌ قَالَ أَرَأَيْتَ لَوْ مَضْمَضْتَ مِنْ الْمَاءِ قُلْتُ إِذًا لَا يَضِيرُ قَالَ فَفِيمَ","id":"Telah menceritakan kepada kami [Abu Al Walid Ath Thayalisi] telah menceritakan kepada kami [Laits bin Sa'd] dari [Bukair bin Abdullah bin Al Asyaj] dari [Abdul Malik bin Sa'id Al Anshari] dari [Jabir bin Abdullah] dari [Umar bin Al Khathab] ia berkata, \"Aku merasa berhasrat, lalu aku mencium dalam keadaan berpuasa. Kemudian aku datang menemui Rasulullah shallallahu 'alaihi wasallam dan berkata, \"Sungguh, hari ini aku telah melakukan perkara yang besar, aku telah mencium dalam keadaan berpuasa! \" Beliau bersabda: \"Bagaimana pendapatmu apabila engkau berkumur-kumur dengan air?\" Aku menjawab, \"Jika demikian hal itu tidak merusak puasa?\" Beliau balik bertanya, \"Dalam hal apa! '"},"1309":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ حَدَّثَنَا عَبْدُ الْمَلِكِ يَعْنِي ابْنَ جُرَيْجٍ قَالَ أَخْبَرَنِي ابْنُ شِهَابٍ أَنَّ أَبَا بَكْرٍ أَخْبَرَهُ عَنْ أَبِيهِ أَنَّ أُمَّ سَلَمَةَ وَعَائِشَةَ أَخْبَرتَاهُ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصْبِحُ جُنُبًا مِنْ أَهْلِهِ ثُمَّ يَصُومُ","id":"Telah mengabarkan kepada kami [Abu 'Ashim] telah menceritakan kepada kami [Abdul Malik] -yaitu Ibnu Juraij- ia berkata, telah mengabarkan kepadaku [Ibnu Syihab] bahwa [Abu Bakr] telah mengabarkan kepadanya dari [Ayahnya] bahwa [Ummu Salamah] dan [Aisyah] telah mengabarkan kepadanya, bahwa Nabi shallallahu 'alaihi wasallam pernah pada pagi hari dalam keadaan junub karena berhubungan dengan isterinya, kemudian beliau berpuasa.\" "},"1310":{"ar":" أَخْبَرَنَا عُثْمَانُ بْنُ مُحَمَّدٍ حَدَّثَنَا جَرِيرٌ عَنْ هِشَامِ بْنِ حَسَّانَ عَنْ ابْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ نَسِيَ وَهُوَ صَائِمٌ فَأَكَلَ أَوْ شَرِبَ فَلْيُتِمَّ صَوْمَهُ فَإِنَّمَا أَطْعَمَهُ اللَّهُ وَسَقَاهُ","id":"Telah mengabarkan kepada kami [Utsman bin Muhammad] telah menceritakan kepada kami [Jarir] dari [Hisyam bin Hassan] dari [Ibnu Sirin] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa makan dan minum karena lupa hendaklah ia sempurnakan puasanya, sesungguhnya ia diberi makan dan minum Allah.\""},"1311":{"ar":" أَخْبَرَنَا أَبُو جَعْفَرٍ مُحَمَّدُ بْنُ مِهْرَانَ الْجَمَّالُ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ عَنْ الْحَارِثِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي ذُبَابٍ عَنْ عَمِّهِ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَكَلَ أَحَدُكُمْ أَوْ شَرِبَ نَاسِيًا وَهُوَ صَائِمٌ ثُمَّ ذَكَرَ فَلْيُتِمَّ صِيَامَهُ فَإِنَّمَا أَطْعَمَهُ اللَّهُ وَسَقَاهُ قَالَ أَبُو مُحَمَّد أَهْلُ الْحِجَازِ يَقُولُونَ يَقْضِي وَأَنَا أَقُولُ لَا يَقْضِي","id":"Telah mengabarkan kepada kami [Abu Ja'far Muhammad bin Mihran Al Jammal] telah menceritakan kepada kami [Hatim bin Isma'il] dari [Al Harits bin 'Abdurrahman bin Abu Dzubab] dari [Pamannya] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian makan atau minum karena lupa, lalu teringat bahwa ia sedang, maka hendaknya ia menyempurnakan puasanya, karena sesungguhnya Allah telah memberinya makan dan minum.\" Abu Muhammad berkata, \"Penduduk Hijaz berpendapat bahwa ia harus mengganti puasanya, sedangkan aku tidak mengatakan ia harus mengganti puasanya.\" "},"1312":{"ar":" أَخْبَرَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ حَدَّثَنِي أَبِي حَدَّثَنِي حُسَيْنٌ الْمُعَلِّمُ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ الْأَوْزَاعِيِّ عَنْ يَعِيشَ بْنِ الْوَلِيدِ عَنْ أَبِيهِ عَنْ مَعْدَانَ بْنِ أَبِي طَلْحَةَ عَنْ أَبِي الدَّرْدَاءِ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَاءَ فَأَفْطَرَ قَالَ فَلَقِيتُ ثَوْبَانَ بِمَسْجِدِ دِمَشْقَ فَذَكَرْتُ ذَلِكَ لَهُ فَقَالَ صَدَقَ أَنَا صَبَبْتُ لَهُ الْوَضُوءَ قَالَ عَبْد اللَّهِ إِذَا اسْتَقَاءَ","id":"Telah mengabarkan kepada kami [Abdush Shamad bin Abdul Warits] telah menceritakan kepadaku [Ayahku] telah menceritakan kepadaku [Husain Al Mu'allim] dari [Yahya bin Abu Katsir] dari [Al Auza'i] dari [Ya'isy bin Al Walid] dari [Ayahnya] dari [Ma'dan bin Abu Thalhah] dari [Abu Ad Darda`], bahwa Nabi shallallahu 'alaihi wasallam pernah muntah kemudian beliau berbuka.\" Ma'dan bin Abu Thalhah berkata, \"Kemudian aku menemui [Tsauban] di Masjid Damaskus dan aku sebutkan hal tersebut kepadanya, lalu ia berkata, \"Ia benar. Bahkan aku yang menuangkan tempat wudlu beliau.\" Abdullah berkata, \"Hal itu jika sengaja muntah.\""},"1313":{"ar":" أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ هِشَامِ بْنِ حَسَّانَ عَنْ ابْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا ذَرَعَ الصَّائِمَ الْقَيْءُ وَهُوَ لَا يُرِيدُهُ فَلَا قَضَاءَ عَلَيْهِ وَإِذَا اسْتَقَاءَ فَعَلَيْهِ الْقَضَاءُ قَالَ عِيسَى زَعَمَ أَهْلُ الْبَصْرَةِ أَنَّ هِشَامًا أَوْهَمَ فِيهِ فَمَوْضِعُ الْخِلَافِ هَا هُنَا","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] telah menceritakan kepada kami [Isa bin Yunus] dari [Hisyam bin Hassan] dari [Ibnu Sirin] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila orang yang berpuasa terpaksa untuk muntah sementara ia tidak menginginkannya maka ia tidak wajib mengganti puasanya. Tetapi jika ia sengaja muntah, maka ia wajib untuk mengganti puasanya.\" Isa berkata, \"Penduduk Bashrah mengaku bahwa Hisyam telah salah dalam hadits tersebut, maka di sinilah letak perselisihan itu.\" "},"1314":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا عَاصِمٌ عَنْ عَبْدِ اللَّهِ بْنِ يَزِيدَ عَنْ أَبِي الْأَشْعَثِ الصَّنْعَانِيِّ عَنْ أَبِي أَسْمَاءَ الرَّحَبِيِّ عَنْ شَدَّادِ بْنِ أَوْسٍ قَالَ مَرَرْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي ثَمَانِ عَشْرَةَ خَلَتْ مِنْ رَمَضَانَ فَأَبْصَرَ رَجُلًا يَحْتَجِمُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفْطَرَ الْحَاجِمُ وَالْمَحْجُومُ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami ['Ashim] dari [Abdullah bin Yazid] dari [Abu Al Asy'ats Ash Shan'ani] dari [Abu Asma Ar Rahbi] dari [Syaddad bin Aus] ia berkata, \"Aku bersama Rasulullah shallallahu 'alaihi wasallam telah melalui delapan belas hari dari bulan Ramadan, kemudian beliau melihat seorang laki-laki berbekam. Maka beliau pun bersabda: \"Orang yang membekam dan yang dibekam telah batal puasanya.\""},"1315":{"ar":" أَخْبَرَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى عَنْ أَبِي قِلَابَةَ أَنَّ أَبَا أَسْمَاءَ الرَّحَبِيَّ حَدَّثَهُ أَنَّ ثَوْبَانَ حَدَّثَهُ قَالَ بَيْنَمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمْشِي بِالْبَقِيعِ فَإِذَا رَجُلٌ يَحْتَجِمُ فَقَالَ أَفْطَرَ الْحَاجِمُ وَالْمَحْجُومُ قَالَ أَبُو مُحَمَّد أَنَا أَتَّقِي الْحِجَامَةَ فِي الصَّوْمِ فِي رَمَضَانَ","id":"Telah mengabarkan kepada kami [Wahb bin Jarir] telah menceritakan kepada kami [Hisyam] dari [Yahya] dari [Abu Qilabah] bahwa [Abu Asma` Ar Rahabi] telah menceritakan kepadanya, bahwa [Tsauban] menceritakan kepadanya, ia berkata, \"Ketika Rasulullah shallallahu 'alaihi wasallam sedang berjalan di Baqi', tiba-tiba ada seorang laki-laki yang sedang berbekam. Beliau lalu bersabda: \"Orang yang membekam dan yang dibekam telah batal puasanya.\" Abu Muhammad berkata, \"Saat berpuasa di bulan Ramadan aku menghindari untuk berpekam.\" "},"1316":{"ar":" أَخْبَرَنَا عَمْرُو بْنُ عَوْنٍ حَدَّثَنَا خَالِدُ بْنُ عَبْدِ اللَّهِ عَنْ وَاصِلٍ مَوْلَى أَبِي عُيَيْنَةَ عَنْ بَشَّارِ بْنِ أَبِي سَيْفٍ عَنْ الْوَلِيدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عِيَاضِ بْنِ غُطَيْفٍ عَنْ أَبِي عُبَيْدَةَ بْنِ الْجَرَّاحِ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الصَّوْمُ جُنَّةٌ مَا لَمْ يَخْرِقْهَا قَالَ أَبُو مُحَمَّد يَعْنِي بِالْغِيبَةِ","id":"Telah mengabarkan kepada kami ['Amru bin 'Aun] telah menceritakan kepada kami [Khalid bin Abdullah] dari [Washil] mantan budak Abu 'Uyainah, dari [Basysyar bin Abu Saif] dari [Al Walid bin 'Abdurrahman] dari ['Iyadl bin Ghuthaif] dari [Abu 'Ubaidah bin Al Jarrah] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Puasa adalah tameng selama ia belum melubanginya.\" Abu Muhammad berkata, \"Yaitu dengan menggunjing orang lain.\" "},"1317":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ النُّعْمَانِ أَبُو النُّعْمَانِ الْأَنْصَارِيُّ حَدَّثَنِي أَبِي عَنْ جَدِّي وَكَانَ جَدِّي قَدْ أُتِيَ بِهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَسَحَ عَلَى رَأْسِهِ وَقَالَ لَا تَكْتَحِلْ بِالنَّهَارِ وَأَنْتَ صَائِمٌ اكْتَحِلْ لَيْلًا بِالْإِثْمِدِ فَإِنَّهُ يَجْلُو الْبَصَرَ وَيُنْبِتُ الشَّعَرَ قَالَ أَبُو مُحَمَّد لَا أَرَى بِالْكُحْلِ بَأْسًا","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami ['Abdurrahman bin An Nu'man Abu An Nu'man Al Anshari] telah menceritakan kepadaku [Ayahku] dari [Kakekku], bahwa ia pernah dibawa ke hadapan Nabi shallallahu 'alaihi wasallam, kemudian beliau mengusap kepalanya dan berkata: \"Janganlah engkau memakai celak pada siang hari sementara engkau berpuasa, bercelaklah pada malam hari menggunakan Itsmid (sejenis tumbuhan), karena sesungguhnya Itsmid dapat mencerahkan pandangan, dan menumbuhkan rambut.\""},"1318":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنِي بَكْرٌ هُوَ ابْنُ مُضَرَ عَنْ عَمْرِو بْنِ الْحَارِثِ عَنْ يَزِيدَ مَوْلَى سَلَمَةَ بْنِ الْأَكْوَعِ عَنْ سَلَمَةَ بْنِ الْأَكْوَعِ أَنَّهُ قَالَ لَمَّا نَزَلَتْ هَذِهِ الْآيَةُ { وَعَلَى الَّذِينَ يُطِيقُونَهُ فِدْيَةٌ طَعَامُ مِسْكِينٍ } قَالَ كَانَ مَنْ أَرَادَ أَنْ يُفْطِرَ وَيَفْتَدِيَ فَعَلَ حَتَّى نَزَلَتْ الْآيَةُ الَّتِي بَعْدَهَا فَنَسَخَتْهَا","id":"Telah mengabarkan kepada kami [Abdullah bin Shalih] telah menceritakan kepadaku [Bakr] -yaitu Ibnu Mudlar- dari ['Amru bin Al Harits] dari [Yazid] mantan budak Salamah bin Al Akwa', bahwa ia berkata ketika turun ayat ini: '(Dan wajib bagi orang-orang yang berat menjalankannya (jika mereka tidak berpuasa) membayar fidyah, (yaitu): memberi makan seorang miskin) ' (Qs.?Al Baqarah: 184).) [Salamah] berkata, \"Dahulu orang yang hendak berbuka dan membayar fidyah maka boleh ia melakukannya, hingga turunlah ayat yang setelahnya dan menghapus hukum ayat tersebut.\" "},"1319":{"ar":" أَخْبَرَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ هَارُونَ ابْنِ ابْنَةِ أُمِّ هَانِئٍ أَوْ ابْنِ ابْنِ أُمِّ هَانِئٍ عَنْ أُمِّ هَانِئٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَيْهَا وَهِيَ صَائِمَةٌ فَأُتِيَ بِإِنَاءٍ فَشَرِبَ ثُمَّ نَاوَلَهَا فَشَرِبَتْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ كَانَ قَضَاءَ رَمَضَانَ فَصُومِي يَوْمًا آخَرَ وَإِنْ كَانَ تَطَوُّعًا فَإِنْ شِئْتِ فَاقْضِيهِ وَإِنْ شِئْتِ فَلَا تَقْضِيهِ","id":"Telah mengabarkan kepada kami [An Nu'man] telah menceritakan kepada kami [Hammad bin Salamah] dari [Simak bin Harb] dari [Harun] anak laki-laki puteri Ummu Hani`, atau anak laki-laki putera Ummu Hani`, dari [Ummu Hani`], bahwa Nabi shallallahu 'alaihi wasallam menemuinya sementara ia dalam keadaan berpuasa. Beliau kemudian diberi suguhan susu lalu meminumnya, beliau kemudian memberikan susu tersebut kepada Ummu Hani` lalu ia meminumnya. Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika untuk mengganti puasa Ramadan maka berpuasalah pada hari yang lain, tetapi jika puasa sunnah; jika engkau mau silahkan engkau menggantinya, jika tidak maka tidak perlu engkau menggantinya.\" "},"1320":{"ar":" حَدَّثَنَا عُثْمَانُ بْنُ مُحَمَّدٍ حَدَّثَنَا جَرِيرٌ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ عَنْ أُمِّ هَانِئٍ قَالَتْ لَمَّا كَانَ يَوْمُ فَتْحِ مَكَّةَ جَاءَتْ فَاطِمَةُ فَجَلَسَتْ عَنْ يَسَارِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأُمُّ هَانِئٍ عَنْ يَمِينِهِ قَالَتْ فَجَاءَتْ الْوَلِيدَةُ بِإِنَاءٍ فِيهِ شَرَابٌ فَنَاوَلَتْهُ فَشَرِبَ مِنْهُ ثُمَّ نَاوَلَهُ أُمَّ هَانِئٍ فَشَرِبَتْ مِنْهُ ثُمَّ قَالَتْ يَا رَسُولَ اللَّهِ لَقَدْ أَفْطَرْتُ وَكُنْتُ صَائِمَةً فَقَالَ لَهَا أَكُنْتِ تَقْضِينَ شَيْئًا قَالَتْ لَا قَالَ فَلَا يَضُرُّكِ إِنْ كَانَ تَطَوُّعًا قَالَ أَبُو مُحَمَّد أَقُولُ بِهِ إِنْ شَاءَ قَضَى وَإِنْ شَاءَ لَمْ يَقْضِ","id":"Telah menceritakan kepada kami [Utsman bin Muhammad] telah menceritakan kepada kami [Jarir] dari [Yazid bin Abu Ziyad] dari [Abdullah bin Al Harits] dari [Ummu Hani`] ia berkata, \"Pada saat hari penaklukan Makkah Fatimah datang dan duduk di sebelah kiri Rasulullah shallallahu 'alaihi wasallam, sedangkan Ummu Hani` di sebelah kanan beliau. Ummu Hani` berkata, \"Kemudian seorang budak wanita datang membawa bejana berisi minuman, lalu ia memberikannya kepada beliau hingga beliau minum sebagian darinya. Kemudian beliau memberikannya kepada Ummu Hani' dan ia pun meminumnya kemudian berkata, \"Wahai Rasulullah, aku telah berbuka, tadinya aku berpuasa.\" Maka beliau berkata kepadanya: \"Apakah engkau mengqadla` sebagian puasa?\" Ummu Hani` menjawab, \"Tidak.\" Beliau lalu bersabda: \"Apabila hanya puasa sunah maka tidak merugikanmu.\" Abu Muhammad berkata, \"Aku berpendapat dengannya, jika mau ia boleh menggantinya, jika tidak maka tidak perlu menggantinya.\" "},"1321":{"ar":" أَخْبَرَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا دُعِيَ أَحَدُكُمْ إِلَى طَعَامٍ وَهُوَ صَائِمٌ فَلْيَقُلْ إِنِّي صَائِمٌ","id":"Telah mengabarkan kepada [Hajjaj bin Minhal] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang di antara kalian diundang untuk makan padahal ia sedang berpuasa, maka hendaknya ia mengatakan 'aku sedang berpuasa'.\""},"1322":{"ar":" أَخْبَرَنَا هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا شُعْبَةُ عَنْ حَبِيبٍ الْأَنْصَارِيِّ قَالَ سَمِعْتُ مَوْلَاةً لَنَا يُقَالُ لَهَا لَيْلَى تُحَدِّثُ عَنْ جَدَّتِهَا أُمِّ عُمَارَةَ بِنْتِ كَعْبٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَيْهَا فَدَعَتْ لَهُ بِطَعَامٍ فَقَالَ لَهَا كُلِي فَقَالَتْ إِنِّي صَائِمَةٌ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الصَّائِمَ إِذَا أُكِلَ عِنْدَهُ صَلَّتْ عَلَيْهِ الْمَلَائِكَةُ حَتَّى يَفْرُغُوا وَرُبَّمَا قَالَ حَتَّى يَقْضُوا أَكْلَهُمْ","id":"Telah mengabarkan kepada kami [Hasyim bin Al Qasim] telah menceritakan kepada kami [Syu'bah] dari [Habib Al Anshari] ia berkata, aku mendengar mantan budak wanita kami yang bernama [Laila] menceritakan dari neneknya [Ummu 'Umarah binti Ka'b], bahwa Nabi shallallahu 'alaihi wasallam datang menemuinya, lalu ia minta agar disuguhkan makanan untuk beliau. Maka beliau berkata kepadanya: \"Makanlah.\" Lalu Ummu Umarah berkata, \"Aku sedang berpuasa.\" Kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya orang yang berpuasa apabila di sisinya terdapat makanan yang disantap maka Malaikat bershalawat kepadanya hingga mereka selesai makan.\" Dan terkadang beliau mengatakan: \"Hingga mereka menghabiskan makan mereka.\""},"1323":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ إِسْرَائِيلَ عَنْ مَنْصُورٍ عَنْ سَالِمٍ عَنْ أَبِي سَلَمَةَ عَنْ أُمِّ سَلَمَةَ قَالَتْ مَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَامَ شَهْرًا تَامًّا إِلَّا شَعْبَانَ فَإِنَّهُ كَانَ يَصِلُهُ بِرَمَضَانَ لِيَكُونَا شَهْرَيْنِ مُتَتَابِعَيْنِ وَكَانَ يَصُومُ مِنْ الشَّهْرِ حَتَّى نَقُولَ لَا يُفْطِرُ وَيُفْطِرُ حَتَّى نَقُولَ لَا يَصُومُ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Musa] dari [Israil] dari [Manshur] dari [Salim] dari [Abu Salamah] dari [Ummu Salamah] ia berkata, \"Aku tidak melihat Rasulullah shallallahu 'alaihi wasallam melakukan puasa penuh satu bulan kecuali pada bulan Sya'ban. Karena beliau menyambungnya dengan bulan Ramadan agar menjadi dua bulan berturut-turut. Kadang beliau berpuasa (dalam sebagian bulan) hingga kami berkata 'Beliau tidak pernah berbuka'. Dan kadang beliau berbuka hingga kami berkata 'Beliau tidak pernah berpuasa'.\" "},"1324":{"ar":" أَخْبَرَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ حَدَّثَنَا عَبْدُ الرَّحْمَنِ الْحَنَفِيُّ يُقَالُ عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ عَنْ الْعَلَاءِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا كَانَ النِّصْفُ مِنْ شَعْبَانَ فَأَمْسِكُوا عَنْ الصَّوْمِ أَخْبَرَنَا الْحَكَمُ بْنُ الْمُبَارَكِ عَنْ عَبْدِ الْعَزِيزِ بْنِ مُحَمَّدٍ عَنْ الْعَلَاءِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ نَحْوَ هَذَا","id":"Telah mengabarkan kepada kami [Abdush Shamad bin Abdul Warits] telah menceritakan kepada kami ['Abdurrahman Al Hanafi] -biasa juga dipnaggil dengan nama 'Abdurrahman bin Ibrahim-, dari [Al 'Ala`] dari [Ayahnya] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila telah berlalu setengah dari bulan Sya'ban, maka tahanlah dari berpuasa.\" Telah mengabarkan kepada kami [Al Hakam bin Al Mubarak] dari [Abdul Aziz bin Muhammad] dari [Al 'Ala`] dari [Ayahnya] dari [Abu Hurairah] seperti ini.\" "},"1325":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا الْجُرَيْرِيُّ عَنْ أَبِي الْعَلَاءِ بْنِ الشِّخِّيرِ عَنْ مُطَرِّفٍ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِرَجُلٍ هَلْ صُمْتَ مِنْ سَرَرِ هَذَا الشَّهْرِ فَقَالَ لَا قَالَ فَإِذَا أَفْطَرْتَ مِنْ رَمَضَانَ فَصُمْ يَوْمَيْنِ قَالَ أَبُو مُحَمَّد سَرَرُهُ آخِرُهُ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Al Jurairi] dari [Abu Al 'Ala` bin Asy Syikhkhir] dari [Mutharrif] dari [Imran bin Hushain], bahwa Rasulullah shallallahu 'alaihi wasallam pernah bertanya kepada seorang laki-laki: \"Apakah engkau berpuasa pada akhir bulan ini?\" Orang tersebut menjawab, \"Tidak.\" Beliau lantas bersabda: \"Apabila engkau berbuka pada bulan Ramadan maka berpuasalah dua hari.\" Abu Muhammad berkata, \"Sararahu artinya akhirnya.\" "},"1326":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَ مَا صَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَهْرًا كَامِلًا غَيْرَ رَمَضَانَ وَإِنْ كَانَ لَيَصُومُ إِذَا صَامَ حَتَّى يَقُولَ الْقَائِلُ لَا وَاللَّهِ لَا يُفْطِرُ وَيُفْطِرُ إِذَا أَفْطَرَ حَتَّى يَقُولَ الْقَائِلُ لَا وَاللَّهِ لَا يَصُومُ","id":"Telah mengabarkan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Abu 'Awanah] dari [Abu Bisyr] dari [Sa'id bin Jubair] dari [Ibnu Abbas] ia berkata, \"Nabi shallallahu 'alaihi wasallam tidak pernah berpuasa satu bulan penuh selain Ramadan, jika beliau berpuasa maka orang akan mengatakan 'Tidak! Demi Allah, beliau tidak pernah berbuka', padahal beliau berbuka. Dan jika beliau berbuka, maka orang akan mengatakan 'Tidak! Demi Allah, beliau tidak pernah berpuasa'.\" "},"1327":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ الْأَوْزَاعِيِّ عَنْ قَتَادَةَ عَنْ مُطَرِّفِ بْنِ عَبْدِ اللَّهِ بْنِ الشِّخِّيرِ عَنْ أَبِيهِ قَالَ ذُكِرَ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلٌ يَصُومُ الدَّهْرَ فَقَالَ لَا صَامَ وَلَا أَفْطَرَ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Al Auza'i] dari [Qatadah] dari [Mutharrif bin Abdullah bin Asy Syikhkhir] dari [Ayahnya] ia berkata, \"Disebut-sebut di sisi Rasulullah shallallahu 'alaihi wasallam seorang laki-laki yang melakukan puasa setahun. Lalu beliau bersabda: \"Ia tidak berpuasa juga tidak berbuka.\""},"1328":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا الْعَوَّامُ بْنُ حَوْشَبٍ قَالَ حَدَّثَنَا سُلَيْمَانُ بْنُ أَبِي سُلَيْمَانَ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُ أَوْصَانِي خَلِيلِي بِثَلَاثٍ لَسْتُ بِتَارِكِهِنَّ أَنْ لَا أَنَامَ إِلَّا عَلَى وِتْرٍ وَأَنْ أَصُومَ ثَلَاثَةَ أَيَّامٍ مِنْ كُلِّ شَهْرٍ وَأَنْ لَا أَدَعَ رَكْعَتَيْ الضُّحَى أَخْبَرَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ عَبَّاسٍ الْجُرَيْرِيِّ عَنْ أَبِي عُثْمَانَ عَنْ أَبِي هُرَيْرَةَ نَحْوَهُ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah menceritakan kepada kami [Al 'Awwam bin Hausyab] ia berkata, telah menceritakan kepada kami [Sulaiman bin Abu Sulaiman] bahwa ia mendengar [Abu Hurairah] berkata, \"Aku diberi wasiat oleh kekasihku dengan tiga hal yang tidak aku tinggalkan; tidak tidur kecuali setelah shalat witir, puasa tiga hari pada setiap bulan, dan tidak meninggalkan dua rakaat dluha.\" Telah mengabarkan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah] dari [Ibnu Abbas Al Jurairi] dari [Abu Utsman] dari [Abu Hurairah] seperti itu.\""},"1329":{"ar":" حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ مُعَاوِيَةَ بْنِ قُرَّةَ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ صِيَامُ الْبِيضِ صِيَامُ الدَّهْرِ وَإِفْطَارُهُ","id":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah] dari [Mu'awiyah bin Qurrah] dari [Ayahnya] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Puasa pada hari Bidl (hari ke tiga belas, empat belas, lima belas) adalah puasa setahun dan berbuka setahun.\" "},"1330":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ عَنْ عَبْدِ الْحَمِيدِ بْنِ جُبَيْرِ بْنِ شَيْبَةَ عَنْ مُحَمَّدِ بْنِ عَبَّادِ بْنِ جَعْفَرٍ قَالَ قُلْتُ لِجَابِرٍ أَنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ صَوْمِ يَوْمِ الْجُمُعَةِ قَالَ نَعَمْ وَرَبِّ هَذَا الْبَيْتِ","id":"Telah mengabarkan kepada kami [Abu 'Ashim] dari [Ibnu Juraij] dari [Abdul Hamid bin Jubair bin Syu'bah] dari [Muhammad bin 'Abbad bin Ja'far] ia berkata, aku bertanya kepada [Jabir], \"Apakah Nabi shallallahu 'alaihi wasallam melarang dari berpuasa pada hari Jum'at? Ia menjawab, \"Ya. Demi Tuhan pemilik Ka'bah ini.\" "},"1331":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ ثَوْرٍ عَنْ خَالِدِ بْنِ مَعْدَانَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ بُسْرٍ عَنْ أُخْتِهِ يُقَالُ لَهَا الصَّمَّاءُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَصُومُوا يَوْمَ السَّبْتِ إِلَّا فِيمَا افْتُرِضَ عَلَيْكُمْ وَإِنْ لَمْ يَجِدْ أَحَدُكُمْ إِلَّا كَذَا أَوْ لِحَاءَ شَجَرَةٍ فَلْيَمْضَغْهُ","id":"Telah mengabarkan kepada kami [Abu 'Ashim] dari [Tsaur] dari [Khalid bin Ma'dan] telah menceritakan kepadaku [Abdullah bin Busr] dari saudara perempuannya yang dipanggil [Ash Shamma`], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian berpuasa pada hari Sabtu kecuali yang diwajibkan atas kalian, dan apabila salah seorang dari kalian tidak mendapatkan kecuali ini, atau kulit pohon maka hendaknya ia mengunyahnya.\""},"1332":{"ar":" حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى عَنْ عُمَرَ بْنِ الْحَكَمِ بْنِ ثَوْبَانَ أَنَّ مَوْلَى قُدَامَةَ بْنِ مَظْعُونٍ حَدَّثَهُ أَنَّ مَوْلَى أُسَامَةَ حَدَّثَهُ قَالَ كَانَ أُسَامَةُ يَرْكَبُ إِلَى مَالٍ لَهُ بِوَادِي الْقُرَى فَيَصُومُ الِاثْنَيْنِ وَالْخَمِيسَ فِي الطَّرِيقِ فَقُلْتُ لَهُ لِمَ تَصُومُ الِاثْنَيْنِ وَالْخَمِيسَ فِي السَّفَرِ وَقَدْ كَبِرْتَ وَضَعُفْتَ أَوْ رَقِقْتَ فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَصُومُ الِاثْنَيْنِ وَالْخَمِيسَ وَقَالَ إِنَّ أَعْمَالَ النَّاسِ تُعْرَضُ يَوْمَ الِاثْنَيْنِ وَالْخَمِيسِ","id":"Telah menceritakan kepada kami [Wahb bin Jarir] telah menceritakan kepada kami [Hisyam] dari [Yahya] dari [Umar bin Al Hakam bin Tsauban] bahwa [Mantan budak Qudamah bin Mazh'un] menceritakan kepadanya, bahwa [Mantan budak Usamah] menceritakan kepadanya, ia berkata, \" [Usamah] pernah menunggangi kendaraan menuju harta kekayaannya di daerah Wadi Al Qura, kemudian dalam perjalanan ia berpuasa senin dan kamis, lalu aku katakan kepadanya, \"Kenapa engkau berpuasa senin dan kamis, padahal engkau telah tua dan lemah?\" Ia lantas menjawab, \"Rasulullah shallallahu 'alaihi wasallam biasa puasa senin dan kamis. Beliau bersabda: \"Sesungguhnya amalan manusia ditampakkan (kepada Allah) pada hari senin dan kamis.\" "},"1333":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ مُحَمَّدِ بْنِ رِفَاعَةَ عَنْ سُهَيْلٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَصُومُ يَوْمَ الِاثْنَيْنِ وَالْخَمِيسِ فَسَأَلْتُهُ فَقَالَ إِنَّ الْأَعْمَالَ تُعْرَضُ يَوْمَ الِاثْنَيْنِ وَالْخَمِيسِ","id":"Telah mengabarkan kepada kami [Abu 'Ashim] dari [Muhammad bin Rifa'ah dari [Suhail] dari [Ayahnya] dari [Abu Hurairah], bahwa Nabi shallallahu 'alaihi wasallam dahulu berpuasa senin dan kamis, maka aku pun menanyakannya kepada beliau, beliau lalu menjawab: \"Sesungguhnya amalan ditampakkan (dilaporkan) pada hari senin dan kamis.\""},"1334":{"ar":" أَخْبَرَنَا عُثْمَانُ بْنُ مُحَمَّدٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَمْرٍو يَعْنِي ابْنَ دِينَارٍ عَنْ عَمْرِو بْنِ أَوْسٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو يَرْفَعُهُ قَالَ أَحَبُّ الصِّيَامِ إِلَى اللَّهِ عَزَّ وَجَلَّ صِيَامُ دَاوُدَ كَانَ يَصُومُ يَوْمًا وَيُفْطِرُ يَوْمًا وَأَحَبُّ الصَّلَاةِ إِلَى اللَّهِ عَزَّ وَجَلَّ صَلَاةُ دَاوُدَ كَانَ يُصَلِّي نِصْفًا وَيَنَامُ ثُلُثًا وَيُسَبِّحُ سُدُسًا قَالَ أَبُو مُحَمَّد هَذَا اللَّفْظُ الْأَخِيرُ غَلَطٌ أَوْ خَطَأٌ إِنَّمَا هُوَ أَنَّهُ كَانَ يَنَامُ نِصْفَ اللَّيْلِ وَيُصَلِّي ثُلُثَهُ وَيُسَبِّحُ تَسْبِيحَةً","id":"Telah mengabarkan kepada kami [Utsman bin Muhammad] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari ['Amru] -yaitu Ibnu Dinar- dari ['Amru bin Aus] dari [Abdullah bin 'Amru] dan ia memarfu'kannya, ia berkata, \"Puasa yang paling Allah 'azza wajalla senangi adalah puasa Daud, ia berpuasa satu hari dan berbuka satu hari. Dan shalat yang paling Allah 'azza wajalla senangi adalah shalat Daud, ia shalat di pertengahan malam, tidur di sepertiganya, dan bertasbih di seperenamnya.\" Abu Muhammad berkata, \"Lafazh yang terakhir ini keliru, yang benar adalah, 'tidur di pertengahan malam dan shalat di sepertiganya dan bertasbih'.\" "},"1335":{"ar":" حَدَّثَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ شُعْبَةَ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ قَزَعَةَ مَوْلَى زِيَادٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا صَوْمَ يَوْمَيْنِ يَوْمَ الْفِطْرِ وَيَوْمَ النَّحْرِ","id":"Telah menceritakan kepada kami [Sa'id bin 'Amir] dari [Syu'bah] dari [Abdul Malik bin 'Umair] dari [Qaza'ah] mantan budak Ziyad, dari [Abu Sa'id Al Khudri] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak boleh berpuasa pada dua hari; Idul Fithri dan hari raya kurban.\""},"1336":{"ar":" حَدَّثَنَا نُعَيْمُ بْنُ حَمَّادٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ حَدَّثَنَا صَفْوَانُ وسَعْدُ بْنُ سَعِيدٍ عَنْ عُمَرَ بْنِ ثَابِتٍ عَنْ أَبِي أَيُّوبَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ صَامَ رَمَضَانَ ثُمَّ أَتْبَعَهُ سِتَّةً مِنْ شَوَّالٍ فَذَلِكَ صِيَامُ الدَّهْرِ","id":"Telah menceritakan kepada kami [Nu'aim bin Hammad] telah menceritakan kepada kami [Abdul Aziz bin Muhammad] telah menceritakan kepada kami [Shafwan] dan [Sa'd bin Sa'id] dari [Umar bin Tsabit] dari [Abu Ayyub] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa berpuasa bulan Ramadan kemudian mengiringinya dengan enam hari di bulan Syawal, maka yang demikian itu seperti puasa satu tahun.\""},"1337":{"ar":" حَدَّثَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ حَدَّثَنَا يَحْيَى بْنُ الْحَارِثِ الذِّمَارِيُّ عَنْ أَبِي أَسْمَاءَ الرَّحَبِيِّ عَنْ ثَوْبَانَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ صِيَامُ شَهْرٍ بِعَشَرَةِ أَشْهُرٍ وَسِتَّةِ أَيَّامٍ بَعْدَهُنَّ بِشَهْرَيْنِ فَذَلِكَ تَمَامُ سَنَةٍ يَعْنِي شَهْرَ رَمَضَانَ وَسِتَّةَ أَيَّامٍ بَعْدَهُ","id":"Telah menceritakan kepada kami [Yahya bin Hassan] telah menceritakan kepada kami [Yahya bin Hamzah] telah menceritakan kepada kami [Yahya bin Al Harits Adz Dzimari] dari [Abu Asma`Ar Rahabi] dari [Tsauban], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berpuasa satu bulan sama dengan sepuluh bulan, dan enam hari setelahnya sama dengan dua bulan, maka dengan begitu sempurnalah satu tahun. Yaitu puasa bulan Ramadan dan enam hari setelahnya.\""},"1338":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ سَعِيدٍ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ إِسْحَقَ عَنْ النُّعْمَانِ بْنِ سَعْدٍ قَالَ جَاءَ رَجُلٌ إِلَى عَلِيٍّ فَسَأَلَهُ عَنْ شَهْرٍ يَصُومُهُ فَقَالَ لَهُ عَلِيٌّ مَا سَأَلَنِي أَحَدٌ عَنْ هَذَا بَعْدَ إِذْ سَمِعْتُ رَجُلًا سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّ شَهْرٍ يَصُومُهُ مِنْ السَّنَةِ فَأَمَرَهُ بِصِيَامِ الْمُحَرَّمِ وَقَالَ إِنَّ فِيهِ يَوْمًا تَابَ اللَّهُ عَلَى قَوْمٍ وَيَتُوبُ فِيهِ عَلَى قَوْمٍ","id":"Telah menceritakan kepada kami [Muhammad bin Sa'id] telah menceritakan kepada kami [Muhammad bin Fudlail] dari ['Abdurrahman bin Ishaq] dari [An Nu'man bin Sa'd] berkata, \"Seorang laki-laki datang menemui Ali dan bertanya kepadanya tentang bulan untuk ia berpuasa. Lalu [Ali] berkata kepadanya, \"Tidak ada seorangpun yang bertanya kepadaku tentang itu hingga saat ini, semenjak aku mendengar seorang laki-laki bertanya kepada Nabi shallallahu 'alaihi wasallam, yaitu bulan apakah yang sebaiknya ia berpuasa dalam setahun?\" Kemudian beliau memerintahkan dia agar berpuasa pada bulan Muharram. Beliau bersabda: \"Sungguh, pada bulan ini ada satu hari dimana Allah telah memberikan taubat kepada suatu kaum dan akan memberi taubat kepada suatu kaum.\""},"1339":{"ar":" أَخْبَرَنَا زَيْدُ بْنُ عَوْفٍ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ مُحَمَّدِ بْنِ الْمُنْتَشِرِ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَفْضَلُ الصِّيَامِ بَعْدَ شَهْرِ رَمَضَانَ شَهْرُ اللَّهِ الَّذِي تَدْعُونَهُ الْمُحَرَّمَ","id":"Telah mengabarkan kepada kami [Zaid bin 'Auf] telah menceritakan kepada kami [Abu 'Awanah] dari [Abdul Malik bin 'Umair] dari [Muhammad bin Al Muntasyir] dari [Humaid bin 'Abdurrahman] dari [Abu Hurairah], bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik puasa setelah Ramadan adalah puasa pada bulan Allah yang kalian sebut Muharram.\""},"1340":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ وَأَخْبَرَنَا يَحْيَى بْنُ حَسَّانَ أَخْبَرَنَا أَبُو عَوَانَةَ عَنْ أَبِي بِشْرٍ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ الْحِمْيَرِيِّ عَنْ أَبِي هُرَيْرَةَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَفْضَلُ الصِّيَامِ بَعْدَ شَهْرِ رَمَضَانَ الْمُحَرَّمُ","id":"Telah menceritakan kepada kami [Abu Nu'aim], dan telah mengabarkan kepada kami [Yahya bin Hassan] telah mengabarkan kepada kami [Abu 'Awanah] dari [Abu Bisyr] dari [Humaid bin 'Abdurrahman Al Humairi] dari [Abu Hurairah], bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik puasa setelah Ramadan adalah puasa Muharram.\""},"1341":{"ar":" أَخْبَرَنَا سَهْلُ بْنُ حَمَّادٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ أَنَّهُ قَالَ قَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةَ وَالْيَهُودُ يَصُومُونَ يَوْمَ عَاشُورَاءَ فَسَأَلَهُمْ فَقَالُوا هَذَا الْيَوْمُ الَّذِي ظَهَرَ فِيهِ مُوسَى عَلَى فِرْعَوْنَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْتُمْ أَوْلَى بِمُوسَى فَصُومُوهُ","id":"Telah mengabarkan kepada kami [Sahl bin Hammad] telah menceritakan kepada kami [Syu'bah] dari [Abu Bisyr] dari [Sa'id bin Jubair] dari [Ibnu Abbas], bahwa ia berkata, \"Rasulullah shallallahu 'alaihi wasallam datang ke Madinah sementara orang-orang Yahudi sedang berpuasa 'Asyura`, maka beliau pun bertanya kepada mereka. Mereka lalu menjawab, \"Ini adalah hari kemenangan Musa atas Fir'aun.\" Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kalian lebih berhak terhadap Musa, maka berpuasalah pada hari tersebut.\""},"1342":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ الْمَجِيدِ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَصُومُ يَوْمَ عَاشُورَاءَ وَيَأْمُرُنَا بِصِيَامِهِ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Abdul Majid] telah menceritakan kepada kami [Ibnu Abu Dzi` b] dari [Az Zuhri] dari ['Urwah] dari [Aisyah], bahwa Nabi shallallahu 'alaihi wasallam berpuasa pada hari 'Asyura` dan memerintahkan kami agar berpuasa pada bulan tersebut.\" "},"1343":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ يَزِيدَ بْنِ أَبِي عُبَيْدٍ عَنْ سَلَمَةَ بْنِ الْأَكْوَعِ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ يَوْمَ عَاشُورَاءَ رَجُلًا مِنْ أَسْلَمَ إِنَّ الْيَوْمَ يَوْمُ عَاشُورَاءَ فَمَنْ كَانَ أَكَلَ أَوْ شَرِبَ فَلْيُتِمَّ بَقِيَّةَ يَوْمِهِ وَمَنْ لَمْ يَكُنْ أَكَلَ أَوْ شَرِبَ فَلْيَصُمْهُ","id":"Telah mengabarkan kepada kami [Abu 'Ashim] dari [Yazid bin Abu 'Ubaid] dari [Salamah bin Al Akwa'], bahwa Nabi shallallahu 'alaihi wasallam pada hari 'Asyura` mengutus seorang laki-laki dari Bani Aslam agar mengatakan, \"Sesungguhnya hari ini adalah hari 'Asyura`, barangsiapa telah makan atau minum hendaknya ia menyempurnakan seluruh harinya, dan barangsiapa belum makan atau minum hendaknya ia berpuasa.\" "},"1344":{"ar":" أَخْبَرَنَا يَعْلَى عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذَا يَوْمُ عَاشُورَاءَ كَانَتْ قُرَيْشٌ تَصُومُهُ فِي الْجَاهِلِيَّةِ فَمَنْ أَحَبَّ مِنْكُمْ أَنْ يَصُومَهُ فَلْيَصُمْهُ وَمَنْ أَحَبَّ مِنْكُمْ أَنْ يَتْرُكَهُ فَلْيَتْرُكْهُ وَكَانَ ابْنُ عُمَرَ لَا يَصُومُهُ إِلَّا أَنْ يُوَافِقَ صِيَامَهُ","id":"Telah mengabarkan kepada kami [Ya'la] dari [Muhammad bin Ishaq] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ini adalah hari 'Asyura`, pada masa Jahiliyah orang-orang Quraisy berpuasa pada hari tersebut. Maka barangsiapa di antara kalian ingin berpuasa hendaklah ia berpuasa, dan barangsiapa di antara kalian ingin meninggalkan puasa hendaklah ia meninggalkannya.\" Dan Ibnu Umar tidak berpuasa pada hari itu kecuali jika bertepatan dengan puasa yang biasa ia lakukan.\""},"1345":{"ar":" أَخْبَرَنَا عَبْدُ الْوَهَّابِ بْنُ سَعِيدٍ حَدَّثَنَا شُعَيْبُ بْنُ إِسْحَقَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْ كَانَ يَوْمُ عَاشُورَاءَ يَوْمًا تَصُومُهُ قُرَيْشٌ فِي الْجَاهِلِيَّةِ فَلَمَّا قَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةَ صَامَهُ وَأَمَرَ بِصِيَامِهِ حَتَّى إِذَا فُرِضَ رَمَضَانُ كَانَ رَمَضَانُ هُوَ الْفَرِيضَةُ وَتُرِكَ يَوْمُ عَاشُورَاءَ فَمَنْ شَاءَ صَامَهُ وَمَنْ شَاءَ تَرَكَهُ","id":"Telah mengabarkan kepada kami [Abdul Wahhab bin Sa'id] telah menceritakan kepada kami [Syu'aib bin Ishaq] dari [Hisyam bin 'Urwah] dari [Ayahnya] dari [Aisyah] ia berkata, \"Hari 'Asyura` adalah hari yang orang-orang Quraisy dahulu berpuasa padanya pada masa Jahiliyah. Kemudian tatkala Rasulullah shallallahu 'alaihi wasallam datang ke Madinah beliau berpuasa pada hari itu dan memerintahkan agar berpuasa padanya, hingga ketika telah diwajibkan puasa Ramadan maka puasa Ramadan adalah yang diwajibkan dan puasa 'Asyura` ditinggalkan. Barangsiapa berkehendak ia boleh puasa dan barangsiapa tidak berkehendak ia boleh meninggalkannya.\" "},"1346":{"ar":" أَخْبَرَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا مُوسَى بْنُ عُلَيٍّ عَنْ أَبِيهِ عَنْ عُقْبَةَ بْنِ عَامِرٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمُ عَرَفَةَ وَأَيَّامُ التَّشْرِيقِ عِيدُنَا أَهْلَ الْإِسْلَامِ وَهِيَ أَيَّامُ أَكْلٍ وَشُرْبٍ","id":"Telah mengabarkan kepada kami [Wahb bin Jarir] telah menceritakan kepada kami [Musa bin Ali] dari [Ayahnya] dari ['Uqbah bin 'Amir] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hari 'Arafah dan hari-hari Tasyriq adalah hari raya kita sebagai orang Islam, dan hari-hari tersebut adalah hari makan dan minum.\""},"1347":{"ar":" أَخْبَرَنَا الْمُعَلَّى بْنُ أَسَدٍ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ حَدَّثَنَا ابْنُ أَبِي نَجِيحٍ عَنْ أَبِيهِ قَالَ سُئِلَ ابْنُ عُمَرَ عَنْ صَوْمِ يَوْمِ عَرَفَةَ فَقَالَ حَجَجْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ يَصُمْهُ وَحَجَجْتُ مَعَ أَبِي بَكْرٍ فَلَمْ يَصُمْهُ وَحَجَجْتُ مَعَ عُمَرَ فَلَمْ يَصُمْهُ وَحَجَجْتُ مَعَ عُثْمَانَ فَلَمْ يَصُمْهُ وَأَنَا لَا أَصُومُهُ وَلَا آمُرُ بِهِ وَلَا أَنْهَى عَنْهُ","id":"Telah mengabarkan kepada kami [Al Mu'alla bin Asad] telah menceritakan kepada kami [Isma'il bin 'Ulaiyyah] telah menceritakan kepada kami [Ibnu Abu Najih] dari [Ayahnya] ia berkata, \" [Ibnu Umar] ditanya mengenai puasa pada hari 'Arafah, lalu ia menjawab, \"Aku pernah berhaji bersama Nabi shallallahu 'alaihi wasallam dan beliau tidak berpuasa padanya, aku berhaji bersama Abu Bakar dan ia tidak berpuasa padanya, aku berhaji bersama Umar dan ia tidak berpuasa padanya, aku berhaji bersama Utsman dan ia tidak berpuasa padanya dan aku tidak berpuasa, tidak memerintahkannya dan tidak melarang darinya.\""},"1348":{"ar":" حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ نَافِعِ بْنِ جُبَيْرٍ عَنْ بِشْرِ بْنِ سُحَيْمٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَهُ أَوْ أَمَرَ رَجُلًا يُنَادِي أَيَّامَ التَّشْرِيقِ أَنَّهُ لَا يَدْخُلُ الْجَنَّةَ إِلَّا مُؤْمِنٌ وَهِيَ أَيَّامُ أَكْلٍ وَشُرْبٍ","id":"Telah menceritakan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Hammad bin Zaid] dari ['Amru bin Dinar] dari [Nafi' bin Jubair] dari [Bisyr bin Suhaim] bahwa Rasulullah shallallahu 'alaihi wasallam memerintahkan kepadanya atau memerintahkan seorang laki-laki agar mengumumkan pada hari-hari tasyriq, bahwa tidak akan masuk Surga kecuali orang mukmin, dan hari-hari tersebut adalah hari-hari makan dan minum.\" "},"1349":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنِي اللَّيْثُ حَدَّثَنِي يَزِيدُ بْنُ عَبْدِ اللَّهِ عَنْ أَبِي مُرَّةَ مَوْلَى عَقِيلٍ أَنَّهُ دَخَلَ هُوَ وَعَبْدُ اللَّهِ بْنُ عَمْرٍو عَلَى عَمْرِو بْنِ الْعَاصِ وَذَلِكَ الْغَدَ أَوْ بَعْدَ الْغَدِ مِنْ يَوْمِ الْأَضْحَى فَقَرَّبَ إِلَيْهِمْ عَمْرٌو طَعَامًا فَقَالَ عَبْدُ اللَّهِ إِنِّي صَائِمٌ فَقَالَ عَمْرٌو أَفْطِرْ فَإِنَّ هَذِهِ الْأَيَّامَ الَّتِي كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْمُرُنَا بِفِطْرِهَا وَيَنْهَانَا عَنْ صِيَامِهَا فَأَفْطَرَ عَبْدُ اللَّهِ فَأَكَلَ وَأَكَلْتُ مَعَهُ","id":"Telah menceritakan kepada kami [Abdullah bin Shalih] telah menceritakan kepadaku [Al Laits] telah menceritakan kepadaku [Yazid bin Abdullah] dari [Abu Murrah] bekas budak 'Aqil, bahwa ia bersama Abdullah bin 'Amru menemui 'Amru bin Al 'Ash sehari setelah hari 'Idul Adhha atau setelahnya, kemudian 'Amru menghidangkan makanan kepada mereka berdua, Abdullah berkata; \"Aku sedang berpuasa.\" ['Amru] menimpali; \"Berbukalah, karena sesungguhnya Rasulullah shallallahu 'alaihi wasallam memerintahkan kami agar berbuka pada hari ini, dan melarang kami berpuasa.\" Lalu Abdullah berbuka dan makan, akupun makan bersamanya.\""},"1350":{"ar":" حَدَّثَنَا سَهْلُ بْنُ حَمَّادٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ أَنَّ امْرَأَةً نَذَرَتْ أَنْ تَحُجَّ فَمَاتَتْ فَجَاءَ أَخُوهَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَهُ عَنْ ذَلِكَ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ كَانَ عَلَيْهَا دَيْنٌ أَكُنْتَ قَاضِيَهُ قَالَ نَعَمْ قَالَ فَاقْضُوا اللَّهَ اللَّهُ أَحَقُّ بِالْوَفَاءِ قَالَ فَصَامَ عَنْهَا","id":"Telah menceritakan kepada kami [Sahl bin Hammad] telah menceritakan kepada kami [Syu'bah] dari [Abu Bisyr] dari [Sa'id bin Jubair] dari [Ibnu Abbas] bahwa seorang wanita bernadzar untuk melakukan haji, ternyata ia meninggal (sebelum menunaikan haji). Lalu saudara laki-lakinya datang menemui Rasulullah shallallahu 'alaihi wasallam dan bertanya kepada beliau mengenai hal tersebut. Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya: \"Seandainya ia memiliki hutang, apakah engkau akan membayarnya?\" Orang tersebut menjawab; \"Ya.\" Beliau bersabda: \"Tunaikanlah (haji tersebut) untuk Allah, Sebab Allah lebih berhak untuk ditunaikan hutangNya.\" Ibnu Abbas berkata; \"Kemudian orang tersebut berpuasa.\""},"1351":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا مُحَمَّدُ بْنُ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خُلُوفُ فَمِ الصَّائِمِ أَطْيَبُ عِنْدَ اللَّهِ مِنْ رِيحِ الْمِسْكِ وَلِلصَّائِمِ فَرْحَتَانِ فَرْحَةٌ عِنْدَ فِطْرِهِ وَفَرْحَةٌ يَوْمَ الْقِيَامَةِ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengkhabarkan kepada kami [Muhammad bin 'Amr] dari [Abu Salamah] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bau mulut orang yang berpuasa lebih wangi di sisi Allah daripada wangi minyak kasturi. Dan orang yang berpuasa memiliki dua kebahagiaan, kebahagiaan ketika berbuka dan kebahagiaan (ketika berjumpa Allah) pada Hari Kiamat.\""},"1352":{"ar":" أَخْبَرَنَا يَزِيدُ أَخْبَرَنَا مُحَمَّدُ بْنُ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُ تَعَالَى كُلُّ عَمَلِ ابْنِ آدَمَ لَهُ فَالْحَسَنَةُ بِعَشْرِ أَمْثَالِهَا إِلَى سَبْعِ مِائَةِ ضِعْفٍ إِلَّا الصِّيَامَ هُوَ لِي وَأَنَا أَجْزِي بِهِ إِنَّهُ يَتْرُكُ الطَّعَامَ وَشَهْوَتَهُ مِنْ أَجْلِي وَيَتْرُكُ الشَّرَابَ وَشَهْوَتَهُ مِنْ أَجْلِي فَهُوَ لِي وَأَنَا أَجْزِي بِهِ","id":"Telah mengabarkan kepada kami [Yazid] telah mengabarkan kepada kami [Muhammad bin 'Amr] dari [Abu Salamah] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah Ta'ala berfirman: \"Setiap perbuatan anak Adam adalah untuknya, satu kebaikan akan mendapatkan pahala sepuluh kebaikan yang sama, hingga tujuh ratus kali lipat, kecuali puasa, puasa itu untukKu dan Aku yang akan balasanya, sebab ia meninggalkan makan dan syahwatnya karena diriKu, dan meninggalkan minum serta syahwatnya untuk diriKu. Puasa adalah untukKu dan Aku yang akan memberi balasan.\""},"1353":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصَّوْمُ جُنَّةٌ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Puasa adalah perisai.\""},"1354":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا هِشَامٌ الدَّسْتَوَائِيُّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَنَسِ بْنِ مَالِكٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا أَفْطَرَ عِنْدَ أُنَاسٍ قَالَ أَفْطَرَ عِنْدَكُمْ الصَّائِمُونَ وَأَكَلَ طَعَامَكُمْ الْأَبْرَارُ وَتَنَزَّلَتْ عَلَيْكُمْ الْمَلَائِكَةُ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Hisyam Ad Dastawa`i] dari [Yahya bin Abu Katsir] dari [Anas bin Malik] bahwa apabila Nabi shallallahu 'alaihi wasallam berbuka bersama beberapa orang, beliau bersabda: \"Orang-orang yang berpuasa telah berbuka puasa di sisi kalian, dan orang-orang yang baik telah makan makanan kalian, serta para Malaikat telah turun kepada kalian.\""},"1355":{"ar":" حَدَّثَنَا سَعِيدُ بْنُ الرَّبِيعِ حَدَّثَنَا شُعْبَةُ عَنْ سُلَيْمَانَ قَالَ سَمِعْتُ مُسْلِمًا الْبَطِينَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا الْعَمَلُ فِي أَيَّامٍ أَفْضَلَ مِنْ الْعَمَلِ فِي عَشْرِ ذِي الْحِجَّةِ قِيلَ وَلَا الْجِهَادُ فِي سَبِيلِ اللَّهِ قَالَ وَلَا الْجِهَادُ فِي سَبِيلِ اللَّهِ إِلَّا رَجُلٌ خَرَجَ بِنَفْسِهِ وَمَالِهِ ثُمَّ لَمْ يَرْجِعْ بِشَيْءٍ","id":"Telah menceritakan kepada kami [Sa'id bin Ar Rabi'] telah menceritakan kepada kami [Syu'bah] dari [Sulaiman], ia berkata; saya mendengar [Muslim Al Bathin] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak ada amalan yang lebih utama daripada amalan pada hari sepuluh Dzul Hijjah.\" Beliau ditanya; \"Tidak pula berjihad di jalan Allah?\" Beliau menjawab: \"Tidak pula berjihad di jalan Allah, kecuali seseorang yang keluar dengan jiwa dan hartanya, kemudian ia tidak kembali dengan sesuatupun.\""},"1356":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا أَصْبَغُ عَنْ الْقَاسِمِ بْنِ أَبِي أَيُّوبَ عَنْ سَعِيدٍ عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا مِنْ عَمَلٍ أَزْكَى عِنْدَ اللَّهِ عَزَّ وَجَلَّ وَلَا أَعْظَمَ أَجْرًا مِنْ خَيْرٍ تَعْمَلُهُ فِي عَشْرِ الْأَضْحَى قِيلَ وَلَا الْجِهَادُ فِي سَبِيلِ اللَّهِ عَزَّ وَجَلَّ قَالَ وَلَا الْجِهَادُ فِي سَبِيلِ اللَّهِ عَزَّ وَجَلَّ إِلَّا رَجُلٌ خَرَجَ بِنَفْسِهِ وَمَالِهِ فَلَمْ يَرْجِعْ مِنْ ذَلِكَ بِشَيْءٍ قَالَ وَكَانَ سَعِيدُ بْنُ جُبَيْرٍ إِذَا دَخَلَ أَيَّامُ الْعَشْرِ اجْتَهَدَ اجْتِهَادًا شَدِيدًا حَتَّى مَا يَكَادُ يَقْدِرُ عَلَيْهِ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Ashbagh] dari [Al Qasim bin Abu Ayyub] dari [Sa'id] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak ada amalan yang lebih suci di sisi Allah 'azza wajalla, dan tidak pula lebih besar pahalanya daripada kebaikan yang engkau lakukan pada tanggal sepuluh hari Adhha (Dzul Hijjah).\" Beliau ditanya; \"Tidak pula berjihad di jalan Allah 'azza wajalla?\" Beliau menjawab: \"Tidak pula berjihad di jalan Allah 'azza wajalla, kecuali seseorang yang keluar dengan jiwa dan hartanya, kemudian tidak kembali dengan sesuatupun.\" Perawi berkata; Apabila Sa'id bin Jubair memasuki tanggal sepuluh (bulan Dzul Hijjah), ia akan lebih semangat lagi hingga hampir saja ia tidak sanggup untuk mengamalkannya.\""},"1357":{"ar":" حَدَّثَنَا أَبُو الرَّبِيعِ الزَّهْرَانِيُّ حَدَّثَنَا إِسْمَعِيلُ بْنُ جَعْفَرٍ حَدَّثَنَا أَبُو سُهَيْلٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا جَاءَ رَمَضَانُ فُتِحَتْ أَبْوَابُ السَّمَاءِ وَغُلِّقَتْ أَبْوَابُ النَّارِ وَصُفِّدَتْ الشَّيَاطِينُ","id":"Telah menceritakan kepada kami [Abu Ar Rabi' Az Zahrani] telah menceritakan kepada kami [Isma'il bin Ja'far] telah menceritakan kepada kami [Abu Suhail] dari [Ayahnya] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila datang Bulan Ramadhan, maka pintu-pintu langit dibuka, dan pintu-pintu Neraka ditutup, serta syetan-syetan pun dibelenggu.\""},"1358":{"ar":" حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَامَ رَمَضَانَ إِيمَانًا وَاحْتِسَابًا غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ وَمَنْ قَامَ لَيْلَةَ الْقَدْرِ غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ","id":"Telah mengceritakan kepada kami [Wahb bin Jarir] telah menceritakan kepada kami [Hisyam] dari [Yahya bin Abu Katsir] dari [Abu Salamah bin Abdurrahman] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Barang siapa melakukan shalat malam pada bulan Ramadhan karena iman dan mengharap pahala, maka dosa-dosanya yang telah lalu akan diampuni, dan barangsiapa melakukan shalat pada malam lailatul qadar, maka dosa-dosanya yang telah lalu akan diamuni.\""},"1359":{"ar":" حَدَّثَنَا زَكَرِيَّا بْنُ عَدِيٍّ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ عَنْ دَاوُدَ بْنِ أَبِي هِنْدٍ عَنْ الْوَلِيدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ أَبِي ذَرٍّ قَالَ صُمْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَهْرَ رَمَضَانَ قَالَ فَلَمْ يَقُمْ بِنَا مِنْ الشَّهْرِ شَيْئًا حَتَّى بَقِيَ سَبْعٌ قَالَ فَقَامَ بِنَا حَتَّى ذَهَبَ ثُلُثُ اللَّيْلِ قَالَ فَلَمَّا كَانَتْ السَّادِسَةُ لَمْ يَقُمْ بِنَا فَلَمَّا كَانَتْ الْخَامِسَةُ قَامَ بِنَا حَتَّى ذَهَبَ شَطْرُ اللَّيْلِ الْآخِرُ قُلْنَا يَا رَسُولَ اللَّهِ لَوْ نَفَّلْتَنَا بَقِيَّةَ هَذِهِ اللَّيْلَةِ فَقَالَ إِنَّ الرَّجُلَ إِذَا قَامَ مَعَ الْإِمَامِ حَتَّى يَنْصَرِفَ مِنْ صَلَاتِهِ حُسِبَ لَهُ قِيَامُ لَيْلَتِهِ فَلَمَّا كَانَتْ الرَّابِعَةُ لَمْ يَقُمْ بِنَا فَلَمَّا كَانَتْ الثَّالِثَةُ جَمَعَ أَهْلَهُ وَنِسَاءَهُ وَالنَّاسَ فَقَامَ بِنَا حَتَّى خَشِينَا أَنْ يَفُوتَنَا الْفَلَاحُ قُلْنَا وَمَا الْفَلَاحُ قَالَ السُّحُورُ قَالَ ثُمَّ لَمْ يَقُمْ بِنَا بَقِيَّةَ الشَّهْرِ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ سُفْيَانَ عَنْ دَاوُدَ عَنْ الْوَلِيدِ بْنِ عَبْدِ الرَّحْمَنِ الْجُرَشِيِّ عَنْ جُبَيْرِ بْنِ نُفَيْرٍ الْحَضْرَمِيِّ عَنْ أَبِي ذَرٍّ نَحْوَهُ","id":"Telah menceritakan kepada kami [Zakariya bin 'Adi] telah menceritakan kepada kami [Yazid bin Zurai'] dari [Daud bin Abu Hindun] dari [Al Walid bin Abdurrahman] dari [Jubair bin Nufair] dari [Abu Dzar], ia berkata; kami pernah berpuasa bersama Rasulullah shallallahu 'alaihi wasallam pada bulan Ramadhan namun beliau tidak melakukan shalat malam bersama kami pada bulan tersebut hingga tinggal tujuh hari. Abu Dzar melanjutkan; \"Kemudian beliau melakukan shalat malam bersama kami sampai berlalu sepertiga malam.\" Abu Dzar melanjutkan; \"Tatkala malam keenam (yaitu malam ke dua puluh empat dari awal Ramadhan), beliau tidak melakukan shalat malam bersama kami, dan tatkala malam kelima (yaitu malam ke dua puluh lima dari awal Ramadhan) beliau melakukan shalat malam bersama kami hingga berlalu setengah malam terakhir. Kami bertanya; \"Wahai Rasulullah, seandainya anda tambahkan shalat sunah bagi kami pada sisa malam ini, maka itu lebih baik bagi kami.\" Beliau bersabda: \"Sesungguhnya apabila seseorang melakukan shalat bersama imam hingga selesai, maka akan dihitung baginya semalam suntuk untuk shalat malam.\" Tatkala malam ke empat yaitu malam ke dua puluh enam dari awal Ramadhan, beliau tidak melalukan shalat malam bersama kami, dan ketika malam ke tiga (yaitu hari ke dua puluh tujuh dari awal Ramadhan), beliau mengumpulkan keluarga dan para isterinya serta para wanita, setelah itu beliau melakukan shalat bersama kami hingga kami khawatir tertinggal falah.\" Kami bertanya; \"Apakah falah itu?\" Abu Dzar menjawab; \"yaitu sahur.\" Abu Dzar berkata; \"Kemudian beliau tidak melakukan shalat malam bersama kami di sisa hari, pada bulan tersebut.\" Telah menceritakan kepada kami ['Ubaidullah bin Musa] dari [Sufyan] dari [Daud] dari [Al Walid bin Abdurrahman Al Jurasyi] dari [Jubair bin Nufair Al Hadhrami] dari [Abu Dzar] seperti hadits di atas."},"1360":{"ar":" حَدَّثَنَا عَاصِمُ بْنُ يُوسُفَ حَدَّثَنَا أَبُو بَكْرِ بْنِ عَيَّاشٍ عَنْ أَبِي حَصِينٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعْتَكِفُ الْعَشْرَ الْأَوَاخِرَ فَلَمَّا كَانَ الْعَامُ الَّذِي قُبِضَ فِيهِ اعْتَكَفَ عِشْرِينَ يَوْمًا","id":"Telah menceritakan kepada kami ['Ashim bin Yusuf] telah menceritakan kepada kami [Abu Bakr bin 'Ayyasy] dari [Abu Hashin] dari [Abu Shalih] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam melakukan i'tikaf pada sepuluh terakhir (bulan Ramadhan), ketika menjelang wafat, beliau melakukan i'tikaf selama dua puluh hari.\""},"1361":{"ar":" حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبُ بْنُ أَبِي حَمْزَةَ عَنْ الزُّهْرِيِّ أَخْبَرَنِي عَلِيُّ بْنُ حُسَيْنٍ أَنَّ صَفِّيَةَ بِنْتَ حُيَيٍّ أَخْبَرَتْهُ أَنَّهَا جَاءَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَزُورُهُ فِي اعْتِكَافِهِ فِي الْمَسْجِدِ الْحَرَامِ فِي الْعَشْرِ الْأَوَاخِرِ مِنْ رَمَضَانَ فَتَحَدَّثَتْ عِنْدَهُ سَاعَةً ثُمَّ قَامَتْ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib bin Abu Hamzah] dari [Az Zuhri] telah mengabarkan kepadaku [Ali bin Husain] bahwa [Shafiyah binti Huyay] telah mengabarkan kepadanya, bahwa ia pernah datang menemui Nabi shallallahu 'alaihi wasallam untuk mengunjunginya ketika beliau tengah I'tikaf di Masjidil Haram pada sepuluh terakhir bulan Ramadhan, lalu Shafiyah berbincang sesaat dengan beliau, setelah itu ia beranjak pergi (pulang).\""},"1362":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا حُمَيْدٌ عَنْ أَنَسٍ عَنْ عُبَادَةَ بْنِ الصَّامِتِ قَالَ خَرَجَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يُرِيدُ أَنْ يُخْبِرَنَا بِلَيْلَةِ الْقَدْرِ فَتَلَاحَى رَجُلَانِ مِنْ الْمُسْلِمِينَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي خَرَجْتُ إِلَيْكُمْ وَأَنَا أُرِيدُ أَنْ أُخْبِرَكُمْ بِلَيْلَةِ الْقَدْرِ وَكَانَ بَيْنَ فُلَانٍ وَفُلَانٍ لِحَاءٌ فَرُفِعَتْ وَعَسَى أَنْ يَكُونَ خَيْرًا فَالْتَمِسُوهَا فِي الْعَشْرِ الْأَوَاخِرِ فِي الْخَامِسَةِ وَالسَّابِعَةِ وَالتَّاسِعَةِ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah menceritakan kepada kami [Humaid] dari [Anas] dari ['Ubadah bin Ash Shamit], ia berkata; Rasulullah shallallahu 'alaihi wasallam keluar hendak mengabarkan lailatul qadar kepada kami, ternyata dua orang dari kaum muslimin saling berselisih. Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Sesungguhnya aku keluar hendak mengabarkan tentang lailatul qadar kepada kalian, karena antara Fulan dan Fulan berselisih (bertengkar), maka laitatul qadar diangkat kembali, semoga saja hal itu lebih baik, maka carilah lailatul qadar pada sepuluh hari terakhir, yaitu pada hari ke lima, ke tujuh dan kesembilan.\""},"1363":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنِي اللَّيْثُ حَدَّثَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ وَقَالَ أَبُو سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أُرِيتُ لَيْلَةَ الْقَدْرِ ثُمَّ أَيْقَظَنِي بَعْضُ أَهْلِي فَنَسِيتُهَا فَالْتَمِسُوهَا فِي الْعَشْرِ الْغَوَابِرِ","id":"Telah mengabarkan kepada kami [Abdullah bin Shalih] telah menceritakan kepadaku [Al Laits] telah menceritakan kepadaku [Yunus] dari [Ibnu Syihab], ia berkata; [Abu Salamah] telah mengatakan dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Telah diperlihatkan lailatul qadar kepadaku, kemudian sebagian keluargaku membangunkanku, namun aku lupa, oleh karena itu, carilah ia di sepuluh malam terakhir (bulan Ramadhan).\""},"1364":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنِي اللَّيْثُ حَدَّثَنِي عُقَيْلٌ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي سَالِمُ بْنُ عَبْدِ اللَّهِ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ قَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْتَمِسُوا لَيْلَةَ الْقَدْرِ فِي السَّبْعِ الْأَوَاخِرِ","id":"Telah mengabarkan kepada kami [Abdullah bin Shalih] telah menceritakan kepadaku [Al Laits] telah menceritakan kepadaku ['Uqail] dari [Ibnu Syihab], ia berkata; telah mengabarkan kepadaku [Salim bin Abdullah] bahwa [Abdullah bin Umar], ia berkata; sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Carilah lailatul qadar pada tujuh hari terakhir (bulan Ramadhan).\""},"1365":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ وَعَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْحَسَنُ بْنُ عَمْرٍو الْفُقَيْمِيُّ عَنْ مِهْرَانَ أَبِي صَفْوَانَ عَنْ ابْنِ عَبَّاسٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَرَادَ الْحَجَّ فَلْيَتَعَجَّلْ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad] dan [Abdullah bin Sa'id] telah menceritakan kepada kami [Abu Mu'awiyah] telah menceritakan kepada kami [Al Hasan bin 'Amr Al Fuqaimi] dari [Mahran Abu Shafwan] dari [Ibnu Abbas], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa ingin melakukan haji, hendaknya ia segera menunaikannya.\""},"1366":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ عَنْ شَرِيكٍ عَنْ لَيْثٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ سَابِطٍ عَنْ أَبِي أُمَامَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ لَمْ يَمْنَعْهُ عَنْ الْحَجِّ حَاجَةٌ ظَاهِرَةٌ أَوْ سُلْطَانٌ جَائِرٌ أَوْ مَرَضٌ حَابِسٌ فَمَاتَ وَلَمْ يَحُجَّ فَلْيَمُتْ إِنْ شَاءَ يَهُودِيًّا وَإِنْ شَاءَ نَصْرَانِيًّا","id":"Telah mengabarkan kepada kami [Yazid bin Harun] dari [Syarik] dari [Laits] dari [Abdurrahman bin Sabith] dari [Abu Umamah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa tidak terhalang untuk melakukan haji oleh suatu hajat yang jelas atau oleh penguasa yang lalim atau penyakit yang menahannya, kemudian ia meninggal dan belum melakukan haji, bisa jadi ia meninggal dalam keadaan sebagai Yahudi atau sebagai Nashrani.\""},"1367":{"ar":" أَخْبَرَنَا مُجَاهِدُ بْنُ مُوسَى حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا زُهَيْرٌ عَنْ أَبِي إِسْحَقَ قَالَ سَمِعْتُ زَيْدَ بْنَ أَرْقَمَ يَقُولُ حَجَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَ هِجْرَتِهِ حَجَّةً قَالَ وَقَالَ أَبُو إِسْحَقَ حَجَّ قَبْلَ هِجْرَتِهِ حَجَّةً","id":"Telah mengabarkan kepada kami [Mujahid bin Musa] telah menceritakan kepada kami [Yahya bin Adam] telah menceritakan kepada kami [Zuhair] dari [Abu Ishaq], ia berkata; saya mendengar [Zaid bin Arqam] berkata; \"Nabi shallallahu 'alaihi wasallam melaksanakan haji sekali setelah hijrah.\" Perawi berkata; Abu Ishaq mengatakan; \"Beliau melakukan haji sekali sebelum berhijrah.\""},"1368":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ قَالَ قُلْتُ لِأَنَسٍ كَمْ حَجَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ حَجَّةً وَاحِدَةً وَاعْتَمَرَ أَرْبَعًا عُمْرَتُهُ الْأُولَى الَّتِي صَدَّهُ الْمُشْرِكُونَ عَنْ الْبَيْتِ وَعُمْرَتُهُ الثَّانِيَةُ حِينَ صَالَحُوهُ فَرَجَعَ مِنْ الْعَامِ الْمُقْبِلِ وَعُمْرَتُهُ مِنْ الْجِعْرَانَةِ حِينَ قَسَّمَ غَنِيمَةَ حُنَيْنٍ فِي ذِي الْقَعْدَةِ وَعُمْرَتُهُ مَعَ حَجَّتِهِ","id":"Telah mengabarkan kepada kami [Abu Al Walid Ath Thayalisi] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Qatadah], ia berkata; Saya berkata kepada [Anas]; \"Berapa kali Nabi shallallahu 'alaihi wasallam melakukan haji?\" Anas menjawab; \"Sekali berhaji dan empat kali Umrah. Beliau pertama kali Umrah ketika orang-orang musyrik menghalanginya dari Ka'bah, dan Umrahnya yang kedua, ketika mereka mengadakan perdamaian dengan beliau, kemudian kembali pada tahun mendatang, dan Umrah dari Ji'ranah ketika beliau membagikan harta rampasan perang Hunain pada Bulan Dzul Qa'dah, serta Umrah beliau bersamaan dengan hajinya.\""},"1369":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ حَدَّثَنَا سُلَيْمَانُ بْنُ كَثِيرٍ عَنْ الزُّهْرِيِّ عَنْ سِنَانٍ عَنْ ابْنِ عَبَّاسٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُتِبَ عَلَيْكُمْ الْحَجُّ فَقِيلَ يَا رَسُولَ اللَّهِ فِي كُلِّ عَامٍ قَالَ لَا وَلَوْ قُلْتُهَا لَوَجَبَتْ الْحَجُّ مَرَّةٌ فَمَا زَادَ فَهُوَ تَطَوُّعٌ أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ شَرِيكٍ عَنْ سِمَاكٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ نَحْوَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] telah menceritakan kepada kami [Sulaiman bin Katsir] dari [Az Zuhri] dari [Sinan] dari [Ibnu Abbas], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Telah diwajibkan haji atas kalian.\" Beliau ditanya; \"Wahai Rasulullah, apakah wajib setiap tahun?, \" Beliau menjawab: \"Tidak, jika aku mengatakannya, niscaya ia menjadi wajib (setiap tahun). Keawajiban haji hanya sekali, dan selebihnya adalah sunnah.\" Telah mengabarkan kepada kami ['Ubaidullah bin Musa] dari [Syarik] dari [Simak] dari [Ikrimah] dari [Ibnu Abbas] sama seperti hadits di atas."},"1370":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ بْنِ يُونُسَ حَدَّثَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَ وَقَّتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأَهْلِ الْمَدِينَةِ ذَا الْحُلَيْفَةِ وَلِأَهْلِ الشَّامِ الْجُحْفَةَ وَلِأَهْلِ نَجْدٍ قَرْنًا قَالَ قَالَ ابْنُ عُمَرَ أَمَّا هَذِهِ الثَّلَاثُ فَإِنِّي سَمِعْتُهُنَّ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبَلَغَنِي أَنَّهُ وَقَّتَ لِأَهْلِ الْيَمَنِ يَلَمْلَمَ أَخْبَرَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارَ عَنْ ابْنِ عُمَرَ مِثْلَهُ","id":"Telah mengabarkan kepada kami [Ahmad bin Abdullah bin Yunus] telah menceritakan kepada kami [Malik] dari [Nafi'] dari [Ibnu Umar], ia berkata; Rasulullah shallallahu 'alaihi wasallam telah menjadikan Dzal Hulaifah sebagai miqat penduduk Madinah, Juhfah sebagai miqat penduduk Syam, Qarnul Manazil sebagai miqat penduduk Najed.\" Ibnu Umar berkata; \"Adapun ketiga tempat ini, saya telah mendengarnya dari Rasulullah shallallahu 'alaihi wasallam, dan telah sampai kepadaku bahwa beliau menjadikan Yalamlam sebagai Miqat bagi penduduk Yaman.\" Telah mengabarkan kepada kami [Ahmad bin Abdullah] telah menceritakan kepada kami [Malik] dari [Abdullah bin Dinar] dari [Ibnu Umar] seperti hadits di atas."},"1371":{"ar":" حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا ابْنُ طَاوُسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَّتَ لِأَهْلِ الْمَدِينَةِ ذَا الْحُلَيْفَةِ وَلِأَهْلِ الشَّامِ الْجُحْفَةَ وَلِأَهْلِ نَجْدٍ قَرْنَ الْمَنَازِلِ وَلِأَهْلِ الْيَمَنِ أَلَمْلَمَ هُنَّ لِأَهْلِهِنَّ وَلِكُلِّ آتٍ أَتَى عَلَيْهِنَّ مِنْ غَيْرِهِنَّ مَنْ أَرَادَ الْحَجَّ وَالْعُمْرَةَ وَمَنْ كَانَ دُونَ ذَلِكَ فَمِنْ حَيْثُ أَنْشَأَ حَتَّى أَهْلُ مَكَّةَ مِنْ مَكَّةَ ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Ibnu Thawus] dari [Ayahnya] dari [Ibnu Abbas] bahwa Nabi shallallahu 'alaihi wasallam telah menjadikan Dzul Hulaifah sebagai miqat bagi penduduk Madinah, Juhfah sebagai miqat penduduk Syam, Qarnul Manazil sebagai miqat penduduk Najed, Alamlam sebagai miqat penduduk Yaman, tempat-tempat tersebut adalah bagi penduduknya dan bagi setiap orang yang datang kepadanya dari luar tempat-tempat tersebut, bagi orang yang ingin melakukan haji dan umrah. Barangsiapa penduduknya di luar miqat-miqat tersebut, maka tempatnya adalah lokasi yang ia gunakan untuk memulai berhaji, hingga penduduk Makkah dari Makkah sendiri.\""},"1372":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ إِبْرَاهِيمَ بْنِ عَبْدِ اللَّهِ بْنِ حُنَيْنٍ عَنْ أَبِيهِ قَالَ امْتَرَى الْمِسْوَرُ بْنُ مَخْرَمَةَ وَابْنُ عَبَّاسٍ فِي غَسْلِ الْمُحْرِمِ رَأْسَهُ فَأَرْسَلُونِي إِلَى أَبِي أَيُّوبَ الْأَنْصَارِيِّ كَيْفَ رَأَيْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَغْسِلُ رَأْسَهُ وَهُوَ مُحْرِمٌ فَأَتَيْتُ أَبَا أَيُّوبَ وَهُوَ بَيْنَ قَرْنَيْ الْبِئْرِ وَقَدْ سُتِرَ عَلَيْهِ بِثَوْبٍ فَسَلَّمْتُ عَلَيْهِ فَضَمَّ الثَّوْبَ إِلَيْهِ فَقُلْتُ أَرْسَلَنِي إِلَيْكَ ابْنُ أَخِيكَ ابْنُ عَبَّاسٍ كَيْفَ رَأَيْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَغْسِلُ رَأْسَهُ فَأَمَرَّ يَدَيْهِ عَلَى رَأْسِهِ مُقْبِلًا وَمُدْبِرًا","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Ibnu 'Uyainah] dari [Zaid bin Aslam] dari [Ibrahim bin Abdullah bin Hunain] dari [Ayahnya], ia berkata; Al Miswar bin Makharamah dan Ibnu Abbas berselisih mengenai orang yang mencuci kepalanya ketika berihram, kemudian mereka mengutusku menemui [Abu Ayyub Al Anshari], agar saya bertanya kepadanya; \"Bagaimana anda melihat Rasulullah shallallahu 'alaihi wasallam mencuci kepalanya ketika berihram?\" Maka saya datang menemui Abu Ayyub, ketika itu ia tengah berada diantara dua sisi sumur, bertabirkan dengan sehelai kain, saya mengucapkan salam kepadanya, namun ia merapatkan kainnya.\" Saya katakan; \"Anak saudaramu yaitu Ibnu Abbas telah mengutusku untuk menemuimu, sembari menanyakan bagaimana anda melihat Rasulullah shallallahu 'alaihi wasallam mencuci kepalanya (ketika berihram)?\" Kemudian ia memberi isyarat dengan menggerakkan kedua tangannya diatas kepala ke depan dan ke belakang."},"1373":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ أَبِي زِيَادٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَعْقُوبَ الْمَدَنِيُّ عَنْ ابْنِ أَبِي الزِّنَادِ عَنْ أَبِيهِ عَنْ خَارِجَةَ بْنِ زَيْدِ بْنِ ثَابِتٍ عَنْ أَبِيهِ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَجَرَّدَ لِلْإِهْلَالِ وَاغْتَسَلَ","id":"Telah mengabarkan kepada kami [Abdullah bin Abu Ziyad] telah menceritakan kepada kami [Abdullah bin Ya'qub Al Madani] dari [Ibnu Abu Az Zinad] dari [Ayahnya] dari [Kharijah bin Zaid bin Tsabit] dari [Ayahnya] bahwa Nabi shallallahu 'alaihi wasallam melepas pakaian berjahitnya ketika hendak melaksanakan ihram, lalu beliau mandi.\""},"1374":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ سُفْيَانَ عَنْ سُمَيٍّ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ حَجَّةٌ مَبْرُورَةٌ لَيْسَ لَهَا ثَوَابٌ إِلَّا الْجَنَّةُ وَعُمْرَتَانِ تُكَفِّرَانِ مَا بَيْنَهُمَا مِنْ الذُّنُوبِ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Musa] dari [Sufyan] dari [Sumay] dari [Abu Shalih] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak ada balasan bagi haji yang mabrur kecuali Surga, dan dua kali Umrah akan menghapuskan dosa antara keduanya.\""},"1375":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا شُعْبَةُ حَدَّثَنِي مَنْصُورٌ قَالَ سَمِعْتُ أَبَا حَازِمٍ يُحَدِّثُ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَنْ حَجَّ الْبَيْتَ فَلَمْ يَرْفُثْ وَلَمْ يَفْسُقْ رَجَعَ كَمَا وَلَدَتْهُ أُمُّهُ","id":"Telah mengabarkan kepada kami [Abu Al Walid Ath Thayalisi] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepadaku [Manshur], ia berkata; saya mendengar [Abu Hazim] menceritakan dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Barangsiapa melaksanakan haji ke Baitullah, tidak berkata-kata kotor serta tidak melakukan kefasikan, maka ia kembali sebagaimana ketika ia dilahirkan oleh ibunya.\""},"1376":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ بْنِ أَبِي فُدَيْكٍ عَنْ الضَّحَّاكِ بْنِ عُثْمَانَ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَرْبُوعٍ عَنْ أَبِي بَكْرٍ قَالَ سُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّ الْحَجِّ أَفْضَلُ قَالَ الْعَجُّ وَالثَّجُّ الْعَجُّ يَعْنِي التَّلْبِيَةَ وَالثَّجُّ يَعْنِي إِهْرَاقَةَ الدَّمِ","id":"Telah menceritakan kepada kami [Muhammad bin Al 'Ala`] telah menceritakan kepada kami [Muhammad bin Isma'il bin Abu Fudaik] dari [Adh Dhahhak bin Utsman] dari [Muhammad bin Al Munkadir] dari [Abdurrahman bin Yarbu'] dari [Abu Bakr], ia berkata; Rasulullah shallallahu 'alaihi wasallam ditanya; \"Haji apakah yang paling utama?\" Beliau bersabda: \"Al 'ajju, dan ats Tsajju. Al 'Ajju yaitu mengucapkan talbiyah, sedangkan ats tsajju yaitu mengalirkan darah (hewan kurban).\""},"1377":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا يَحْيَى هُوَ ابْنُ سَعِيدٍ عَنْ عُمَرَ بْنِ نَافِعٍ عَنْ أَبِيهِ عَنْ ابْنِ عُمَرَ أَنَّ رَجُلًا سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا نَلْبَسُ مِنْ الثِّيَابِ إِذَا أَحْرَمْنَا قَالَ لَا تَلْبَسُوا الْقُمُصَ وَلَا السَّرَاوِيلَاتِ وَلَا الْعَمَائِمَ وَلَا الْبَرَانِسَ وَلَا الْخِفَافَ إِلَّا أَنْ يَكُونَ أَحَدٌ لَيْسَتْ لَهُ نَعْلَانِ فَلْيَلْبَسْ الْخُفَّيْنِ وَلْيَجْعَلْهُمَا أَسْفَلَ مِنْ الْكَعْبَيْنِ وَلَا تَلْبَسُوا مِنْ الثِّيَابِ شَيْئًا مَسَّهُ وَرْسٌ وَلَا زَعْفَرَانٌ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Yahya] yaitu Ibnu Sa'id dari [Umar bin Nafi'] dari [Ayahnya] dari [Ibnu Umar] bahwa seorang laki-laki bertanya kepada Nabi shallallahu 'alaihi wasallam; \"Pakaian apakah yang harus kami kenakan ketika ihram?\" Beliau menjawab: \"Janganlah memakai jubah, celana panjang, sorban, baju panjang yang bertutup kepala, serta sepatu, kecuali jika seseorang tidak mendapatkan dua sandal, maka ia boleh mengenakan sepatu dan memotongnya hingga di bawah kedua mata kaki, dan janganlah kalian memakai pakaian yang dilumuri waras, serta Za'faran.\" "},"1378":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ أَبِي الشَّعْثَاءِ أَخْبَرَنِي ابْنُ عَبَّاسٍ أَنَّهُ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ لَمْ يَجِدْ إِزَارًا فَلْيَلْبَسْ سَرَاوِيلَ وَمَنْ لَمْ يَجِدْ نَعْلَيْنِ فَلْيَلْبَسْ خُفَّيْنِ قَالَ قُلْتُ أَوْ قِيلَ أَيَقْطَعُهُمَا قَالَ لَا","id":"Telah mengabarkan kepada kami [Abu 'Ashim] dari [Ibnu Juraij] dari ['Amru bin Dinar] dari [Abu Asy Sya'tsa`], telah mengabarkan kepadaku [Ibnu Abbas] bahwa ia mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa tidak mendapatkan sarung, hendaknya ia memakai celana panjang, dan barangsiapa tidak mendapatkan sandal, hendaknya ia memakai sepatu.\" Ibnu Abbas berkata; aku bertanya -atau beliau ditanya; \"Apakah ia harus memotong sepatu tersebut?\" Beliau menjawab: \"Tidak.\""},"1379":{"ar":" أَخْبَرَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَ سُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَمَّا يَلْبَسُ الْمُحْرِمُ قَالَ لَا يَلْبَسُ الْقُمُصَ وَلَا الْعَمَائِمَ وَلَا السَّرَاوِيلَاتِ وَلَا الْبَرَانِسَ وَلَا الْخِفَافَ إِلَّا أَنْ لَا يَجِدَ نَعْلَيْنِ فَيَلْبَسَ خُفَّيْنِ وَيَقْطَعَهُمَا أَسْفَلَ مِنْ الْكَعْبَيْنِ","id":"Telah mengabarkan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Malik] dari [Nafi'] dari [Ibnu Umar], ia berkata; Rasulullah shallallahu 'alaihi wasallam ditanya mengenai pakaian apakah yang dikenakan oleh orang yang berihram?\" Beliau bersabda: \"Janganlah ia memakai jubah, sorban, celana panjang, baju panjang yang bertutup kepala, serta sepatu, kecuali jika tidak mendapatkan dua sandal, hendaknya ia memakai sepatu dan memotongnya hingga di bawah kedua mata kaki.\""},"1380":{"ar":" أَخْبَرَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ أَنَّهَا قَالَتْ كُنْتُ أُطَيِّبُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَبْلَ أَنْ يُحْرِمَ بِأَطْيَبِ الطِّيبِ قَالَ وَكَانَ عُرْوَةُ يَقُولُ لَنَا تَطَيَّبُوا قَبْلَ أَنْ تُحْرِمُوا وَقَبْلَ أَنْ تُفِيضُوا يَوْمَ النَّحْرِ","id":"Telah mengabarkan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Hammad bin Salamah] dari [Hisyam bin 'Urwah] dari [Ayahnya] dari ['Aisyah] bahwa ia berkata; \"Saya pernah memberi minyak wangi yang paling baik kepada Rasulullah shallallahu 'alaihi wasallam sebelum berihram.\" Perawi berkata; ['Urwah] mengatakan kepada kami; \"Pakailah minyak wangi sebelum berihram dan sebelum thawaf Ifadhah pada hari Kurban.\""},"1381":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنِي اللَّيْثُ عَنْ هِشَامٍ عَنْ عُثْمَانَ بْنِ عُرْوَةَ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْ لَقَدْ كُنْتُ أُطَيِّبُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَ إِحْرَامِهِ بِأَطْيَبِ مَا أَجِدُهُ","id":"Telah menceritakan kepada kami [Abdullah bin Shalih] telah menceritakan kepadaku [Al Laits] dari [Hisyam] dari [Utsman bin 'Urwah] dari ['Urwah] dari ['Aisyah], ia berkata; \"Saya pernah memberi sebaik-baik minyak wangi yang saya dapatkan kepada Rasulullah shallallahu 'alaihi wasallam ketika berihram.\""},"1382":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ وَجَعْفَرُ بْنُ عَوْنٍ قَالَا حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ أَنَّ عَبْدَ الرَّحْمَنِ بْنَ الْقَاسِمِ أَخْبَرَهُ عَنْ أَبِيهِ قَالَ سَمِعْتُ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا تَقُولُ طَيَّبْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِحُرْمِهِ وَطَيَّبْتُهُ بِمِنًى قَبْلَ أَنْ يُفِيضَ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] dan [Ja'far bin 'Aun] keduanya berkata; telah menceritakan kepada kami [Yahya bin Sa'id] bahwa [Abdurrahman bin Al Qasim] telah mengabarkan kepadanya dari [Ayahnya], ia berkata; saya mendengar ['Aisyah radliallahu 'anha] berkata; \"Saya pernah memberi minyak wangi kepada Rasulullah shallallahu 'alaihi wasallam untuk ihramnya dan saya memberinya minyak wangi di Mina sebelum beliau bertolak menuju Ka'bah.\""},"1383":{"ar":" حَدَّثَنِي عُثْمَانُ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدَةُ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْ نُفِسَتْ أَسْمَاءُ بِمُحَمَّدِ بْنِ أَبِي بَكْرٍ بِالشَّجَرَةِ فَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبَا بَكْرٍ أَنْ تَغْتَسِلَ وَتُهِلَّ","id":"Telah menceritakan kepadaku [Utsman bin Muhammad] telah menceritakan kepada kami ['Abdah] dari ['Ubaidullah bin Umar] dari [Abdurrahman bin Al Qasim] dari [Ayahnya] dari ['Aisyah], ia berkata; Asma` mengalami nifas karena melahirkan Muhammad bin Abu Bakr di bawah pohon, kemudian Rasulullah shallallahu 'alaihi wasallam memerintahkan Abu Bakr agar Asma` mandi dan bertalbiyah.\""},"1384":{"ar":" أَخْبَرَنَا عُثْمَانُ بْنُ مُحَمَّدٍ حَدَّثَنَا جَرِيرٌ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ جَعْفَرِ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ جَابِرٍ فِي حَدِيثِ أَسْمَاءَ بِنْتِ عُمَيْسٍ حِينَ نُفِسَتْ بِذِي الْحُلَيْفَةِ فَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبَا بَكْرٍ أَنْ يَأْمُرَهَا أَنْ تَغْتَسِلَ وَتُهِلَّ","id":"Telah mengabarkan kepada kami [Utsman bin Muhammad] telah menceritakan kepada kami [Jarir] dari [Yahya bin Sa'id] dari [Ja'far bin Muhammad] dari [Ayahnya] dari [Jabir] dalam hadits Asma` binti 'Umais, ketika ia nifas karena melahirkan di Dzul Hulaifah, kemudian Rasulullah shallallahu 'alaihi wasallam memerintahkan Abu Bakr agar Asma` mandi dan bertalbiyah.\""},"1385":{"ar":" أَخْبَرَنَا عَمْرُو بْنُ عَوْنٍ أَخْبَرَنَا عَبْدُ السَّلَامِ بْنُ حَرْبٍ عَنْ خُصَيْفٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحْرَمَ دُبُرَ الصَّلَاةِ","id":"Telah mengabarkan kepada kami ['Amru bin 'Aun] telah mengabarkan kepada kami [Abdussalam bin Harb] dari [Khushaif] dari [Sa'id bin Jubair] dari [Ibnu Abbas radliallahu 'anhu] bahwa Nabi shallallahu 'alaihi wasallam ihram setelah mengerjakan shalat.\""},"1386":{"ar":" أَخْبَرَنَا إِسْحَقُ قَالَ أَخْبَرَنَا النَّضْرُ هُوَ ابْنُ شُمَيْلٍ أَخْبَرَنَا أَشْعَثُ عَنْ الْحَسَنِ عَنْ أَنَسِ بْنِ مَالِكٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحْرَمَ أَوْ أَهَلَّ فِي دُبُرِ الصَّلَاةِ","id":"Telah mengabarkan kepada kami [Ishaq], ia berkata; telah mengabarkan kepada kami [An Nadhr yaitu Ibnu Syumail] telah mengabarkan kepada kami [Asy'ats] dari [Al Hasan] dari [Anas bin Malik] bahwa Nabi shallallahu 'alaihi wasallam ihram atau bertalbiyah seusai shalat.\""},"1387":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا يَحْيَى يَعْنِي ابْنَ سَعِيدٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا لَبَّى قَالَ لَبَّيْكَ اللَّهُمَّ لَبَّيْكَ لَبَّيْكَ لَا شَرِيكَ لَكَ لَبَّيْكَ إِنَّ الْحَمْدَ وَالنِّعْمَةَ لَكَ وَالْمُلْكَ لَا شَرِيكَ لَكَ قَالَ يَحْيَى وَذَكَرَ نَافِعٌ أَنَّ ابْنَ عُمَرَ كَانَ يَزِيدُ هَؤُلَاءِ الْكَلِمَاتِ لَبَّيْكَ وَالرَّغْبَاءُ إِلَيْكَ وَالْعَمَلُ لَبَّيْكَ لَبَّيْكَ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Yahya yaitu Ibnu Sa'id] dari [Nafi'] dari [Ibnu Umar] bahwa apabila Nabi shallallahu 'alaihi wasallam bertalbiyah, beliau mengucapkan; LABBAIKALLAAHUMMA LABBAIK, LABBAIKA LAA SYARIIKA LAKA LABBAIK INNAL HAMDA WAN NI'MATA WAL MULKA LAA SYARII KALAK. (ya Allah, aku memenuhi seruanMu, aku memenuhi seruanMu, aku memenuhi seruanMu. Tidak ada sekutu bagiMu, aku memenuhi seruanMu, sesungguhnya segala puji, kenikmatan dan seluruh kerajaan adalah milikMu, tidak ada sekutu bagiMu).\" [Yahya] mengatakan; [Nafi'] menyebutkan bahwa [Ibnu Umar] menambah kata-kata tersebut dengan redaksi: \"LABBAIKA WAR RAGHBAAU ILAIK, WAL 'AMALU LABBAIK, LABBAIK.\" (aku memenuhi seruanMu, dan harapan serta amalan tertuju kepadaMu, aku memenuhi seruanmu, aku memenuhi seruanMu).\""},"1388":{"ar":" أَخْبَرَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ خَلَّادِ بْنِ السَّائِبِ عَنْ أَبِيهِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَانِي جِبْرَائِيلُ فَقَالَ مُرْ أَصْحَابَكَ أَوْ مَنْ مَعَكَ أَنْ يَرْفَعُوا أَصْوَاتَهُمْ بِالتَّلْبِيَةِ أَوْ بِالْإِهْلَالِ حَدَّثَنَا عُثْمَانُ بْنُ مُحَمَّدٍ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ بِإِسْنَادِهِ نَحْوَهُ","id":"Telah mengabarkan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Malik] dari [Abdullah bin Abu Bakr] dari [Khallad bin As Sa`ib] dari [Ayahnya], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jibril datang kepadaku, lalu ia berkata; \"Perintahkanlah kepada para sahabatmu atau orang yang bersamamu agar mengeraskan suara ketika bertalbiyah, atau ihlal.\" Telah menceritakan kepada kami [Utsman bin Muhammad] telah menceritakan kepada kami [Ibnu 'Uyainah] dari [Abdullah bin Abu Bakr] dengan sanad seperti hadits di atas.\""},"1389":{"ar":" أَخْبَرَنَا أَبُو النُّعْمَانِ حَدَّثَنَا ثَابِتُ بْنُ يَزِيدَ حَدَّثَنَا هِلَالُ بْنُ خَبَّابٍ قَالَ فَحَدَّثْتُ عِكْرِمَةَ فَحَدَّثَنِي عَنْ ابْنِ عَبَّاسٍ أَنَّ ضُبَاعَةَ بِنْتَ الزُّبَيْرِ بْنِ عَبْدِ الْمُطَّلِبِ أَتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنِّي أُرِيدُ أَنْ أَحُجَّ فَكَيْفَ أَقُولُ قَالَ قُولِي لَبَّيْكَ اللَّهُمَّ لَبَّيْكَ وَمَحِلِّي حَيْثُ تَحْبِسُنِي فَإِنَّ لَكِ عَلَى رَبِّكِ مَا اسْتَثْنَيْتِ","id":"Telah mengabarkan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Tsabit bin Yazid] telah menceritakan kepada kami [Hilal bin Khabbab], ia berkata; kemudian saya menceritakan kepada [Ikrimah] lalu ia menceritakan kepadaku dari [Ibnu Abbas] bahwa Dluba'ah binti Az Zubair bin Abdul Muththalib datang kepada Nabi shallallahu 'alaihi wasallam dan berkata; \"Wahai Rasulullah, sesungguhnya saya ingin berhaji, bagaimana saya berucap?\" Beliau bersabda: \"Ucapkanlah; LABBAIKALLAAHUMMA LABBAIK WA MAHALLII HAITSU TAHBISUNII (ya Allah, aku memenuhi seruanMu, aku memenuhi seruanMu, dan tempatku di mana Engkau menahanku).\" Sesungguhnya bagimu atas Rabbmu apa yang telah engkau kecualikan.\""},"1390":{"ar":" أَخْبَرَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا مَالِكٌ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ تَعَالَى عَنْهَا أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفْرَدَ الْحَجَّ","id":"Telah mengabarkan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Malik] dari [Abdurrahman bin Al Qasim] dari [Ayahnya] dari ['Aisyah radliallahu 'anha] bahwa Rasulullah shallallahu 'alaihi wasallam melakukan haji ifard.\" "},"1391":{"ar":" أَخْبَرَنَا سُلَيْمَانُ بْنُ حَرْبٍ أَخْبَرَنَا أَبُو هِلَالٍ حَدَّثَنَا قَتَادَةُ عَنْ مُطَرِّفٍ قَالَ قَالَ عِمْرَانُ بْنُ حُصَيْنٍ إِنِّي مُحَدِّثُكَ بِحَدِيثٍ لَعَلَّ اللَّهَ أَنْ يَنْفَعَكَ بِهِ بَعْدُ إِنَّهُ كَانَ يُسَلَّمُ عَلَيَّ وَإِنَّ ابْنَ زِيَادٍ أَمَرَنِي فَاكْتَوَيْتُ فَاحْتُبِسَ عَنِّي حَتَّى ذَهَبَ أَثَرُ الْمَكَاوِي وَاعْلَمْ أَنَّ الْمُتْعَةَ حَلَالٌ فِي كِتَابِ اللَّهِ لَمْ يَنْهَ عَنْهَا نَبِيٌّ وَلَمْ يَنْزِلْ فِيهَا كِتَابٌ قَالَ رَجُلٌ بِرَأْيِهِ مَا بَدَا لَهُ","id":"Telah mengabarkan kepada kami [Sulaiman bin Harb] telah mengabarkan kepada kami [Abu Hilal] telah menceritakan kepada kami [Qatadah] dari [Mutharrif], ia berkata; [Imran bin Hushain] berkata; saya akan menyampaikan satu hadits kepadamu, semoga Allah memberikan manfaat kepadamu, sesungguhnya saya pernah diberi salam (oleh para Malaikat), dan Ibnu Ziyad memerintahkanku agar aku melakukan kai (penyembuhan dengan besi panas), ternyata (salam para Malaikat) terhalangi dariku hingga bekas kay hilang. Dan ketahuilah bahwa haji mut'ah adalah halal dalam Kitabullah, tidak ada seorang nabipun yang melarang dan tidak ada kitab yang turun untuk melarangnya. Dan orang berbicara menggunakan pendapatnya semau dia.\" "},"1392":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ خَالِدٍ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ الزُّهْرِيِّ عَنْ مُحَمَّدِ بْنِ عَبْدِ اللَّهِ بْنِ نَوْفَلٍ قَالَ سَمِعْتُ عَامَ حَجَّ مُعَاوِيَةُ يَسْأَلُ سَعْدَ بْنَ مَالِكٍ كَيْفَ تَقُولُ بِالتَّمَتُّعِ بِالْعُمْرَةِ إِلَى الْحَجِّ قَالَ حَسَنَةٌ جَمِيلَةٌ فَقَالَ قَدْ كَانَ عُمَرُ يَنْهَى عَنْهَا فَأَنْتَ خَيْرٌ مِنْ عُمَرَ قَالَ عُمَرُ خَيْرٌ مِنِّي وَقَدْ فَعَلَ ذَلِكَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ خَيْرٌ مِنْ عُمَرَ","id":"Telah mengabarkan kepada kami [Ahmad bin Khalid] telah menceritakan kepada kami [Muhammad bin Ishaq] dari [Az Zuhri] dari [Muhammad bin Abdullah bin Naufal], ia berkata; \"Saya mendengar Mu'awiyah bertanya kepada [Sa'd bin Malik] pada tahun haji; \"Bagaimana pendapatmu mengenai haji tamattu' dengan menggabungkan umrah kepada haji?\" Sa'd menjawab; \"Itu hal yang bagus.\" Lalu ia berkata; \"Namun Umar pernah melarangnya, sepertinya kamu lebih baik daripada Umar.\" Sa'd menimpali; \"Justru Umar lebih baik daripada aku, dan Nabi shallallahu 'alaihi wasallam telah melakukan hal itu, sementara beliau lebih baik daripada Umar.\""},"1393":{"ar":" حَدَّثَنَا سَهْلُ بْنُ حَمَّادٍ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا قَيْسُ بْنُ مُسْلِمٍ عَنْ طَارِقٍ عَنْ أَبِي مُوسَى قَالَ أَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ حَجَّ وَهُوَ مُنِيخٌ بِالْبَطْحَاءِ فَقَالَ لِي أَحَجَجْتَ قُلْتُ نَعَمْ قَالَ كَيْفَ أَهْلَلْتَ قَالَ قُلْتُ لَبَّيْكَ بِإِهْلَالٍ كَإِهْلَالِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَحْسَنْتَ اذْهَبْ فَطُفْ بِالْبَيْتِ وَبِالصَّفَا وَالْمَرْوَةِ ثُمَّ حِلَّ قَالَ فَطُفْتُ بِالْبَيْتِ وَبِالصَّفَا وَالْمَرْوَةِ ثُمَّ أَتَيْتُ امْرَأَةً مِنْ نِسَاءِ بَنِي قَيْسٍ فَجَعَلَتْ تَفْلِي رَأْسِي فَجَعَلْتُ أُفْتِي النَّاسَ بِذَلِكَ فَقَالَ لِي رَجُلٌ يَا عَبْدَ اللَّهِ بْنَ قَيْسٍ رُوَيْدًا بَعْضَ فُتْيَاكَ فَإِنَّكَ لَا تَدْرِي مَا أَحْدَثَ أَمِيرُ الْمُؤْمِنِينَ فِي النُّسُكِ بَعْدَكَ فَقُلْتُ يَا أَيُّهَا النَّاسُ مَنْ كُنَّا أَفْتَيْنَاهُ فُتْيَا فَلْيَتَّئِدْ فَإِنَّ أَمِيرَ الْمُؤْمِنِينَ قَادِمٌ عَلَيْكُمْ فَبِهِ فَأْتَمُّوا فَلَمَّا قَدِمَ أَتَيْتُهُ فَذَكَرْتُ ذَلِكَ لَهُ فَقَالَ إِنْ نَأْخُذْ بِكِتَابِ اللَّهِ فَإِنَّ كِتَابَ اللَّهِ يَأْمُرُ بِالتَّمَامِ وَإِنْ نَأْخُذْ بِسُنَّةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَحِلَّ حَتَّى بَلَغَ الْهَدْيُ مَحِلَّهُ","id":"Telah menceritakan kepada kami [Sahl bin Hammad] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Qais bin Muslim] dari [Thariq] dari [Abu Musa], ia berkata; \"Saya datang kepada Rasulullah shallallahu 'alaihi wasallam ketika beliau sedang menunaikan haji, ketika itu Nabi shallallahu 'alaihi wasallam singgah di Bathha`. Kemudian beliau bertanya kepadaku: \"Apakah kamu sedang menunaikan haji?\" saya menjawab; \"Ya.\" Beliau bertanya: \"Apa yang kamu bertalbiyah?\" Ia berkata; \"Aku penuhi panggilan-Mu, yaitu bertalbiyah sebagaimana talbiyahnya Nabi shallallahu 'alaihi wasallam.\" Beliau bersabda: \"Kamu benar, pergi dan thawaflah di Ka'bah dan (sa'i) di Shafa serta Marwah, setelah itu bertahallullah.\" Abu Musa berkata; lalu saya melakukan thawaf di Ka'bah, serta Shafa dan Marwah, kemudian aku menemui seorang wanita Bani Qais (yaitu isterinya -pent), lalu ia membersihkan kutu dari kepalaku. saya juga biasa berfatwa kepada orang-orang dengan masalah tersebut. Suatu ketika seorang laki-laki berkata kepadaku; \"Wahai Abdullah bin Qais, berhati-hatilah dengan sebagian fatwamu. Sesungguhnya kamu tidak mengetahui apa yang dilakukan Amirul mukminin dalam perkara manasik setelahmu.\" Aku langsung berkata; \"Wahai sekalian manusia, barangsiapa telah kami beri fatwa, hendaknya ia tidak terburu-buru, karena sesungguhnya [Amirul mukminin] akan datang kepada kalian, maka ikutilah dia.\" Ketika Amirul Mukminin Umar tiba, aku langsung menemuinya, dan memberitahukan permasalahan tersebut kepadanya, dia lalu menjawab; \"Jika kita mengambil kitabullah, sesungguhnya Allah memerintahkan kita untuk melakukan secara sempurna, namun jika kita mengambil sunnah Nabi shallallahu 'alaihi wasallam, sesungguhnya Nabi shallallahu 'alaihi wasallam tidak bertahallul hingga hewan kurban sampai di tempatnya.\""},"1394":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا يَحْيَى عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ خَمْسٌ لَا جُنَاحَ فِي قَتْلِ مَنْ قُتِلَ مِنْهُنَّ الْغُرَابُ وَالْفَأْرَةُ وَالْحِدَأَةُ وَالْعَقْرَبُ وَالْكَلْبُ الْعَقُورُ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Yahya] dari [Nafi'] dari [Ibnu Umar] bahwa Nabi shallallahu 'alaihi wasallam bersabda; \"Lima binatang yang tidak ada dosa bagi orang yang (berihram) untuk membunuhnya, yaitu; Burung gagak, tikus, elang, kalajengking, anjing buas.\""},"1395":{"ar":" أَخْبَرَنَا إِسْحَقُ أَخْبَرَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْ أَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِقَتْلِ خَمْسِ فَوَاسِقَ فِي الْحِلِّ وَالْحَرَمِ الْحِدَأَةِ وَالْغُرَابِ وَالْفَأْرَةِ وَالْعَقْرَبِ وَالْكَلْبِ الْعَقُورِ قَالَ عَبْد اللَّهِ الْكَلْبُ الْعَقُورُ وَقَالَ بَعْضُهُمْ الْأَسْوَدُ أَخْبَرَنَا عَبْدُ الرَّزَّاقِ قَالَ بَعْضُ أَصْحَابِنَا إِنَّ مَعْمَرًا كَانَ يَذْكُرُهُ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِ وَعَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Ishaq] telah mengabarkan kepada kami [Abdurrazaq] telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari ['Urwah] dari [Aisyah] radliallahu 'anha, ia berkata; Rasulullah shallallahu 'alaihi wasallam memerintahkan membunuh lima binatang pengganggu di luar tanah haram maupun di tanah haram, yaitu; burung elang, gagak, tikus, kalajengking, dan anjing buas.\" Abdullah mengatakan; \"anjing buas, \" sedangkan sebagian yang lain mengatakan; \"Anjing hitam.\" Telah mengabarkan kepada kami [Abdurrazaq], ia berkata; [sebagian sahabat kami] mengatakan bahwa [Ma'mar] menyebutkannya dari [Az Zuhri] dari [Salim] dari [Ayahnya] dan dari ['Urwah] dari ['Aisyah] radliallahu 'anha dari Nabi shallallahu 'alaihi wasallam.\""},"1396":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ اللَّهِ بْنِ عُثْمَانَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَ احْتَجَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ مُحْرِمٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Abdullah bin Utsman] dari [Sa'id bin Jubair] dari [Ibnu Abbas], ia berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah berbekam ketika sedang ihram.\""},"1397":{"ar":" حَدَّثَنَا مَرْوَانُ بْنُ مُحَمَّدٍ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ حَدَّثَنَا عَلْقَمَةُ بْنُ أَبِي عَلْقَمَةَ عَنْ عَبْدِ الرَّحْمَنِ الْأَعْرَجِ عَنْ عَبْدِ اللَّهِ ابْنِ بُحَيْنَةَ قَالَ احْتَجَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِلَحْيِ جَمَلٍ وَهُوَ مُحْرِمٌ","id":"Telah menceritakan kepada kami [Marwan bin Muhammad] telah menceritakan kepada kami [Sulaiman bin Bilal] telah menceritakan kepada kami ['Alqamah bin Abu 'Alqamah] dari [Abdurrahman Al A'raj] dari [Abdullah bin Buhainah], ia berkata; Rasulullah shallallahu 'alaihi wasallam pernah berbekam di Lahyi Jamal ketika beliau sedang berihram.\""},"1398":{"ar":" حَدَّثَنَا إِسْحَقُ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ عَطَاءٍ وَطَاوُسٍ عَنْ ابْنِ عَبَّاسٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ احْتَجَمَ وَهُوَ مُحْرِمٌ قَالَ إِسْحَقُ قَالَ سُفْيَانُ مَرَّةً عَنْ عَطَاءٍ وَمَرَّةً عَنْ طَاوُسٍ وَجَمَعَهُمَا مَرَّةً","id":"Telah menceritakan kepada kami [Ishaq] telah menceritakan kepada kami [Sufyan] dari ['Amr] dari [Atha`] dan [Thawus] dari [Ibnu Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam berbekam ketika sedang ihram.\" [Ishaq] berkata; [Sufyan] mengatakan sesekali dari 'Atha` dan sesekali dari Thawus dan sesekali menggabungkan keduanya.\""},"1399":{"ar":" حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ جَابِرِ بْنِ زَيْدٍ عَنْ ابْنِ عَبَّاسٍ قَالَ تَزَوَّجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ مُحْرِمٌ","id":"Telah menceritakan kepada kami [Hasyim bin Al Qasim] telah menceritakan kepada kami [Syu'bah] dari ['Amru bin Dinar] dari [Jabir bin Zaid] dari [Ibnu Abbas], ia berkata; Nabi shallallahu 'alaihi wasallam menikah ketika sedang berihram.\""},"1400":{"ar":" حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ نُبَيْهِ بْنِ وَهْبٍ أَنَّ رَجُلًا مِنْ قُرَيْشٍ خَطَبَ إِلَى أَبَانَ بْنِ عُثْمَانَ وَهُوَ أَمِيرُ الْمَوْسِمِ فَقَالَ أَبَانُ لَا أُرَاهُ عِرَاقِيًّا جَافِيًا إِنَّ الْمُحْرِمَ لَا يَنْكِحُ وَلَا يُنْكِحُ أَخْبَرَنَا بِذَلِكَ عُثْمَانُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ أَبُو مُحَمَّد تَقُولُ بِهَذَا قَالَ نَعَمْ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Nafi'] dari [Nubaih bin Wahb] bahwa seorang laki-laki Quraisy mengajukan lamaran kepada [Aban bin Utsman] -dia adalah seorang pemandu haji pada musim itu- Aban berkata; \"Saya tidak menganggapmu seorang badui tulen, sesungguhnya orang yang berihram tidak boleh menikah dan menikahkan.\" [Utsman] telah mengabarkan hal itu kepada kami, dari Rasulullah shallallahu 'alaihi wasallam. Ketika Abu Muhammad ditanya; \"Apakah kamu berpendapat seperti itu? Ia menjawab; \"Ya.\""},"1401":{"ar":" حَدَّثَنَا عَمْرُو بْنُ عَاصِمٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ حَبِيبِ بْنِ الشَّهِيدِ عَنْ مَيْمُونِ بْنِ مِهْرَانَ عَنْ يَزِيدَ بْنِ الْأَصَمِّ أَنَّ مَيْمُونَةَ قَالَتْ تَزَوَّجَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ حَلَالَانِ بَعْدَمَا رَجَعَ مِنْ مَكَّةَ بِسَرِفَ","id":"Telah menceritakan kepada kami ['Amr bin 'Ashim] telah menceritakan kepada kami [Hammad bin Salamah] dari [Habib bin Asy Syahid] dari [Maimun bin Mahran] dari [Yazid bin Al Asham] bahwa [Maimunah] berkata; \"Rasulullah shallallahu 'alaihi wasallam menikahiku ketika kami dalam keadaan halal (idak sedang berihram), kembalinya beliau dari Makkah yaitu tepatnya di daerah Sarif.\""},"1402":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ مَطَرٍ الْوَرَّاقِ عَنْ رَبِيعَةَ بْنِ أَبِي عَبْدِ الرَّحْمَنِ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ أَبِي رَافِعٍ قَالَ تَزَوَّجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَيْمُونَةَ حَلَالًا وَبَنَى بِهَا حَلَالًا وَكُنْتُ الرَّسُولَ بَيْنَهُمَا","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Hammad bin Zaid] dari [Mathar Al Warraq] dari [Rabi'ah bin Abu Abdurrahman] dari [Sulaiman bin Yasar] dari [Abu Rafi'], ia berkata; Rasulullah shallallahu 'alaihi wasallam menikahi Maimunah ketika dalam keadaan halal (tidak berihram), dan beliau mencampurinya dalam keadaan halal (tidak berihram), sementara saya-lah utusan (perantara) antara keduanya.\""},"1403":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا هِشَامٌ الدَّسْتَوَائِيُّ عَنْ يَحْيَى عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ قَالَ انْطَلَقَ أَبِي مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَ الْحُدَيْبِيَةِ فَأَحْرَمَ أَصْحَابُهُ وَلَمْ يُحْرِمْ أَبُو قَتَادَةَ فَأَصَابَ حِمَارَ وَحْشٍ فَطَعَنَهُ وَأَكَلَ مِنْ لَحْمِهِ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنِّي أَصَبْتُ حِمَارَ وَحْشٍ فَطَعَنْتُهُ فَقَالَ لِلْقَوْمِ كُلُوا وَهُمْ مُحْرِمُونَ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah menceritakan kepada kami [Hisyam Ad Dastawai] dari [Yahya] dari [Abdullah bin Abu Qatadah], ia berkata; \"Ayahku pergi bersama Nabi shallallahu 'alaihi wasallam pada saat terjadinya perdamaian Hudaibiyah, beberapa sahabat kemudian berihram, sedangkan Abu Qatadah tidak berihram. Lalu ia mendapatkan seekor keledai liar, dan ia menusuknya serta memakan sebagian dagingnya. kemudian saya mengatakan; \"Wahai Rasulullah, sesungguhnya saya telah mendapatkan keledai liar, lalu saya menusuknya (menyembelihnya).\" beliau kemudian berkata kepada para sahabatnya; \"Makanlah!.\" Padahal mereka sedang berihram.\""},"1404":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ عُثْمَانَ بْنِ عَبْدِ اللَّهِ بْنِ مَوْهَبٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِ قَالَ بَيْنَمَا نَحْنُ نَسِيرُ وَهُمْ مُحْرِمُونَ وَأَبُو قَتَادَةَ حَلَالٌ إِذْ رَأَيْتُ حِمَارًا فَرَكِبْتُ فَرَسًا فَأَصَبْتُهُ فَأَكَلُوا مِنْ لَحْمِهِ وَهُمْ مُحْرِمُونَ وَلَمْ آكُلْ فَأَتَوْا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلُوهُ فَقَالَ أَشَرْتُمْ قَتَلْتُمْ أَوْ قَالَ ضَرَبْتُمْ قَالُوا لَا قَالَ فَكُلُوا","id":"Telah mengabarkan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah] dari [Utsman bin Abdullah bin Mauhab] dari [Abdullah bin Abu Qatadah] dari [ayahnya], ia berkata; \"Ketika kami berjalan, sementara para sahabat yang lain sedang berihram, -ketika itu Abu Qatadah tidak berihram- tiba-tiba saya melihat seekor keledai, saya langsung menunggang kudaku dan menangkap keledai tersebut.\" Kemudian para sahabat ikut makan dagingnya, padahal mereka sedang berihram, sementara aku tidak memakannya. Lalu mereka datang kepada Nabi shallallahu 'alaihi wasallam dan menanyakan hal itu kepada beliau, beliau bersabda: \"Apakah kalian menangkapnya lalu membunuhnya?\" Atau beliau bersabda: \"Apakah kalian memukulnya?\" Mereka mengatakan; \"Tidak.\" Beliau bersabda; \"Makanlah.\""},"1405":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ صَالِحِ بْنِ كَيْسَانَ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ عَنْ الصَّعْبِ بْنِ جَثَّامَةَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُتِيَ بِلَحْمِ حِمَارِ وَحْشٍ فَرَدَّهُ وَقَالَ إِنَّا حُرُمٌ لَا نَأْكُلُ الصَّيْدَ","id":"Telah mengabarkan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Hammad bin Zaid] dari [Shalih bin Kaisan] dari ['Ubaidullah bin Abdullah] dari [Ibnu Abbas] dari [Ash Sha'b bin Jatstsamah] bahwa Nabi shallallahu 'alaihi wasallam pernah diberi daging keledai liar, kemudian beliau menolaknya sambil mengatakan: \"Sesungguhnya kami sedang berihram, dan tidak makan daging hewan buruan.\""},"1406":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ عَنْ ابْنِ الْمُنْكَدِرِ عَنْ مُعَاذِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عُثْمَانَ التَّيْمِيِّ عَنْ أَبِيهِ قَالَ كُنَّا مَعَ طَلْحَةَ بْنِ عُبَيْدِ اللَّهِ فِي سَفَرٍ فَأُهْدِيَ لَهُ طَيْرٌ وَهُمْ مُحْرِمُونَ وَهُوَ رَاقِدٌ فَمِنَّا مَنْ أَكَلَ وَمِنَّا مَنْ تَوَرَّعَ فَاسْتَيْقَظَ طَلْحَةُ فَأَخْبَرُوهُ فَوَفَّقَ مَنْ أَكَلَهُ وَقَالَ أَكَلْنَاهُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Abu 'Ashim] dari [Ibnu Juraij] dari [Ibnu Al Munkadir] dari [Mu'adz bin Abdurrahman bin Utsman At Taimi] dari [Ayahnya], ia berkata; Kami pernah bersama [Thalhah bin 'Ubaidullah] dalam suatu perjalanan, kemudian ia diberi hadiah (daging) seekor burung, sementara orang-orang sedang berihram -Ketika itu ia sedang tidur- Lantas diantara kami ada yang memakannya dan ada yang tidak memakannya. Ketika Abu Thalhah terbangun, mereka memberitahukan hal tersebut kepadanya, ternyata dia membenarkan orang yang memakannya dan berkata; \"Kami pernah memakannya bersama Rasulullah shallallahu 'alaihi wasallam.\""},"1407":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ حَدَّثَنِي الصَّعْبُ بْنُ جَثَّامَةَ قَالَ مَرَّ بِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا بِالْأَبْوَاءِ أَوْ بِوَدَّانَ فَأَهْدَيْتُ لَهُ لَحْمَ حِمَارِ وَحْشٍ فَرَدَّهُ عَلَيَّ فَلَمَّا رَأَى فِي وَجْهِي الْكَرَاهِيَةَ قَالَ إِنَّهُ لَيْسَ بِنَا رَدٌّ عَلَيْكَ وَلَكِنَّا حُرُمٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Ibnu 'Uyainah] dari [Az Zuhri] dari ['Ubaidullah bin Abdullah] dari [Ibnu Abbas] telah menceritakan kepadaku [Ash Sha'b bin Jatstsamah], ia berkata; Rasulullah shallallahu 'alaihi wasallam pernah melewatiku ketika aku berada di Abwa` atau di Waddan, kemudian aku menghadiahkan daging keledai liar kepada beliau, namun beliau menolaknya, ketika beliau melihat ketidak senangan pada rona mukaku, beliau bersabda: \"Sesungguhnya kami tidak bermaksud untuk menolak pemberianmu, akan tetapi kami sedang berihram.\""},"1408":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الرَّقَاشِيُّ حَدَّثَنَا وُهَيْبٌ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ ابْنِ عَبَّاسٍ عَنْ الْفَضْلِ بْنِ عَبَّاسٍ أَنَّهُ كَانَ رَدِيفَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَجَّةِ الْوَدَاعِ جَاءَتْ امْرَأَةٌ مِنْ خَثْعَمَ فَقَالَتْ إِنَّ فَرِيضَةَ اللَّهِ فِي الْحَجِّ عَلَى عِبَادِهِ أَدْرَكَتْ أَبِي شَيْخًا كَبِيرًا لَا يَسْتَمْسِكُ عَلَى رَاحِلَتِهِ وَلَمْ يَحُجَّ أَفَأَحُجُّ عَنْهُ قَالَ نَعَمْ سُئِلَ أَبُو مُحَمَّد تَقُولُ بِهَذَا قَالَ نَعَمْ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah Ar Raqasyi] telah menceritakan kepada kami [Wuhaib] dari [Ma'mar] dari [Az Zuhri] dari [Sulaiman bin Yasar] dari [Ibnu Abbas] dari [Al Fadhl bin Abbas] bahwa ketika ia membonceng Nabi shallallahu 'alaihi wasallam saat haji wada', seorang wanita dari Khats'am datang seraya berkata; \"Sesungguhnya kewajiban haji telah Allah wajibkan kepada para hambanya, sementara ayahku sudah tua renta, tidak mampu berada di atas kendaraan dan belum melakukan haji, apakah saya boleh berhaji untuknya?\" Beliau bersabda: \"Ya.\" Abu Muhammad ditanya; \"Apakah kamu berpendapat dengan hadits ini? Ia menjawab; \"Ya.\""},"1409":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ عَنْ ابْنِ شِهَابٍ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ ابْنِ عَبَّاسٍ عَنْ الْفَضْلِ هُوَ ابْنُ عَبَّاسٍ أَنَّ امْرَأَةً سَأَلَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ إِنَّ أَبِي شَيْخٌ لَا يَسْتَوِي عَلَى الْبَعِيرِ أَدْرَكَتْهُ فَرِيضَةُ اللَّهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حُجِّي عَنْهُ","id":"Telah mengabarkan kepada kami [Abu 'Ashim] dari [Ibnu Juraij] dari [Ibnu Syihab] dari [Sulaiman bin Yasar] dari [Ibnu Abbas] dari [Al Fadhl yaitu Ibnu Abbas] bahwa seorang wanita bertanya kepada Nabi shallallahu 'alaihi wasallam, katanya; \"Sesungguhnya kewajiban Allah yaitu berhaji telah mengenai ayahku yang sudah tua, sementara dirinya tidak mampu lagi tegak di atas kendaraannya, \" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berhajilah untuknya.\""},"1410":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنِي الزُّهْرِيُّ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ ابْنِ عَبَّاسٍ أَنَّ امْرَأَةً مِنْ خَثْعَمَ اسْتَفْتَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَجَّةِ الْوَدَاعِ وَالْفَضْلُ بْنُ عَبَّاسٍ رَدِيفُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّ فَرِيضَةَ اللَّهِ عَلَى عِبَادِهِ أَدْرَكَتْ أَبِي شَيْخًا كَبِيرًا لَا يَسْتَطِيعُ أَنْ يَسْتَوِيَ عَلَى الرَّاحِلَةِ فَهَلْ يَقْضِي أَنْ أَحُجَّ عَنْهُ قَالَ نَعَمْ حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوًا مِنْ حَدِيثِ الْأَوْزَاعِيِّ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Al Auza'i] telah menceritakan kepadaku [Az Zuhri] dari [Sulaiman bin Yasar] dari [Ibnu Abbas] bahwa seorang wanita dari Khats'am meminta fatwa kepada Rasulullah shallallahu 'alaihi wasallam ketika haji wada', sementara Al Fadhl bin Abbas membonceng (dibelakang) Rasulullah shallallahu 'alaihi wasallam, wanita itu berkata; \"Wahai Rasulullah, sesungguhnya kewajiban haji yang Allah wajibkan kepada para hambaNya telah mengenai ayahku yang tua renta, sementara dia tidak mampu berada tegak di atas kendaraan, apakah aku dapat menggantikan haji untuknya?\" Beliau menjawab: \"Ya.\" Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Ibnu 'Uyainah] dari [Az Zuhri] dari [Sulaiman bin Yasar] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam seperti haditsnya Al Auza'i."},"1411":{"ar":" حَدَّثَنَا مُسَدَّدٌ أَخْبَرَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ يَحْيَى بْنِ أَبِي إِسْحَقَ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ حَدَّثَنِي الْفَضْلُ بْنُ عَبَّاسٍ أَوْ عُبَيْدُ اللَّهِ بْنُ الْعَبَّاسِ أَنَّ رَجُلًا قَالَ يَا رَسُولَ اللَّهِ إِنَّ أَبِي أَوْ أُمِّي عَجُوزٌ كَبِيرٌ إِنْ أَنَا حَمَلْتُهَا لَمْ تَسْتَمْسِكْ وَإِنْ رَبَطْتُهَا خَشِيتُ أَنْ أَقْتُلَهَا قَالَ أَرَأَيْتَ إِنْ كَانَ عَلَى أَبِيكَ أَوْ أُمِّكَ دَيْنٌ أَكُنْتَ تَقْضِيهِ قَالَ نَعَمْ قَالَ فَحُجَّ عَنْ أَبِيكَ أَوْ أُمِّكَ قِيلَ لِعَبْدِ اللَّهِ الْحَجُّ عَنْ الْحَيِّ قَالَ إِذَا لَزِمَهُ قِيلَ لَهُ تَقُولُ بِحَدِيثِ الْفَضْلِ بْنِ الْعَبَّاسِ قَالَ نَعَمْ","id":"Telah menceritakan kepada kami [Musaddad] telah mengabarkan kepada kami [Hammad bin Zaid] dari [Yahya bin Abu Ishaq] dari [Sulaiman bin Yasar], telah menceritakan kepadaku [Al Fadhl bin Abbas] atau ['Ubaidullah bin Al Abbas] bahwa seorang laki-laki berkata; \"Wahai Rasulullah, sesungguhnya ayahku -atau ibuku- telah lanjut usia, apabila saya menggendongnya (diatas kendaraan), ia tidak akan mampu bertahan lama, jika aku mengikatnya, aku khawatir akan membunuhnya.\" Beliau bertanya: \"Bagaimana pendapatmu apabila ayahmu atau ibumu memiliki hutang, apakah engkau akan membayarnya?\" Ia berkata; \"Ya.\" Beliau bersabda: \"Berhajilah untuk ayah atau ibumu.\" Abdullah ditanya; \"Apakah diperbolehkan haji untuk orang yang hidup?\" Ia berkata; \"Apabila haji tersebut wajib atasnya.\" Ditanyakan pula kepadanya; \"Apakah kamu berpendapat dengan hadits Al Fadhl bin Al Abbas? Dia menjawab; \"Ya.\""},"1412":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ حُمَيْدٍ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ مُجَاهِدٍ عَنْ يُوسُفَ بْنِ الزُّبَيْرِ مَوْلًى لِآلِ الْزُّبَيْرِ عَنْ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ قَالَ جَاءَ رَجُلٌ مِنْ خَثْعَمَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ أَبِي أَدْرَكَهُ الْإِسْلَامُ وَهُوَ شَيْخٌ كَبِيرٌ لَا يَسْتَطِيعُ رُكُوبَ الرَّحْلِ وَالْحَجُّ مَكْتُوبٌ عَلَيْهِ أَفَأَحُجُّ عَنْهُ قَالَ أَنْتَ أَكْبَرُ وَلَدِهِ قَالَ نَعَمْ قَالَ أَرَأَيْتَ لَوْ كَانَ عَلَى أَبِيكَ دَيْنٌ فَقَضَيْتَهُ عَنْهُ أَكَانَ ذَلِكَ يُجْزِئُ عَنْهُ قَالَ نَعَمْ قَالَ فَاحْجُجْ عَنْهُ","id":"Telah menceritakan kepada kami [Muhammad bin Humaid] telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Mujahid] dari [Yusuf bin Az Zubair] mantan budak keluarga Az Zubair dari [Abdullah bin Az Zubair], ia berkata; \"Seorang laki-laki dari Khats'am datang kepada Rasulullah shallallahu 'alaihi wasallam, katanya; \"Sesungguhnya ayahku masuk Islam ketika sudah tua dan tidak lagi mampu mengendarai kendaraan, sementara kewajiban haji telah wajib atas dirinya, apakah saya boleh berhaji untuknya?\" Beliau bertanya: \"Apakah kamu anaknya yang paling tua?\" laki-laki tiu menjawab; \"Ya.\" Beliau bersabda: \"Bagaimana pendapatmu seandainya ayahmu memiliki hutang, kemudian kamu melunasinya?, apakah hal itu sah baginya?\" laki-laki itu menjawab; \"Ya.\" Beliau bersabda: \"Berhajilah untuknya.\""},"1413":{"ar":" أَخْبَرَنَا صَالِحُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا عَبْدُ الْعَزِيزِ هُوَ ابْنُ عَبْدِ الصَّمَدِ عَنْ مَنْصُورٍ عَنْ مُجَاهِدٍ عَنْ مَوْلَى ابْنِ الزُّبَيْرِ يُقَالُ لَهُ يُوسُفُ بْنُ الزُّبَيْرِ أَوْ الزُّبَيْرُ بْنُ يُوسُفَ عَنْ سَوْدَةَ بِنْتِ زَمْعَةَ قَالَتْ جَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ أَبِي شَيْخٌ كَبِيرٌ لَا يَسْتَطِيعُ أَنْ يَحُجَّ قَالَ أَرَأَيْتَ لَوْ كَانَ عَلَى أَبِيكَ دَيْنٌ فَقَضَيْتَهُ عَنْهُ قُبِلَ مِنْهُ قَالَ نَعَمْ قَالَ اللَّهُ أَرْحَمُ حُجَّ عَنْ أَبِيكَ","id":"Telah mengabarkan kepada kami [Shalih bin Abdullah] telah menceritakan kepada kami [Abdul Aziz yaitu Ibnu Abdusshamad] dari [Manshur] dari [Mujahid] dari mantan budak Ibnu Az Zubair yang disebut [Yusuf bin Az Zubair] atau Az Zubair bin Yusuf dari [Saudah binti Zam'ah], ia berkata; \"Seorang laki-laki datang kepada Nabi shallallahu 'alaihi wasallam seraya berkata; \"Sesungguhnya ayahku telah lanjut usia dan tidak mampu untuk berhaji.\" Beliau bersabda: \"Bagaimana pendapatmu seandainya ayahmu memiliki hutang, kemudian kamu melunasinya, apakah hal itu diterima?\" Ia berkata; \"Ya.\" Beliau bersabda: \" Allah lebih pemurah, berhajilah untuk ayahmu.\""},"1414":{"ar":" حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَ مَا تَرَكْتُ اسْتِلَامَ هَذَيْنِ الرُّكْنَيْنِ فِي شِدَّةٍ وَلَا رَخَاءٍ مُنْذُ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْتَلِمُهُمَا قُلْتُ لِنَافِعٍ أَكَانَ ابْنُ عُمَرَ يَمْشِي بَيْنَ الرُّكْنَيْنِ قَالَ إِنَّمَا كَانَ يَمْشِي لِيَكُونَ أَيْسَرَ لِاسْتِلَامِهِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar], ia berkata; \"Saya tidak meninggalkan untuk menyentuh dua rukun ini walau dalam keadaan sulit maupun mudah, semenjak saya melihat Rasulullah shallallahu 'alaihi wasallam menyentuh keduanya.\" Saya bertanya kepada Nafi'; \"Apakah Ibnu Umar berjalan diantara kedua rukun tersebut?\" Ia menjawab; \"Sesungguhnya Ibnu Umar berjalan agar lebih mudah untuk menyentuhnya.\""},"1415":{"ar":" حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ وَسُلَيْمَانُ بْنُ حَرْبٍ قَالَا حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُثْمَانَ بْنِ خُثَيْمٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيَبْعَثَنَّ اللَّهُ الْحَجَرَ يَوْمَ الْقِيَامَةِ وَلَهُ عَيْنَانِ يُبْصِرُ بِهِمَا وَلِسَانٌ يَنْطِقُ بِهِ يَشْهَدُ عَلَى مَنْ اسْتَلَمَهُ بِحَقٍّ قَالَ سُلَيْمَانُ لِمَنْ اسْتَلَمَهُ","id":"Telah menceritakan kepada kami [Hajjaj bin Minhal] dan [Sulaiman bin Harb] keduanya berkata; telah menceritakan kepada kami [Hammad bin Salamah] telah menceritakan kepada kami [Abdullah bin Utsman bin Khutsaim] dari [Sa'id bin Jubair] dari [Ibnu Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh Allah akan membangkitkan Hajar Aswad pada Hari Kiamat dalam keadaan memiliki dua mata untuk melihat dan lidah untuk berbicara, ia memberikan persaksian atas orang yang menyentuhnya dengan benar.\" [Sulaiman] mengatakan; \"Bagi orang yang menyentuhnya.\""},"1416":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ جَعْفَرِ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ جَابِرٍ قَالَ رَمَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْحَجَرِ إِلَى الْحَجَرِ ثَلَاثَةَ أَشْوَاطٍ","id":"Telah mengabarkan kepada kami [Ahmad bin Abdullah] telah menceritakan kepada kami [Malik bin Anas] dari [Ja'far bin Muhammad] dari [Ayahnya] dari [Jabir], ia berkata; Rasulullah shallallahu 'alaihi wasallam berjalan dengan langkah cepat dari Hajar Aswad ke Hajar Aswad (lagi) sebanyak tiga kali putaran.\""},"1417":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا عُقْبَةُ بْنُ خَالِدٍ حَدَّثَنَا عُبَيْدُ اللَّهِ حَدَّثَنِي نَافِعٌ عَنْ ابْنِ عُمَرَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا طَافَ بِالْبَيْتِ الطَّوَافَ الْأَوَّلَ خَبَّ ثَلَاثَةً وَمَشَى أَرْبَعَةً وَكَانَ يَسْعَى بِبَطْنِ الْمَسِيلِ إِذَا سَعَى بَيْنَ الصَّفَا وَالْمَرْوَةِ فَقُلْتُ لِنَافِعٍ أَكَانَ عَبْدُ اللَّهِ يَمْشِي إِذَا بَلَغَ الرُّكْنَ الْيَمَانِيَ قَالَ لَا إِلَّا أَنْ يُزَاحَمَ عَلَى الرُّكْنِ فَإِنَّهُ كَانَ لَا يَدَعُهُ حَتَّى يَسْتَلِمَهُ","id":"Telah menceritakan kepada kami [Abdullah bin Sa'id] telah menceritakan kepada kami ['Uqbah bin Khalid] telah menceritakan kepada kami ['Ubaidullah] telah menceritakan kepadaku [Nafi'] dari [Ibnu Umar] bahwa Apabila Rasulullah shallallahu 'alaihi wasallam melakukan thawaf pertama di Ka'bah, beliau berjalan dengan langkah cepat sebanyak tiga putaran, berjalan biasa sebanyak empat kali putaran dan berlari-lari kecil antara Shafa dan Marwah di perut lembah.\" Lalu aku bertanya kepada Nafi'; \"Apakah Abdullah berjalan apabila ia sampai di Rukun Yamani?\" Nafi' menjawab; \"Tidak, kecuali apabila keadaan di Rukun Yamani ramai (berdesakan), sesungguhnya ia tidak meninggalkan Rukun tersebut hingga menyentuhnya.\""},"1418":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُمَرَ بْنِ أَبَانَ حَدَّ��َنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَ رَمَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْحَجَرِ إِلَى الْحَجَرِ ثَلَاثًا وَمَشَى أَرْبَعًا","id":"Telah menceritakan kepada kami [Abdullah bin Umar bin Aban] telah menceritakan kepada kami [Abdullah bin Al Mubarak] telah mengabarkan kepada kami ['Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar], ia berkata; Rasulullah shallallahu 'alaihi wasallam berjalan cepat dari Hajar Aswad ke Hajar Aswad (lagi) sebanyak tiga kali putaran dan berjalan biasa sebanyak empat kali putaran.\""},"1419":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ جُرَيْجٍ عَنْ عَبْدِ الْحَمِيدِ هُوَ ابْنُ جُبَيْرٍ عَنْ ابْنِ يَعْلَى عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ طَافَ مُضْطَبِعًا","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Ibnu Juraij] dari [Abdul Hamid yaitu Ibnu Jubair] dari [Ibnu Ya'la] dari [Ayahnya] dari Nabi shallallahu 'alaihi wasallam bahwa beliau melakukan thawaf dengan menyelendangkan kain ihramnya dari bawah ketiak kanan hingga menutupi pundak kirinya.\""},"1420":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَهَلَّ بِالْحَجِّ وَالْعُمْرَةِ كَفَاهُ لَهُمَا طَوَافٌ وَاحِدٌ وَلَا يَحِلُّ حَتَّى يَحِلَّ مِنْهُمَا","id":"Telah mengabarkan kepada kami [Sa'id bin Manshur] telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari ['Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menggabungkan haji dan umrah, maka baginya cukup thawaf sekali, dan dia belum di anggap halal (masih dalam keadaan ihram) hingga ia selesai bertahallaul untuk haji dan Umrah.\""},"1421":{"ar":" أَخْبَرَنَا عَمْرُو بْنُ عَوْنٍ عَنْ خَالِدِ بْنِ عَبْدِ اللَّهِ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَافَ بِالْبَيْتِ عَلَى بَعِيرٍ كُلَّمَا أَتَى عَلَى الرُّكْنِ أَشَارَ إِلَيْهِ بِشَيْءٍ فِي يَدِهِ وَكَبَّرَ","id":"Telah mengabarkan kepada kami ['Amr bin 'Aun] dari [Khalid bin Abdullah] dari [Khalid Al Hadzdza`] dari [Ikrimah] dari [Ibnu Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam thawaf mengelilingi Ka'bah di atas untanya, setiap kali beliau sampai ke Rukun, beliau memberi isyarat kepadanya dengan sesuatu yang ada di tangannya sambil bertakbir.\""},"1422":{"ar":" أَخْبَرَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا مَالِكٌ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْ قَدِمْتُ مَكَّةَ وَأَنَا حَائِضٌ وَلَمْ أَطُفْ بَيْنَ الصَّفَا وَالْمَرْوَةِ فَشَكَوْتُ ذَلِكَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ افْعَلِي مَا يَفْعَلُ الْحَاجُّ غَيْرَ أَنْ لَا تَطُوفِي بِالْبَيْتِ","id":"Telah mengabarkan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Malik] dari [Abdurrahman bin Al Qasim] dari [Ayahnya] dari ['Aisyah] radliallahu 'anha, ia berkata; \"Setibanya di Makkah, aku dalam keadaan haid, dan belum melakukan thawaf antara Shafa dan Marwah, lalu aku mengadukan hal itu kepada Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Lakukanlah sebagaimana yang dilakukan orang yang berhaji, hanya saja kamu jangan thawaf di Ka'bah.\""},"1423":{"ar":" أَخْبَرَنَا الْحُمَيْدِيُّ حَدَّثَنَا الْفُضَيْلُ بْنُ عِيَاضٍ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الطَّوَافُ بِالْبَيْتِ صَلَاةٌ إِلَّا أَنَّ اللَّهَ أَحَلَّ فِيهِ الْمَنْطِقَ فَمَنْ نَطَقَ فِيهِ فَلَا يَنْطِقْ إِلَّا بِخَيْرٍ أَخْبَرَنَا عَلِيُّ بْنُ مَعْبَدٍ عَنْ مُوسَى بْنِ أَعْيَنَ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah mengabarkan kepada kami [Al Humaidi] telah menceritakan kepada kami [Al Fudhail bin 'Iyadh] dari ['Atha` bin As Sa`ib] dari [Thawus] dari [Ibnu Abbas], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Thawaf mengelilingi Ka'bah adalah shalat, hanya saja Allah memperbolehkan berbicara ketika melakukannya, barangsiapa berbicara disaat melakukan thawaf, maka janganlah ia berbicara kecuali yang baik.\" Telah mengabarkan kepada kami [Ali bin Ma'bad] dari [Musa bin A'yan] dari [Atha` bin As Sa`ib] dari [Thawus] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam seperti hadits di atas."},"1424":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا حُمَيْدٌ عَنْ أَنَسٍ قَالَ قَالَ عُمَرُ بْنُ الْخَطَّابِ وَافَقْتُ رَبِّي فِي ثَلَاثٍ قُلْتُ يَا رَسُولَ اللَّهِ لَوْ اتَّخَذْتَ مِنْ مَقَامِ إِبْرَاهِيمَ مُصَلًّى فَأَنْزَلَ اللَّهُ تَعَالَى { وَاتَّخِذُوا مِنْ مَقَامِ إِبْرَاهِيمَ مُصَلًّى }","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah menceritakan kepada kami [Humaid] dari [Anas], ia berkata; [Umar bin Al Khathab] berkata; \"Rabbku menyepakatiku dalam tiga perkara, yaitu; ketika saya mengatakan; \"Wahai Rasulullah, seandainya anda menjadikan Maqam Ibrahim sebagai tempat shalat maka itu akan lebih baik, kemudian Allah Ta'ala menurunkan ayat: WATTAKHIDZUU MIN MAQAAMI IBRAAHIIMA MUSHALLAA (Dan jadikanlah sebahagian maqam Ibrahim tempat shalat). QS Al Baqarah; 125."},"1425":{"ar":" أَخْبَرَنَا إِسْمَعِيلُ بْنُ أَبَانَ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ عَنْ جَعْفَرِ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَ أَبُو جَعْفَرٍ دَخَلْنَا عَلَى جَابِرِ بْنِ عَبْدِ اللَّهِ فَسَأَلَ عَنْ الْقَوْمِ حَتَّى انْتَهَى إِلَيَّ فَقُلْتُ أَنَا مُحَمَّدُ بْنُ عَلِيِّ بْنِ الْحُسَيْنِ بْنِ عَلِيٍّ فَأَهْوَى بِيَدِهِ إِلَى زِرِّيَ الْأَعْلَى وَزِرِّيَ الْأَسْفَلِ ثُمَّ وَضَعَ فَمَهُ بَيْنَ ثَدْيَيَّ وَأَنَا يَوْمَئِذٍ غُلَامٌ شَابٌّ فَقَالَ مَرْحَبًا بِكَ يَا ابْنَ أَخِي سَلْ عَمَّا شِئْتَ فَسَأَلْتُهُ وَهُوَ أَعْمَى وَجَاءَ وَقْتُ الصَّلَاةِ فَقَامَ فِي سَاجَةٍ مُلْتَحِفًا بِهَا كُلَّمَا وَضَعَهَا عَلَى مَنْكِبَيْهِ رَجَعَ طَرَفُهَا إِلَيْهِ مِنْ صِغَرِهَا وَرِدَاؤُهُ إِلَى جَنْبِهِ عَلَى الْمِشْجَبِ فَصَلَّى فَقُلْتُ أَخْبِرْنِي عَنْ حَجَّةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ بِيَدِهِ فَعَقَدَ تِسْعًا فَقَالَ مَكَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تِسْعَ سِنِينَ لَمْ يَحُجَّ ثُمَّ أُذِّنَ فِي النَّاسِ بِالْحَجِّ فِي الْعَاشِرَةِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَاجٌّ فَقَدِمَ الْمَدِينَةَ بَشَرٌ كَثِيرٌ كُلُّهُمْ يَلْتَمِسُ أَنْ يَأْتَمَّ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَيَعْمَلَ مِثْلَ عَمَلِهِ فَخَرَجْنَا مَعَهُ حَتَّى أَتَيْنَا ذَا الْحُلَيْفَةِ فَوَلَدَتْ أَسْمَاءُ بِنْتُ عُمَيْسٍ مُحَمَّدَ بْنَ أَبِي بَكْرٍ فَأَرْسَلَتْ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَيْفَ أَصْنَعُ فَقَالَ اغْتَسِلِي وَاسْتَثْفِرِي بِثَوْبٍ وَأَحْرِمِي فَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمَسْجِدِ ثُمَّ رَكِبَ الْقَصْوَاءَ حَتَّى اسْتَوَتْ بِهِ نَاقَتُهُ عَلَى الْبَيْدَاءِ فَنَظَرْتُ إِلَى مَدِّ بَصَرِي مِنْ بَيْنِ يَدَيْهِ مِنْ رَاكِبٍ وَمَاشٍ وَعَنْ يَمِينِهِ مِثْلُ ذَلِكَ وَعَنْ يَسَارِهِ مِثْلُ ذَلِكَ وَخَلْفَهُ مِثْلُ ذَلِكَ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ أَظْهُرِنَا وَعَلَيْهِ يُنْزَلُ الْقُرْآنُ وَهُوَ يَعْرِفُ تَأْوِيلَهُ فَأَهَلَّ بِالتَّوْحِيدِ لَبَّيْكَ اللَّهُمَّ لَبَّيْكَ لَبَّيْكَ لَا شَرِيكَ لَكَ لَبَّيْكَ إِنَّ الْحَمْدَ وَالنِّعْمَةَ لَكَ وَالْمُلْكَ لَا شَرِيكَ لَكَ فَأَهَلَّ النَّاسُ بِهَذَا الَّذِي يُهِلُّونَ بِهِ فَلَمْ يَزِدْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْهِمْ شَيْئًا وَلَبَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَلْبِيَتَهُ حَتَّى إِذَا أَتَيْنَا الْبَيْتَ مَعَهُ قَالَ جَابِرٌ لَسْنَا نَنْوِي إِلَّا الْحَجَّ لَسْنَا نَعْرِفُ الْعُمْرَةَ حَتَّى إِذَا أَتَيْنَا الْبَيْتَ مَعَهُ اسْتَلَمَ الرُّكْنَ فَرَمَلَ ثَلَاثًا وَمَشَى أَرْبَعًا ثُمَّ تَقَدَّمَ إِلَى مَقَامِ إِبْرَاهِيمَ فَصَلَّى فَقَرَأَ { وَاتَّخِذُوا مِنْ مَقَامِ إِبْرَاهِيمَ مُصَلًّى } فَجَعَلَ الْمَقَامَ بَيْنَهُ وَبَيْنَ الْبَيْتِ وَكَانَ أَبِي يَقُولُ وَلَا أَعْلَمُهُ ذَكَرَهُ عَنْ جَابِرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كَانَ يَقْرَأُ فِي الرَّكْعَتَيْنِ قُلْ هُوَ اللَّهُ أَحَدٌ وَقُلْ يَا أَيُّهَا الْكَافِرُونَ ثُمَّ رَجَعَ إِلَى الرُّكْنِ فَاسْتَلَمَهُ ثُمَّ خَرَجَ مِنْ الْبَابِ إِلَى الصَّفَا فَلَمَّا أَتَى الصَّفَا قَرَأَ { إِنَّ الصَّفَا وَالْمَرْوَةَ مِنْ شَعَائِرِ اللَّهِ } أَبْدَأُ بِمَا بَدَأَ اللَّهُ بِهِ فَبَدَأَ بِالصَّفَا فَرَقِيَ عَلَيْهِ حَتَّى رَأَى الْبَيْتَ فَوَحَّدَ اللَّهَ وَكَبَّرَهُ وَقَالَ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ يُحْيِي وَيُمِيتُ وَهُوَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ أَنْجَزَ وَعْدَهُ وَنَصَرَ عَبْدَهُ وَهَزَمَ الْأَحْزَابَ وَحْدَهُ ثُمَّ دَعَا بَيْنَ ذَلِكَ فَقَالَ مِثْلَ هَذَا ثَلَاثَ مَرَّاتٍ ثُمَّ نَزَلَ إِلَى الْمَرْوَةِ حَتَّى إِذَا انْصَبَّتْ قَدَمَاهُ فِي بَطْنِ الْوَادِي قَالَ عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ الدَّارِمِيُّ يَعْنِي فَرَمَلَ حَتَّى إِذَا صَعِدْنَا مَشَى حَتَّى إِذَا أَتَيْنَا الْمَرْوَةَ فَفَعَلَ عَلَى الْمَرْوَةِ كَمَا فَعَلَ عَلَى الصَّفَا حَتَّى إِذَا كَانَ آخِرَ طَوَافٍ عَلَى الْمَرْوَةِ قَالَ إِنِّي لَوْ اسْتَقْبَلْتُ مِنْ أَمْرِي مَا اسْتَدْبَرْتُ لَمْ أَسُقْ الْهَدْيَ وَجَعَلْتُهَا عُمْرَةً فَمَنْ كَانَ مِنْكُمْ لَيْسَ مَعَهُ هَدْيٌ فَلْيُحِلَّ وَيَجْعَلْهَا عُمْرَةً فَقَامَ سُرَاقَةُ بْنُ مَالِكِ بْنِ جُعْشُمٍ فَقَالَ يَا رَسُولَ اللَّهِ أَلِعَامِنَا هَذَا أَوْ لِأَبَدِ أَبَدٍ فَشَبَكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَصَابِعَهُ فِي الْأُخْرَى فَقَالَ دَخَلَتْ الْعُمْرَةُ فِي الْحَجِّ هَكَذَا مَرَّتَيْنِ لَا بَلْ لِأَبَدِ أَبَدٍ لَا بَلْ لَأَبَدِ أَبَدٍ وَقَدِمَ عَلِيٌّ بِبُدْنٍ مِنْ الْيَمَنِ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَوَجَدَ فَاطِمَةَ مِمَّنْ حَلَّ وَلَبِسَتْ ثِيَابَ صَبِيغٍ وَاكْتَحَلَتْ فَأَنْكَرَ عَلِيٌّ ذَلِكَ عَلَيْهَا فَقَالَتْ أَبِي أَمَرَنِي فَكَانَ عَلِيٌّ يَقُولُ ذَهَبْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُحَرِّشُهُ عَلَى فَاطِمَةَ فِي الَّذِي صَنَعَتْ مُسْتَفْتِيًا لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيم��ا ذَكَرَتْ فَأَنْكَرْتُ ذَلِكَ عَلَيْهَا فَقَالَ صَدَقَتْ مَا فَعَلْتَ حِينَ فَرَضْتَ الْحَجَّ قَالَ قُلْتُ اللَّهُمَّ إِنِّي أُهِلُّ بِمَا أَهَلَّ بِهِ رَسُولُكَ قَالَ فَإِنَّ مَعِيَ الْهَدْيَ فَلَا تَحْلِلْ قَالَ فَكَانَ جَمَاعَةُ الْهَدْيِ الَّذِي قَدِمَ بِهِ عَلِيٌّ مِنْ الْيَمَنِ وَالَّذِي أَتَى بِهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِائَةَ بَدَنَةٍ فَحَلَّ النَّاسُ كُلُّهُمْ وَقَصَّرُوا إِلَّا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَنْ كَانَ مَعَهُ هَدْيٌ فَلَمَّا كَانَ يَوْمُ التَّرْوِيَةِ وَجَّهَ إِلَى مِنًى فَأَهْلَلْنَا بِالْحَجِّ وَرَكِبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى بِنَا الظُّهْرَ وَالْعَصْرَ وَالْمَغْرِبَ وَالْعِشَاءَ وَالصُّبْحَ ثُمَّ مَكَثَ قَلِيلًا حَتَّى إِذَا طَلَعَتْ الشَّمْسُ أَمَرَ بِقُبَّةٍ مِنْ شَعَرٍ تُضْرَبُ لَهُ بِنَمِرَةَ ثُمَّ رَكِبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَارَ لَا تَشُكُّ قُرَيْشٌ إِلَّا أَنَّهُ وَاقِفٌ عِنْدَ الْمَشْعَرِ الْحَرَامِ كَمَا كَانَتْ قُرَيْشٌ تَصْنَعُ فِي الْجَاهِلِيَّةِ فِي الْمُزْدَلِفَةِ فَسَارَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى أَتَى عَرَفَةَ فَوَجَدَ الْقُبَّةَ قَدْ ضُرِبَتْ بِنَمِرَةَ فَنَزَلَهَا حَتَّى إِذَا زَاغَتْ يَعْنِي الشَّمْسَ أَمَرَ بِالْقَصْوَاءِ فَرُحِّلَتْ لَهُ فَأَتَى بَطْنَ الْوَادِي فَخَطَبَ النَّاسَ وَقَالَ إِنَّ دِمَاءَكُمْ وَأَمْوَالَكُمْ حَرَامٌ كَحُرْمَةِ يَوْمِكُمْ هَذَا فِي شَهْرِكُمْ هَذَا فِي بَلَدِكُمْ هَذَا أَلَا إِنَّ كُلَّ شَيْءٍ مِنْ أَمْرِ الْجَاهِلِيَّةِ تَحْتَ قَدَمَيَّ مَوْضُوعٌ وَدِمَاءُ الْجَاهِلِيَّةِ مَوْضُوعَةٌ وَأَوَّلُ دَمٍ وُضِعَ دِمَاؤُنَا دَمُ رَبِيعَةَ بْنِ الْحَارِثِ كَانَ مُسْتَرْضَعًا فِي بَنِي سَعْدٍ فَقَتَلَتْهُ هُذَيْلٌ وَرِبَا الْجَاهِلِيَّةِ مَوْضُوعٌ وَأَوَّلُ رِبًا أَضَعُهُ رِبَا عَبَّاسِ بْنِ عَبْدِ الْمُطَّلِبِ فَإِنَّهُ مَوْضُوعٌ كُلُّهُ فَاتَّقُوا اللَّهَ فِي النِّسَاءِ فَإِنَّمَا أَخَذْتُمُوهُنَّ بِأَمَانَةِ اللَّهِ وَاسْتَحْلَلْتُمْ فُرُوجَهُنَّ بِكَلِمَةِ اللَّهِ وَإِنَّ لَكُمْ عَلَيْهِنَّ أَنْ لَا يُوطِئْنَ فُرُشَكُمْ أَحَدًا تَكْرَهُونَهُ فَإِنْ فَعَلْنَ ذَلِكَ فَاضْرِبُوهُنَّ ضَرْبًا غَيْرَ مُبَرِّحٍ وَلَهُنَّ عَلَيْكُمْ رِزْقُهُنَّ وَكِسْوَتُهُنَّ بِالْمَعْرُوفِ وَأَنْتُمْ مَسْئُولُونَ عَنِّي فَمَا أَنْتُمْ قَائِلُونَ قَالُوا نَشْهَدُ أَنَّكَ قَدْ بَلَّغْتَ وَأَدَّيْتَ وَنَصَحْتَ فَقَالَ بِأُصْبُعِهِ السَّبَّابَةِ فَرَفَعَهَا إِلَى السَّمَاءِ وَيَنْكُتُهَا إِلَى النَّاسِ اللَّهُمَّ اشْهَدْ اللَّهُمَّ اشْهَدْ اللَّهُمَّ اشْهَدْ ثُمَّ أَذَّنَ بِلَالٌ بِنِدَاءٍ وَاحِدٍ وَإِقَامَةٍ فَصَلَّى الظُّهْرَ ثُمَّ أَقَامَ فَصَلَّى الْعَصْرَ لَمْ يُصَلِّ بَيْنَهُمَا شَيْئًا ثُمَّ رَكِبَ حَتَّى وَقَفَ فَجَعَلَ بَطْنَ نَاقَتِهِ الْقَصْوَاءِ إِلَى الصُّخَيْرَاتِ وَقَالَ إِسْمَعِيلُ إِلَى الشُّجَيْرَاتِ وَجَعَلَ حَبْلَ الْمُشَاةِ بَيْنَ يَدَيْهِ ثُمَّ اسْتَقْبَلَ الْقِبْلَةَ فَلَمْ يَزَلْ وَاقِفًا حَتَّى غَرَبَتْ الشَّمْسُ وَذَهَبَتْ الصُّفْرَةُ حَتَّى غَابَ الْقُرْصُ فَأَرْدَفَ أُسَامَةَ خَلْفَهُ ثُمَّ دَفَعَ وَقَدْ شَنَقَ لِلْقَصْوَاءِ الزِّمَامَ حَتَّى إِنَّهُ لَيُصِيبُ رَأْسُهَا مَوْرِكَ رَحْلِهِ وَيَقُولُ بِيَدِهِ الْيُمْنَى السَّكِينَةَ السَّكِينَةَ كُلَّمَا أَتَى حَبْلًا مِنْ الْحِبَالِ أَرْخَى لَهَا قَلِيلًا حَتَّى تَصْعَدَ حَتَّى أَتَى الْمُزْدَلِفَةَ فَصَلَّى بِهَا الْمَغْرِبَ وَالْعِشَاءَ بِأَذَانٍ وَإِقَامَتَيْنِ ثُمَّ اضْطَجَعَ حَتَّى إِذَا طَلَعَ الْفَجْرُ صَلَّى الْفَجْرَ بِأَذَانٍ وَإِقَامَةٍ ثُمَّ رَكِبَ الْقَصْوَاءَ حَتَّى وَقَفَ عَلَى الْمَشْعَرِ الْحَرَامِ وَاسْتَقْبَلَ الْقِبْلَةَ فَدَعَا اللَّهَ وَكَبَّرَهُ وَهَلَّلَهُ وَوَحَّدَهُ حَتَّى أَسْفَرَ جِدًّا ثُمَّ دَفَعَ قَبْلَ أَنْ تَطْلُعَ الشَّمْسُ وَأَرْدَفَ الْفَضْلَ بْنَ الْعَبَّاسِ وَكَانَ رَجُلًا حَسَنَ الشَّعْرِ أَبْيَضَ وَسِيمًا فَلَمَّا دَفَعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ بِالظُّعُنِ يَجْرِينَ فَطَفِقَ الْفَضْلُ يَنْظُرُ إِلَيْهِنَّ فَأَخَذَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهُ فَوَضَعَهَا عَلَى وَجْهِ الْفَضْلِ فَحَوَّلَ الْفَضْلُ رَأْسَهُ مِنْ الشِّقِّ الْآخَرِ فَوَضَعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهُ مِنْ الشِّقِّ الْآخَرِ حَتَّى إِذَا أَتَى مُحَسِّرَ حَر","id":"Telah mengabarkan kepada kami [Isma'il bin Aban] telah menceritakan kepada kami [Hatim bin Isma'il] dari [Ja'far bin Muhammad] dari [Ayahnya] dari [Jabir bin Abdullah], Abu Ja'far berkata; kami menemui Jabir bin Abdullah lalu ia bertanya kepada orang-orang hingga sampai kepadaku, lalu aku menjawab; Aku adalah Muhammad bin Ali bin Al Husain bin Ali. Kemudian ia menggerakkan tangannya ke kancing bajuku yang paling atas dan yang paling bawah kemudian meletakkan mulutnya di antara kedua susunya, saat itu aku masih muda, lalu ia berkata; \"Selamat datang wahai anak saudaraku, bertanyalah sesukamu!.\" Lalu aku bertanya kepadanya -ia adalah orang yang buta- ketika waktu shalat telah tiba, ia berdiri dengan berselimutkan kain, setiap kali ia meletakkannya di atas pundak, maka ujungnya kembali ke bawah kerena kecilnya, sedangkan selendangnya ke samping di atas gantungan baju, kemudian ia mengerjakan shalat. Lalu saya katakan; \"Beritahukanlah kepadaku mengenai haji Rasulullah shallallahu 'alaihi wasallam! \" ia mengisyaratkan dengan tangannya dan menggenggam sembilan jari sambil berkata; Rasulullah shallallahu 'alaihi wasallam tinggal selama sembilan tahun, namun ia belum pernah melakukan haji, pada tahun kesembilan, setelah diumumkan bahwa Nabi shallallahu 'alaihi wasallam hendak melaksanakan haji, maka orang-orang banyak yang berdatangan ke Madinah, mereka ingin ikut serta bersama Rasulullah shallallahu 'alaihi wasallam dan melakukan seperti yang beliau lakukan. Lalu kami keluar bersama beliau hingga tiba di Dzul Hulaifah, kemudian Asma` binti 'Umais melahirkan Muhammad bin Abu Bakr. Lalu ia mengirim utusan kepada Rasulullah shallallahu 'alaihi wasallam untuk bertanya \"Bagaimana yang harus saya perbuat?\" Beliau bersabda; \"Mandi dan balutlah kemaluanmu dengan secarik kain dan berihramlah.\" Lalu Rasulullah shallallahu 'alaihi wasallam melakukan shalat di Masjid, seusai shalat beliau menunggangi untanya yang bernama Al Qashwa` hingga tiba di Baida`. Dan saya melihat sejauh mata memandang, di hadapan beliau terdapat orang yang berkendaraan dan yang berjalan kaki, di samping kanannya juga demikian, dan di sebelah kirinya juga demikian, serta di belakangnya juga demikian. Sementara Rasulullah shallallahu 'alaihi wasallam berada di antara kami, lalu turunlah Al Qur'an dan beliau mengetahui penjelasannya. Lalu beliau mengucapkan talbiyah menggunakan kalimat tauhid: LABBAIKALLAAHUMMA LABBAIK, LABBAIKA LAA SYARIIKA LAKA LABBAIK, INNAL HAMDA WAN NI'MATA LAKA WAL MULKA LAA SYARIIKA LAK. (ya Allah, aku memenuhi seruanMu, aku memenuhi seruanMu tidak ada sekutu bagiMu, aku memenuhi seruanMu. Sesungguhnya segala puji dan kenikmatan serta seluruh kerajaan milikMu, tidak ada sekutu bagiMu). Kemudian orang-orang mengucapkan talbiyah seperti ini, Rasulullah shallallahu 'alaihi wasallam tidak menambahkan sedikitpun. Rasulullah shallallahu 'alaihi wasallam maish mengucapkan talbiyah hingga ketika kami tiba di Ka'bah bersama beliau, kami tidak berniat kecuali untuk melakukan haji, kami belum mengetahui Umrah, hingga kami sampai ke Ka'bah bersamanya, beliau menyentuh Rukun dan berjalan cepat tiga kali, berjalan biasa empat kali kemudian maju ke Maqam Ibrahim dan melakukan shalat serta membaca: \"Dan jadikanlah sebahagian maqam Ibrahim tempat shalat.\" Beliau menjadikan maqam ada di antara dirinya dan Ka'bah. Dahulu ayahku berkata dan saya tidak tahu ia menyebutkannya dari Jabir dari Nabi shallallahu 'alaihi wasallam, ia berkata; beliau membaca pada dua raka'at tersebut QUL HUWALLAAHU AHAD dan QUL YAA AYYUHAL KAAFIRUUN. Kemudian beliau kembali ke Rukun dan menyentuhnya, kemudian keluar dari pintu menuju ke Shafa, ketika telah sampai di Shafa beliau membaca: INNASH SHAFAA WAL MARWATA MIN SYA'AARILLAAH, beliau mengatakan: \"Aku memulai dengan apa yang dimulai Allah.\" Kemudian beliau memulai dengan Shafa. Beliau naik hingga melihat Ka'bah lalu mentauhidkan serta mengagungkan Allah. Beliau mengucapkan: LAA ILAAHA ILALLAAHU WAHDAHU LAA SYARIIKA LAHU, LAHUL MULKU WA LAHUL HAMDU YUHYII WA YUMIITU WA HUWA 'ALAA KULLI SYAI IN QADIIR. LAA ILAAHA ILLALLAAHU WAHDAH, ANJAZA WA'DAH WA NASHARA 'ABDAH, WA HAZAMAL AHZAABA WAHDAH. (Tidak ada Tuhan yang berhak disembah kecuali Allah semata tidak ada sekutu bagiNya, milikNya seluruh kerajaan dan bagiNya segala puji, Dia Yang menghidupkan dan Yang mematikan dan Dia Maha Mampu melakukan segala sesuatu. Tidak ada Tuhan yang berhak disembah kecuali Allah semata, Dia menyelamatkan dengan sendirian, dan menolong hambaNya serta mengalahkan kelompok-kelompok musuh sendirian). Kemudian beliau berdoa lalu mengucapkan seperti itu tiga kali. Setelah itu beliau turun ke Marwah hingga ketika kedua kaki beliau menginjak di dasar lembah - [Abdullah bin Abdurrahman Ad Darimi] berkata- yaitu; beliau lari cepat, sehingga kami naik, beliau berjalan. Ketika sampai ke Marwah beliau melakukan seperti yang beliau lakukan di atas Shafa, setelah thawaf terakhir di atas Marwah, beliau bersabda: \"Jika dulu tampak kepadaku perkara yang terlihat saat ini, maka aku tidak akan membawa hewan kurban dan aku akan menjadikannya sebagai 'Umrah, maka barangsiapa tidak membawa hewan kurban, hendaknya ia bertahallul lalu menjadikannya Umrah.\" Kemudian Suraqah bin Malik bin Ju'syam berdiri seraya berkata; \"Wahai Rasulullah, apakah hal itu untuk tahun kita ini atau untuk selamanya?\" Rasulullah shallallahu 'alaihi wasallam menjalin jari-jarinya lalu bersabda; \"Umrah telah masuk dalam masalah haji seperti ini.\" Beliau mengucapkannya sebanyak dua kali, kemudian bersabda: \"Tidak, melainkan untuk selamanya.\" Setelah itu Ali datang membawa hewan kurban dari Yaman untuk Nabi shallallahu 'alaihi wasallam, lalu ia mendapati Fathimah diantara orang-orang yang telah bertahallul dan memakai pakaian yang longgar, serta memakai celak. Lalu Ali mengingkari apa yang dilakukan Fathimah. Kemudian Fathimah berkata; \"Ayahku yang menyuruhku.\" Ali berkata; \"Aku pergi menemui Rasulullah shallallahu 'alaihi wasallam mengadukan kepada beliau apa yang dilakukan Fathimah, yaitu dalam rangka meminta fatwa kepada Rasulullah shallallahu 'alaihi wasallam terhadap apa yang Fathimah sebutkan dan yang saya ingkari.\" Beliau bersabda: \"Ia benar. Apa yang engkau lakukan ketika hendak melakukan haji?\" Ali menjawab; saya mengatakan; \"Ya Allah, saya mengucapkan talbiyah seperti yang diucapkan rasulMu.\" Beliau bersabda: \"Sesungguhnya aku membawa hewan kurban, maka janganlah engkau bertahallul.\" Hewan kurban yang dibawa Ali dari Yaman dan yang dibawa Nabi shallallahu 'alaihi wasallam berjumlah seratus unta. Kemudian orang-orang bertahallul serta memotong rambut, kecuali Nabi shallallahu 'alaihi wasallam dan orang-orang yang membawa hewan kurban. Ketika hari Tarwiyah, beliau menghadap ke Mina dan kami bertalbiyah untuk melakukan haji, seemntara Rasulullah shallallahu 'alaihi wasallam menaiki kendaraan, lalu beliau mengerjakan shalat Zhuhur, Ashar, Maghrib dan Isya` serta Subuh bersama kami, beliau tinggal sebentar hingga matahari terbit, lalu beliau memerintahkan agar didirikan kemah dari sabut untuk beliau di Namirah, kemudian Rasulullah shallallahu 'alaihi wasallam menaiki kendaraan lalu berjalan. orang-orang Quraisy tidaklah ragu, hanya saja beliau berdiri di Masy'ar Al Haram sebagaimana yang dahulu dilakukan orang-orang Quraisy pada masa jahiliyah di Muzdalifah. Rasulullah shallallahu 'alaihi wasallam berjalan hingga sampai di 'Arafah, lalu beliau mendapati kemah yang telah didirikan di Namirah, beliau singgah di sana hingga matahari condong, lalu beliau memerintahkan agar untanya yang bernama Qashwa` dipersiapkan, kemudian diberi pelana lalu beliau pergi ke tengah bukit dan berkhutbah, sabdanya: \"Sesungguhnya darah dan harta kalian adalah haram seperti haramnya hari kalian ini, pada bulan kalian ini dan di Negeri kalian ini. Ketahuilah sesungguhnya segala perkara pada masa jahiliyah telah ditinggalkan di bawah kedua kakiku, darah pada masa jahiliyah telah digugurkan dan darah pertama yang digugurkan adalah darah kami yaitu darah Rabi'ah bin Al Harits, dahulu ia disusui di kalangan orang-orang Bani Sa'd, kemudian ia dibunuh oleh orang-orang Hudzail, dan riba jahiliyah telah dibatalkan, sedangkan riba pertama yang aku batalkan adalah riba Abbas bin Abdul Muththalib, sesungguhnya riba tersebut semuanya dibatalkan. Bertakwalah kalian kepada Allah terhadap para wanita, sesungguhnya kalian mengambil mereka dengan amanah Allah, dan menghalalkan farji mereka dengan kalimat Allah, sesungguhnya hak kalian atas mereka, supaya mereka tidak mempersilahkan orang yang tidak kalian sukai memasuki rumah kalian, apabila mereka melakukan hal itu, maka pukullah mereka dengan pukulan yang tidak menyakitkan. Mereka memiliki hak atas kalian untuk memberikan makan serta pakaian kepada mereka dengan cara yang baik. Apakah kalian mendapatkan pertanyaan mengenai diriku, apakah pendapat kalian?\" Mereka menjawab; \"Kami bersaksi bahwa anda telah menyampaikan dan menunaikan risalah serta memberikan nasehat.\" Kemudian beliau bersabda dengan mengangkat jari telunjuknya ke langit dan mengarahkan kepada orang-orang, sabdanya: \"Ya Allah, saksikanlah, ya Allah saksikanlah.\" Kemudian Bilal mengumandangkan adzan dan iqamah satu kali. Setelah itu beliau melakukan shalat Zhuhur kemudian berdiri dan melakukan shalat Ashar serta tidak melakukan shalat apapun di antara keduanya. Kemudian beliau berdiri dan menempatkan perut untanya yaitu Al Qashwa` menghadap beberapa batu kecil, sedangkan Isma'il mengatakan; \"Menghadap ke beberapa pohon kecil. Dan menempatkan Hablul Musyah (yaitu tempat mereka berkumpul) di hadapan beliau, kemudian beliau menghadap Kiblat, dan beliau tetap berdiri hingga matahari berada di barat dan warna kuningnya telah hilang, hingga bulatannya tenggelam. Lalu beliau memboncengkan Usamah di belakangnya. Setelah itu beliau berjalan dan menarik tali kendali unta beliau yang bernama Qashwa` hingga kepalanya menyentuh pangkal pelananya, dan beliau berkata sambil mengisyaratkan dengan tangannya yang kanan: \"Tenang-tenang.\" Setiap kali kepalanya mendekati tali, beliau mengendorkan sedikit, hingga naik dan beliau sampai di Muzdalifah, lalu beliau melakukan shalat Maghrib serta Isya` dengan satu adzan dan dua iqamah, setelah itu beliau berbaring hingga terbit fajar, lalu beliau melakukan shalat Subuh dengan satu adzan dan iqamah. Kemudian beliau menunggangi Qashwa` hingga berdiri di atas Masy'ar Al Haram, dan menghadap ke Kiblat. Lalu beliau berdoa kepada Allah, mengagungkan serta bertahlil dan mentauhidkanNya. Hingga cahaya pagi menyebar, kemudian beliau bertolak sebelum matahari terbit, dan memboncengkan Al Fadhl bin Al Abbas, -ia adalah laki-laki yang berambut indah, putih dan indah bersinar- Setelah Nabi shallallahu 'alaihi wasallam bertolak, beliau melewati beberapa orang wanita yang berlari, lalu Al Fadhl mulai melihat kearah mereka, Nabi shallallahu 'alaihi wasallam memegang tangannya dan langsung meletakkannya di wajah Al Fadhl, kemudian Al Fadhl memalingkan wajahnya ke sisi yang lain. Lalu Nabi shallallahu 'alaihi wasallam pun meletakkan tangannya dari sisi yang lain. Setelah sampai di Muhassir, beliau bergeser sedikit, lalu menelusuri jalan tengah yang mengeluarkanmu ke Jumrah Al Kubra, setelah sampai Jumrah yang terdapat pohonnya, beliau melempar dengan tujuh kerikil dan bertakbir pada setiap lemparan kerikil. Kemudian beliau melempar dari tengah bukit, lalu pergi ke tempat penyembelihan dan menyembelih enam puluh tiga unta dengan tangan beliau sendiri, setelah itu beliau memberikan kepada Ali, lalu ia menyembelih yang tersisa dan beliau juga ikut serta menyembelih unta, beliau memerintahkan dari setiap seekor unta untuk dikerjakan lebih dari dua orang, lalu di letakkan di dalam periuk dan dimasak. Mereka berdua makan sebagian dagingnya dan minum sebagian kuahnya kemudian beliau menunggang kendaraan dan kembali ke Ka'bah hingga sampai Ka'bah dan melakukan shalat Zhuhur di Mekkah serta mendatangi Bani Abdul Muththalib sementara mereka mengambil air Zamzam, kemudian beliau bersabda: \"Minumlah wahai Bani Abdul Muththalib, seandainya orang-orang tidak akan mengalahkan kalian dalam memberi minum, sungguh aku akan minum bersama kalian.\" Kemudian mereka memberi beliau satu ember kemudian beliau minum. Telah mengabarkan kepada kami [Muhammad bin Sa'id Al Ashbahani] telah mengabarkan kepada kami [Hatim bin Isma'il] dari [Ja'far] dari [ayahnya] dari [Jabir] dengan hadits ini."},"1426":{"ar":" أَخْبَرَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادٌ هُوَ ابْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَ بَيْنَا رَجُلٌ وَاقِفٌ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعَرَفَةَ فَوَقَعَ عَنْ رَاحِلَتِهِ أَوْ قَالَ فَأَقْعَصَتْهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اغْسِلُوهُ بِمَاءٍ وَسِدْرٍ وَكَفِّنُوهُ فِي ثَوْبَيْنِ وَلَا تُحَنِّطُوهُ وَلَا تُخَمِّرُوا رَأْسَهُ فَإِنَّ اللَّهَ تَعَالَى يَبْعَثُهُ يَوْمَ الْقِيَامَةِ مُلَبِّيًا","id":"Telah mengabarkan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad yaitu Ibnu Zaid] dari [Ayyub] dari [Sa'id bin Jubair] dari [Ibnu Abbas], ia berkata; Ketika seorang laki-laki wuquf bersama Nabi shallallahu 'alaihi wasallam di Arafah, tiba-tiba ia terjatuh dari kendaraannya -atau Ibnu Abbas berkata; untanya menginjaknya hingga menyebabkan ia meninggal dunia- Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mandikan ia dengan air dan daun bidara, serta kafani dia dengan dua kain kafan, janganlah kalian memberi minyak wangi, dan janganlah kalian tutupi kepalanya, karena sesungguhnya Allah Ta'ala akan membangkitkannya pada Hari Kiamat dalam keadaan bertalbiyah.\""},"1427":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي زِيَادٍ عَنْ الْقَاسِمِ عَنْ عَائِشَةَ قَالَتْ إِنَّمَا جُعِلَ الطَّوَافُ بِالْبَيْتِ وَرَمْيُ الْجِمَارِ وَالسَّعْيُ بَيْنَ الصَّفَا وَالْمَرْوَةِ لِإِقَامَةِ ذِكْرِ اللَّهِ قَالَ أَبُو عَاصِمٍ كَانَ يَرْفَعُهُ أَخْبَرَنَا أَبُو نُعَيْمٍ وَمُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي زِيَادٍ عَنْ الْقَاسِمِ عَنْ عَائِشَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah mengabarkan kepada kami [Abu 'Ashim] dari ['Ubaidullah bin Abu Ziyad] dari [Al Qasim] dari ['Aisyah], ia berkata; \"Sesungguhnya thawaf di Ka'bah, melempar jumrah, serta berlari-lari kecil antara Shafa dan Marwah itu di laksanakan dalam rangkan mengingat Allah.\" Abu 'Ashim berkata, Al Qasim meriwayatkan hadits ini secara marfu'.\" Telah mengabarkan kepada kami [Abu Nu'aim] dan [Muhammad bin Yusuf] dari [Sufyan] dari ['Ubaidullah bin Abu Ziyad] dari [Al Qasim] dari ['Aisyah] dari Nabi shallallahu 'alaihi wasallam seperti hadits di atas."},"1428":{"ar":" أَخْبَرَنَا نُعَيْمُ بْنُ حَمَّادٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ رَبِيعَةَ بْنِ أَبِي عَبْدِ الرَّحْمَنِ عَنْ بِلَالِ بْنِ الْحَارِثِ عَنْ أَبِيهِ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ فَسْخُ الْحَجِّ لَنَا خَاصَّةً أَمْ لِمَنْ بَعْدَنَا قَالَ بَلْ لَنَا خَاصَّةً","id":"Telah mengabarkan kepada kami [Nu'aim bin Hammad] telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Rabi'ah bin Abu Abdurrahman] dari [Bilal bin Al Harits] dari [ayahnya], ia berkata; Aku berkata; \"Wahai Rasulullah, mengubah niat dari melakukan haji ke umrah khusus untuk kita atau untuk orang setelah kita?\" Beliau menjawab: \"Bahkan khusus untuk kita.\""},"1429":{"ar":" أَخْبَرَنَا سَهْلُ بْنُ حَمَّادٍ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ مُجَاهِدٍ عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ هَذِهِ عُمْرَةٌ اسْتَمْتَعْنَا بِهَا فَمَنْ لَمْ يَكُنْ مَعَهُ هَدْيٌ فَلْيَحِلَّ الْحِلَّ كُلَّهُ فَقَدْ دَخَلَتْ الْعُمْرَةُ فِي الْحَجِّ إِلَى يَوْمِ الْقِيَامَةِ","id":"Telah mengabarkan kepada kami [Sahl bin Hammad] telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] dari [Mujahid] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Ini adalah Umrah yang kita laksanakan secara tamattu', barangsiapa tidak membawa hewan kurban, hendaknya ia bertahallul secara menyeluruh, sesungguhnya umrah ini telah masuk dalam haji hingga Hari Kiamat.\""},"1430":{"ar":" أَخْبَرَنَا جَعْفَرُ بْنُ عَوْنٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عُمَرَ بْنِ عَبْدِ الْعَزِيزِ عَنْ رَبِيعِ بْنِ سَبْرَةَ أَنَّ أَبَاهُ حَدَّثَهُ أَنَّهُمْ سَارُوا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى بَلَغُوا عُسْفَانَ فَقَالَ لَهُ رَجُلٌ مِنْ بَنِي مُدْلِجٍ يُقَالُ لَهُ مَالِكُ بْنُ سُرَاقَةَ أَوْ سُرَاقَةُ بْنُ مَالِكٍ اقْضِ لَنَا قَضَاءَ قَوْمٍ وُلِدُوا الْيَوْمَ قَالَ إِنَّ اللَّهَ قَدْ أَدْخَلَ عَلَيْكُمْ فِي حَجِّكُمْ هَذَا عُمْرَةً فَإِذَا أَنْتُمْ قَدِمْتُمْ فَمَنْ تَطَوَّفَ بِالْبَيْتِ وَبِالصَّفَا وَالْمَرْوَةِ فَقَدْ حَلَّ إِلَّا مَنْ كَانَ مَعَهُ هَدْيٌ","id":"Telah mengabarkan kepada kami [Ja'far bin 'Aun] telah menceritakan kepada kami [Abdul Aziz] dari [Rabi' bin Sabrah] bahwa [Ayahnya] telah menceritakan kepadanya bahwa para sahabat berjalan bersama Nabi shallallahu 'alaihi wasallam hingga sampai 'Usfan, kemudian seorang laki-laki dari Bani Mudlij yang bernama Malik bin Suraqah atau Suraqah bin Malik berkata kepada beliau; \"Putuskan untuk kami seperti keputusan orang-orang yang di lahirkan pada hari ini.\" Beliau bersabda: \"Sesungguhnya Allah telah memasukkan umrah ke dalam haji kalian ini, apabila kalian datang (ke Makkah) dan melakukan thawaf di Ka'bah serta (sa'i) di Shafa dan Marwah, sungguh ia telah bertahallul, kecuali orang yang memiliki hewan kurban.\""},"1431":{"ar":" أَخْبَرَنَا شِهَابُ بْنُ عَبَّادٍ حَدَّثَنَا دَاوُدُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اعْتَمَرَ أَرْبَعَ عُمَرٍ عُمْرَةَ الْحُدَيْبِيَةِ وَعُمْرَةَ الْقَضَاءِ أَوْ قَالَ عُمْرَةَ الْقِصَاصِ شَكَّ شِهَابُ بْنُ عَبَّادٍ مِنْ قَابِلٍ وَالثَّالِثَةَ مِنْ الْجِعْرَانَةِ وَالرَّابِعَةَ الَّتِي مَعَ حَجَّتِهِ","id":"Telah mengabarkan kepada kami [Syihab bin Abbad] telah menceritakan kepada kami [Daud bin Abdurrahman] dari ['Amr bin Dinar] dari [Ikrimah] dari [Ibnu Abbas] bahwa Nabi shallallahu 'alaihi wasallam telah 'Umrah sebanyak empat kali, yaitu; Umrah Hudaibiyah, umrah Qadha` -atau mengatakan; Umrah Qishash (Syihab bin 'Abbad ragu mengenai redaksi haditsnya) - atas Umrah sebelumnya, ketiga (Umrah) dari Ji'ranah dan keempat Umrah yang dilakukan bersama dengan haji beliau.\""},"1432":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِامْرَأَةٍ اعْتَمِرِي فِي رَمَضَانَ فَإِنَّ عُمْرَةً فِي رَمَضَانَ تَعْدِلُ حَجَّةً","id":"Telah mengabarkan kepada kami [Abu 'Ashim] dari [Ibnu Juraij] dari [Atha`] dari [Ibnu Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda kepada seorang wanita: \"Berumrahlah pada bulan Ramadhan, karena Umrah pada bulan Ramadhan setara dengan ibadah haji.\""},"1433":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ خَالِدٍ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ عِيسَى بْنِ مَعْقِلِ بْنِ أَبِي مَعْقَلٍ الْأَسَدِيِّ أَسَدُ خُزَيْمَةَ حَدَّثَنِي يُوسُفُ بْنُ عَبْدِ اللَّهِ بْنِ سَلَامٍ عَنْ جَدَّتِهِ أُمِّ مَعْقَلٍ قَالَتْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عُمْرَةٌ فِي رَمَضَانَ تَعْدِلُ حَجَّةً","id":"Telah mengabarkan kepada kami [Ahmad bin Khalid] telah menceritakan kepada kami [Muhammad bin Ishaq] dari [Isa bin Ma'qil bin Abu Ma'qil Al Asadi] yaitu singa bani Khuzaimah, telah menceritakan kepadaku [Yusuf bin Abdullah bin Salam] dari neneknya yaitu [Ummu Ma'qil], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Umrah pada bulan Ramdhan setara dengan ibadah haji.\""},"1434":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يَزِيدَ الْبَزَّازُ حَدَّثَنَا يَحْيَى بْنُ زَكَرِيَّا حَدَّثَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي مُزَاحِمُ بْنُ أَبِي مُزَاحِمٍ عَنْ عَبْدِ الْعَزِيزِ بْنِ عَبْدِ اللَّهِ عَنْ مُحَرِّشٍ الْكَعْبِيِّ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ مِنْ الْجِعْرَانَةِ حِينَ أَنْشَأَ مُعْتَمِرًا فَدَخَلَ مَكَّةَ لَيْلًا فَقَضَى عُمْرَتَهُ ثُمَّ خَرَجَ مِنْ تَحْتِ لَيْلَتِهِ فَأَصْبَحَ بِالْجِعْرَانَةِ كَبَائِتٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Yazid Al Bazzar] telah menceritakan kepada kami [Yahya bin Zakariya] telah menceritakan kepada kami [Ibnu Juraij] telah mengabarkan kepadaku [Muzahim bin Abu Muzahim] dari [Abdul Aziz bin Abdullah] dari [Muharrisy Al Ka'bi] bahwa Rasulullah shallallahu 'alaihi wasallam keluar dari Ji'ranah ketika hendak melakukan Umrah, kemudian beliau memasuki Makkah pada malam hari, lalu beliau menyelesaikan Umrahnya, lantas beliau keluar (dari Makkah) pada malam harinya dan di pagi hari sudah berada di Ji'ranah seperti orang yang sedang bermalam.\""},"1435":{"ar":" حَدَّثَنَا صَدَقَةُ بْنُ الْفَضْلِ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ عَمْرٍو سَمِعَ عَمْرَو بْنَ أَوْسٍ يَقُولُ أَخْبَرَنِي عَبْدُ الرَّحْمَنِ بْنُ أَبِي بَكْرٍ يَقُولُ أَمَرَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ أُرْدِفَ عَائِشَةَ فَأُعْمِرَهَا مِنْ التَّنْعِيمِ قَالَ سُفْيَانُ كَانَ شُعْبَةُ يُعْجِبُهُ مِثْلَ هَذَا الْإِسْنَادِ","id":"Telah menceritakan kepada kami [Shadaqah bin Al Fadhl] telah menceritakan kepada kami [Ibnu 'Uyainah] dari ['Amru] ia mendengar ['Amr bin Aus] berkata; telah mengabarkan kepadaku [Abdurrahman bin Abu Bakr], ia berkata; Rasulullah shallallahu 'alaihi wasallam memerintahkanku agar memboncengkan Aisyah dan mengumrahkannya dari Tan'im.\" Sufyan berkata; Syu'bah kagum dengan sanad ini."},"1436":{"ar":" حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا دَاوُدُ الْعَطَّارُ عَنْ ابْنِ خُثَيْمٍ عَنْ يُوسُفَ بْنِ مَاهَكَ عَنْ حَفْصَةَ بِنْتِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرٍ الصِّدِّيقِ عَنْ أَبِيهَا أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِعَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرٍ أَرْدِفْ أُخْتَكَ يَعْنِي عَائِشَةَ وَأَعْمِرْهَا مِنْ التَّنْعِيمِ فَإِذَا هَبَطْتَ مِنْ الْأَكَمَةِ فَمُرْهَا فَلْتُحْرِمْ فَإِنَّهَا عُمْرَةٌ مُتَقَبَّلَةٌ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Daud Al 'Athar] dari [Ibnu Khutsaim] dari [Yusuf bin Mahik] dari [Hafshah binti Abdurrahman bin Abu Bakr Ash Shiddiq] dari [Ayahnya] bahwa Nabi shallallahu 'alaihi wasallam berkata kepada Abdurrahman bin Abu Bakr: \"Boncengkanlah saudara perempuanmu -yaitu Aisyah- dan umrahkanlah dia dari Tan'im. Apabila kamu telah turun dari anak bukit, perintahkan dirinya agar berihram, sesungguhnya hal itu adalah umrah yang diterima (oleh Allah).\""},"1437":{"ar":" أَخْبَرَنَا مُسَدَّدٌ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ أَنَّ عُمَرَ قَالَ إِنِّي لَأُقَبِّلُكَ وَإِنِّي لَأَعْلَمُ أَنَّكَ حَجَرٌ وَلَكِنِّي رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُقَبِّلُكَ","id":"Telah mengabarkan kepada kami [Musaddad] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar] bahwa [Umar] berkata; \"Sungguh aku akan menciummu dan sungguh aku mengetahui bahwa engkau hanyalah sebongkah batu, akan tetapi aku melihat Rasulullah shallallahu 'alaihi wasallam menciummu.\""},"1438":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ جَعْفَرِ بْنِ عَبْدِ اللَّهِ بْنِ عُثْمَانَ قَالَ رَأَيْتُ مُحَمَّدَ بْنَ عَبَّادِ بْنِ جَعْفَرٍ يَسْتَلِمُ الْحَجَرَ ثُمَّ يُقَبِّلُهُ وَيَسْجُدُ عَلَيْهِ فَقُلْتُ لَهُ مَا هَذَا فَقَالَ رَأَيْتُ خَالَكَ عَبْدَ اللَّهِ بْنَ عَبَّاسٍ يَفْعَلُهُ ثُمَّ قَالَ رَأَيْتُ عُمَرَ فَعَلَهُ ثُمَّ قَالَ إِنِّي لَأَعْلَمُ أَنَّكَ حَجَرٌ وَلَكِنِّي رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَفْعَلُ هَذَا","id":"Telah mengabarkan kepada kami [Abu 'Ashim] dari [Ja'far bin Abdullah bin Utsman], ia berkata; saya melihat [Muhammad bin 'Abbad bin Ja'far] menyentuh Hajar Aswad kemudian menciumnya, dan bersujud di atasnya.\" aku bertanya kepadanya; \"Apa-apaan ini? Muhammad bin Abbad menjawab; \"Aku pernah melihat pamanmu yaitu [Abdullah bin Abbas] melakukannya, kemudian berkata; aku pernah melihat Umar melakukannya, kemudian [Umar] berkata; \"Sungguh aku mengetahui engkau hanyalah sebongkah batu, akan tetapi aku melihat Rasulullah shallallahu 'alaihi wasallam melakukan hal ini.\""},"1439":{"ar":" حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَ دَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَكَّةَ وَرَدِيفُهُ أُسَامَةُ بْنُ زَيْدٍ فَأَنَاخَ فِي أَصْلِ الْكَعْبَةِ فَقَالَ ابْنُ عُمَرَ وَسَعَى النَّاسُ فَدَخَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبِلَالٌ وَأُسَامَةُ فَقُلْتُ لِبِلَالٍ مِنْ وَرَاءِ الْبَابِ أَيْنَ صَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ بَيْنَ السَّارِيَتَيْنِ أَخْبَرَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ بْنِ يُونُسَ حَدَّثَنَا لَيْثٌ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمٍ عَنْ عَبْدِ اللَّهِ أَنَّهُ قَالَ دَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْبَيْتَ هُوَ وَأُسَامَةُ بْنُ زَيْدٍ وَبِلَالٌ وَعُثْمَانُ بْنُ طَلْحَةَ الْحَجَبِيُّ فَذَكَرَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Hammad bin Salamah] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar], ia berkata; Rasulullah shallallahu 'alaihi wasallam memasuki Makkah sedangkan Usamah bin Zaid membonceng beliau. Kemudian beliau menambatkan untanya di pondasi Ka'bah. Ibnu Umar berkata; Sementara orang-orang melakukan sa'i, lalu Nabi shallallahu 'alaihi wasallam, Bilal dan Usamah masuk ke dalam Ka'bah. aku bertanya kepada [Bilal] dari belakang pintu; \"Di manakah Rasulullah shallallahu 'alaihi wasallam mengerjakan shalat? Bilal menjawab; \"Diantara dua tiang.\" Telah mengabarkan kepada kami [Ahmad bin Abdullah bin Yunus] telah menceritakan kepada kami [Laits] dari [Ibnu Syihab] dari [Salim] dari [Abdullah] bahwa ia berkata; Rasulullah shallallahu 'alaihi wasallam memasuki Ka'bah bersama Usamah bin Zaid, Bilal dan Utsman bin Thalhah Al Hajabi, kemudian ia menyebutkan seperti di atas."},"1440":{"ar":" حَدَّثَنِي فَرْوَةُ بْنُ أَبِي الْمَغْرَاءِ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْ قَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْلَا حَدَاثَةُ عَهْدِ قَوْمِكِ بِالْكُفْرِ لَنَقَضْتُ الْكَعْبَةَ ثُمَّ لَبَنَيْتُهَا عَلَى أُسِّ إِبْرَاهِيمَ فَإِنَّ قُرَيْشًا حِينَ بَنَتْ اسْتَقْصَرَتْ ثُمَّ جَعَلَتْ لَهَا خَلْفًا ","id":"Telah menceritakan kepadaku [Farwah bin Abu Al Maghra`] telah menceritakan kepada kami [Ali bin Mushir] dari [Hisyam bin 'Urwah] dari [Ayahnya] dari ['Aisyah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku; \"Seandainya tidak karena kaummu masih dekat dengan kekafiran, sungguh aku akan merombak Ka'bah, kemudian membangunnya di atas pondasi Ibrahim. Sesungguhnya orang-orang Quraisy ketika membangun sempat menguranginya, kemudian mereka membuat pintu lain di belakang.\""},"1441":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ الْأَشْعَثِ بْنِ سُلَيْمٍ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْ سَأَلْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْجَدْرِ أَمِنَ الْبَيْتِ هُوَ قَالَ نَعَمْ قُلْتُ فَمَا لَهُمْ لَمْ يُدْخِلُوهُ فِي الْبَيْتِ فَقَالَ إِنَّ قَوْمَكِ قَصَّرَتْ بِهِمْ النَّفَقَةُ قُلْتُ فَمَا شَأْنُ بَابِهِ مُرْتَفِعًا قَالَ فَعَلَ ذَلِكَ قَوْمُكِ لِيُدْخِلُوا مَنْ شَاءُوا وَيَمْنَعُوا مَنْ شَاءُوا وَلَوْلَا أَنَّ قَوْمَكِ حَدِيثُ عَهْدٍ بِجَاهِلِيَّةٍ فَأَخَافُ أَنْ تُنْكِرَ قُلُوبُهُمْ لَعَمَدْتُ إِلَى الْحِجْرِ فَجَعَلْتُهُ فِي الْبَيْتِ وَأَلْزَقْتُ بَابَهُ بِالْأَرْضِ","id":"Telah mengabarkan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Abu Al Ahwash] dari [Al Asy'ats bin Sulaim] dari [Al Aswad] dari ['Aisyah], ia berkata; Saya bertanya kepada Nabi shallallahu 'alaihi wasallam mengenai batu-batu di sekitar dinding, apakah ia termasuk bagian dari Ka'bah? Beliau bersabda; \"Ya.\" Aku bertanya; \"Mengapa mereka tidak memasukkannya ke dalam Ka'bah?\" Beliau menjawab; \"Sesungguhnya kaummu mengalami keterbatasan biaya.\" Aku bertanya; \"Kenapa pintunya tinggi?\" Beliau menjawab; \"Kaummu melakukan hal itu supaya mereka dapat memasukkan orang yang mereka kehendaki dan menahan orang yang mereka kehendaki. Seandainya kaummu tidak dekat dengan masa jahiliyah dan aku tidak khawatir hati mereka akan ingkar, niscaya aku datangi Hijr dan menjadikannya di dalam Ka'bah, dan aku menurunkan pintunya (Ka'bah) dengan tanah.\""},"1442":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ أَحْمَدَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَمْرٍو عَنْ عَطَاءٍ سَمِعْتُ ابْنَ عَبَّاسٍ يَقُولُ التَّحْصِيبُ لَيْسَ بِشَيْءٍ إِنَّمَا هُوَ مَنْزِلٌ نَزَلَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبُو مُحَمَّد التَّحْصِيبُ مَوْضِعٌ بِمَكَّةَ وَهُوَ مَوْضِعٌ بِبَطْحَاءَ","id":"Telah mengabarkan kepada kami [Muhammad bin Ahmad] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari ['Amru] dari ['Atha`] aku mendengar [Ibnu Abbas] berkata; \"Tahshib itu bukanlah bagian dari haji, ia hanya tempat yang pernah di gunakan Rasulullah shallallahu 'alaihi wasallam singgah.\" Abu Muhammad berkata; \"Tahshib adalah suatu tempat di Makkah yaitu tempat di daerah Bathha`."},"1443":{"ar":" أَخْبَرَنَا الْأَسْوَدُ بْنُ عَامِرٍ حَدَّثَنَا أَبُو كُدَيْنَةَ هُوَ يَحْيَى بْنُ الْمُهَلَّبِ عَنْ الْأَعْمَشِ عَنْ الْحَكَمِ عَنْ مِقْسَمٍ عَنْ ابْنِ عَبَّاسٍ قَالَ صَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِنًى خَمْسَ صَلَوَاتٍ ","id":"Telah mengabarkan kepada kami [Al Aswad bin 'Amir] telah menceritakan kepada kami [Abu Kudainah] yaitu Yahya bin Al Muhallab dari [Al A'masy] dari [Al Hakam] dari [Miqsam] dari [Ibnu Abbas], ia berkata; Rasulullah shallallahu 'alaihi wasallam melakukan shalat lima waktu di Mina.\""},"1444":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ أَحْمَدَ وَأَحْمَدُ بْنُ مُحَمَّدِ بْنِ حَنْبَلٍ عَنْ إِسْحَقَ بْنِ يُوسُفَ حَدَّثَنَا سُفْيَان�� الثَّوْرِيُّ عَنْ عَبْدِ الْعَزِيزِ بْنِ رُفَيْعٍ قَالَ قُلْتُ لِأَنَسِ بْنِ مَالِكٍ حَدِّثْنِي بِشَيْءٍ عَقَلْتَهُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيْنَ صَلَّى الظُّهْرَ يَوْمَ التَّرْوِيَةِ قَالَ بِمِنًى قَالَ قُلْتُ فَأَيْنَ صَلَّى الْعَصْرَ يَوْمَ النَّفْرِ قَالَ بِالْأَبْطَحِ ثُمَّ قَالَ اصْنَعْ مَا يَصْنَعُ أُمَرَاؤُكَ","id":"Telah mengabarkan kepada kami [Muhammad bin Ahmad] serta [Ahmad bin Muhammad bin Hanbal] dari [Ishaq bin Yusuf] telah menceritakan kepada kami [Sufyan Ats Tsauri] dari [Abdul Aziz bin Rufai'], ia berkata; aku bertanya kepada [Anas bin Malik]; \"Sampaikanlah kepadaku sesuatu yang kamu pahami dari Rasulullah shallallahu 'alaihi wasallam, dimanakah beliau melakukan shalat Zhuhur pada hari Tarwiyah?\" Anas menjawab; \"Di Mina.\" Abdul Aziz melanjutkan; saya bertanya; \"Dimanakah beliau melakukan shalat Ashar pada hari Nafar? Anas menjawab; \"Di Abthah.\" Kemudian Anas berkata; \"Lakukanlah apa yang telah dilakukan oleh para pemimpinmu.\" "},"1445":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنِي اللَّيْثُ قَالَ حَدَّثَنِي خَالِدٌ عَنْ سَعِيدِ بْنِ أَبِي هِلَالٍ عَنْ قَتَادَةَ عَنْ أَنَسٍ أَنَّهُ حَدَّثَهُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى الظُّهْرَ وَالْعَصْرَ وَالْمَغْرِبَ وَالْعِشَاءَ وَرَقَدَ رَقْدَةً بِمِنًى ثُمَّ رَكِبَ إِلَى الْبَيْتِ فَطَافَ بِهِ","id":"Telah mengabarkan kepada kami [Abdullah bin Shalih] telah menceritakan kepadaku [Al Laits], ia berkata; telah menceritakan kepadaku [Khalid] dari [Sa'id bin Abu Hilal] dari [Qatadah] dari [Anas] bahwa Rasulullah shallallahu 'alaihi wasallam melakukan shalat Zhuhur, Ashar, Maghrib dan Isya` serta tidur sesaat di Mina, kemudian beliau menaiki kendaraannya bertolak menuju Ka'bah dan thawaf mengelilinginya.\""},"1446":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ الصَّلْتِ عَنْ مَنْصُورِ بْنِ أَبِي الْأَسْوَدِ عَنْ سُلَيْمَانَ عَنْ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ قَالَ قَالَ عَبْدُ اللَّهِ وَصَلَّى مَعَ عُثْمَانَ بِمِنًى أَرْبَعَ رَكَعَاتٍ لَقَدْ صَلَّيْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي هَذَا الْمَكَانِ رَكْعَتَيْنِ رَكْعَتَيْنِ وَمَعَ أَبِي بَكْرٍ رَكْعَتَيْنِ رَكْعَتَيْنِ وَمَعَ عُمَرَ رَكْعَتَيْنِ رَكْعَتَيْنِ ثُمَّ تَفَرَّقَتْ بِكُمْ الطُّرُقُ فَلَيْتَ حَظِّي مِنْ أَرْبَعِ رَكَعَاتٍ رَكْعَتَانِ مُتَقَبَّلَتَانِ_","id":"Telah mengabarkan kepada kami [Muhammad bin Ash Shalt] dari [Manshur bin Abu Al Aswad] dari [Sulaiman] dari [Ibrahim] dari [Abdurrahman bin Yazid], ia berkata; [Abdullah] berkata; -dan dia pernah melakukan shalat empat raka'at bersama Utsman di Mina- Bahwa aku pernah melakukan shalat bersama Rasulullah shallallahu 'alaihi wasallam dua raka'at dua raka'at ditempat ini (Mina), bersama Abu Bakr dua raka'at dua raka'at, bersama Umar dua raka'at dua raka'at, namun kalian berselisih (antara mengqashar dan menyempurnakan shalat), semoga bagianku dari keempat raka'at itu, dua raka'at yang diterima.\""},"1447":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ الْأَوْزَاعِيِّ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى بِمِنًى رَكْعَتَيْنِ وَأَبَا بَكْرٍ رَكْعَتَيْنِ وَعُمَرَ رَكْعَتَيْنِ وَعُثْمَانَ رَكْعَتَيْنِ صَدْرًا مِنْ إِمَارَتِهِ ثُمَّ أَتَمَّهَا بَعْدُ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] dari [Al Auza'i] dari [Az Zuhri] dari [Salim] dari [Ayahnya] bahwa Rasulullah shallallahu 'alaihi wasallam, Abu Bakr, dan Umar serta di awal kepemimpinan Utsman pernah melakukan shalat dua raka'at di Mina, setelah itu Utsman melakukannya secara sempurna.\""},"1448":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ سُفْيَانَ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي سَلَمَةَ الْمَاجِشُونِ عَنْ ابْنِ عُمَرَ قَالَ خَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ مِنًى فَمِنَّا مَنْ يُكَبِّرُ وَمِنَّا مَنْ يُلَبِّي","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Musa] dari [Sufyan] dari [Yahya bin Sa'id] dari [Abdullah bin Abu Salamah Al Majisyun] dari [Ibnu Umar], ia berkata; \"Kami pernah keluar bersama Rasulullah shallallahu 'alaihi wasallam dari Mina, dan diantara kami ada yang bertakbir dan ada yang bertalbiyah.\""},"1449":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا مَالِكٌ حَدَّثَنِي مُحَمَّدُ بْنُ أَبِي بَكْرٍ الثَّقَفِيُّ قَالَ سَأَلْتُ أَنَسَ بْنَ مَالِكٍ وَنَحْنُ غَادِيَانِ مِنْ مِنًى إِلَى عَرَفَاتٍ عَنْ التَّلْبِيَةِ كَيْفَ كُنْتُمْ تَصْنَعُونَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كَانَ يُلَبِّي الْمُلَبِّي فَلَا يُنْكَرُ عَلَيْهِ وَيُكَبِّرُ الْمُكَبِّرُ فَلَا يُنْكَرُ عَلَيْهِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Malik] telah menceritakan kepadaku [Muhammad bin Abu Bakr Ats Tsaqafi], ia berkata; Aku bertanya kepada [Anas bin Malik] mengenai talbiyah ketika kami bertolak dari Mina menuju Arafah; \"Bagaimana dahulu kalian melakukannya bersama Rasulullah shallallahu 'alaihi wasallam?\" Anas menjawab; \"Dahulu orang yang bertalbiyah mengucapkan talbiyah, namun beliau tida mengingkarinya dan orang yang bertakbir mengucapkan takbir, beliau juga tidak mengingkarinya.\""},"1450":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا ابْنُ عُيَيْنَةَ حَدَّثَنِي عَمْرُو بْنُ دِينَارٍ عَنْ مُحَمَّدِ بْنِ جُبَيْرِ بْنِ مُطْعِمٍ قَالَ قَالَ جُبَيْرٌ أَضْلَلْتُ بَعِيرًا لِي فَذَهَبْتُ أَطْلُبُهُ فَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاقِفًا مَعَ النَّاسِ بِعَرَفَةَ فَقُلْتُ وَاللَّهِ إِنَّ هَذَا لَمِنْ الْحُمْسِ فَمَا شَأْنُهُ هَا هُنَا","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Ibnu 'Uyainah] telah menceritakan kepadaku ['Amru bin Dinar] dari [Muhammad bin Jubair bin Muth'im], ia berkata; [Jubair] berkata; Aku kehilangan untaku, kemudian aku pergi mencarinya, aku sempat melihat Rasulullah shallallahu 'alaihi wasallam bersama orang-orang wukuf di Arafah, aku pun berkata; \"Demi Allah, sesungguhnya ini adalah sebagian besar orang-orang Quraisy, apa yang mereka lakukan di sini?.\""},"1451":{"ar":" حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ أُسَامَةَ بْنِ زَيْدٍ عَنْ عَطَاءٍ عَنْ جَابِرٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَمَى ثُمَّ قَعَدَ لِلنَّاسِ فَجَاءَهُ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي حَلَقْتُ قَبْلَ أَنْ أَنْحَرَ قَالَ لَا حَرَجَ ثُمَّ جَاءَهُ آخَرُ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي حَلَقْتُ قَبْلَ أَنْ أَرْمِيَ قَالَ لَا حَرَجَ قَالَ فَمَا سُئِلَ عَنْ شَيْءٍ إِلَّا قَالَ لَا حَرَجَ ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُّ عَرَفَةَ مَوْقِفٌ وَكُلُّ مُزْدَلِفَةَ مَوْقِفٌ وَمِنًى كُلُّهَا مَنْحَرٌ وَكُلُّ فِجَاجِ مَكَّةَ طَرِيقٌ وَمَنْحَرٌ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Musa] dari [Usamah bin Zaid] dari ['Atha`] dari [Jabir] bahwa Rasulullah shallallahu 'alaihi wasallam melempar (jumroh) kemudian duduk (bercakap-cakap) bersama orang-orang, lalu seorang laki-laki datang seraya berkata; \"Wahai Rasulullah, saya mencukur sebelum menyembelih.\" Beliau menjawab: \"Tidak mengapa.\" Kemudian datang orang yang lain seraya berkata; \"Wahai Rasulullah, saya mencukur sebelum melempar jumrah.\" Beliau menjawab: \"Tidak mengapa.\" Jabir berkata; Tidaklah beliau ditanya mengenai sesuatu melainkan beliau menjawab: \"Tidak mengapa.\" Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seluruh 'Arafah adalah tempat wuquf, seluruh Muzdalifah adalah tempat wuquf, dan seluruh Mina adalah tempat menyembelih serta seluruh lorong di Makkah adalah jalan dan tempat menyembelih.\""},"1452":{"ar":" حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ أَخْبَرَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ أُسَامَةَ بْنِ زَيْدٍ أَنَّهُ كَانَ رَدِيفَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَفَاضَ مِنْ عَرَفَةَ وَكَانَ يَسِيرُ الْعَنَقَ فَإِذَا أَتَى عَلَى فَجْوَةٍ نَصَّ","id":"Telah menceritakan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Hammad bin Salamah] telah mengabarkan kepada kami [Hisyam bin 'Urwah] dari [Ayahnya] dari [Usamah bin Zaid] bahwa ia pernah membonceng Nabi shallallahu 'alaihi wasallam. Ketika beliau bertolak dari 'Arafah, beliau berjalan dengan tenang, dan jika berada di tempat yang datar beliau mempercepat jalannya.\""},"1453":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا زُهَيْرٌ عَنْ إِبْرَاهِيمَ بْنِ عُقْبَةَ أَخْبَرَنِي كُرَيْبٌ أَنَّهُ سَأَلَ أُسَامَةَ بْنَ زَيْدٍ قَالَ أَخْبِرْنِي عَشِيَّةَ رَدِفْتَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَيْفَ فَعَلْتُمْ أَوْ صَنَعْتُمْ قَالَ جِئْنَا الشِّعْبَ الَّذِي يُنِيخُ النَّاسُ فِيهِ لِلْمُعَرَّسِ فَأَنَاخَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَاقَتَهُ ثُمَّ بَالَ وَمَا قَالَ أَهْرَاقَ الْمَاءَ ثُمَّ دَعَا بِالْوَضُوءِ فَتَوَضَّأَ وُضُوءًا لَيْسَ بِالسَّابِغِ جِدًّا قُلْتُ يَا رَسُولَ اللَّهِ الصَّلَاةَ قَالَ الصَّلَاةُ أَمَامَكَ قَالَ فَرَكِبَ حَتَّى قَدِمْنَا الْمُزْدَلِفَةَ فَأَقَامَ الْمَغْرِبَ ثُمَّ أَنَاخَ وَالنَّاسُ فِي مَنَازِلِهِمْ فَلَمْ يَحِلُّوا حَتَّى أَقَامَ الْعِشَاءَ الْآخِرَةَ فَصَلَّى ثُمَّ حَلَّ النَّاسُ قَالَ قُلْتُ أَخْبِرْنِي كَيْفَ فَعَلْتُمْ حِينَ أَصْبَحْتُمْ قَالَ رَدِفَهُ الْفَضْلُ بْنُ عَبَّاسٍ فَانْطَلَقْتُ أَنَا فِي سُبَّاقِ قُرَيْشٍ عَلَى رِجْلَيَّ أَخْبَرَنَا حَجَّاجٌ حَدَّثَنَا حَمَّادٌ حَدَّثَنَا مُوسَى بْنُ عُقْبَةَ عَنْ كُرَيْبِ بْنِ أَبِي مُسْلِمٍ عَنْ أُسَامَةَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Zuhair] dari [Ibrahim bin 'Uqbah] telah mengabarkan kepadaku [Kuraib] bahwa ia pernah bertanya kepada [Usamah bin Zaid], katanya; \"Beritahukanlah kepadaku pada sore hari saat kamu membonceng Nabi shallallahu 'alaihi wasallam, bagaimana yang kalian lakukan -atau kalian perbuat? - Usamah menjawab; \"Kami mendatangi lembah tempat orang-orang menderumkan unta mereka sebagai tempat peristirahatan pada akhir malam. Kemudian Nabi shallallahu 'alaihi wasallam menambatkan untanya, beliau lalu buang air kecil. -Usamah bin Zaid tidak mengatakan dia menuangkan air- Kemudian beliau meminta air wudhu, lalu beliau berwudhu dengan wudhu yang tidak berlebihan. Saya bertanya; \"Wahai Rasulullah, apakah anda hendak mengerjakan shalat?\" Beliau menjawab: \"Shalat ada di hadapanmu.\" Usamah berkata; \"Kemudian beliau menaiki kendaraannya hingga kami tiba di Muzdalifah, setelah itu beliau mengerjakan shalat Maghrib dan menambatkan untanya, sementara orang-orang masih berada di persinggahan mereka, mereka tidak beranjak hingga mendirikan shalat Isya`, lalu beliau melakukan shalat. Seusai mengerjakan shalat, orang-orangpun beranjak.\" Kuraib berkata; \"Beritahukan kepadaku bagaimana kalian melakukan ketika pada pagi harinya?\" Usamah menjawab; \"Beliau berboncengan dengan Al Fadhl bin Abbas, sementara aku pergi berlomba-lomba dengan berjalan kaki bersama orang-orang Quraisy menuju Mina.\" Telah mengabarkan kepada kami [Hajjaj] telah menceritakan kepada kami [Hammad] telah menceritakan kepada kami [Musa bin 'Uqbah] dari [Kuraib bin Abu Muslim] dari [Usamah] seperti hadits di atas."},"1454":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ قَالَ عَدِيُّ بْنُ ثَابِتٍ أَنْبَأَنِي قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ يَزِيدَ عَنْ أَبِي أَيُّوبَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَمَعَ بَيْنَ الْمَغْرِبِ وَالْعِشَاءِ يَعْنِي بِجَمْعٍ","id":"Telah mengabarkan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah], ia berkata; ['Adi bin Tsabit] telah memberitakan kepadaku, katanya; Saya mendengar [Abdullah bin Yazid] dari [Abu Ayyub] bahwa Rasulullah shallallahu 'alaihi wasallam menjama' antara Shalat Maghrib dan Isya` yaitu Jama' (Muzdalifah).\""},"1455":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ الْمَجِيدِ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمٍ عَنْ أَبِيهِ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى الْمَغْرِبَ وَالْعِشَاءَ بِالْمُزْدَلِفَةِ لَمْ يُنَادِ فِي وَاحِدَةٍ مِنْهُمَا إِلَّا بِالْإِقَامَةِ وَلَمْ يُسَبِّحْ بَيْنَهُمَا وَلَا عَلَى إِثْرِ وَاحِدَةٍ مِنْهُمَا","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Abdul Majid] telah menceritakan kepada kami [Ibnu Abu Dzi`b] dari [Ibnu Syihab] dari [Salim] dari [Ayahnya] bahwa Nabi shallallahu 'alaihi wasallam melakukan Shalat Maghrib dan Isya` di Muzdalifah dan tidak mengumandangkan (adzan) dalam salah satu dari dua shalat tersebut kecuali hanya satu iqamah, dan tidak melakukan shalat sunah di antara keduanya serta tidak pula setelahnya.\""},"1456":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ عَنْ عَطَاءٍ عَنْ ابْنِ شَوَّالٍ أَخْبَرَهُ أَنَّ أُمَّ حَبِيبَةَ أَخْبَرَتْهُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَهَا أَنْ تَنْفِرَ مِنْ جَمْعٍ بِلَيْلٍ","id":"Telah mengabarkan kepada kami [Abu 'Ashim] dari [Ibnu Juraij] dari ['Atha`] dari [Ibnu Syawwal] ia telah mengabarkan kepadanya, bahwa [Ummu Habibah] telah mengabarkan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam telah memerintahkannya agar bertolak dari Jama' (Muzdalifah) pada malam hari.\""},"1457":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ الْمَجِيدِ حَدَّثَنَا أَفْلَحُ قَالَ سَمِعْتُ الْقَاسِمَ بْنَ مُحَمَّدٍ يُحَدِّثُ عَنْ عَائِشَةَ قَالَتْ اسْتَأْذَنَتْ سَوْدَةُ بِنْتُ زَمْعَةَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَأْذَنَ لَهَا فَتَدْفَعَ قَبْلَ أَنْ يَدْفَعَ فَأَذِنَ لَهَا قَالَ الْقَاسِمُ وَكَانَتْ امْرَأَةً ثَبِطَةً قَالَ الْقَاسِمُ الثَّبِطَةُ الثَّقِيلَةُ فَدَفَعَتْ وَحُبِسْنَا مَعَهُ حَتَّى دَفَعْنَا بِدَفْعِهِ قَالَتْ عَائِشَةُ فَلَأَنْ أَكُونَ اسْتَأْذَنْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَمَا اسْتَأْذَنَتْ سَوْدَةُ فَأَدْفَعَ قَبْلَ النَّاسِ أَحَبُّ إِلَيَّ مِنْ مَفْرُوحٍ بِهِ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Abdul Majid] telah menceritakan kepada kami [Aflah], ia berkata; saya mendengar [Al Qasim bin Muhammad] menceritakan dari [Aisyah], ia berkata; Saudah binti Zam'ah meminta izin kepada Rasulullah shallallahu 'alaihi wasallam agar beliau memberinya izin untuk bertolak (dari Muzdalifah menuju Mina) sebelum beliau bertolak. Kemudian beliau memberinya izin. -Al Qasim berkata; Saudah adalah wanita yang lambat dan berat.- Kemudian Saudah bertolak, sementara kami tertahan bersama beliau, hingga akhirnya kami berangkat ketika beliau berangkat. 'Asyah berkata; \"Sungguh seandainya aku meminta izin kepada Rasulullah shallallahu 'alaihi wasallam sebagaimana Saudah meminta izin, hingga aku dapat berangkat sebelum orang-orang berangkat, lebih aku sukai daripada sesuatu yang disenangi oleh beliau.\""},"1458":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا بُكَيْرُ بْنُ عَطَاءٍ قَالَ سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ يَعْمُرَ الدِّيلِيَّ يَقُولُ سُئِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْحَجِّ فَقَالَ الْحَجُّ عَرَفَاتٌ أَوْ يَوْمُ عَرَفَةَ وَمَنْ أَدْرَكَ لَيْلَةَ جَمْعٍ قَبْلَ صَلَاةِ الصُّبْحِ فَقَدْ أَدْرَكَ وَقَالَ أَيَّامُ مِنًى ثَلَاثَةُ أَيَّامٍ { فَمَنْ تَعَجَّلَ فِي يَوْمَيْنِ فَلَا إِثْمَ عَلَيْهِ وَمَنْ تَأَخَّرَ فَلَا إِثْمَ عَلَيْهِ }","id":"Telah mengabarkan kepada kami [Abu Al Walid Ath Thayalisi] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Bukair bin 'Atha`], ia berkata; saya mendengar [Abdurrahman bin Ya'mur Ad Dili] ia berkata; Nabi shallallahu 'alaihi wasallam ditanya mengenai haji, beliau menjawab: \"Haji itu (wukuf) di Arafah, atau pada hari Arafah, barangsiapa menjumpai malam di Muzdalifah sebelum shalat Subuh, berarti ia telah mendapatkan haji.\" Beliau bersabda: \"Hari-hari di Mina adalah tiga hari, barangsiapa mempercepat dalam dua hari maka tidak ada dosa baginya dan barangsiapa yang memperlambat maka tidak ada dosa baginya.\" QS Al Baqarah; 203."},"1459":{"ar":" أَخْبَرَنَا يَعْلَى حَدَّثَنَا إِسْمَعِيلُ عَنْ عَامِرٍ عَنْ عُرْوَةَ بْنِ مُضَرِّسٍ قَالَ جَاءَ رَجُلٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْمَوْقِفِ عَلَى رُءُوسِ النَّاسِ فَقَالَ يَا رَسُولَ اللَّهِ جِئْتُ مِنْ جَبَلَيْ طَيِّءٍ أَكْلَلْتُ مَطِيَّتِي وَأَتْعَبْتُ نَفْسِي وَاللَّهِ إِنْ بَقِيَ جَبَلٌ إِلَّا وَقَفْتُ عَلَيْهِ فَهَلْ لِي مِنْ حَجٍّ قَالَ مَنْ شَهِدَ مَعَنَا هَذِهِ الصَّلَاةَ وَقَدْ أَتَى عَرَفَاتٍ قَبْلَ ذَلِكَ لَيْلًا أَوْ نَهَارًا فَقَدْ قَضَى تَفَثَهُ وَتَمَّ حَجُّهُ أَخْبَرَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي السَّفَرِ عَنْ الشَّعْبِيِّ عَنْ عُرْوَةَ بْنِ مُضَرِّسِ بْنِ حَارِثَةَ بْنِ لَامٍ قَالَ أَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ نَحْوَهُ","id":"Telah mengabarkan kepada kami [Ya'la] telah menceritakan kepada kami [Isma'il] dari ['Amir] dari ['Urwah bin Mudharris], ia berkata; \"Seorang laki-laki dating kepada Rasulullah shallallahu 'alaihi wasallam ditempat wukuf tepat di tengah kerumumanan orang-orang, kemudian ia berkata; \"Wahai Rasulullah, saya datang dari dua Gunung Thayyi`, hingga membuat diriku dan kendaraanku letih, demi Allah, tidak ada satupun gunung melainkan aku melakukan wukuf padanya, apakah hajiku sah? Beliau bersabda: \"Barangsiapa melakukan shalat sini bersama kami, dan sebelumnya telah mendatangi Arafah, baik di siang hari ataupun malam hari, maka ia telah menunaikan manasik dan hajinya telah sempurna.\" Telah mengabarkan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah] dari [Abdullah bin Abu As Safar] dari [Asy Sya'bi] dari ['Urwah bin Mudharris bin Haritsah bin Lam], ia berkata; Saya pernah datang menemui Rasulullah shallallahu 'alaihi wasallam, kemudian ia menyebutkan seperti hadits di atas."},"1460":{"ar":" أَخْبَرَنَا أَبُو غَسَّانَ مَالِكُ بْنُ إِسْمَعِيلَ حَدَّثَنَا إِسْرَائِيلُ عَنْ أَبِي إِسْحَقَ عَنْ عَمْرِو بْنِ مَيْمُونٍ عَنْ عُمَرَ بْنِ الْخَطَّابِ قَالَ كَانَ أَهْلُ الْجَاهِلِيَّةِ يُفِيضُونَ مِنْ جَمْعٍ بَعْدَ طُلُوعِ الشَّمْسِ وَكَانُوا يَقُولُونَ أَشْرِقْ ثَبِيرُ لَعَلَّنَا نُغِيرُ وَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَالَفَهُمْ فَدَفَعَ قَبْلَ طُلُوعِ الشَّمْسِ بِقَدْرِ صَلَاةِ الْمُسْفِرِينَ أَوْ قَالَ الْمُشْرِقِينَ بِصَلَاةِ الْغَدَاةِ","id":"Telah mengabarkan kepada kami [Abu Ghassan Malik bin Isma'il] telah menceritakan kepada kami [Israil] dari [Abu Ishaq] dari ['Amr bin Maimun] dari [Umar bin Al Khathab], ia berkata; \"Dahulu orang-orang jahiliyah berangkat dari Jama' (Muzdalifah) setelah terbit matahari, mereka mengatakan; \"Terbitlah (wahai matahari) di atas Tsabir (nama gunung di Makkah), agar kami dapat berjalan dengan cepat.\" Maka Rasulullah shallallahu 'alaihi wasallam menyelisihi mereka, beliau bertolak sebelum matahari terbit, seukuran para musafir melakukan shalat -atau berkata; ketika orang-orang bangun untuk melaksanakan shalat shubuh.\""},"1461":{"ar":" أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا عِيسَى بْنُ يُونُسَ عَنْ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي أَبُو الزُّبَيْرِ أَنَّ أَبَا مَعْبَدٍ مَوْلَى ابْنِ عَبَّاسٍ أَخْبَرَهُ عَنْ ابْنِ عَبَّاسٍ عَنْ الْفَضْلِ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي عَشِيَّةِ عَرَفَةَ وَغَدَاةِ جَمْعٍ حِينَ دَفَعُوا عَلَيْكُمْ السَّكِينَةَ وَهُوَ كَافٌّ نَاقَتَهُ حَتَّى إِذَا دَخَلَ مُحَسِّرًا أَوْضَعَ أَخْبَرَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا لَيْثٌ عَنْ أَبِي الزُّبَيْرِ بِإِسْنَادِهِ نَحْوَهُ قَالَ عَبْد اللَّهِ الْإِيضَاعُ لِلْإِبِلِ وَالْإِيجَافُ لِلْخَيْلِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Isa bin Yunus] dari [Ibnu Juraij], ia berkata; telah mengabarkan kepadaku [Abu Az Zubair] bahwa [Abu Ma'bad] mantan budak Ibnu Abbas, telah mengabarkan kepadanya dari [Ibnu Abbas] dari [Al Fadhl] bahwa Nabi shallallahu 'alaihi wasallam bersabda pada sore hari di Arafah dan pada pagi harinya di Muzdalifah, ketika mereka telah bertolak: \" Hendaknya kalian tenang.\" Beliau menahan laju untanya, hingga ketika beliau memasuki Muhassir, beliau mempercepat lajuu kendaraannya.\" Telah mengabarkan kepada kami [Ahmad bin Abdullah] telah menceritakan kepada kami [Laits] dari [Abu Az Zubair] dengan sanad seperti itu. Abdullah berkata; idha' adalah ungkapan untuk unta, sedangkan ijaf adalah ungkapan untuk kuda.\""},"1462":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ أَنَّ عَبْدَ اللَّهِ بْنَ عَبْدِ اللَّهِ وَسَالِمًا كَلَّمَا ابْنَ عُمَرَ لَيَالِيَ نَزَلَ الْحَجَّاجُ بِابْنِ الزُّبَيْرِ قَبْلَ أَنْ يُقْتَلَ فَقَالَا لَا يَضُرُّكَ أَنْ لَا تَحُجَّ الْعَامَ نَخَافُ أَنْ يُحَالَ بَيْنَكَ وَبَيْنَ الْبَيْتِ فَقَالَ قَدْ خَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُعْتَمِرِينَ فَحَالَ كُفَّارُ قُرَيْشٍ دُونَ الْبَيْتِ فَنَحَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَدْيَهُ وَحَلَقَ رَأْسَهُ ثُمَّ رَجَعَ فَأُشْهِدُكُمْ أَنِّي قَدْ أَوْجَبْتُ عُمْرَةً فَإِنْ خُلِّيَ بَيْنِي وَبَيْنَ الْبَيْتِ طُفْتُ وَإِنْ حِيلَ بَيْنِي وَبَيْنَهُ فَعَلْتُ كَمَا كَانَ فَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا مَعَهُ فَأَهَلَّ بِالْعُمْرَةِ مِنْ ذِي الْحُلَيْفَةِ ثُمَّ سَارَ فَقَالَ إِنَّمَا شَأْنُهُمَا وَاحِدٌ أُشْهِدُكُمْ أَنِّي قَدْ أَوْجَبْتُ حَجًّا مَعَ عُمْرَتِي قَالَ نَافِعٌ فَطَافَ لَهُمَا طَوَافًا وَاحِدًا وَسَعَى لَهُمَا سَعْيًا وَاحِدًا ثُمَّ لَمْ يَحِلَّ حَتَّى جَاءَ يَوْمَ النَّحْرِ فَأَهْدَى وَكَانَ يَقُولُ مَنْ جَمَعَ الْعُمْرَةَ وَالْحَجَّ فَأَهَلَّ بِهِمَا جَمِيعًا فَلَا يَحِلَّ حَتَّى يَحِلَّ مِنْهُمَا جَمِيعًا يَوْمَ النَّحْرِ","id":"Telah mengabarkan kepada kami [Abdullah bin Sa'id] telah menceritakan kepada kami [Abu Usamah] dari ['Ubaidullah] dari [Nafi'] bahwa Abdullah bin Abdullah dan Salim berbicara kepada [Ibnu Umar] -pada malam saat jama'ah haji singgah di (tempat) Ibnu Az Zubair sebelum ia terbunuh- keduanya berkata; \"Tidak mengapa engkau tidak melakukan haji pada tahun ini, kami khawatir anda akan dihalangi mendatangi Ka'bah.\" Ibnu Umar berkata; \"Kami pernah keluar bersama Rasulullah shallallahu 'alaihi wasallam untuk melakukan umrah, Namun orang-orang Quraisy menghalangi sebelum sampai ke Ka'bah, kemudian Rasulullah shallallahu 'alaihi wasallam menyembelih hewan kurbannya, mencukur rambut kepalanya, kemudian kembali (ke Madinah). Maka aku bersaksi kepada kalian bahwa aku akan mewajibkan diriku untuk melakukan umrah, apabila aku tidak dihalangi mendatangi Ka'bah, maka aku akan melakukan thawaf, jika aku dihalangi untuk mendatangi (Ka'bah), maka aku akan melakukan sebagaimana yang dahulu dilakukan Rasulullah shallallahu 'alaihi wasallam ketika aku bersama beliau. Beliau mengucapkan talbiyah untuk umrah dari Dzul Hulaifah, kemudian berjalan, beliau bersabda: \"Sesungguhnya perkara haji adan Umrah adalah satu, \" aku bersaksi kepada kalian bahwa aku mewajibkan diriku untuk melakukan haji bersamaan dengan umrahku. Nafi' mengatakan; \"Kemudian Ibnu Umar melakukan thawaf untuk (haji dan Umrahnya) dengan satu thawaf dan sa'I satu kali. Dia tidak bertahallul hingga datang hari penyembelihan kurban, setelah itu ia berkurban. Ibnu Umar juga berkata; \"Barangsiapa menggabungkan niat umrah dan haji dan bertalbiyah untuk keduanya secara bersamaan, maka janganlah bertahallul hingga bertahallul pada hari penyembelihan hewan kurban.\""},"1463":{"ar":" حَدَّثَنَا أَبُو عَاصِمٍ عَنْ حَجَّاجٍ الصَّوَّافِ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عِكْرِمَةَ عَنْ الْحَجَّاجِ بْنِ عَمْرٍو الْأَنْصَارِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ كُسِرَ أَوْ عُرِجَ فَقَدْ حَلَّ وَعَلَيْهِ حَجَّةٌ أُخْرَى قَالَ أَبُو مُحَمَّد رَوَاهُ مُعَاوِيَةُ بْنُ سَلَّامٍ وَمَعْمَرٌ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عِكْرِمَةَ عَنْ عَبْدِ اللَّهِ بْنِ رَافِعٍ عَنْ الْحَجَّاجِ بْنِ عَمْرٍو عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abu 'Ashim] dari [Hajjaj Ash Shawwaf] dari [Yahya bin Abu Katsir] dari [Ikrimah] dari [Al Hajjaj bin 'Amr Al Anshari] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa tulangnya patah atau kakinya pincang, maka sebenarnya ia telah bertahallul dan ia wajib melakukan haji yang lain.\" Abu Muhammad berkata; telah diriwayatkan oleh [Mu'awiyah bin Sallam] dan [Ma'mar] dari [Yahya bin Abu Katsir] dari [Ikrimah] dari [Abdullah bin Rafi'] dari [Al Hajjaj bin 'Amru] dari Nabi shallallahu 'alaihi wasallam."},"1464":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى أَخْبَرَنَا ابْنُ جُرَيْجٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَ رَمَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْجَمْرَةَ يَوْمَ النَّحْرِ الضُّحَى وَبَعْدَ ذَلِكَ عِنْدَ زَوَالِ الشَّمْسِ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Musa] telah mengabarkan kepada kami [Ibnu Juraij] dari [Abu Az Zubair] dari [Jabir], ia berkata; Rasulullah shallallahu 'alaihi wasallam melempar jumrah pada hari penyembelihan hewan kurban ketika matahari naik sepenggalah, setelah itu ketika tergelincirnya matahari.\""},"1465":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ أَبِي الْبَدَّاحِ بْنِ عَاصِمٍ عَنْ أَبِيهِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْخَصَ لِرِعَاءِ الْإِبِلِ أَنْ يَرْمُوا يَوْمَ النَّحْرِ ثُمَّ يَرْمُوا الْغَدَ أَوْ مِنْ بَعْدِ الْغَدِ لِيَوْمَيْنِ ثُمَّ يَرْمُوا يَوْمَ النَّفْرِ قَالَ أَبُو مُحَمَّد مِنْهُمْ مَنْ يَقُولُ عَبْدُ اللَّهِ بْنُ أَبِي بَكْرٍ عَنْ أَبِيهِ عَنْ أَبِي الْبَدَّاحِ","id":"Telah mengabarkan kepada kami [Abdullah bin Maslamah] telah menceritakan kepada kami [Malik] dari [Abdullah bin Abu Bakr] dari [Abu Al Baddah bin 'Ashim] dari [Ayahnya] bahwa Rasulullah shallallahu 'alaihi wasallam memberikan keringanan bagi penggembala unta untuk melempar jumrah pada hari penyembelihan kurban, kemudian ia melempar keesokan harinya atau lusa untuk dua hari, kemudian melempar pada hari Nafar (sekembalinya dari Mina).\" Abu Muhammad berkata; [Diantara perawi] ada yang mengatakan; [Abdullah bin Abu Bakr] dari [Ayahnya] dari [Abu Al Baddah]."},"1466":{"ar":" أَخْبَرَنَا عُثْمَانُ بْنُ عُمَرَ حَدَّثَنَا عُثْمَانُ بْنُ مُرَّةَ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عُثْمَانَ التَّيْمِيِّ قَالَ أَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَجَّةِ الْوَدَاعِ أَنْ نَرْمِيَ الْجَمْرَةَ بِمِثْلِ حَصَى الْخَذْفِ","id":"Telah mengabarkan kepada kami [Utsman bin Umar] telah menceritakan kepada kami [Utsman bin Murrah] dari [Abu Salamah bin Abdurrahman] dari [Abdurrahman bin Utsman At Taimi], ia berkata; Rasulullah shallallahu 'alaihi wasallam memerintahkan kami pada saat haji wada' agar melempar jumrah dengan kerikil.\""},"1467":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ سُفْيَانَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَ أَمَرَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَمَوْا بِمِثْلِ حَصَى الْخَذْفِ وَأَوْضَعَ فِي وَادِي مُحَسِّرٍ وَقَالَ عَلَيْكُمْ السَّكِينَةَ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Musa] dari [Sufyan] dari [Abu Az Zubair] dari [Jabir], ia berkata; Rasulullah shallallahu 'alaihi wasallam memerintahkan mereka agar melempar jumrah dengan kerikil, dan mempercepat laju kendaraan di Bukit Muhassir, beliau bersabda: \"Hendaknya kalian tenang.\""},"1468":{"ar":" أَخْبَرَنَا عَمْرُو بْنُ عَوْنٍ أَخْبَرَنَا خَالِدٌ عَنْ حُمَيْدٍ الْأَعْرَجِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ مُعَاذٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَأْمُرُنَا أَنْ نَرْمِيَ الْجِمَارَ بِمِثْلِ حَصَى الْخَذْفِ قِيلَ لِأَبِي مُحَمَّدٍ عَبْدُ الرَّحْمَنِ بْنُ مُعَاذٍ لَهُ صُحْبَةٌ قَالَ نَعَمْ","id":"Telah mengabarkan kepada kami ['Amru bin 'Aun] telah mengabarkan kepada kami [Khalid] dari [Humaid Al A'raj] dari [Muhammad bin Ibrahim] dari [Abdurrahman bin Mu'adz] bahwa Rasulullah shallallahu 'alaihi wasallam memerintahkan kami agar melempar jumrah dengan kerikil.\" Abu Muhammad ditanya; \"Apakah Abdurrahman bin Mu'adz seorang sahabat?\" Dia menjawab; \"Ya.\""},"1469":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ وَالْمُؤَمَّلُ وَأَبُو نُعَيْمٍ عَنْ أَيْمَنَ بْنِ نَابِلٍ عَنْ قُدَامَةَ بْنِ عَبْدِ اللَّهِ بْنِ عَمَّارٍ الْكِلَابِيِّ قَالَ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْمِي الْجِمَارَ عَلَى نَاقَةٍ صَهْبَاءَ لَيْسَ ثَمَّ ضَرْبٌ وَلَا طَرْدٌ وَلَا إِلَيْكَ إِلَيْكَ","id":"Telah mengabarkan kepada kami [Abu 'Ashim] dan [Al Mu`ammal] serta [Abu Nu'aim] dari [Aiman bin Nabil] dari [Qudamah bin Abdullah bin 'Ammar Al Kilabi], ia berkata; Saya mendengar Rasulullah shallallahu 'alaihi wasallam melempar jumrah di atas unta shahba`, tanpa ada pukulan, pengusiran dan tanpa ada kata-kata; menyingkirlah-menyingkirlah.\" "},"1470":{"ar":" أَخْبَرَنَا زَكَرِيَّا بْنُ عَدِيٍّ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَمْرٍو عَنْ عَبْدِ الْكَرِيمِ هُوَ الْجَزَرِيُّ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ عَنْ الْفَضْلِ قَالَ كُنْتُ رِدْفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ يَزَلْ يُلَبِّي حَتَّى رَمَى الْجَمْرَةَ","id":"Telah mengabarkan kepada kami [Zakariya bin 'Adi] telah menceritakan kepada kami ['Ubaidullah bin 'Amru] dari [Abdul Karim yaitu Al Jazari] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dari [Al Fadhl], ia berkata; \"Aku pernah membonceng Rasulullah shallallahu 'alaihi wasallam, beliau senantiasa bertalbiyah hingga beliau melontar jumrah.\""},"1471":{"ar":" أَخْبَرَنَا عُثْمَانُ بْنُ عُمَرَ أَخْبَرَنَا يُونُسُ عَنْ الزُّهْرِيِّ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا رَمَى الْجَمْرَةَ الَّتِي تَلِي الْمَسْجِدَ مَسْجِدَ مِنًى يَرْمِيهَا بِسَبْعِ حَصَيَاتٍ يُكَبِّرُ مَعَ كُلِّ حَصَاةٍ ثُمَّ تَقَدَّمَ أَمَامَهَا فَوَقَفَ مُسْتَقْبِلَ الْقِبْلَةِ رَافِعًا يَدَيْهِ وَكَانَ يُطِيلُ الْوُقُوفَ ثُمَّ يَأْتِي الْجَمْرَةَ الثَّانِيَةَ فَيَرْمِيهَا بِسَبْعِ حَصَيَاتٍ يُكَبِّرُ كُلَّمَا رَمَى بِحَصَاةٍ ثُمَّ يَنْحَدِرُ مِنْ ذَاتِ الْيَسَارِ مِمَّا يَلِي الْوَادِي رَافِعًا يَدَيْهِ يَدْعُو ثُمَّ يَأْتِي الْجَمْرَةَ الَّتِي عِنْدَ الْعَقَبَةِ فَيَرْمِيهَا بِسَبْعِ حَصَيَاتٍ يُكَبِّرُ كُلَّمَا رَمَى بِحَصَاةٍ ثُمَّ يَنْصَرِفُ وَلَا يَقِفُ عِنْدَهَا قَالَ الزُّهْرِيُّ سَمِعْتُ سَالِمَ بْنَ عَبْدِ اللَّهِ يُحَدِّثُ بِهَذَا الْحَدِيثِ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَكَانَ ابْنُ عُمَرَ يَفْعَلُهُ","id":"Telah mengabarkan kepada kami [Utsman bin Umar] telah mengabarkan kepada kami [Yunus] dari [Az Zuhri] bahwa apabila Rasulullah shallallahu 'alaihi wasallam melempar jumrah yang terletak di sebelah masjid Mina, beliau melemparnya dengan tujuh kerikil sembari bertakbir pada setiap lontaran kerikil, kemudian beliau maju ke depannya dan berdiri menghadap Kiblat dengan mengangkat kedua tangannya (berdoa) dan berdiri lama, kemudian mendatangi jumrah yang kedua lalu melemparnya dengan tujuh kerikil sembari bertakbir pada setiap lemparan, kemudian turun dari sisi kiri jalan yang berada di sisi bukit, beliau mengangkat kedua tangannya sembari berdoa, kemudian mendatangi jumrah yang ada di 'Aqabah, beliau lalu melemparnya dengan tujuh kerikil sambil bertakbir setiap kali melempar, setelah itu beliau beranjak pergi dan tidak berdiri di sana.\" [Az Zuhri] berkata; Aku mendengar [Salim bin Abdullah] menceritakan hadits ini dari [Ayahnya] dari Nabi shallallahu 'alaihi wasallam. Perawi berkata; \"Dan Ibnu Umar juga melakukan hal itu.\""},"1472":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ هُوَ الْمَاجِشُونُ عَنْ عَبْدِ الرَّحْمَنِ هُوَ ابْنُ الْقَاسِمِ عَنْ الْقَاسِمِ عَنْ عَائِشَةَ قَالَتْ خَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا نَذْكُرُ إِلَّا الْحَجَّ فَلَمَّا جِئْنَا سَرِفَ طَمِثْتُ فَلَمَّا كَانَ يَوْمُ النَّحْرِ طَهُرْتُ فَأَرْسَلَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَفَضْتُ فَأُتِيَ بِلَحْمِ بَقَرٍ فَقُلْتُ مَا هَذَا قَالُوا أَهْدَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ نِسَائِهِ الْبَقَرَ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Abdul Aziz yaitu Al Majisyun] dari [Abdurrahman yaitu Ibnu Al Qasim] dari [Al Qasim] dari ['Aisyah], ia berkata; \"Kami keluar bersama Rasulullah shallallahu 'alaihi wasallam dan tidak menyebutkan sesuatupun kecuali (masalah) haji. Setelah kami sampai di Sarif, aku mengalami haid. Ketika hari penyembelihan kurban (awal hari Adha) aku telah suci. Lalu Rasulullah shallallahu 'alaihi wasallam mengirim utusan kepadaku (agar aku segera dating), aku pun segera bertolak untuk berangkat, beliau lalu diberi daging sapi, aku bertanya; \"Apa ini?\" Para sahabat menjawab; Rasulullah shallallahu 'alaihi wasallam telah berkurban sapi untuk para isterinya.\""},"1473":{"ar":" أَخْبَرَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ الْمَدِينِيُّ حَدَّثَنَا هِشَامُ بْنُ يُوسُفَ حَدَّثَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي عَبْدُ الْحَمِيدِ بْنُ جُبَيْرٍ عَنْ صَفِيَّةَ بِنْتِ شَيْبَةَ قَالَتْ أَخْبَرَتْنِي أُمُّ عُثْمَانَ بِنْتُ أَبِي سُفْيَانَ أَنَّ ابْنَ عَبَّاسٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ عَلَى النِّسَاءِ حَلْقٌ إِنَّمَا عَلَى النِّسَاءِ التَّقْصِيرُ","id":"Telah mengabarkan kepada kami [Ali bin Abdullah Al Madini] telah menceritakan kepada kami [Hisyam bin Yusuf] telah menceritakan kepada kami [Ibnu Juraij] telah mengabarkan kepadaku [Abdul Hamid bin Jubair] dari [Shafiyah binti Syaibah] ia berkata; telah mengabarkan kepadaku [Ummu Utsman binti Abu Sufyan] bahwa [Ibnu Abbas] berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wanita tidak diwajibkan untuk mencukur rambut, (akan tetapi) ia hanya dianjurkan untuk memendekkan.\""},"1474":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ رَحِمَ اللَّهُ الْمُحَلِّقِينَ قِيلَ وَالْمُقَصِّرِينَ قَالَ رَحِمَ اللَّهُ الْمُحَلِّقِينَ قَالَ فِي الرَّابِعَةِ وَالْمُقَصِّرِينَ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam bahwa beliau bersabda: \"Semoga Allah merahmati orang-orang yang mencukur rambutnya.\" Dikatakan kepada beliau; \"Dan orang-orang yang memendekkan rambutnya.\" Beliau bersabda: \"Semoga Allah merahmati orang-orang yang mencukur rambutnya.\" Pada kali yang keempat, beliau bersabda: \"Dan orang-orang yang memendekkan rambutnya.\""},"1475":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ هُوَ ابْنُ أَبِي سَلَمَةَ الْمَاجِشُونُ عَنْ الزُّهْرِيِّ عَنْ عِيسَى بْنِ طَلْحَةَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَ الْجَمْرَةِ وَهُوَ يُسْأَلُ فَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ نَحَرْتُ قَبْلَ أَنْ أَرْمِيَ قَالَ ارْمِ وَلَا حَرَجَ قَالَ آخَرُ يَا رَسُولَ اللَّهِ حَلَقْتُ قَبْلَ أَنْ أَنْحَرَ قَالَ انْحَرْ وَلَا حَرَجَ قَالَ فَمَا سُئِلَ عَنْ شَيْءٍ قُدِّمَ وَلَا أُخِّرَ إِلَّا قَالَ افْعَلْ وَلَا حَرَجَ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Abdul Aziz yaitu Ibnu Abu Salamah Al Majisyun] dari [Az Zuhri] dari [Isa bin Thalhah] dari [Abdullah bin 'Amru], ia berkata; Aku melihat Rasulullah shallallahu 'alaihi wasallam berada di jumrah ketika ditanya, seseorang berkata; \"Wahai Rasulullah, saya menyembelih sebelum melempar jumrah.\" Beliau bersabda: \"Tidak mengapa, lemparlah.\" Orang yang lainnya bertanya; \"Wahai Rasulullah, saya mencukur rambut sebelum menyembelih.\" Beliau menjawab: \"Tidak mengapa, sembelihlah.\" Dan tidaklah beliau ditanya mengenai sesuatu yang didahulukan dan diakhirkan, melainkan beliau menjawab: \"Tidak mengapa, lakukanlah.\""},"1476":{"ar":" أَخْبَرَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ حَدَّثَنَا الزُّهْرِيُّ عَنْ عِيسَى بْنِ طَلْحَةَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَفَ لِلنَّاسِ فِي حَجَّة�� الْوَدَاعِ فَقَالَ لَهُ رَجُلٌ يَا رَسُولَ اللَّهِ حَلَقْتُ قَبْلَ أَنْ أَذْبَحَ قَالَ لَا حَرَجَ قَالَ لَمْ أَشْعُرْ ذَبَحْتُ قَبْلَ أَنْ أَرْمِيَ قَالَ لَا حَرَجَ فَلَمْ يُسْأَلْ يَوْمَئِذٍ عَنْ شَيْءٍ قُدِّمَ أَوْ أُخِّرَ إِلَّا قَالَ لَا حَرَجَ قَالَ عَبْد اللَّهِ أَنَا أَقُولُ بِهَذَا وَأَهْلُ الْكُوفَةِ يُشَدِّدُونَ","id":"Telah mengabarkan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] telah menceritakan kepada kami [Malik bin Anas] telah menceritakan kepada kami [Az Zuhri] dari [Isa bin Thalhah] dari [Abdullah bin 'Amru] bahwa Rasulullah shallallahu 'alaihi wasallam berdiri di hadapan orang-orang pada saat haji wada', kemudian seorang laki-laki bertanya; \"Wahai Rasulullah, saya telah mencukur rambut sebelum menyembelih.\" Beliau menjawab: \"Tidak mengapa.\" Orang tersebut mengatakan; \"Aku tidak merasa bila diriku telah menyembelih sebelum melempar jumrah.\" Beliau menjawab: \"Tidak mengapa.\" Tidaklah saat itu beliau ditanya mengenai sesuatu yang didahulukan atau diakhirkan, melainkan beliau menjawab; \"Tidak mengapa.\" Abdullah berkata; \"Aku berpendapat seperti ini, sementara penduduk Kufah bersikap keras.\""},"1477":{"ar":" أَخْبَرَنَا عَبْدُ الْوَهَّابِ بْنُ سَعِيدٍ حَدَّثَنَا شُعَيْبُ بْنُ إِسْحَقَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ نَاجِيَةَ الْأَسْلَمِيِّ صَاحِبِ هَدْيِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ سَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَيْفَ أَصْنَعُ بِمَا عَطِبَ مِنْ الْهَدْيِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُّ بَدَنَةٍ عَطِبَتْ فَانْحَرْهَا ثُمَّ أَلْقِ نَعْلَهَا فِي دَمِهَا ثُمَّ خَلِّ بَيْنَهَا وَبَيْنَ النَّاسِ فَلْيَأْكُلُوهَا أَخْبَرَنَا مُحَمَّدُ بْنُ سَعِيدٍ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ نَاجِيَةَ نَحْوَهُ","id":"Telah mengabarkan kepada kami [Abdul Wahhab bin Sa'id] telah menceritakan kepada kami [Syu'aib bin Ishaq] dari [Hisyam bin 'Urwah] dari [Ayahnya] dari [Najiyah Al Aslami] -seorang yang menuntun hewan kurban Rasulullah shallallahu 'alaihi wasallam- ia berkata; Aku bertanya kepada Rasulullah shallallahu 'alaihi wasallam; \"Apa yang harus aku laukan terhadap hewan kurban yang hampir mati?\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sembelihlah seluruh unta yang hampir mati, kemudian lemparkan telapak kakinya pada darahnya, setelah itu biarkanlah (dagingnya) berada di antara orang-orang supaya mereka memakannya.\" Telah mengabarkan kepada kami [Muhammad bin Sa'id] telah menceritakan kepada kami [Hafsh bin Ghiyats] dari [Hisyam bin 'Urwah] dari [Ayahnya] dari [Najiyah] seperti hadits di atas."},"1478":{"ar":" أَخْبَرَنَا يَعْلَى بْنُ عُبَيْدٍ وَأَبُو نُعَيْمٍ قَالَا حَدَّثَنَا الْأَعْمَشُ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْ أَهْدَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّةً غَنَمًا","id":"Telah mengabarkan kepada kami [Ya'la bin 'Ubaid] dan [Abu Nu'aim] keduanya berkata; telah menceritakan kepada kami [Al A'masy] dari [Ibrahim] dari [Al Aswad] dari ['Aisyah] ia berkata; \"Sesekali Rasulullah shallallahu 'alaihi wasallam berkurban dengan seekor kambing.\""},"1479":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ قَالَ سَمِعْتُ أَبَا حَسَّانَ يُحَدِّثُ عَنْ ابْنِ عَبَّاسٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى الظُّهْرَ بِذِي الْحُلَيْفَةِ ثُمَّ دَعَا بِبَدَنَةٍ فَأَشْعَرَهَا مِنْ صَفْحَةِ سَنَامِهَا الْأَيْمَنِ ثُمَّ سَلَتَ الدَّمَ عَنْهَا وَقَلَّدَهَا نَعْلَيْنِ ثُمَّ أُتِيَ بِرَاحِلَتِهِ فَلَمَّا قَعَدَ عَلَيْهَا وَاسْتَوَتْ عَلَى الْبَيْدَاءِ أَهَلَّ بِالْحَجِّ","id":"Telah mengabarkan kepada kami [Abu Al Walid Ath Thayalisi] telah menceritakan kepada kami [Syu'bah] dari [Qatadah], ia berkata; Aku mendengar [Abu Hassan] menceritakan dari [Ibnu Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam melakukan shalat Zhuhur di Dzul Hulaifah, kemudian beliau meminta seekor unta dan (sedikit) melukai pada sisi punuk kanannya (sebagai tanda bahwa itu adalah hewan kurban), setelah menghentikan darah hewan kurbannya, beliau mengalunginya dengan dua sandal, lalu beliau diberi kendaraannya, ketika beliau telah duduk di atas hewan tunggangannya hingga berada di Baida`, beliau mengucapkan talbiyah untuk melakukan haji.\""},"1480":{"ar":" أَخْبَرَنَا أَبُو النَّضْرِ هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا شُعْبَةُ قَالَ قَتَادَةُ أَخْبَرَنِي قَالَ سَمِعْتُ أَنَسًا يُحَدِّثُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ انْتَهَى إِلَى رَجُلٍ يَسُوقُ بَدَنَتَهُ قَالَ ارْكَبْهَا فَقَالَ إِنَّهَا بَدَنَةٌ قَالَ ارْكَبْهَا قَالَ إِنَّهَا بَدَنَةٌ قَالَ ارْكَبْهَا وَيْحَكَ","id":"Telah mengabarkan kepada kami [Abu An Nadhr Hasyim bin Al Qasim] telah menceritakan kepada kami [Syu'bah] ia berkata; telah mengabarkan kepadaku [Qatadah] ia berkata; saya mendengar [Anas] menceritakan dari Rasulullah shallallahu 'alaihi wasallam, bahwa beliau sampai kepada seorang laki-laki yang sedang menggiring hewan kurbannya, lalu beliau bersabda: \"Tunggangilah! \" Laki-laki itu menjawab; \"Ia adalah unta kurban.\" Beliau bersabda: \"Tunggangilah unta tersebut! \" laki-laki tersebut berkata; \"Ia adalah unta kurban.\" Beliau bersabda: \"Celaka kamu, Tunggangilah!.\""},"1481":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ يُونُسَ بْنِ عُبَيْدٍ عَنْ زِيَادِ بْنِ جُبَيْرٍ عَنْ ابْنِ عُمَرَ أَنَّهُ رَأَى رَجُلًا قَدْ أَنَاخَ بَدَنَةً فَقَالَ ابْعَثْهَا قِيَامًا مُقَيَّدَةً سُنَّةَ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Yunus bin 'Ubaid] dari [Ziyad bin Jubair] dari [Ibnu Umar] bahwa ia melihat seorang laki-laki menderumkan untanya, kemudian dia berkata: \"Bangunkan unta tersebut dalam keadaan terikat sesuai dengan sunah Muhammad shallallahu 'alaihi wasallam.\""},"1482":{"ar":" أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ قَرَأْتُ عَلَى أَبِي قُرَّةَ هُوَ مُوسَى بْنُ طَارِقٍ عَنْ ابْنِ جُرَيْجٍ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ عُثْمَانَ بْنِ خُثَيْمٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ رَجَعَ مِنْ عُمْرَةِ الْجِعْرَانَةِ بَعَثَ أَبَا بَكْرٍ عَلَى الْحَجِّ فَأَقْبَلْنَا مَعَهُ حَتَّى إِذَا كُنَّا بِالْعَرْجِ ثُوِّبَ بِالصُّبْحِ فَلَمَّا اسْتَوَى لِيُكَبِّرَ سَمِعَ الرَّغْوَةَ خَلْفَ ظَهْرِهِ فَوَقَفَ عَنْ التَّكْبِيرِ فَقَالَ هَذِهِ رَغْوَةُ نَاقَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْجَدْعَاءِ لَقَدْ بَدَا لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْحَجِّ فَلَعَلَّهُ أَنْ يَكُونَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنُصَلِّيَ مَعَهُ فَإِذَا عَلِيٌّ عَلَيْهَا فَقَالَ أَبُو بَكْرٍ أَمِيرٌ أَمْ رَسُولٌ قَالَ لَا بَلْ رَسُولٌ أَرْسَلَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِبَرَاءَةٌ أَقْرَؤُهَا عَلَى النَّاسِ فِي مَوَاقِفِ الْحَجِّ فَقَدِمْنَا مَكَّةَ فَلَمَّا كَانَ قَبْلَ التَّرْوِيَةِ بِيَوْمٍ قَامَ أَبُو بَكْرٍ فَخَطَبَ النَّاسَ فَحَدَّثَهُمْ عَنْ مَنَاسِكِهِمْ حَتَّى إِذَا فَرَغَ قَامَ عَلِيٌّ فَقَرَأَ عَلَى النَّاسِ بَرَاءَةٌ حَتَّى خَتَمَهَا ثُمَّ خَرَجْنَا مَعَهُ حَتَّى إِذَا كَانَ يَوْمُ عَرَفَةَ قَامَ أَبُو بَكْرٍ فَخَطَبَ النَّاسَ فَحَدَّثَهُمْ عَنْ مَنَاسِكِهِمْ حَتَّى إِذَا فَرَغَ قَامَ عَلِيٌّ فَقَرَأَ عَلَى النَّاسِ بَرَاءَةٌ حَتَّى خَتَمَهَا ثُمَّ كَانَ يَوْمُ النَّحْرِ فَأَفَضْنَا فَلَمَّا رَجَعَ أَبُو بَكْرٍ خَطَبَ النَّاسَ فَحَدَّثَهُمْ عَنْ إِفَاضَتِهِمْ وَعَنْ نَحْرِهِمْ وَعَنْ مَنَاسِكِهِمْ فَلَمَّا فَرَغَ قَامَ عَلِيٌّ فَقَرَأَ عَلَى النَّاسِ بَرَاءَةٌ حَتَّى خَتَمَهَا فَلَمَّا كَانَ يَوْمُ النَّفْرِ الْأَوَّلُ قَامَ أَبُو بَكْرٍ فَخَطَبَ النَّاسَ فَحَدَّثَهُمْ كَيْفَ يَنْفِرُونَ وَكَيْفَ يَرْمُونَ فَعَلَّمَهُمْ مَنَاسِكَهُمْ فَلَمَّا فَرَغَ قَامَ عَلِيٌّ فَقَرَأَ بَرَاءَةٌ عَلَى النَّاسِ حَتَّى خَتَمَهَا","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim], ia berkata; saya membacakan kepada [Abu Qurrah yaitu Musa bin Thariq], dari [Ibnu Juraij], ia berkata; telah menceritakan kepada kami [Abdullah bin Utsman bin Khutsaim] dari [Abu Az Zubair] dari [Jabir bin Abdullah] bahwa sekembalinya Nabi shallallahu 'alaihi wasallam dari Umrah Ji'ranah, beliau mengutus Abu Bakar memimpin haji, lalu kami berangkat bersama Abu Bakr, hingga tiba sampai di Al 'Arj, seseorang mengumandangkan adzan shubuh, ketika Abu Bakr berdiri untuk bertakbir, ia mendengar suara unta yang adatang dari arah dibelakangnya hingga ia menghentikan takbirnya, ia berkata; \"Ini adalah suara unta Rasulullah shallallahu 'alaihi wasallam yang bernama Al Jad'a`, tampaknya Rasulullah shallallahu 'alaihi wasallam hendak melaksanakan haji, semoga ia adalah Rasulullah shallallahu 'alaihi wasallam sehingga kita dapat melaksanakan shalat bersama beliau.\" Ternyata orang yang berada diatas unta tersebut adalah Ali, Abu Bakar berkata kepadanya; \"Engkau sebagai pemimpin (haji) ataukah hanya sebagai utusan? Ia menjawab; \"Tidak, bahkan aku hanyalah utusan. Rasulullah shallallahu 'alaihi wasallam telah mengutusku membawa surat Bara`ah yang akan aku bacakan dihadapan orang-orang di beberapa tempat pemberhentian haji.\" Setibanya kami di Makkah, yaitu sehari sebelum hari Tarwiyah (tanggal delapan dzulhijjah), Abu Bakar radliallahu 'anhu berdiri dan berkhutbah di hadapan orang-orang, ia berbicara mengenai manasik haji, seusai Abu Bakr menyampaikan khutbahnya, Ali radliallahu 'anhu berdiri dan membacakan surat Taubah hingga selesai. Setelah itu kami berangkat lagi bersama Abu Bakr, ketika hari 'Arafah, Abu Bakr berkhutbah di hadapan orang-orang dan menyampaikan tentang manasik haji mereka, seusai Abu Bakr berkhutbah, Ali berdiri dan membacakan Surat Bara`ah hingga selesai. Ketika hari raya Kurban tiba, kami pun bertolak, ketika Abu Bakr kembali, dia berdiri dan berkhutbah di hadapan orang-orang dan menyampaikan tentang ifadlah (keberangkatan), penyembelihan dan manasik mereka, seusai berkhutbah, maka Ali berdiri dan membacakan surat Al Bara`ah hingga selesai. Ketika hari nafar awal (kembali dari mina ke Makkah pada gelombang yang pertama) tiba, Abu Bakar kembali berkhutbah di hadapan orang-orang, dan menyampaikan tentang bagaimana seharusnya mereka kembali (ke Makkah), dan bagaimana mereka melontar jumrah, serta mengejari merka tentang manasik haji mereka, seusai berkhutbah, maka Ali berdiri untuk membacakan surat Taubah di hadapan orang-orang hingga selesai.\""},"1483":{"ar":" أَخْبَرَنَا أَبُو حَاتِمٍ أَشْهَلُ بْنُ حَاتِمٍ حَدَّثَنَا ابْنُ عَوْنٍ عَنْ مُحَمَّدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرَةَ عَنْ أَبِيهِ قَالَ لَمَّا كَانَ ذَلِكَ الْيَوْمُ قَعَدَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى بَعِيرٍ لَا أَدْرِي جَمَلٌ أَوْ نَاقَةٌ وَأَخَذَ إِنْسَانٌ بِخِطَامِهِ أَوْ قَالَ بِزِمَامِهِ فَقَالَ أَيُّ يَوْمٍ هَذَا قَالَ فَسَكَتْنَا حَتَّى ظَنَنَّا أَنَّهُ سَيُسَمِّيهِ سِوَى اسْمِهِ فَقَالَ أَلَيْسَ يَوْمَ النَّحْرِ قُلْنَا بَلَى قَالَ فَأَيُّ شَهْرٍ هَذَا قَالَ فَسَكَتْنَا حَتَّى ظَنَنَّا أَنَّهُ سَيُسَمِّيهِ سِوَى اسْمِهِ فَقَالَ أَلَيْسَ ذَا الْحِجَّةِ قُلْنَا بَلَى قَالَ فَأَيُّ بَلَدٍ هَذَا قَالَ فَسَكَتْنَا حَتَّى ظَنَنَّا أَنَّهُ سَيُسَمِّيهِ سِوَى اسْمِهِ فَقَالَ أَلَيْسَ الْبَلْدَةَ قُلْنَا بَلَى قَالَ فَإِنَّ دِمَاءَكُمْ وَأَمْوَالَكُمْ وَأَعْرَاضَكُمْ بَيْنَكُمْ حَرَامٌ كَحُرْمَةِ يَوْمِكُمْ هَذَا فِي شَهْرِكُمْ هَذَا فِي بَلَدِكُمْ هَذَا أَلَا لِيُبَلِّغْ الشَّاهِدُ الْغَائِبَ فَإِنَّ الشَّاهِدَ عَسَى أَنْ يُبَلِّغَ مَنْ هُوَ أَوْعَى مِنْهُ","id":"Telah mengabarkan kepada kami [Abu Hatim Asyhal bin Hatim] telah menceritakan kepada kami [Ibnu 'Aun] dari [Muhammad] dari [Abdurrahman bin Abu Bakrah] dari [Ayahnya], ia berkata; Ketika hari itu tiba (hari raya kurban), Nabi shallallahu 'alaihi wasallam duduk di atas unta -saya tidak tahu apakah unta jantan atau unta betina- sementara orang-orang memegangi tali kendalinya -atau berkata; tali kekangnya- kemudian beliau bertanya: \"Hari apakah ini?\" Abu Bakrah berkata; \"Kami diam, hingga kami menyangka beliau akan menamainya dengan selain namanya. Lalu beliau bersabda: \"Bukankah hari Nahr (hari raya kurban)?\" Kami menjawab; \"Benar.\" Beliau bertanya: \"Bulan apakah ini?\" Abu Barzah melanjutkan; \"Kami pun diam, hingga kami menyangka beliau akan menamainya dengan selain namanya, \" beliau lalu bersabda: \"Bukankah (bulan) Dzul Hijjah?\" Kami menjawab; \"Benar.\" Beliau bertanya lagi: \"Negeri apakah ini?\" Abu Barzah berkata; \"Kami diam, hingga kami menyangka beliau akan menamainya dengan selain namanya. beliau bersabda: \"Bukankah ini Negeri Haram?\" Kami menjawab; \"Benar.\" Beliau bersabda: \"Sesungguhnya darah kalian, harta, dan kehormatan kalian adalah haram atas kalian, seperti haramnya hari kalian ini, pada bulan kalian ini dan di negeri kalian kalian ini. Hendaknya orang yang hadir menyampaikan kepada orang yang tidak hadir. Karena bisa jadi orang yang hadir menyampaikan kepada orang yang lebih faham dari dirinya.\""},"1484":{"ar":" أَخْبَرَنَا يَعْلَى حَدَّثَنَا الْأَعْمَشُ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْ حَاضَتْ صَفِيَّةُ فَلَمَّا كَانَتْ لَيْلَةُ النَّفْرِ قَالَتْ أَيْ حَلْقَى أَيْ عَقْرَى بِلُغَةٍ لَهُمْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَسْتِ قَدْ طُفْتِ يَوْمَ النَّحْرِ قَالَتْ بَلَى قَالَ فَارْكَبِي حَدَّثَنَا سَهْلُ بْنُ حَمَّادٍ عَنْ شُعْبَةَ عَنْ الْحَكَمِ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ بِنَحْوِهِ","id":"Telah mengabarkan kepada kami [Ya'la] telah menceritakan kepada kami [Al A'masy] dari [Ibrahim] dari [Al Aswad] dari ['Aisyah], ia berkata; \"Suatu ketika Shafiyah haid, setelah malam nafar (sekembalinya dari Mina ke Makkah) ia berkata; \"\"Celaka aku (maksudnya tidak beruntung) -Dengan bahasa mereka- Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bukankah kamu telah melakukan thawaf pada hari Nahr?\" Ia berkata; \"Benar.\" Beliau bersabda: \"Naiklah kendaraan.\" Telah menceritakan kepada kami [Sahl bin Hammad] dari [Syu'bah] dari [Al Hakam] dari [Ibrahim] dari [Al Aswad] dari ['Aisyah] seperti hadits di atas."},"1485":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يَزِيدَ الْبَزَّازُ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ أَبِي إِسْحَقَ عَنْ زَيْدِ بْنِ يُثَيْعٍ قَالَ سَأَلْنَا عَلِيًّا بِأَيِّ شَيْءٍ بُعِثْتَ قَالَ بُعِثْتُ بِأَرْبَعٍ لَا يَدْخُلُ الْجَنَّةَ إِلَّا نَفْسٌ مُؤْمِنَةٌ وَلَا يَطُوفُ بِالْبَيْتِ عُرْيَانٌ وَلَا يَجْتَمِعُ مُسْلِمٌ وَكَافِرٌ فِي الْحَجِّ بَعْدَ عَامِهِمْ هَذَا وَمَنْ كَانَ بَيْنَهُ وَبَيْنَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَهْدٌ فَعَهْدُهُ إِلَى مُدَّتِهِ وَمَنْ لَمْ يَكُنْ لَهُ عَهْدٌ فَهِيَ أَرْبَعَةُ أَشْهُرٍ يَقُولُ بَعْدَ يَوْمِ النَّحْرِ أَجَلُهُمْ عِشْرِينَ مِنْ ذِي الْحِجَّةِ فَاقْتُلُوهُمْ بَعْدَ الْأَرْبَعَةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Yazid Al Bazzaz] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Abu Ishaq] dari [Zaid bin Yutsai'], ia berkata; kami bertanya kepada [Ali]; \"Dengan apakah kamu diutus (oleh Rasulullah)?\" Ia menjawab; \"Dengan empat hal, yaitu; tidak akan masuk Surga kecuali jiwa mukmin, orang-orang yang telanjang tidak boleh melakukan thawaf di Ka'bah, orang Muslim dan kafir tidak boleh berkumpul dalam melaksanakan haji setelah tahun ini, dan barangsiapa antara dirinya dan Rasulullah shallallahu 'alaihi wasallam ada perjanjian, maka perjanjiannya itu hingga sampai kepada waktunya, dan barangsiapa tidak memiliki pernjanjian, maka waktu mereka hanya empat bulan.\" Beliau bersabda: \"Setelah hari penyembelihan, tempo mereka sampai pada tanggal dua puluh Dzul Hijjah, maka bunuhlah mereka setelah empat bulan.\""},"1486":{"ar":" حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ الْمَجِيدِ الْحَنَفِيُّ حَدَّثَنَا شُعْبَةُ أَخْبَرَنِي أَبُو قَزَعَةَ قَالَ سَمِعْتُ مُهَاجِرًا يَقُولُ سُئِلَ جَابِرُ بْنُ عَبْدِ اللَّهِ عَنْ رَفْعِ الْأَيْدِي عِنْدَ الْبَيْتِ فَقَالَ إِنَّمَا كَانَ يَصْنَعُ ذَلِكَ الْيَهُودُ حَجَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفَصَنَعْنَا ذَاكَ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Abdul Majid Al Hanafi] telah menceritakan kepada kami [Syu'bah] telah mengabarkan kepadaku [Abu Qaza'ah], ia berkata; saya mendengar [Muhajir] berkata; [Jabir bin Abdullah] ditanya mengenai mengangkat tangan ketika di Ka'bah. Jabir menjawab; \"Sesungguhnya yang melakukan hal itu adalah orang-orang Yahudi, kami telah berhaji bersama Rasulullah shallallahu 'alaihi wasallam, apakah kami melakukan hal tersebut?.\""},"1487":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ وَحَجَّاجٌ قَالَا حَدَّثَنَا شُعْبَةُ أَخْبَرَنِي عَلِيُّ بْنُ مُدْرِكٍ قَالَ سَمِعْتُ أَبَا زُرْعَةَ يُحَدِّثُ عَنْ جَرِيرِ بْنِ عَبْدِ اللَّهِ أَنَّ رَسُولَ اللَّهِ اسْتَنْصَتَ النَّاسَ فِي حَجَّةِ الْوَدَاعِ ثُمَّ قَالَ لَا تَرْجِعُوا بَعْدِي كُفَّارًا يَضْرِبُ بَعْضُكُمْ رِقَابَ بَعْضٍ","id":"Telah mengabarkan kami [Abu Al Walid] dan [Hajjaj] mereka berkata; telah menceritakan kepada kami [Syu'bah] telah mengabarkan kepada kami [Ali bin Mudrik], ia berkata; saya mendengar [Abu Zur'ah] menceritakan dari [Jarir bin Abdullah] bahwa Rasulullah shallallahu 'alaihi wasallam meminta orang-orang supaya tenang pada saat melakukan haji wada', kemudian beliau bersabda: \"Janganlah kalian kembali menjadi kafir sepeninggalku, dengan saling menebas leher sebagian kalian terhadap sebagian yang lain.\""},"1488":{"ar":" أَخْبَرَنَا جَعْفَرُ بْنُ عَوْنٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ أَبِي خَالِدٍ قَالَ وَسَمِعْتُ ابْنَ أَبِي أَوْفَى يَقُولُ سَعَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ الصَّفَا وَالْمَرْوَةِ وَنَحْنُ نَسْتُرُهُ مِنْ أَهْلِ مَكَّةَ أَنْ يُصِيبَهُ أَحَدٌ بِحَجَرٍ أَوْ بِرَمْيَةٍ","id":"Telah mengabarkan kepada kami [Ja'far bin 'Aun] telah menceritakan kepada kami [Isma'il bin Abu Khalid], ia berkata; aku mendengar [Ibnu Abu Aufa] berkata; Rasulullah shallallahu 'alaihi wasallam melakukan sa'i antara Shafa dan Marwah, sementara kami menutupinya dari penduduk Makkah agar tidak ada seorangpun yang menimpakan batu atau lemparan kepada beliau.\""},"1489":{"ar":" أَخْبَرَنَا سَهْلُ بْنُ حَمَّادٍ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ عَلِيِّ بْنِ الْحُسَيْنِ عَنْ مَرْوَانَ بْنِ الْحَكَمِ أَنَّهُ شَهِدَ عَلِيًّا وَعُثْمَانَ بَيْنَ مَكَّةَ وَالْمَدِينَةِ وَعُثْمَانُ يَنْهَى عَنْ الْمُتْعَةِ فَلَمَّا رَأَى ذَلِكَ عَلِيٌّ أَهَلَّ بِهِمَا جَمِيعًا فَقَالَ لَبَّيْكَ بِحَجَّةٍ وَعُمْرَةٍ مَعًا فَقَالَ تَرَانِي أَنْهَى عَنْهُ وَتَفْعَلُهُ فَقَالَ لَمْ أَكُنْ لِأَدَعَ سُنَّةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِقَوْلِ أَحَدٍ مِنْ النَّاسِ","id":"Telah mengabarkan kepada kami [Sahl bin Hammad] telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] dari [Ali bin Al Husain] dari [Marwan bin Al Hakam] bahwa ia menyaksikan [Ali] dan Utsman berada di Makkah dan Madinah. Saat itu Utsman melarang haji tamattu', setelah Ali melihat hal itu, Ali mengucapkan talbiyah untuk haji dan umrah bersamaan, ia mengucapkan: \"Labbaika bihajjatin wa 'umrah ma'an.\" Utsman pun berkata; \"Kamu lihat aku melarang hal itu, tapi kamu justru melakukannya? Ali berkata; aku tidak akan meninggalkan sunnah Rasulullah shallallahu 'alaihi wasallam karena perkataan seseorang.\""},"1490":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا حُمَيْدٌ عَنْ أَنَسٍ أَنَّهُ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَبَّيْكَ بِعُمْرَةٍ وَحَجٍّ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah menceritakan kepada kami [Humaid] dari [Anas] bahwa ia mendengar Nabi shallallahu 'alaihi wasallam mengucapkan: \"LABBAIKA BI'UMRATIN WA HAJJ.\" (aku memenuhi panggilanmu untuk melakukan umrah dan haji).\""},"1491":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ حَبِيبِ بْنِ الشَّهِيدِ عَنْ بَكْرِ بْنِ عَبْدِ اللَّهِ عَنْ أَنَسٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَهَلَّ بِهِمَا جَمِيعًا فَلَقِيتُ ابْنَ عُمَرَ فَأَخْبَرْتُهُ بِقَوْلِ أَنَسٍ فَقَالَ إِنَّمَا أَهَلَّ بِالْحَجِّ فَرَجَعْتُ إِلَى أَنَسٍ فَأَخْبَرْتُهُ بِقَوْلِ ابْنِ عُمَرَ فَقَالَ مَا يَعُدُّونَا إِلَّا صِبْيَانًا","id":"Telah mengabarkan kepada kami [Sa'id bin 'Amir] dari [Habib bin Asy Syahid] dari [Bakr bin Abdullah] dari [Anas] bahwa Rasulullah shallallahu 'alaihi wasallam mengucapkan talbiyah untuk keduanya (haji dan umrah) secara bersamaan. Setelah itu aku bertemu dengan Ibnu Umar dan mengabarkan perkataan Anas kepadanya, Ibnu Umar berkata; \"Sesungguhnya beliau hanya mengucapkan tahlil untuk haji saja.\" Lalu aku kembali kepada Anas, dan mengabarkan perkataan [Ibnu Umar] kepadanya, Anas pun berkata; \"Mereka hanya menganggap kami sebagai anak-anak.\""},"1492":{"ar":" حَدَّثَنَا عَمْرُو بْنُ عَوْنٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ أَبِي الزُّبَيْرِ عَنْ عَبْدِ اللَّهِ بْنِ بَابَاهُ عَنْ جُبَيْرِ بْنِ مُطْعِمٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَا بَنِي عَبْدِ مَنَافٍ إِنْ وَلِيتُمْ هَذَا الْأَمْرَ فَلَا تَمْنَعُوا أَحَدًا طَافَ أَوْ صَلَّى أَيَّ سَاعَةٍ شَاءَ مِنْ لَيْلٍ أَوْ نَهَارٍ","id":"Telah menceritakan kepada kami ['Amru bin 'Aun] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Abu Az Zubair] dari [Abdullah bin Babah] dari [Jubair bin Muth'im] bahwa Nabi shallallahu 'alaihi wasallam bersabda; \"Wahai Bani Abdu Manaf, apabila kalian mengurusi perkara ini, janganlan kalian melarang seseorang untuk thawaf atau melakukan shalat pada saat kapanpun yang ia kehendaki, baik malam ataupun siang.\""},"1493":{"ar":" حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ أَخْبَرَنِي نَافِعٌ عَنْ ابْنِ عُمَرَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَاتَ بِذِي طُوًى حَتَّى أَصْبَحَ ثُمَّ دَخَلَ مَكَّةَ وَكَانَ ابْنُ عُمَرَ يَفْعَلُهُ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya bin Sa'id] dari ['Ubaidullah] telah mengabarkan kepadaku [Nafi'] dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam bermalam di Dzu Thuwa' hingga pagi hari, setelah itu beliau memasuki Makkah, dan Ibnu Umar juga melakukan hal itu.\""},"1494":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا عُقْبَةُ بْنُ خَالِدٍ عَنْ عُبَيْدِ اللَّهِ حَدَّثَنِي نَافِعٌ عَنْ ابْنِ عُمَرَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَدْخُلُ مَكَّةَ مِنْ الثَّنِيَّةِ الْعُلْيَا وَيَخْرُجُ مِنْ الثَّنِيَّةِ السُّفْلَى","id":"Telah mengabarkan kepada kami [Abdullah bin Sa'id] telah menceritakan kepada kami ['Uqbah bin Khalid] dari ['Ubaidullah] telah menceritakan kepadaku [Nafi'] dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam memasuki Makkah dari Ats Tsanyyah Ulya, dan keluar dari Ats Tsaniyyah Sufla.\""},"1495":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا عُقْبَةُ بْنُ خَالِدٍ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَدْخَلَ رِجْلَهُ فِي الْغَرْزِ وَاسْتَوَتْ بِهِ نَاقَتُهُ أَهَلَّ مِنْ مَسْجِدِ ذِي الْحُلَيْفَةِ","id":"Telah mengabarkan kepada kami [Abdullah bin Sa'id] telah menceritakan kepada kami ['Uqbah bin Khalid] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar], ia berkata; \"Apabila Rasulullah shallallahu 'alaihi wasallam memasukkan kakinya pada sanggurdi (pelana) dan untanya telah berdiri tegap, beliau berniat sambil bertalbiyah dari Masjid Dzul Hulaifah.\""},"1496":{"ar":" أَخْبَرَنَا عُثْمَانُ بْنُ مُحَمَّدِ بْنِ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ أَحْمَدَ بْنِ أَبِي خَلَفٍ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ أَيُّوبَ بْنِ مُوسَى عَنْ نُبَيْهِ بْنِ وَهْبٍ عَنْ أَبَانَ بْنِ عُثْمَانَ عَنْ أَبِيهِ أَنَّ النَّبِيَّ قَالَ فِي الْمُحْرِمِ إِذَا اشْتَكَى عَيْنَيْهِ يَضْمِدُهَا بِالصَّبِرِ","id":"Telah mengabarkan kepada kami [Utsman bin Muhammad bin Abu Syaibah] dan [Muhammad bin Ahmad bin Abu Khalaf] keduanya berkata; telah menceritakan kepada kami [Sufyan] dari [Ayyub bin Musa] dari [Nubaih bin Wahb] dari [Aban bin Utsman] dari [ayahnya] bahwa Nabi shallallahu 'alaihi wasallam bersabda tentang orang yang berihram: \"Apabila matanya sakit, hendaknya ia membalutnya dengan shabir.\" "},"1497":{"ar":" أَخْبَرَنَا هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ دِينَارٍ قَالَ سَمِعْتُ ابْنَ عُمَرَ يَقُولُ قَدِمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَطَافَ بِالْبَيْتِ وَصَلَّى عِنْدَ الْمَقَامِ رَكْعَتَيْنِ ثُمَّ خَرَجَ إِلَى الصَّفَا قَالَ شُعْبَةُ فَحَدَّثَنِي أَيُّوبُ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ قَالَ هِيَ السُّنَّةُ","id":"Telah mengabarkan kepada kami [Hasyim bin Al Qasim] telah menceritakan kepada kami [Syu'bah] dari ['Amru bin Dinar], ia berkata; aku mendengar [Ibnu Umar] berkata; Nabi shallallahu 'alaihi wasallam tiba (di Makkah) kemudian beliau thawaf di Ka'bah, setelah itu shalat dua raka'at di Maqam Ibrahim, kemudian beliau keluar menuju Shafa.\" [Syu'bah] berkata; telah menceritakan kepadaku [Ayyub] dari ['Amru bin Dinar] dari [Ibnu Umar], ia berkata; \"Itu adalah sunnah.\""},"1498":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ ابْنِ عُيَيْنَةَ عَنْ سُلَيْمَانَ الْأَحْوَلِ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ قَالَ كَانَ النَّاسُ يَنْصَرِفُونَ فِي كُلِّ وَجْهٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَنْفِرَنَّ أَحَدٌ حَتَّى يَكُونَ آخِرُ عَهْدِهِ بِالْبَيْتِ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Ibnu 'Uyainah] dari [Sulaiman Al Ahwal] dari [Thawus] dari [Ibnu Abbas], ia berkata; \"Dahulu orang-orang beranjak pergi dari segala arah, lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah seorangpun yang keluar dari Makkah hingga akhir masanya di Ka'bah.\""},"1499":{"ar":" أَخْبَرَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا ابْنُ طَاوُسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ قَالَ رُخِّصَ لِلْحَائِضِ أَنْ تَنْفِرَ إِذَا أَفَاضَتْ قَالَ وَسَمِعْتُ ابْنَ عُمَرَ عَامَ الْأَوَّلِ أَنَّهَا لَا تَنْفِرُ ثُمَّ سَمِعْتُهُ يَقُولُ تَنْفِرُ إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَخَّصَ لَهُنَّ","id":"Telah mengabarkan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Ibnu Thawus] dari [Ayahnya] dari [Ibnu Abbas], ia berkata; \"Wanita yang haid diberi keringanan agar kembali (dari Makkah setelah haji) apabila ia telah melakukan thawaf ifadhah.\" Thawus berkata; aku mendengar [Ibnu Umar] pada tahun pertama, bahwa wanita yang haid yang telah melakukan thawaf ifadhah, tidak boleh kembali (dari Makkah sehabis melaksanakan haji). Setelah itu aku mendengar ia berkata; \"Boleh kembali (dari Mekkah setelah haji), sesungguhnya Nabi shallallahu 'alaihi wasallam telah memberikan keringanan bagi mereka.\""},"1500":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ يَقُولُ حَدَّثَنِي اللَّيْثُ حَدَّثَنِي عُقَيْلٌ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي طَاوُسٌ الْيَمَانِيُّ أَنَّهُ سَمِعَ عَبْدَ اللَّهِ بْنَ عُمَرَ وَهُوَ يُسْأَلُ عَنْ حَبْسِ النِّسَاءِ عَنْ الطَّوَافِ بِالْبَيْتِ إِذَا حِضْنَ قَبْلَ النَّفْرِ وَقَدْ أَفَضْنَ يَوْمَ النَّحْرِ فَقَالَ إِنَّ عَائِشَةَ كَانَتْ تَذْكُرُ رُخْصَةً لِلنِّسَاءِ وَذَلِكَ قَبْلَ مَوْتِ عَبْدِ اللَّهِ بْنِ عُمَرَ بِعَامٍ","id":"Telah mengabarkan kepada kami [Abdullah bin Shalih], ia berkata; telah menceritakan kepadaku [Al Laits] telah menceritakan kepadaku ['Uqail] dari [Ibnu Syihab], ia berkata; telah mengabarkan kepadaku [Thawus Al Yamani] bahwa ia mendengar [Abdullah bin Umar] ditanya mengenai larangan wanita melakukan thawaf di Ka'bah, di saat haid sebelum nafar (kembali dari Mina), setelah melakukan Thawaf ifadhah pada hari Nahr (hari pertama 'Idul Adhha), Ibnu Umar berkata; \"Sesungguhnya ['Aisyah] pernah menyebutkan keringanan bagi wanita.\" Peristiwa itu terjadi setahun sebelum meninggalnya Abdullah bin Umar."}};
